import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Database {
  id: string;
  name: string;
  type: 'postgres' | 'mysql' | 'sqlite' | 'parquet' | 'mssql';
  connectionString?: string; // Optional, internal use
}

export interface QueryResult {
  columns: string[];
  rows: any[][];
  executionTimeMs: number;
  rowCount: number;
  error?: string;
  timestamp: number;
}

export interface EditorTab {
  id: string;
  title: string;
  content: string;
  isDirty: boolean;
  isExecuting: boolean;
  results: QueryResult[]; // History of results for this tab
  activeResultIndex: number; // Which result is currently showing
}

export interface PaginationConfig {
  page: number;
  pageSize: number;
}

// Message types for Muul communication
export type MuulMessageType = 'DB_LIST' | 'DB_EXECUTE' | 'DB_CANCEL';

export interface MuulMessage {
  type: MuulMessageType;
  payload?: any;
  requestId?: string;
}

import { Database, QueryResult } from '../types';

/**
 * Mocks the communication with the "Muul" browser extension or shell.
 * In a real scenario, this would likely use window.postMessage or a specific JS bridge.
 */

// Simulated delay helper
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

class MuulService {
  private activeQueries: Map<string, boolean> = new Map();

  /**
   * Fetches available databases from the credential manager.
   */
  async getDatabases(): Promise<Database[]> {
    console.log('[MuulService] Requesting DB list...');
    await delay(600); // Simulate bridge latency

    return [
      { id: 'db-1', name: 'Production DB (Read-Only)', type: 'postgres' },
      { id: 'db-2', name: 'Analytics Parquet', type: 'parquet' },
      { id: 'db-3', name: 'Local Dev SQLite', type: 'sqlite' },
      { id: 'db-4', name: 'Legacy MSSQL', type: 'mssql' },
    ];
  }

  /**
   * Executes a SQL query against a specific database.
   */
  async executeQuery(dbId: string, sql: string, queryId: string): Promise<QueryResult> {
    console.log(`[MuulService] Executing on ${dbId}:`, sql);
    this.activeQueries.set(queryId, true);

    const startTime = performance.now();

    try {
      // Simulate execution time proportional to complexity
      const executionTime = Math.random() * 1000 + 200;
      await delay(executionTime);

      if (!this.activeQueries.get(queryId)) {
        throw new Error("Query was cancelled by user.");
      }

      // Mock Data Generation based on query content keywords
      const lowerSql = sql.toLowerCase();
      let columns: string[] = [];
      let rows: any[][] = [];

      if (lowerSql.includes('select')) {
        if (lowerSql.includes('users')) {
          columns = ['id', 'username', 'email', 'created_at', 'status', 'role'];
          rows = Array.from({ length: 45 }, (_, i) => [
            i + 1,
            `user_${i + 1}`,
            `user${i + 1}@muul.example.com`,
            new Date(Date.now() - Math.random() * 10000000000).toISOString(),
            Math.random() > 0.2 ? 'active' : 'inactive',
            Math.random() > 0.8 ? 'admin' : 'viewer'
          ]);
        } else if (lowerSql.includes('orders')) {
          columns = ['order_id', 'customer_id', 'total_amount', 'status', 'order_date'];
          rows = Array.from({ length: 120 }, (_, i) => [
            1000 + i,
            Math.floor(Math.random() * 50) + 1,
            (Math.random() * 500).toFixed(2),
            ['pending', 'shipped', 'delivered', 'cancelled'][Math.floor(Math.random() * 4)],
            new Date(Date.now() - Math.random() * 5000000000).toISOString(),
          ]);
        } else {
           // Generic fallback data
           columns = ['id', 'name', 'value', 'category', 'score'];
           rows = Array.from({ length: 25 }, (_, i) => [
             i, 
             `Item ${i}`, 
             Math.floor(Math.random() * 1000), 
             ['A', 'B', 'C'][Math.floor(Math.random() * 3)],
             Math.floor(Math.random() * 100)
           ]);
        }
      } else if (lowerSql.includes('update') || lowerSql.includes('insert') || lowerSql.includes('delete')) {
        columns = ['affected_rows'];
        rows = [[Math.floor(Math.random() * 10)]];
      } else {
        // Syntax error simulation
        if (Math.random() > 0.9) {
           throw new Error(`Syntax error at line 1: Unexpected token near '${sql.substring(0, 10)}...'`);
        }
        columns = ['result'];
        rows = [['Command completed successfully']];
      }

      return {
        columns,
        rows,
        rowCount: rows.length,
        executionTimeMs: Math.round(performance.now() - startTime),
        timestamp: Date.now()
      };

    } catch (e: any) {
      return {
        columns: [],
        rows: [],
        rowCount: 0,
        executionTimeMs: Math.round(performance.now() - startTime),
        timestamp: Date.now(),
        error: e.message || 'Unknown error occurred'
      };
    } finally {
      this.activeQueries.delete(queryId);
    }
  }

  cancelQuery(queryId: string) {
    console.log(`[MuulService] Cancelling query ${queryId}`);
    if (this.activeQueries.has(queryId)) {
      this.activeQueries.set(queryId, false); // Signal cancellation
    }
  }
}

export const muulService = new MuulService();

import React, { forwardRef, useImperativeHandle, useRef } from 'react';

interface SqlEditorProps {
  value: string;
  onChange: (value: string) => void;
  disabled?: boolean;
}

export interface SqlEditorRef {
  getSelection: () => { start: number; end: number; text: string };
  focus: () => void;
}

const SqlEditor = forwardRef<SqlEditorRef, SqlEditorProps>(({ value, onChange, disabled }, ref) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useImperativeHandle(ref, () => ({
    getSelection: () => {
      const el = textareaRef.current;
      if (!el) return { start: 0, end: 0, text: '' };
      const start = el.selectionStart;
      const end = el.selectionEnd;
      const text = el.value.substring(start, end);
      return { start, end, text };
    },
    focus: () => {
      textareaRef.current?.focus();
    }
  }));

  // Basic syntax highlighting approach (simulated by overlay logic if we had complex library, 
  // but for raw React without Prism/Monaco, we style the textarea to look like code)

  return (
    <div className="relative w-full h-full font-mono text-sm bg-slate-900 overflow-hidden">
      <textarea
        ref={textareaRef}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        disabled={disabled}
        spellCheck={false}
        className={`w-full h-full p-4 bg-transparent text-slate-200 resize-none focus:outline-none focus:ring-0 leading-relaxed ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
        placeholder="-- Write your SQL query here.&#10;-- Select text to run specific lines.&#10;SELECT * FROM users;"
      />

      {/* Line Numbers Bar (Visual Only - simplified) */}
      <div className="absolute top-0 left-0 bottom-0 w-0 border-r border-slate-700 bg-slate-800 pointer-events-none hidden md:block">
        {/* Implementation of line numbers would require syncing scroll, omitting for stability in single-file logic */}
      </div>
    </div>
  );
});

SqlEditor.displayName = 'SqlEditor';

export default SqlEditor;

import React, { useState, useMemo } from 'react';
import { QueryResult } from '../types';
import { ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from 'lucide-react';

interface DataTableProps {
  result: QueryResult;
}

const DataTable: React.FC<DataTableProps> = ({ result }) => {
  const [pageSize, setPageSize] = useState(10);
  const [currentPage, setCurrentPage] = useState(1);

  // Reset page when result changes
  React.useEffect(() => {
    setCurrentPage(1);
  }, [result.timestamp]);

  const totalPages = Math.ceil(result.rows.length / pageSize);

  const currentRows = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return result.rows.slice(start, start + pageSize);
  }, [result.rows, currentPage, pageSize]);

  if (result.error) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-red-400">
        <div className="text-4xl mb-4">⚠️</div>
        <h3 className="text-xl font-bold mb-2">Execution Error</h3>
        <p className="font-mono bg-red-950/30 p-4 rounded border border-red-900/50 max-w-2xl whitespace-pre-wrap">
          {result.error}
        </p>
      </div>
    );
  }

  if (result.rows.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-slate-500">
        <p className="text-lg">Query executed successfully. No data returned.</p>
        <p className="text-sm mt-2 font-mono text-slate-600">{result.rowCount} rows affected.</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-slate-900">
      {/* Controls */}
      <div className="flex items-center justify-between p-2 bg-slate-850 border-b border-slate-800">
        <div className="text-xs text-slate-400 font-mono">
          {result.rows.length} rows • {result.executionTimeMs}ms
        </div>
        <div className="flex items-center space-x-4">
            <div className="flex items-center space-x-2 text-sm">
                <span className="text-slate-400">Rows:</span>
                <select 
                    value={pageSize}
                    onChange={(e) => setPageSize(Number(e.target.value))}
                    className="bg-slate-800 border border-slate-700 text-slate-200 text-xs rounded px-2 py-1 focus:outline-none focus:border-blue-500"
                >
                    <option value={10}>10</option>
                    <option value={50}>50</option>
                    <option value={100}>100</option>
                    <option value={1000}>1000</option>
                </select>
            </div>
            <div className="flex items-center space-x-1">
                <button 
                    onClick={() => setCurrentPage(1)} 
                    disabled={currentPage === 1}
                    className="p-1 hover:bg-slate-700 rounded disabled:opacity-30"
                >
                    <ChevronsLeft size={16} />
                </button>
                <button 
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))} 
                    disabled={currentPage === 1}
                    className="p-1 hover:bg-slate-700 rounded disabled:opacity-30"
                >
                    <ChevronLeft size={16} />
                </button>
                <span className="text-xs font-mono w-16 text-center">
                    {currentPage} / {totalPages}
                </span>
                <button 
                    onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} 
                    disabled={currentPage === totalPages}
                    className="p-1 hover:bg-slate-700 rounded disabled:opacity-30"
                >
                    <ChevronRight size={16} />
                </button>
                <button 
                    onClick={() => setCurrentPage(totalPages)} 
                    disabled={currentPage === totalPages}
                    className="p-1 hover:bg-slate-700 rounded disabled:opacity-30"
                >
                    <ChevronsRight size={16} />
                </button>
            </div>
        </div>
      </div>

      {/* Table Area */}
      <div className="flex-1 overflow-auto">
        <table className="w-full text-left border-collapse text-sm">
          <thead className="bg-slate-800 sticky top-0 z-10 shadow-sm">
            <tr>
              <th className="p-2 border-b border-slate-700 text-xs font-semibold text-slate-400 w-12 text-center">#</th>
              {result.columns.map((col, idx) => (
                <th key={idx} className="p-3 border-b border-slate-700 text-xs font-semibold text-slate-300 font-mono whitespace-nowrap min-w-[100px]">
                  {col}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {currentRows.map((row, rowIndex) => (
              <tr key={rowIndex} className="hover:bg-slate-800/30 transition-colors">
                <td className="p-2 text-xs text-slate-600 text-center font-mono border-r border-slate-800/50">
                   {(currentPage - 1) * pageSize + rowIndex + 1}
                </td>
                {row.map((cell: any, cellIndex: number) => {
                    let displayValue = cell;
                    if (typeof cell === 'object' && cell !== null) {
                        displayValue = JSON.stringify(cell);
                    }
                    if (cell === null) displayValue = <span className="text-slate-600 italic">NULL</span>;
                    if (typeof cell === 'boolean') displayValue = cell ? 'TRUE' : 'FALSE';

                    return (
                        <td key={cellIndex} className="p-2 px-3 text-slate-300 whitespace-nowrap overflow-hidden text-ellipsis max-w-xs border-r border-slate-800/50">
                        {displayValue}
                        </td>
                    );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default DataTable;

import React, { useMemo, useState } from 'react';
import { QueryResult } from '../types';
import { 
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer 
} from 'recharts';
import { BarChart3, LineChart as LineChartIcon, PieChart as PieChartIcon } from 'lucide-react';

interface DataVisualizerProps {
  result: QueryResult;
}

type ChartType = 'bar' | 'line' | 'pie';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4'];

const DataVisualizer: React.FC<DataVisualizerProps> = ({ result }) => {
  const [chartType, setChartType] = useState<ChartType>('bar');
  const [xAxisKey, setXAxisKey] = useState<string>('');
  const [dataKeys, setDataKeys] = useState<string[]>([]);

  // Detect potential axes
  const { numericColumns, stringColumns, formattedData } = useMemo(() => {
    if (!result || !result.rows.length) {
      return { numericColumns: [], stringColumns: [], formattedData: [] };
    }

    const cols = result.columns;
    const sampleRow = result.rows[0];

    const numCols: string[] = [];
    const strCols: string[] = [];

    cols.forEach((col, idx) => {
      const val = sampleRow[idx];
      if (typeof val === 'number') numCols.push(col);
      else strCols.push(col);
    });

    // Map rows array to object array for Recharts
    const data = result.rows.map(row => {
      const obj: any = {};
      cols.forEach((col, idx) => {
        obj[col] = row[idx];
      });
      return obj;
    });

    return { numericColumns: numCols, stringColumns: strCols, formattedData: data };
  }, [result]);

  // Set defaults if keys aren't selected
  React.useEffect(() => {
    if (formattedData.length > 0) {
      if (!xAxisKey && stringColumns.length > 0) setXAxisKey(stringColumns[0]);
      else if (!xAxisKey && result.columns.length > 0) setXAxisKey(result.columns[0]);

      if (dataKeys.length === 0 && numericColumns.length > 0) setDataKeys([numericColumns[0]]);
    }
  }, [formattedData, numericColumns, stringColumns, xAxisKey, dataKeys, result.columns]);

  if (result.error || result.rows.length === 0) {
     return <div className="h-full flex items-center justify-center text-slate-500">No data to visualize</div>;
  }

  if (numericColumns.length === 0) {
    return <div className="h-full flex items-center justify-center text-slate-500">No numeric columns found to visualize</div>;
  }

  const handleDataKeyToggle = (key: string) => {
    setDataKeys(prev => 
      prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]
    );
  };

  return (
    <div className="h-full flex flex-col bg-slate-900">
      {/* Config Toolbar */}
      <div className="p-4 border-b border-slate-800 bg-slate-850 grid grid-cols-1 md:grid-cols-3 gap-4">

        {/* Chart Type Selector */}
        <div className="flex space-x-1 bg-slate-800 p-1 rounded-lg w-fit">
          <button 
            onClick={() => setChartType('bar')}
            className={`p-2 rounded ${chartType === 'bar' ? 'bg-slate-700 text-blue-400' : 'text-slate-400 hover:text-slate-200'}`}
            title="Bar Chart"
          >
            <BarChart3 size={18} />
          </button>
          <button 
            onClick={() => setChartType('line')}
            className={`p-2 rounded ${chartType === 'line' ? 'bg-slate-700 text-green-400' : 'text-slate-400 hover:text-slate-200'}`}
            title="Line Chart"
          >
            <LineChartIcon size={18} />
          </button>
          <button 
            onClick={() => setChartType('pie')}
            className={`p-2 rounded ${chartType === 'pie' ? 'bg-slate-700 text-purple-400' : 'text-slate-400 hover:text-slate-200'}`}
            title="Pie Chart"
          >
            <PieChartIcon size={18} />
          </button>
        </div>

        {/* Axes Selectors */}
        <div className="flex flex-col space-y-2 md:col-span-2">
            <div className="flex items-center space-x-2">
                <label className="text-xs text-slate-500 w-12 font-bold uppercase">X-Axis</label>
                <select 
                    value={xAxisKey} 
                    onChange={e => setXAxisKey(e.target.value)}
                    className="bg-slate-800 text-xs text-slate-200 border border-slate-700 rounded px-2 py-1 flex-1"
                >
                    {result.columns.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
            </div>

            {chartType !== 'pie' && (
                 <div className="flex items-start space-x-2">
                 <label className="text-xs text-slate-500 w-12 font-bold uppercase mt-1">Y-Axis</label>
                 <div className="flex flex-wrap gap-2 flex-1">
                     {numericColumns.map(col => (
                         <button
                             key={col}
                             onClick={() => handleDataKeyToggle(col)}
                             className={`text-xs px-2 py-1 rounded border ${
                                 dataKeys.includes(col) 
                                 ? 'bg-blue-900/30 border-blue-600 text-blue-200' 
                                 : 'bg-slate-800 border-slate-700 text-slate-400'
                             }`}
                         >
                             {col}
                         </button>
                     ))}
                 </div>
             </div>
            )}

        </div>
      </div>

      {/* Chart Render Area */}
      <div className="flex-1 p-4 overflow-hidden">
        <ResponsiveContainer width="100%" height="100%">
          {chartType === 'bar' ? (
            <BarChart data={formattedData}>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
              <XAxis dataKey={xAxisKey} stroke="#94a3b8" fontSize={12} tickFormatter={(val) => `${val}`.substring(0, 10)} />
              <YAxis stroke="#94a3b8" fontSize={12} />
              <Tooltip 
                contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                itemStyle={{ color: '#e2e8f0' }}
              />
              <Legend />
              {dataKeys.map((key, index) => (
                <Bar key={key} dataKey={key} fill={COLORS[index % COLORS.length]} />
              ))}
            </BarChart>
          ) : chartType === 'line' ? (
            <LineChart data={formattedData}>
               <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
              <XAxis dataKey={xAxisKey} stroke="#94a3b8" fontSize={12} tickFormatter={(val) => `${val}`.substring(0, 10)} />
              <YAxis stroke="#94a3b8" fontSize={12} />
              <Tooltip 
                 contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                 itemStyle={{ color: '#e2e8f0' }}
              />
              <Legend />
              {dataKeys.map((key, index) => (
                <Line type="monotone" key={key} dataKey={key} stroke={COLORS[index % COLORS.length]} strokeWidth={2} dot={false} />
              ))}
            </LineChart>
          ) : (
            <PieChart>
                <Pie
                    data={formattedData}
                    dataKey={dataKeys[0] || numericColumns[0]}
                    nameKey={xAxisKey}
                    cx="50%"
                    cy="50%"
                    outerRadius={120}
                    fill="#8884d8"
                    label={({name, percent}) => `${name} ${(percent * 100).toFixed(0)}%`}
                >
                    {formattedData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                </Pie>
                <Tooltip 
                    contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                    itemStyle={{ color: '#e2e8f0' }}
                />
            </PieChart>
          )}
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default DataVisualizer;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Database, EditorTab, QueryResult } from './types';
import { muulService } from './services/muulService';
import { 
  Play, Plus, X, Save, Download, Database as DbIcon, 
  LayoutTemplate, Table as TableIcon, Activity, Ban 
} from 'lucide-react';
import SqlEditor, { SqlEditorRef } from './components/SqlEditor';
import DataTable from './components/DataTable';
import DataVisualizer from './components/DataVisualizer';

const App: React.FC = () => {
  // State
  const [databases, setDatabases] = useState<Database[]>([]);
  const [selectedDbId, setSelectedDbId] = useState<string>('');

  const [tabs, setTabs] = useState<EditorTab[]>([
    { 
      id: 'tab-1', 
      title: 'Query 1', 
      content: '', 
      isDirty: false, 
      isExecuting: false, 
      results: [],
      activeResultIndex: -1 
    }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab-1');
  const [viewMode, setViewMode] = useState<'table' | 'chart'>('table');

  // Refs
  const editorRef = useRef<SqlEditorRef>(null);

  // Initialization
  useEffect(() => {
    muulService.getDatabases().then(dbs => {
      setDatabases(dbs);
      if (dbs.length > 0) setSelectedDbId(dbs[0].id);
    });
  }, []);

  const activeTab = tabs.find(t => t.id === activeTabId)!;
  const activeResult = activeTab?.activeResultIndex >= 0 
    ? activeTab.results[activeTab.activeResultIndex] 
    : null;

  // -- Actions --

  const handleCreateTab = () => {
    const newId = `tab-${Date.now()}`;
    const newTab: EditorTab = {
      id: newId,
      title: `Query ${tabs.length + 1}`,
      content: '',
      isDirty: false,
      isExecuting: false,
      results: [],
      activeResultIndex: -1
    };
    setTabs([...tabs, newTab]);
    setActiveTabId(newId);
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (tabs.length === 1) return; // Prevent closing last tab

    const newTabs = tabs.filter(t => t.id !== id);
    setTabs(newTabs);
    if (activeTabId === id) {
      setActiveTabId(newTabs[newTabs.length - 1].id);
    }
  };

  const handleUpdateContent = (content: string) => {
    setTabs(prev => prev.map(t => 
      t.id === activeTabId ? { ...t, content, isDirty: true } : t
    ));
  };

  const handleRenameTab = (id: string, newName: string) => {
    setTabs(prev => prev.map(t => t.id === id ? { ...t, title: newName } : t));
  };

  // Execution Logic
  const handleRunQuery = async () => {
    if (!selectedDbId) {
      alert("Please select a database first.");
      return;
    }

    const editor = editorRef.current;
    if (!editor) return;

    // Determine what to run
    const selection = editor.getSelection();
    let queriesToRun: string[] = [];

    if (selection.text && selection.text.trim().length > 0) {
      // Run selected only
      queriesToRun = [selection.text];
    } else {
      // Run all, split by semi-colon
      queriesToRun = activeTab.content
        .split(';')
        .map(q => q.trim())
        .filter(q => q.length > 0);
    }

    if (queriesToRun.length === 0) return;

    // Set Loading State
    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: true } : t));

    // Create a new execution session ID (mocking cancellation token)
    const executionId = Date.now().toString();

    // Store current execution ID on tab (could be refined for race conditions)
    // For this mock, we just use the active tab state

    try {
      const results: QueryResult[] = [];

      // Execute sequentially
      for (const query of queriesToRun) {
        // Check if still executing (cancellation check)
        const currentTab = tabs.find(t => t.id === activeTabId); 
        // Note: checking state inside async loop in React needs refs usually, 
        // but we'll rely on the service to throw if cancelled or just stop logic

        const result = await muulService.executeQuery(selectedDbId, query, executionId);
        results.push(result);

        // Simulating "stop on error" usually, but let's run all for now unless critical
        if (result.error) break; 
      }

      setTabs(prev => prev.map(t => {
        if (t.id === activeTabId) {
            // Append new results to history, or replace? 
            // Usually "Last run" replaces view, but we keep history.
            // Let's replace for simplicity of "output window".
            return {
                ...t,
                isExecuting: false,
                results: [results[results.length - 1], ...t.results], // Add latest to top
                activeResultIndex: 0
            };
        }
        return t;
      }));

    } catch (e) {
      // Handle crash
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
    }
  };

  const handleCancelQuery = () => {
    // In a real app we'd map the execution ID to the service
    // Here we just toggle state and mock service call
    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
    // Pass a generic cancel for now as we didn't store the exact ID in state for this simple demo
    // In robust app, executionId is state.
  };

  const handleDownload = () => {
    if (!activeResult) return;
    const csvContent = [
      activeResult.columns.join(','),
      ...activeResult.rows.map(row => row.map(cell => 
        cell === null ? '' : typeof cell === 'string' ? `"${cell.replace(/"/g, '""')}"` : cell
      ).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `query_result_${Date.now()}.csv`;
    a.click();
  };

  const handleSaveQuery = () => {
      // Mock save functionality
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isDirty: false } : t));
      alert(`Saved "${activeTab.title}" to local storage (Mock)`);
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-950 text-slate-200">

      {/* Header / Toolbar */}
      <header className="h-14 border-b border-slate-800 bg-slate-900 flex items-center px-4 justify-between shrink-0">
        <div className="flex items-center space-x-4">
          <div className="flex items-center text-blue-400 font-bold text-lg tracking-tight">
            <DbIcon className="mr-2" /> Muul<span className="text-slate-100">SQL</span>
          </div>

          <div className="h-6 w-px bg-slate-700 mx-2"></div>

          {/* Database Selector */}
          <div className="relative group">
            <select 
              value={selectedDbId}
              onChange={(e) => setSelectedDbId(e.target.value)}
              className="appearance-none bg-slate-800 hover:bg-slate-700 border border-slate-700 text-sm rounded py-1.5 pl-3 pr-8 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors w-64 cursor-pointer"
            >
              {databases.map(db => (
                <option key={db.id} value={db.id}>
                   {db.type.toUpperCase()} • {db.name}
                </option>
              ))}
            </select>
            <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
              <Activity size={12} />
            </div>
          </div>
        </div>

        <div className="flex items-center space-x-2">
            {activeTab.isExecuting ? (
                 <button 
                 onClick={handleCancelQuery}
                 className="flex items-center px-4 py-1.5 bg-red-600 hover:bg-red-700 text-white text-sm font-medium rounded shadow-lg transition-all animate-pulse"
               >
                 <Ban size={16} className="mr-2" /> Cancel
               </button>
            ) : (
                <button 
                onClick={handleRunQuery}
                className="flex items-center px-4 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium rounded shadow-lg hover:shadow-blue-500/20 transition-all active:scale-95"
                title="Run selected query or all queries (Cmd+Enter)"
              >
                <Play size={16} className="mr-2 fill-current" /> Run
              </button>
            )}

          <div className="h-6 w-px bg-slate-700 mx-2"></div>

          <button onClick={handleSaveQuery} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded transition-colors" title="Save Query">
            <Save size={18} />
          </button>
          <button onClick={handleDownload} disabled={!activeResult} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded transition-colors disabled:opacity-30" title="Download CSV">
            <Download size={18} />
          </button>
        </div>
      </header>

      {/* Tabs Row */}
      <div className="flex items-center bg-slate-900 border-b border-slate-800 px-2 pt-2 overflow-x-auto no-scrollbar">
        {tabs.map(tab => (
          <div 
            key={tab.id}
            onClick={() => setActiveTabId(tab.id)}
            className={`group flex items-center min-w-[150px] max-w-[250px] px-3 py-2 text-xs border-t border-r border-l rounded-t-md cursor-pointer select-none transition-colors ${
              activeTabId === tab.id 
                ? 'bg-slate-850 border-slate-700 text-blue-400 font-medium' 
                : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-800 hover:text-slate-300'
            }`}
          >
            <span className="mr-2 truncate flex-1">
                {tab.title} {tab.isDirty && '*'}
            </span>
            <button 
              onClick={(e) => handleCloseTab(tab.id, e)}
              className={`opacity-0 group-hover:opacity-100 p-0.5 rounded-full hover:bg-slate-700 ${tabs.length === 1 ? 'hidden' : ''}`}
            >
              <X size={12} />
            </button>
          </div>
        ))}
        <button 
          onClick={handleCreateTab}
          className="ml-2 p-1 text-slate-500 hover:text-blue-400 transition-colors"
        >
          <Plus size={16} />
        </button>
      </div>

      {/* Main Content Area - Split View */}
      <div className="flex-1 flex flex-col md:flex-row overflow-hidden bg-slate-950">

        {/* Editor Pane */}
        <div className="flex-1 flex flex-col min-h-[300px] border-b md:border-b-0 md:border-r border-slate-800">
           <SqlEditor 
             ref={editorRef}
             value={activeTab.content} 
             onChange={handleUpdateContent}
             disabled={activeTab.isExecuting}
           />
           {activeTab.isExecuting && (
               <div className="bg-slate-800/50 text-xs text-blue-300 px-4 py-1 border-t border-slate-800 flex items-center">
                   <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse mr-2"></div>
                   Running query...
               </div>
           )}
        </div>

        {/* Results Pane */}
        <div className="flex-1 flex flex-col bg-slate-900 min-h-[300px]">
            {/* Result Toolbar */}
            <div className="h-10 border-b border-slate-800 flex items-center justify-between px-4 bg-slate-850">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Output</span>
                <div className="flex space-x-1 bg-slate-800 p-0.5 rounded">
                    <button 
                        onClick={() => setViewMode('table')}
                        className={`px-3 py-1 text-xs rounded flex items-center ${viewMode === 'table' ? 'bg-slate-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
                    >
                        <TableIcon size={12} className="mr-1.5" /> Table
                    </button>
                    <button 
                        onClick={() => setViewMode('chart')}
                        className={`px-3 py-1 text-xs rounded flex items-center ${viewMode === 'chart' ? 'bg-slate-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
                    >
                        <LayoutTemplate size={12} className="mr-1.5" /> Chart
                    </button>
                </div>
            </div>

            <div className="flex-1 overflow-hidden relative">
                {!activeResult ? (
                    <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 opacity-50">
                        <Play size={48} className="mb-4 stroke-1" />
                        <p>Run a query to see results</p>
                    </div>
                ) : (
                    <>
                        {viewMode === 'table' ? (
                            <DataTable result={activeResult} />
                        ) : (
                            <DataVisualizer result={activeResult} />
                        )}
                    </>
                )}
            </div>
        </div>
      </div>

      {/* Footer Status Bar */}
      <footer className="h-6 bg-slate-900 border-t border-slate-800 flex items-center px-4 text-[10px] text-slate-500 justify-between shrink-0">
         <div className="flex items-center space-x-4">
            <span>Ready</span>
            <span>{selectedDbId ? `Connected: ${databases.find(d => d.id === selectedDbId)?.name}` : 'No Database Selected'}</span>
         </div>
         <div>
            Muul MessageHandler v1.0.0
         </div>
      </footer>
    </div>
  );
};

export default App;

