import React, { forwardRef, useImperativeHandle, useRef, useState, useEffect } from 'react';
import { format } from 'sql-formatter';
import { Wand2, AlignLeft, Scissors, Copy } from 'lucide-react';

interface SqlEditorProps {
  value: string;
  onChange: (value: string) => void;
  disabled?: boolean;
  dbType?: string; // e.g. 'postgres', 'mysql', 'sqlite'
}

export interface SqlEditorRef {
  getSelection: () => { start: number; end: number; text: string };
  focus: () => void;
}

const SqlEditor = forwardRef<SqlEditorRef, SqlEditorProps>(({ value, onChange, disabled, dbType = 'sql' }, ref) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [contextMenu, setContextMenu] = useState<{ x: number; y: number; visible: boolean }>({ 
    x: 0, y: 0, visible: false 
  });

  useImperativeHandle(ref, () => ({
    getSelection: () => {
      const el = textareaRef.current;
      if (!el) return { start: 0, end: 0, text: '' };
      const start = el.selectionStart;
      const end = el.selectionEnd;
      const text = el.value.substring(start, end);
      return { start, end, text };
    },
    focus: () => {
      textareaRef.current?.focus();
    }
  }));

  // Close context menu on click outside
  useEffect(() => {
    const handleClick = () => setContextMenu({ ...contextMenu, visible: false });
    window.addEventListener('click', handleClick);
    return () => window.removeEventListener('click', handleClick);
  }, [contextMenu]);

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    if (disabled) return;

    // Adjust position if close to edge (basic bounds check)
    let x = e.clientX;
    let y = e.clientY;

    setContextMenu({ x, y, visible: true });
  };

  const mapDbTypeToDialect = (type: string) => {
    switch (type) {
      case 'postgres': return 'postgresql';
      case 'mysql': return 'mysql';
      case 'sqlite': return 'sqlite';
      case 'mssql': return 'transactsql';
      case 'parquet': return 'spark'; // Common dialect for big data
      default: return 'sql';
    }
  };

  const formatQuery = (onlySelection: boolean) => {
    if (!textareaRef.current) return;

    const el = textareaRef.current;
    const start = el.selectionStart;
    const end = el.selectionEnd;
    const fullText = el.value;
    const selectedText = fullText.substring(start, end);

    try {
      const dialect = mapDbTypeToDialect(dbType);

      if (onlySelection && selectedText.trim().length > 0) {
        const formattedSelection = format(selectedText, { language: dialect, tabWidth: 2, keywordCase: 'upper' });
        const newText = fullText.substring(0, start) + formattedSelection + fullText.substring(end);
        onChange(newText);
        // Restore cursor/selection? Ideally select the new formatted block, but simple focus for now.
      } else {
        const formattedDoc = format(fullText, { language: dialect, tabWidth: 2, keywordCase: 'upper' });
        onChange(formattedDoc);
      }
    } catch (e) {
      console.error("Formatting failed", e);
      // Fallback or alert could go here
    }
  };

  const handleCopy = async () => {
     const el = textareaRef.current;
     if(!el) return;
     const text = el.value.substring(el.selectionStart, el.selectionEnd) || el.value;
     await navigator.clipboard.writeText(text);
  };

  return (
    <div 
      ref={containerRef} 
      className="relative w-full h-full font-mono text-sm bg-slate-900 overflow-hidden"
      onContextMenu={handleContextMenu}
    >
      <textarea
        ref={textareaRef}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        disabled={disabled}
        spellCheck={false}
        className={`w-full h-full p-4 bg-transparent text-slate-200 resize-none focus:outline-none focus:ring-0 leading-relaxed ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
        placeholder="-- Write your SQL query here.&#10;-- Right-click to format.&#10;SELECT * FROM users;"
      />

      {/* Visual Line Numbers Gutter */}
      <div className="absolute top-0 left-0 bottom-0 w-0 border-r border-slate-700 bg-slate-800 pointer-events-none hidden md:block" />

      {/* Custom Context Menu */}
      {contextMenu.visible && (
        <div 
          style={{ top: contextMenu.y, left: contextMenu.x }}
          className="fixed z-50 w-48 bg-slate-800 border border-slate-700 rounded-lg shadow-xl overflow-hidden py-1 ring-1 ring-black/50"
        >
          <div className="px-3 py-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-wider border-b border-slate-700/50 mb-1">
             Edit ({dbType})
          </div>
          <button 
            onClick={() => formatQuery(true)}
            className="w-full text-left px-4 py-2 text-xs text-slate-200 hover:bg-slate-700 flex items-center space-x-2"
          >
            <AlignLeft size={14} className="text-blue-400" />
            <span>Format Selection</span>
          </button>
           <button 
            onClick={() => formatQuery(false)}
            className="w-full text-left px-4 py-2 text-xs text-slate-200 hover:bg-slate-700 flex items-center space-x-2"
          >
            <Wand2 size={14} className="text-purple-400" />
            <span>Format Document</span>
          </button>
          <div className="h-px bg-slate-700 my-1" />
           <button 
            onClick={handleCopy}
            className="w-full text-left px-4 py-2 text-xs text-slate-200 hover:bg-slate-700 flex items-center space-x-2"
          >
            <Copy size={14} className="text-slate-400" />
            <span>Copy</span>
          </button>
        </div>
      )}
    </div>
  );
});

SqlEditor.displayName = 'SqlEditor';

