const SqlEditor = forwardRef<SqlEditorRef, SqlEditorProps>(({ value, onChange, disabled, dbType = 'sql' }, ref) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const preRef = useRef<HTMLPreElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [contextMenu, setContextMenu] = useState<{ x: number; y: number; visible: boolean }>({ 
    x: 0, y: 0, visible: false 
  });

  useImperativeHandle(ref, () => ({
    getSelection: () => {
      const el = textareaRef.current;
      if (!el) return { start: 0, end: 0, text: '' };
      const start = el.selectionStart;
      const end = el.selectionEnd;
      const text = el.value.substring(start, end);
      return { start, end, text };
    },
    focus: () => {
      textareaRef.current?.focus();
    }
  }));

  // Sync scroll from textarea to pre
  const handleScroll = () => {
    if (textareaRef.current && preRef.current) {
      preRef.current.scrollTop = textareaRef.current.scrollTop;
      preRef.current.scrollLeft = textareaRef.current.scrollLeft;
    }
  };

  // Close context menu on click outside
  useEffect(() => {
    const handleClick = () => setContextMenu({ ...contextMenu, visible: false });
    window.addEventListener('click', handleClick);
    return () => window.removeEventListener('click', handleClick);
  }, [contextMenu]);

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    if (disabled) return;
    setContextMenu({ x: e.clientX, y: e.clientY, visible: true });
  };

  const mapDbTypeToDialect = (type: string) => {
    switch (type) {
      case 'postgres': return 'postgresql';
      case 'mysql': return 'mysql';
      case 'sqlite': return 'sqlite';
      case 'mssql': return 'transactsql';
      case 'parquet': return 'spark';
      default: return 'sql';
    }
  };

  const formatQuery = (onlySelection: boolean) => {
    if (!textareaRef.current) return;
    const el = textareaRef.current;
    const start = el.selectionStart;
    const end = el.selectionEnd;
    const fullText = el.value;
    const selectedText = fullText.substring(start, end);

    try {
      const dialect = mapDbTypeToDialect(dbType);
      if (onlySelection && selectedText.trim().length > 0) {
        const formattedSelection = format(selectedText, { language: dialect, tabWidth: 2, keywordCase: 'upper' });
        const newText = fullText.substring(0, start) + formattedSelection + fullText.substring(end);
        onChange(newText);
      } else {
        const formattedDoc = format(fullText, { language: dialect, tabWidth: 2, keywordCase: 'upper' });
        onChange(formattedDoc);
      }
    } catch (e) {
      console.error("Formatting failed", e);
    }
  };

  const handleCopy = async () => {
     const el = textareaRef.current;
     if(!el) return;
     const text = el.value.substring(el.selectionStart, el.selectionEnd) || el.value;
     await navigator.clipboard.writeText(text);
  };

  // --- Syntax Highlighting Logic ---
  const highlightedHTML = useMemo(() => {
    if (!value) return '<br/>'; // Ensure line height with empty content

    // Escape HTML first to prevent injection of user code as HTML
    let safeText = value
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;");

    // Regex Definitions
    // Note: Order matters. Comments first, then strings, then keywords.
    const patterns = [
      // Comments: -- ... or /* ... */
      { regex: /(&lt;!--[\s\S]*?--&gt;|--.*$|\/\*[\s\S]*?\*\/)/gm, className: 'text-slate-500 italic' },
      // Strings: '...' or "..."
      { regex: /('([^']|'')*'|"[^"]*")/g, className: 'text-green-400' },
      // Numbers
      { regex: /\b\d+(\.\d+)?\b/g, className: 'text-orange-300' },
      // Keywords (Case insensitive matching, but rendered as they are)
      { 
        regex: /\b(SELECT|FROM|WHERE|INSERT|UPDATE|DELETE|JOIN|LEFT|RIGHT|INNER|OUTER|ON|GROUP|BY|ORDER|LIMIT|OFFSET|AND|OR|NOT|IN|IS|NULL|AS|CASE|WHEN|THEN|ELSE|END|CREATE|TABLE|DROP|ALTER|VIEW|INDEX|VALUES|SET|DISTINCT|HAVING|UNION|ALL|EXISTS|LIKE|BETWEEN|CAST|CONVERT)\b/gim, 
        className: 'text-blue-400 font-bold' 
      },
      // Functions
      {
         regex: /\b(COUNT|SUM|AVG|MIN|MAX|COALESCE|DATE|NOW|GETDATE|ROUND|UPPER|LOWER|SUBSTRING|TRIM)\b/gim,
         className: 'text-purple-400'
      }
    ];

    // We use a tokenization approach to avoid replacing inside already replaced tags.
    // However, for simplicity and performance in this constraint, we will split by tokens.
    // But simplest robust way without a heavy parser is to replace unique placeholders, then restore.
    // Or, cleaner: We construct a combined regex. 
    // Given the complexity of overlapping regex in raw string replacement, a simple tokenizer loop is safer.

    // Simplified Tokenizer for React rendering
    // We will just replace matches with HTML spans. 
    // To avoid replacing content inside <span> tags we just created, we need to be careful.
    // The safest "Single Pass" regex strategy:

    const combinedRegex = /(&lt;!--[\s\S]*?--&gt;|--.*$|\/\*[\s\S]*?\*\/)|('([^']|'')*'|"[^"]*")|(\b\d+(?:\.\d+)?\b)|(\b(?:SELECT|FROM|WHERE|INSERT|UPDATE|DELETE|JOIN|LEFT|RIGHT|INNER|OUTER|ON|GROUP|BY|ORDER|LIMIT|OFFSET|AND|OR|NOT|IN|IS|NULL|AS|CASE|WHEN|THEN|ELSE|END|CREATE|TABLE|DROP|ALTER|VIEW|INDEX|VALUES|SET|DISTINCT|HAVING|UNION|ALL|EXISTS|LIKE|BETWEEN|CAST|CONVERT)\b)|(\b(?:COUNT|SUM|AVG|MIN|MAX|COALESCE|DATE|NOW|GETDATE|ROUND|UPPER|LOWER|SUBSTRING|TRIM)\b)/gim;

    return safeText.replace(combinedRegex, (match, comment, string, number, keyword, func) => {
        if (comment) return `<span class="text-slate-500 italic">${comment}</span>`;
        if (string) return `<span class="text-green-400">${string}</span>`;
        if (number) return `<span class="text-orange-300">${number}</span>`;
        if (keyword) return `<span class="text-blue-400 font-bold">${match}</span>`; // use match to preserve case
        if (func) return `<span class="text-purple-400">${match}</span>`;
        return match;
    }) + '<br/>'; // Trailing break for scrolling
  }, [value]);

  return (
    <div 
      ref={containerRef} 
      className="relative w-full h-full font-mono text-sm bg-slate-900 overflow-hidden group"
      onContextMenu={handleContextMenu}
    >
      {/* Overlay Layer (Syntax Highlighting) */}
      <pre
        ref={preRef}
        className="absolute inset-0 p-4 m-0 pointer-events-none whitespace-pre-wrap break-all overflow-hidden z-0 bg-slate-900"
        aria-hidden="true"
        dangerouslySetInnerHTML={{ __html: highlightedHTML }}
      />

      {/* Input Layer (Textarea) */}
      <textarea
        ref={textareaRef}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onScroll={handleScroll}
        disabled={disabled}
        spellCheck={false}
        autoCapitalize="off"
        autoComplete="off"
        className={`relative z-10 w-full h-full p-4 bg-transparent text-transparent caret-white resize-none focus:outline-none focus:ring-0 leading-relaxed whitespace-pre-wrap break-all overflow-auto ${disabled ? 'opacity-50 cursor-not-allowed' : ''} selection:bg-blue-500/30 selection:text-transparent`}
        placeholder="SELECT * FROM users;"
      />

      {/* Line Gutter (Visual) */}
      <div className="absolute top-0 left-0 bottom-0 w-1 border-r border-slate-700/50 bg-slate-800/20 pointer-events-none z-20" />

      {/* Context Menu */}
      {contextMenu.visible && (
        <div 
          style={{ top: contextMenu.y, left: contextMenu.x }}
          className="fixed z-50 w-48 bg-slate-800 border border-slate-700 rounded-lg shadow-xl overflow-hidden py-1 ring-1 ring-black/50"
        >
          <div className="px-3 py-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-wider border-b border-slate-700/50 mb-1">
             Edit ({dbType})
          </div>
          <button onClick={() => formatQuery(true)} className="w-full text-left px-4 py-2 text-xs text-slate-200 hover:bg-slate-700 flex items-center space-x-2">
            <AlignLeft size={14} className="text-blue-400" /> <span>Format Selection</span>
          </button>
           <button onClick={() => formatQuery(false)} className="w-full text-left px-4 py-2 text-xs text-slate-200 hover:bg-slate-700 flex items-center space-x-2">
            <Wand2 size={14} className="text-purple-400" /> <span>Format Document</span>
          </button>
          <div className="h-px bg-slate-700 my-1" />
           <button onClick={handleCopy} className="w-full text-left px-4 py-2 text-xs text-slate-200 hover:bg-slate-700 flex items-center space-x-2">
            <Copy size={14} className="text-slate-400" /> <span>Copy</span>
          </button>
        </div>
      )}
    </div>
  );
});

SqlEditor.displayName = 'SqlEditor';

export default SqlEditor;

import React, { useState, useEffect, useRef } from 'react';
import { Database, EditorTab, QueryResult } from './types';
import { muulService } from './services/muulService';
import { 
  Play, Plus, X, Save, Download, Database as DbIcon, 
  Activity, Ban, ChevronDown, ChevronUp 
} from 'lucide-react';
import SqlEditor, { SqlEditorRef } from './components/SqlEditor';
import ResultsPane from './components/ResultsPane';

type LayoutMode = 'bottom' | 'right' | 'left' | 'float';

const App: React.FC = () => {
  // --- State ---
  const [databases, setDatabases] = useState<Database[]>([]);
  const [selectedDbId, setSelectedDbId] = useState<string>('');

  const [tabs, setTabs] = useState<EditorTab[]>([
    { 
      id: 'tab-1', 
      title: 'Query 1', 
      content: '', 
      isDirty: false, 
      isExecuting: false, 
      results: [],
      activeResultIndex: -1 
    }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab-1');
  const [viewMode, setViewMode] = useState<'table' | 'chart'>('table');
  const [isEditorExpanded, setIsEditorExpanded] = useState(true);

  // Layout State
  const [layout, setLayout] = useState<LayoutMode>('bottom');
  const [panelSize, setPanelSize] = useState(40); // Percentage for docked mode
  const [floatRect, setFloatRect] = useState({ x: 100, y: 100, w: 600, h: 400 });

  // --- Refs ---
  const editorRef = useRef<SqlEditorRef>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const dragInfo = useRef<{ 
    isDragging: boolean; 
    type: 'resize-dock' | 'move-float' | 'resize-float'; 
    startX: number; 
    startY: number; 
    startSize?: number;
    startRect?: typeof floatRect;
  }>({ isDragging: false, type: 'resize-dock', startX: 0, startY: 0 });

  // --- Effects ---
  useEffect(() => {
    muulService.getDatabases().then(dbs => {
      setDatabases(dbs);
      if (dbs.length > 0) setSelectedDbId(dbs[0].id);
    });
  }, []);

  // Global mouse event handlers for dragging/resizing
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragInfo.current.isDragging) return;

      const { type, startX, startY, startSize, startRect } = dragInfo.current;
      const container = containerRef.current;

      if (type === 'resize-dock' && container && startSize !== undefined) {
        const rect = container.getBoundingClientRect();
        let delta = 0;
        let newSize = startSize;

        if (layout === 'bottom') {
           // Delta Y affects height. Moving UP increases height (since panel is at bottom)
           delta = (startY - e.clientY) / rect.height * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'right') {
           // Delta X affects width. Moving LEFT increases width
           delta = (startX - e.clientX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'left') {
           // Delta X affects width. Moving RIGHT increases width
           delta = (e.clientX - startX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        }
        setPanelSize(newSize);
      } 
      else if (type === 'move-float' && startRect) {
        setFloatRect({
          ...startRect,
          x: startRect.x + (e.clientX - startX),
          y: startRect.y + (e.clientY - startY)
        });
      }
      else if (type === 'resize-float' && startRect) {
        setFloatRect({
          ...startRect,
          w: Math.max(300, startRect.w + (e.clientX - startX)),
          h: Math.max(200, startRect.h + (e.clientY - startY))
        });
      }
    };

    const handleMouseUp = () => {
      dragInfo.current.isDragging = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [layout]);

  // --- Helpers ---
  const activeTab = tabs.find(t => t.id === activeTabId)!;
  const activeResult = activeTab?.activeResultIndex >= 0 
    ? activeTab.results[activeTab.activeResultIndex] 
    : null;
  const selectedDb = databases.find(d => d.id === selectedDbId);

  // --- Actions ---

  const handleCreateTab = () => {
    const newId = `tab-${Date.now()}`;
    setTabs([...tabs, {
      id: newId, title: `Query ${tabs.length + 1}`, content: '', isDirty: false, isExecuting: false, results: [], activeResultIndex: -1
    }]);
    setActiveTabId(newId);
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (tabs.length === 1) return;
    const newTabs = tabs.filter(t => t.id !== id);
    setTabs(newTabs);
    if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
  };

  const handleRunQuery = async () => {
    if (!selectedDbId) return alert("Please select a database first.");
    const editor = editorRef.current;
    if (!editor) return;

    const selection = editor.getSelection();
    let queriesToRun = selection.text.trim().length > 0 
        ? [selection.text] 
        : activeTab.content.split(';').map(q => q.trim()).filter(q => q.length > 0);

    if (queriesToRun.length === 0) return;

    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: true } : t));
    const executionId = Date.now().toString();

    try {
      const results: QueryResult[] = [];
      for (const query of queriesToRun) {
        const result = await muulService.executeQuery(selectedDbId, query, executionId);
        results.push(result);
        if (result.error) break; 
      }
      setTabs(prev => prev.map(t => t.id === activeTabId ? {
        ...t, isExecuting: false, results: [results[results.length - 1], ...t.results], activeResultIndex: 0
      } : t));
    } catch (e) {
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
    }
  };

  const handleCancelQuery = () => {
    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
  };

  // --- Drag Starters ---
  const startDockResize = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { 
        isDragging: true, 
        type: 'resize-dock', 
        startX: e.clientX, 
        startY: e.clientY, 
        startSize: panelSize 
    };
    document.body.style.cursor = layout === 'bottom' ? 'row-resize' : 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const startFloatMove = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { isDragging: true, type: 'move-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  const startFloatResize = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragInfo.current = { isDragging: true, type: 'resize-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-950 text-slate-200">

      {/* Header */}
      <header className="h-14 border-b border-slate-800 bg-slate-900 flex items-center px-4 justify-between shrink-0 z-30 relative">
        <div className="flex items-center space-x-4">
          <div className="flex items-center text-blue-400 font-bold text-lg tracking-tight">
            <DbIcon className="mr-2" /> Muul<span className="text-slate-100">SQL</span>
          </div>
          <div className="h-6 w-px bg-slate-700 mx-2"></div>
          <div className="relative group">
            <select 
              value={selectedDbId}
              onChange={(e) => setSelectedDbId(e.target.value)}
              className="appearance-none bg-slate-800 hover:bg-slate-700 border border-slate-700 text-sm rounded py-1.5 pl-3 pr-8 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors w-64 cursor-pointer"
            >
              {databases.map(db => (
                <option key={db.id} value={db.id}>{db.type.toUpperCase()} • {db.name}</option>
              ))}
            </select>
            <Activity size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400" />
          </div>
        </div>

        <div className="flex items-center space-x-2">
            {activeTab.isExecuting ? (
                 <button onClick={handleCancelQuery} className="flex items-center px-4 py-1.5 bg-red-600 hover:bg-red-700 text-white text-sm font-medium rounded shadow animate-pulse">
                   <Ban size={16} className="mr-2" /> Cancel
                 </button>
            ) : (
                <button onClick={handleRunQuery} className="flex items-center px-4 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium rounded shadow hover:shadow-blue-500/20 active:scale-95">
                  <Play size={16} className="mr-2 fill-current" /> Run
                </button>
            )}
            <div className="h-6 w-px bg-slate-700 mx-2"></div>
            <button onClick={() => alert("Mock Save")} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded"><Save size={18} /></button>
            <button className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded disabled:opacity-30" disabled={!activeResult}><Download size={18} /></button>
        </div>
      </header>

      {/* Tabs Container */}
      <div className="flex items-center bg-slate-900 border-b border-slate-800 pr-2 pt-2 shrink-0">
         {/* Scrollable List */}
         <div className="flex-1 flex overflow-x-auto no-scrollbar items-end px-2">
            {tabs.map(tab => (
              <div key={tab.id} onClick={() => setActiveTabId(tab.id)} className={`group flex items-center min-w-[150px] max-w-[250px] px-3 py-2 text-xs border-t border-r border-l rounded-t-md cursor-pointer select-none whitespace-nowrap ${activeTabId === tab.id ? 'bg-slate-850 border-slate-700 text-blue-400 font-medium' : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-800'}`}>
                <span className="mr-2 truncate flex-1">{tab.title} {tab.isDirty && '*'}</span>
                <button onClick={(e) => handleCloseTab(tab.id, e)} className={`opacity-0 group-hover:opacity-100 p-0.5 rounded-full hover:bg-slate-700 ${tabs.length === 1 ? 'hidden' : ''}`}><X size={12} /></button>
              </div>
            ))}
         </div>
         {/* Fixed Controls on the right */}
         <div className="flex items-center border-l border-slate-800 pl-2 pb-1 space-x-1">
             <button 
                onClick={() => setIsEditorExpanded(!isEditorExpanded)} 
                className={`p-1.5 hover:bg-slate-800 rounded transition-colors ${!isEditorExpanded ? 'text-blue-400' : 'text-slate-500'}`} 
                title={isEditorExpanded ? "Collapse Editor" : "Expand Editor"}
             >
                 {isEditorExpanded ? <ChevronDown size={16} /> : <ChevronUp size={16} />}
             </button>
             <button onClick={handleCreateTab} className="p-1.5 text-slate-500 hover:text-blue-400 hover:bg-slate-800 rounded transition-colors" title="New Tab"><Plus size={16} /></button>
         </div>
      </div>

      {/* Workspace Container */}
      <div 
        ref={containerRef}
        className={`flex-1 flex overflow-hidden bg-slate-950 relative ${
            layout === 'bottom' ? 'flex-col' : 
            layout === 'left' ? 'flex-row-reverse' : 
            'flex-row'
        }`}
      >

        {/* SQL Editor Area */}
        <div 
            style={layout === 'bottom' ? {} : { display: isEditorExpanded ? 'flex' : 'none' }}
            className={`
                ${layout === 'float' ? 'w-full h-full' : 'flex-1'} 
                flex flex-col min-h-0 min-w-0 z-0 transition-all duration-300
                ${layout === 'bottom' && !isEditorExpanded ? '!flex-none !h-0 overflow-hidden' : ''}
            `}
        >
           <SqlEditor 
             ref={editorRef}
             value={activeTab.content} 
             onChange={c => setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: c, isDirty: true } : t))}
             disabled={activeTab.isExecuting}
             dbType={selectedDb?.type}
           />
           {activeTab.isExecuting && (
               <div className="bg-slate-800/50 text-xs text-blue-300 px-4 py-1 border-t border-slate-800 flex items-center shrink-0">
                   <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse mr-2"></div>
                   Running query...
               </div>
           )}
        </div>

        {/* Resizer Handle (Docked Mode) */}
        {layout !== 'float' && isEditorExpanded && (
            <div 
                onMouseDown={startDockResize}
                className={`
                    ${layout === 'bottom' ? 'h-1.5 w-full cursor-row-resize' : 'w-1.5 h-full cursor-col-resize'} 
                    bg-slate-950 hover:bg-blue-600 transition-colors z-20 flex-shrink-0 border-slate-800
                    ${layout === 'bottom' ? 'border-t border-b' : 'border-l border-r'}
                `} 
            />
        )}

        {/* Results Pane (Docked Mode) */}
        {layout !== 'float' && (
            <div 
                style={layout === 'bottom' 
                    ? { height: isEditorExpanded ? `${panelSize}%` : '100%' } 
                    : { width: `${panelSize}%` }
                } 
                className="flex flex-col min-h-0 min-w-0 z-10 transition-all duration-300"
            >
                <ResultsPane 
                    result={activeResult} 
                    viewMode={viewMode} 
                    setViewMode={setViewMode}
                    layout={layout}
                    setLayout={setLayout}
                />
            </div>
        )}

        {/* Floating Window Mode */}
        {layout === 'float' && (
            <div 
                style={{ top: floatRect.y, left: floatRect.x, width: floatRect.w, height: floatRect.h }}
                className="absolute z-50 shadow-2xl border border-slate-700 rounded-lg overflow-hidden flex flex-col bg-slate-900 ring-1 ring-black/50"
            >
                <ResultsPane 
                    result={activeResult}
                    viewMode={viewMode}
                    setViewMode={setViewMode}
                    layout={layout}
                    setLayout={setLayout}
                    onHeaderMouseDown={startFloatMove}
                />
                {/* Resize Handle for Floating Window */}
                <div 
                    onMouseDown={startFloatResize}
                    className="absolute bottom-0 right-0 w-5 h-5 cursor-nwse-resize bg-transparent hover:bg-blue-500/20 z-50 rounded-tl-lg"
                />
            </div>
        )}

      </div>

      {/* Footer */}
      <footer className="h-6 bg-slate-900 border-t border-slate-800 flex items-center px-4 text-[10px] text-slate-500 justify-between shrink-0 z-40">
         <div className="flex items-center space-x-4">
            <span>Ready</span>
            <span>{selectedDbId ? `Connected: ${selectedDb?.name}` : 'No Database Selected'}</span>
         </div>
         <div>Muul MessageHandler v1.0.0</div>
      </footer>
    </div>
  );
};

export default App;

export interface Database {
  id: string;
  name: string;
  type: 'postgres' | 'mysql' | 'sqlite' | 'parquet' | 'mssql';
  connectionString?: string; // Optional, internal use
}

export interface QueryResult {
  columns: string[];
  rows: any[][];
  executionTimeMs: number;
  rowCount: number;
  error?: string;
  timestamp: number;
}

export interface EditorTab {
  id: string;
  title: string;
  content: string;
  isDirty: boolean;
  isExecuting: boolean;
  results: QueryResult[]; // History of results for this tab
  activeResultIndex: number; // Which result is currently showing
}

export interface PaginationConfig {
  page: number;
  pageSize: number;
}

// Visualization Configuration to be saved
export type ChartType = 'bar' | 'line' | 'pie';

export interface ChartConfig {
  type: ChartType;
  xAxisKey: string;
  dataKeys: string[];
}

export interface PinnedChart {
  id: string;
  title: string;
  query: string;
  dbId: string;
  config: ChartConfig;
  createdAt: number;
}

// Message types for Muul communication
export type MuulMessageType = 'DB_LIST' | 'DB_EXECUTE' | 'DB_CANCEL';

export interface MuulMessage {
  type: MuulMessageType;
  payload?: any;
  requestId?: string;
}

import React, { useMemo, useState, useEffect } from 'react';
import { QueryResult, ChartConfig, ChartType } from '../types';
import { 
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer 
} from 'recharts';
import { BarChart3, LineChart as LineChartIcon, PieChart as PieChartIcon, Pin, Save } from 'lucide-react';

interface DataVisualizerProps {
  result: QueryResult;
  initialConfig?: ChartConfig;
  onPin?: (config: ChartConfig) => void;
  onSave?: (config: ChartConfig) => void;
  readOnly?: boolean; // For dashboard view (hides controls)
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4'];

const DataVisualizer: React.FC<DataVisualizerProps> = ({ result, initialConfig, onPin, onSave, readOnly = false }) => {
  const [chartType, setChartType] = useState<ChartType>(initialConfig?.type || 'bar');
  const [xAxisKey, setXAxisKey] = useState<string>(initialConfig?.xAxisKey || '');
  const [dataKeys, setDataKeys] = useState<string[]>(initialConfig?.dataKeys || []);

  // Update internal state if initialConfig changes (e.g. switching tabs or loading dashboard)
  useEffect(() => {
    if (initialConfig) {
      setChartType(initialConfig.type);
      setXAxisKey(initialConfig.xAxisKey);
      setDataKeys(initialConfig.dataKeys);
    }
  }, [initialConfig]);

  // Detect potential axes
  const { numericColumns, stringColumns, formattedData } = useMemo(() => {
    if (!result || !result.rows.length) {
      return { numericColumns: [], stringColumns: [], formattedData: [] };
    }

    const cols = result.columns;
    const sampleRow = result.rows[0];

    const numCols: string[] = [];
    const strCols: string[] = [];

    cols.forEach((col, idx) => {
      const val = sampleRow[idx];
      if (typeof val === 'number') numCols.push(col);
      else strCols.push(col);
    });

    // Map rows array to object array for Recharts
    const data = result.rows.map(row => {
      const obj: any = {};
      cols.forEach((col, idx) => {
        obj[col] = row[idx];
      });
      return obj;
    });

    return { numericColumns: numCols, stringColumns: strCols, formattedData: data };
  }, [result]);

  // Set defaults if keys aren't selected and NO initial config was provided
  useEffect(() => {
    if (initialConfig) return; // Don't override saved config

    if (formattedData.length > 0) {
      if (!xAxisKey && stringColumns.length > 0) setXAxisKey(stringColumns[0]);
      else if (!xAxisKey && result.columns.length > 0) setXAxisKey(result.columns[0]);

      if (dataKeys.length === 0 && numericColumns.length > 0) setDataKeys([numericColumns[0]]);
    }
  }, [formattedData, numericColumns, stringColumns, xAxisKey, dataKeys, result.columns, initialConfig]);

  if (result.error) {
     return <div className="h-full flex items-center justify-center text-red-400 p-4 text-center">{result.error}</div>;
  }

  if (result.rows.length === 0) {
     return <div className="h-full flex items-center justify-center text-slate-500">No data to visualize</div>;
  }

  const handleDataKeyToggle = (key: string) => {
    setDataKeys(prev => 
      prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]
    );
  };

  const currentConfig: ChartConfig = {
    type: chartType,
    xAxisKey,
    dataKeys
  };

  return (
    <div className="h-full flex flex-col bg-slate-900">
      {/* Config Toolbar */}
      {!readOnly && (
        <div className="p-4 border-b border-slate-800 bg-slate-850 flex flex-col md:flex-row gap-4 justify-between items-start md:items-center">

          <div className="flex flex-col md:flex-row gap-4 w-full md:w-auto">
            {/* Chart Type Selector */}
            <div className="flex space-x-1 bg-slate-800 p-1 rounded-lg w-fit">
              <button 
                onClick={() => setChartType('bar')}
                className={`p-2 rounded ${chartType === 'bar' ? 'bg-slate-700 text-blue-400' : 'text-slate-400 hover:text-slate-200'}`}
                title="Bar Chart"
              >
                <BarChart3 size={18} />
              </button>
              <button 
                onClick={() => setChartType('line')}
                className={`p-2 rounded ${chartType === 'line' ? 'bg-slate-700 text-green-400' : 'text-slate-400 hover:text-slate-200'}`}
                title="Line Chart"
              >
                <LineChartIcon size={18} />
              </button>
              <button 
                onClick={() => setChartType('pie')}
                className={`p-2 rounded ${chartType === 'pie' ? 'bg-slate-700 text-purple-400' : 'text-slate-400 hover:text-slate-200'}`}
                title="Pie Chart"
              >
                <PieChartIcon size={18} />
              </button>
            </div>

            {/* Axes Selectors */}
            <div className="flex flex-col space-y-2">
                <div className="flex items-center space-x-2">
                    <label className="text-xs text-slate-500 w-12 font-bold uppercase">X-Axis</label>
                    <select 
                        value={xAxisKey} 
                        onChange={e => setXAxisKey(e.target.value)}
                        className="bg-slate-800 text-xs text-slate-200 border border-slate-700 rounded px-2 py-1 min-w-[120px]"
                    >
                        {result.columns.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                </div>

                {chartType !== 'pie' && (
                    <div className="flex items-start space-x-2">
                    <label className="text-xs text-slate-500 w-12 font-bold uppercase mt-1">Y-Axis</label>
                    <div className="flex flex-wrap gap-2 max-w-[300px]">
                        {numericColumns.length > 0 ? numericColumns.map(col => (
                            <button
                                key={col}
                                onClick={() => handleDataKeyToggle(col)}
                                className={`text-xs px-2 py-1 rounded border transition-colors ${
                                    dataKeys.includes(col) 
                                    ? 'bg-blue-900/30 border-blue-600 text-blue-200' 
                                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'
                                }`}
                            >
                                {col}
                            </button>
                        )) : <span className="text-xs text-slate-600 italic">No numeric columns</span>}
                    </div>
                </div>
                )}
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex items-center space-x-2 border-l border-slate-800 pl-4">
             {onPin && (
               <button 
                 onClick={() => onPin(currentConfig)}
                 className="flex items-center px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs rounded border border-slate-700 transition-all hover:border-blue-500 hover:text-blue-400"
               >
                 <Pin size={14} className="mr-2" /> Pin to Dashboard
               </button>
             )}
             {onSave && (
                <button 
                  onClick={() => onSave(currentConfig)}
                  className="flex items-center px-3 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-xs rounded shadow transition-all"
                >
                  <Save size={14} className="mr-2" /> Save Changes
                </button>
             )}
          </div>
        </div>
      )}

      {/* Chart Render Area */}
      <div className={`flex-1 p-4 overflow-hidden ${readOnly ? 'pointer-events-none' : ''}`}>
        <ResponsiveContainer width="100%" height="100%">
          {chartType === 'bar' ? (
            <BarChart data={formattedData}>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
              <XAxis dataKey={xAxisKey} stroke="#94a3b8" fontSize={12} tickFormatter={(val) => `${val}`.substring(0, 10)} />
              <YAxis stroke="#94a3b8" fontSize={12} />
              <Tooltip 
                contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                itemStyle={{ color: '#e2e8f0' }}
              />
              {!readOnly && <Legend />}
              {dataKeys.map((key, index) => (
                <Bar key={key} dataKey={key} fill={COLORS[index % COLORS.length]} />
              ))}
            </BarChart>
          ) : chartType === 'line' ? (
            <LineChart data={formattedData}>
               <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
              <XAxis dataKey={xAxisKey} stroke="#94a3b8" fontSize={12} tickFormatter={(val) => `${val}`.substring(0, 10)} />
              <YAxis stroke="#94a3b8" fontSize={12} />
              <Tooltip 
                 contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                 itemStyle={{ color: '#e2e8f0' }}
              />
              {!readOnly && <Legend />}
              {dataKeys.map((key, index) => (
                <Line type="monotone" key={key} dataKey={key} stroke={COLORS[index % COLORS.length]} strokeWidth={2} dot={false} />
              ))}
            </LineChart>
          ) : (
            <PieChart>
                <Pie
                    data={formattedData}
                    dataKey={dataKeys[0] || numericColumns[0]}
                    nameKey={xAxisKey}
                    cx="50%"
                    cy="50%"
                    outerRadius={readOnly ? 80 : 120}
                    fill="#8884d8"
                    label={({name, percent}) => readOnly ? null : `${name} ${(percent * 100).toFixed(0)}%`}
                >
                    {formattedData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                </Pie>
                <Tooltip 
                    contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                    itemStyle={{ color: '#e2e8f0' }}
                />
            </PieChart>
          )}
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default DataVisualizer;

