export default App;

import { Database, QueryResult } from '../types';
import initSqlJs from 'sql.js';
import Papa from 'papaparse';

// We store the SQL.js engine instance and our databases here
class MuulService {
  private SQL: any = null;
  private databases: Map<string, any> = new Map(); // Map<id, SQL.Database>
  private dbMetadata: Map<string, Database> = new Map();

  /**
   * Initializes the SQL.js WASM engine.
   */
  async initialize() {
    if (this.SQL) return;
    try {
      this.SQL = await initSqlJs({
        locateFile: (file: string) => `https://sql.js.org/dist/${file}`
      });
      console.log("SQL.js initialized");

      // Create a default in-memory DB for playground
      this.createDatabase('mem-1', 'In-Memory Playground', 'sqlite');

      // Seed playground
      const db = this.databases.get('mem-1');
      db.run("CREATE TABLE demo (id int, name char);");
      db.run("INSERT INTO demo VALUES (1, 'Hello'), (2, 'World');");

    } catch (e) {
      console.error("Failed to init SQL.js", e);
    }
  }

  createDatabase(id: string, name: string, type: any, data?: Uint8Array) {
    if (!this.SQL) return;
    const db = new this.SQL.Database(data); // Empty or from file
    this.databases.set(id, db);
    this.dbMetadata.set(id, { id, name, type });
  }

  async registerFile(file: File): Promise<string> {
    if (!this.SQL) await this.initialize();
    const id = `db-${Date.now()}`;

    return new Promise((resolve, reject) => {
      if (file.name.endsWith('.csv')) {
        // Handle CSV: Parse and Import into a NEW In-Memory DB
        Papa.parse(file, {
          header: true,
          skipEmptyLines: true,
          complete: (results) => {
             const db = new this.SQL.Database();
             const tableName = file.name.replace(/[^a-zA-Z0-9]/g, '_').replace('.csv', '');

             if (results.data.length > 0) {
                const headers = Object.keys(results.data[0] as any);
                // Create Table
                const createSql = `CREATE TABLE ${tableName} (${headers.map(h => `${h} TEXT`).join(', ')});`;
                db.run(createSql);

                // Insert Data (Batching could be improved for huge files)
                // SQL.js doesn't support bulk insert easily with parameterized, so we iterate
                // For speed in this demo, we construct a big INSERT statement
                const insertBase = `INSERT INTO ${tableName} VALUES`;
                const batchSize = 100;
                let values: string[] = [];

                (results.data as any[]).forEach((row, idx) => {
                    const rowVals = headers.map(h => {
                         const val = row[h];
                         return val ? `'${String(val).replace(/'/g, "''")}'` : 'NULL';
                    });
                    values.push(`(${rowVals.join(',')})`);

                    if (values.length >= batchSize) {
                        db.run(`${insertBase} ${values.join(',')};`);
                        values = [];
                    }
                });
                if (values.length > 0) db.run(`${insertBase} ${values.join(',')};`);
             }

             this.databases.set(id, db);
             this.dbMetadata.set(id, { id, name: file.name, type: 'csv-import' });
             resolve(id);
          },
          error: (err) => reject(err)
        });
      } else {
         // Assume SQLite (binary)
         const reader = new FileReader();
         reader.onload = () => {
            const u8 = new Uint8Array(reader.result as ArrayBuffer);
            this.createDatabase(id, file.name, 'sqlite', u8);
            resolve(id);
         };
         reader.onerror = reject;
         reader.readAsArrayBuffer(file);
      }
    });
  }

  async getDatabases(): Promise<Database[]> {
    if (!this.SQL) await this.initialize();
    return Array.from(this.dbMetadata.values());
  }

  async executeQuery(dbId: string, sql: string, queryId: string): Promise<QueryResult> {
    if (!this.SQL) await this.initialize();

    const startTime = performance.now();
    const db = this.databases.get(dbId);

    if (!db) {
      return {
        columns: [], rows: [], rowCount: 0, executionTimeMs: 0, timestamp: Date.now(),
        error: "Database instance not found. It may have been closed."
      };
    }

    try {
      // sql.js .exec returns [{columns, values}]
      // We handle multiple statements but just return the last result for this simple UI
      const res = db.exec(sql);

      if (res.length === 0) {
        // Query OK but no results (e.g. UPDATE/INSERT)
        // We can check rowsModified() if needed
        return {
          columns: [],
          rows: [],
          rowCount: db.getRowsModified(),
          executionTimeMs: Math.round(performance.now() - startTime),
          timestamp: Date.now()
        };
      }

      // Return the last result set
      const last = res[res.length - 1];

      return {
        columns: last.columns,
        rows: last.values,
        rowCount: last.values.length,
        executionTimeMs: Math.round(performance.now() - startTime),
        timestamp: Date.now()
      };

    } catch (e: any) {
      return {
        columns: [],
        rows: [],
        rowCount: 0,
        executionTimeMs: Math.round(performance.now() - startTime),
        timestamp: Date.now(),
        error: e.message
      };
    }
  }
}

export const muulService = new MuulService();

import React, { useEffect, useState, useRef } from 'react';
import { PinnedChart, QueryResult, ChartConfig, Database, DashboardLayout, DashboardRow, DashboardWidget } from '../types';
import { muulService } from '../services/muulService';
import { exportService } from '../services/exportService';
import DataVisualizer from './DataVisualizer';
import MarkdownVisualizer from './MarkdownVisualizer';
import { 
  RefreshCw, Trash2, Edit, AlertCircle, Database as DbIcon, 
  Plus, Layout, Monitor, MoveHorizontal, X, FileText, BarChart3, GripVertical,
  Download, Info
} from 'lucide-react';

interface DashboardProps {
  dashboards: DashboardLayout[];
  pinnedCharts: PinnedChart[];
  databases: Database[];
  activeDashboardId: string;
  refreshRate: number;
  onSetActiveDashboard: (id: string) => void;
  onAddDashboard: (title: string) => void;
  onUpdateDashboard: (layout: DashboardLayout) => void;
  onDeleteDashboard: (id: string) => void;
  onRemoveChartDefinition: (id: string) => void;
  onUpdateChartDefinition: (id: string, newConfig: ChartConfig) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  dashboards, 
  pinnedCharts, 
  databases, 
  activeDashboardId,
  refreshRate,
  onSetActiveDashboard,
  onAddDashboard,
  onUpdateDashboard,
  onDeleteDashboard,
  onRemoveChartDefinition,
  onUpdateChartDefinition
}) => {
  const [results, setResults] = useState<Record<string, QueryResult>>({});
  const [loading, setLoading] = useState<Record<string, boolean>>({});
  const [isDesignerMode, setIsDesignerMode] = useState(false);
  const [draggingItem, setDraggingItem] = useState<{ rowId: string; index: number } | null>(null);
  const [activeQueryInfo, setActiveQueryInfo] = useState<string | null>(null); // To show info popover
  const refreshIntervalRef = useRef<number | null>(null);

  // --- Helpers ---
  const activeDashboard = dashboards.find(d => d.id === activeDashboardId) || dashboards[0];
  const getChartDef = (chartId: string) => pinnedCharts.find(c => c.id === chartId);
  const getDbName = (dbId?: string) => databases.find(d => d.id === dbId)?.name || 'Unknown DB';

  // --- Data Fetching ---
  const refreshChart = async (chartId: string) => {
    const chart = getChartDef(chartId);
    if (!chart) return;

    setLoading(prev => ({ ...prev, [chartId]: true }));
    try {
      const result = await muulService.executeQuery(chart.dbId, chart.query, `dash-${chart.id}-${Date.now()}`);
      setResults(prev => ({ ...prev, [chartId]: result }));
    } catch (error) {
       console.error("Dashboard execution error", error);
    } finally {
      setLoading(prev => ({ ...prev, [chartId]: false }));
    }
  };

  const handleRefreshAll = () => {
     if (!activeDashboard) return;
     activeDashboard.rows.forEach(row => {
         row.widgets.forEach(w => {
             if (w.type === 'chart') refreshChart(w.content);
         });
     });
  };

  // --- Effects ---
  useEffect(() => {
    if (!activeDashboard) return;
    const chartIds = new Set<string>();
    activeDashboard.rows.forEach(row => {
      row.widgets.forEach(w => {
        if (w.type === 'chart') chartIds.add(w.content);
      });
    });
    chartIds.forEach(id => {
      if (!results[id]) refreshChart(id);
    });
  }, [activeDashboard, pinnedCharts]);

  useEffect(() => {
    if (refreshIntervalRef.current) {
        clearInterval(refreshIntervalRef.current);
        refreshIntervalRef.current = null;
    }
    if (refreshRate > 0) {
        refreshIntervalRef.current = window.setInterval(handleRefreshAll, refreshRate * 1000);
    }
    return () => {
        if (refreshIntervalRef.current) clearInterval(refreshIntervalRef.current);
    }
  }, [refreshRate, activeDashboard]);

  // --- Export ---
  const handleExportPPT = () => {
      if (!activeDashboard) return;
      exportService.exportDashboardToPPT(activeDashboard, pinnedCharts, results);
  };

  // --- Designer Actions ---
  const handleAddRow = () => {
    onUpdateDashboard({
        ...activeDashboard,
        rows: [...activeDashboard.rows, { id: `row-${Date.now()}`, widgets: [] }]
    });
  };

  const handleDeleteRow = (rowId: string) => {
      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.filter(r => r.id !== rowId)
      });
  };

  const handleAddWidget = (rowId: string, type: 'chart' | 'markdown') => {
      let content = '';
      let title = 'New Widget';

      if (type === 'markdown') {
          content = '### New Markdown\nEdit this content...';
          title = 'Text Block';
      } else {
          if (pinnedCharts.length === 0) {
              alert("No pinned charts available to add. Go to SQL Editor to pin queries.");
              return;
          }
          const firstChart = pinnedCharts[0];
          content = firstChart.id;
          title = firstChart.title;
      }

      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.map(r => 
            r.id === rowId ? { ...r, widgets: [...r.widgets, { id: `widget-${Date.now()}`, type, colSpan: 12, content, title }] } : r
          )
      });
  };

  const handleRemoveWidget = (rowId: string, widgetId: string) => {
      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.map(r => 
            r.id === rowId ? { ...r, widgets: r.widgets.filter(w => w.id !== widgetId) } : r
          )
      });
  };

  const handleChangeWidgetWidth = (rowId: string, widgetId: string, delta: number) => {
    onUpdateDashboard({
        ...activeDashboard,
        rows: activeDashboard.rows.map(r => {
            if (r.id !== rowId) return r;
            return {
                ...r,
                widgets: r.widgets.map(w => {
                    if (w.id !== widgetId) return w;
                    return { ...w, colSpan: Math.max(1, Math.min(12, w.colSpan + delta)) };
                })
            };
        })
    });
  };

  const handleMarkdownChange = (rowId: string, widgetId: string, newContent: string) => {
      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.map(r => {
              if (r.id !== rowId) return r;
              return {
                  ...r,
                  widgets: r.widgets.map(w => w.id === widgetId ? { ...w, content: newContent } : w)
              };
          })
      });
  };

  // --- Drag & Drop ---
  const handleDragStart = (e: React.DragEvent, rowId: string, index: number) => {
      setDraggingItem({ rowId, index });
      e.dataTransfer.effectAllowed = 'move';
  };
  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); e.dataTransfer.dropEffect = 'move'; };

  const moveWidget = (sourceRowId: string, sourceIndex: number, targetRowId: string, targetIndex: number) => {
      const newRows = activeDashboard.rows.map(r => ({ ...r, widgets: [...r.widgets] }));
      const sourceRow = newRows.find(r => r.id === sourceRowId);
      const targetRow = newRows.find(r => r.id === targetRowId);
      if (!sourceRow || !targetRow) return;

      const [widget] = sourceRow.widgets.splice(sourceIndex, 1);
      let finalIndex = targetIndex;
      if (sourceRowId === targetRowId && sourceIndex < targetIndex) finalIndex--;
      targetRow.widgets.splice(finalIndex, 0, widget);

      onUpdateDashboard({ ...activeDashboard, rows: newRows });
  };

  const handleDropOnWidget = (e: React.DragEvent, targetRowId: string, targetIndex: number) => {
      e.preventDefault(); e.stopPropagation();
      if (!draggingItem) return;
      moveWidget(draggingItem.rowId, draggingItem.index, targetRowId, targetIndex);
      setDraggingItem(null);
  };
  const handleDropOnRow = (e: React.DragEvent, targetRowId: string) => {
      e.preventDefault(); e.stopPropagation();
      if (!draggingItem) return;
      const targetRow = activeDashboard.rows.find(r => r.id === targetRowId);
      if (targetRow) moveWidget(draggingItem.rowId, draggingItem.index, targetRowId, targetRow.widgets.length);
      setDraggingItem(null);
  };

  return (
    <div className="flex flex-col h-full w-full bg-slate-950 overflow-hidden relative" onClick={() => setActiveQueryInfo(null)}>

      {/* Dashboard Toolbar */}
      <div className="h-14 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4 shrink-0">
          <div className="flex items-center space-x-1 overflow-x-auto no-scrollbar">
              {dashboards.map(d => (
                  <button
                    key={d.id}
                    onClick={() => onSetActiveDashboard(d.id)}
                    className={`px-4 py-2 text-sm rounded-t-lg border-t border-r border-l border-b-0 transition-colors ${
                        activeDashboardId === d.id 
                        ? 'bg-slate-950 border-slate-700 text-blue-400 font-medium translate-y-[1px]' 
                        : 'bg-transparent border-transparent text-slate-500 hover:text-slate-300 hover:bg-slate-800'
                    }`}
                  >
                      {d.title}
                  </button>
              ))}
              <button 
                onClick={(e) => {
                    e.currentTarget.blur();
                    const name = prompt("Dashboard Name:");
                    if(name) onAddDashboard(name);
                }} 
                className="p-2 ml-2 text-slate-500 hover:text-blue-400 hover:bg-slate-800 rounded"
              >
                  <Plus size={16} />
              </button>
          </div>

          <div className="flex items-center space-x-3">
               <button onClick={handleExportPPT} className="flex items-center px-3 py-1.5 bg-orange-700/50 hover:bg-orange-600 text-orange-200 text-xs rounded border border-orange-600 transition-all">
                <Download size={14} className="mr-2" /> Export PPT
              </button>
              <div className="h-6 w-px bg-slate-800"></div>
              <button onClick={() => setIsDesignerMode(!isDesignerMode)} className={`flex items-center px-3 py-1.5 text-xs rounded border transition-all ${isDesignerMode ? 'bg-blue-900/30 border-blue-500 text-blue-400' : 'bg-slate-800 border-slate-700 text-slate-400'}`}>
                  {isDesignerMode ? <Layout size={14} className="mr-2" /> : <Monitor size={14} className="mr-2" />} {isDesignerMode ? 'Designer' : 'View'}
              </button>
              <div className="h-6 w-px bg-slate-800"></div>
              <button onClick={handleRefreshAll} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded relative">
                <RefreshCw size={16} className={refreshRate > 0 ? "text-green-400" : ""} />
                {refreshRate > 0 && <span className="absolute top-1 right-1 w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>}
              </button>
          </div>
      </div>

      {/* Workspace */}
      <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-950">
          <div className="space-y-6 max-w-7xl mx-auto">
              {activeDashboard.rows.map((row, rowIndex) => (
                  <div key={row.id} className={`relative group/row ${isDesignerMode ? 'p-2 border border-dashed border-slate-700 rounded-xl bg-slate-900/30 min-h-[100px]' : ''}`} onDragOver={isDesignerMode ? handleDragOver : undefined} onDrop={isDesignerMode ? (e) => handleDropOnRow(e, row.id) : undefined}>
                      {isDesignerMode && (
                          <div className="absolute -top-3 left-4 bg-slate-800 text-xs text-slate-400 px-2 py-0.5 rounded border border-slate-700 flex items-center space-x-2 shadow-sm z-10">
                              <span className="font-mono">Row {rowIndex + 1}</span>
                              <div className="h-3 w-px bg-slate-600"></div>
                              <button onClick={() => handleDeleteRow(row.id)} className="hover:text-red-400"><Trash2 size={12} /></button>
                          </div>
                      )}

                      <div className="grid grid-cols-12 gap-6 min-h-[50px]">
                          {row.widgets.length === 0 && isDesignerMode && (
                              <div className="col-span-12 flex items-center justify-center py-8 text-slate-600 border-2 border-dashed border-slate-800 rounded-lg pointer-events-none">Empty Row</div>
                          )}

                          {row.widgets.map((widget, widgetIndex) => {
                              const chartDef = widget.type === 'chart' ? getChartDef(widget.content) : null;

                              return (
                                <div key={widget.id} className={`relative flex flex-col bg-slate-900 border border-slate-800 rounded-lg shadow-sm overflow-hidden min-h-[300px] transition-all ${isDesignerMode ? 'cursor-grab active:cursor-grabbing hover:border-blue-500' : ''} ${draggingItem?.rowId === row.id && draggingItem?.index === widgetIndex ? 'opacity-40 border-dashed border-slate-600' : ''}`} style={{ gridColumn: `span ${widget.colSpan} / span ${widget.colSpan}` }} draggable={isDesignerMode} onDragStart={(e) => isDesignerMode && handleDragStart(e, row.id, widgetIndex)} onDragOver={isDesignerMode ? handleDragOver : undefined} onDrop={isDesignerMode ? (e) => handleDropOnWidget(e, row.id, widgetIndex) : undefined}>

                                    {/* Widget Header */}
                                    <div className="h-9 px-3 flex items-center justify-between bg-slate-850 border-b border-slate-800 shrink-0 select-none relative z-20">
                                        <div className="flex items-center space-x-2 overflow-hidden">
                                            {isDesignerMode && <GripVertical size={14} className="text-slate-600 cursor-grab" />}
                                            {widget.type === 'chart' && (
                                                <div className={`w-2 h-2 rounded-full shrink-0 ${loading[widget.content] ? 'bg-yellow-500 animate-pulse' : results[widget.content]?.error ? 'bg-red-500' : 'bg-green-500'}`} />
                                            )}
                                            <span className="text-xs font-bold text-slate-300 truncate">{widget.title || (chartDef?.title)}</span>

                                            {/* Query Info Icon */}
                                            {widget.type === 'chart' && chartDef && (
                                              <div className="relative group/info">
                                                <button 
                                                  onClick={(e) => { e.stopPropagation(); setActiveQueryInfo(activeQueryInfo === widget.id ? null : widget.id); }}
                                                  className="ml-2 text-slate-600 hover:text-blue-400"
                                                >
                                                  <Info size={12} />
                                                </button>
                                                {/* Popover for Query */}
                                                {activeQueryInfo === widget.id && (
                                                  <div 
                                                    className="absolute top-6 left-0 w-64 md:w-80 bg-slate-800 border border-slate-600 p-3 rounded-lg shadow-2xl z-50 text-xs text-slate-300"
                                                    onClick={(e) => e.stopPropagation()}
                                                  >
                                                    <div className="font-bold mb-1 text-slate-400">Original Query</div>
                                                    <pre className="font-mono bg-slate-900 p-2 rounded border border-slate-700 overflow-x-auto max-h-40 whitespace-pre-wrap">{chartDef.query}</pre>
                                                  </div>
                                                )}
                                              </div>
                                            )}
                                        </div>

                                        {isDesignerMode ? (
                                            <div className="flex items-center space-x-1" onMouseDown={e => e.stopPropagation()}>
                                                <button onClick={() => handleChangeWidgetWidth(row.id, widget.id, -1)} disabled={widget.colSpan <= 1} className="p-1 hover:bg-slate-700 rounded text-slate-500 disabled:opacity-30"><MoveHorizontal size={12} className="rotate-180" /></button>
                                                <span className="text-[10px] font-mono text-slate-500 w-4 text-center">{widget.colSpan}</span>
                                                <button onClick={() => handleChangeWidgetWidth(row.id, widget.id, 1)} disabled={widget.colSpan >= 12} className="p-1 hover:bg-slate-700 rounded text-slate-500 disabled:opacity-30"><MoveHorizontal size={12} /></button>
                                                <div className="w-px h-3 bg-slate-700 mx-1"></div>
                                                <button onClick={() => handleRemoveWidget(row.id, widget.id)} className="p-1 hover:bg-red-900/50 hover:text-red-400 rounded text-slate-500"><X size={12} /></button>
                                            </div>
                                        ) : (
                                          widget.type === 'chart' && <button onClick={() => refreshChart(widget.content)} className="p-1 text-slate-500 hover:text-blue-400 rounded hover:bg-slate-800"><RefreshCw size={12} /></button>
                                        )}
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1 relative overflow-hidden" onMouseDown={e => isDesignerMode && e.stopPropagation()}>
                                        {widget.type === 'markdown' ? (
                                            <MarkdownVisualizer content={widget.content} onChange={(val) => handleMarkdownChange(row.id, widget.id, val)} isDesignerMode={isDesignerMode} />
                                        ) : (
                                            <>
                                                {loading[widget.content] && !results[widget.content] ? (
                                                    <div className="absolute inset-0 flex items-center justify-center text-slate-600"><RefreshCw className="animate-spin" /></div>
                                                ) : results[widget.content]?.error ? (
                                                     <div className="absolute inset-0 flex flex-col items-center justify-center text-red-400 p-4 text-center"><AlertCircle size={24} className="mb-2 opacity-50" /><span className="text-xs font-mono">{results[widget.content].error}</span></div>
                                                ) : results[widget.content] && chartDef ? (
                                                    <DataVisualizer result={results[widget.content]} initialConfig={chartDef.config} readOnly={true} />
                                                ) : <div className="absolute inset-0 flex items-center justify-center text-slate-600 text-xs">{chartDef ? 'Waiting for data...' : 'Chart definition not found'}</div>}
                                            </>
                                        )}
                                    </div>
                                    {widget.type === 'chart' && chartDef && <div className="h-6 bg-slate-900 border-t border-slate-800 px-3 flex items-center justify-between text-[10px] text-slate-600 font-mono"><span className="truncate">{getDbName(chartDef.dbId)}</span>{results[widget.content] && <span>{results[widget.content].executionTimeMs}ms</span>}</div>}
                                </div>
                              );
                          })}
                      </div>

                      {isDesignerMode && (
                          <div className="mt-2 flex justify-center opacity-0 group-hover/row:opacity-100 transition-opacity">
                              <div className="bg-slate-800 rounded-full border border-slate-700 p-1 flex space-x-1 shadow-lg transform translate-y-1/2">
                                  <button onClick={() => handleAddWidget(row.id, 'chart')} className="px-3 py-1 text-xs rounded-full hover:bg-blue-600 hover:text-white text-slate-300 flex items-center transition-colors"><BarChart3 size={12} className="mr-1" /> Add Chart</button>
                                  <div className="w-px bg-slate-700 my-1"></div>
                                  <button onClick={() => handleAddWidget(row.id, 'markdown')} className="px-3 py-1 text-xs rounded-full hover:bg-purple-600 hover:text-white text-slate-300 flex items-center transition-colors"><FileText size={12} className="mr-1" /> Add Text</button>
                              </div>
                          </div>
                      )}
                  </div>
              ))}
              {isDesignerMode && <button onClick={handleAddRow} className="w-full py-4 border-2 border-dashed border-slate-800 hover:border-slate-600 hover:bg-slate-900 rounded-xl flex items-center justify-center text-slate-500 hover:text-slate-300 transition-all"><Plus size={20} className="mr-2" /> Add Layout Row</button>}
          </div>
      </div>
    </div>
  );
};

