    });
  }

  async getDatabases(): Promise<Database[]> {
    if (!this.SQL) await this.initialize();
    return Array.from(this.dbMetadata.values());
  }

  async executeQuery(dbId: string, sql: string, queryId: string): Promise<QueryResult> {
    if (!this.SQL) await this.initialize();

    const startTime = performance.now();
    const db = this.databases.get(dbId);

    if (!db) {
      return {
        columns: [], rows: [], rowCount: 0, executionTimeMs: 0, timestamp: Date.now(),
        error: "Database instance not found. It may have been closed."
      };
    }

    try {
      // sql.js .exec returns [{columns, values}]
      // We handle multiple statements but just return the last result for this simple UI
      const res = db.exec(sql);

      if (res.length === 0) {
        // Query OK but no results (e.g. UPDATE/INSERT)
        // We can check rowsModified() if needed
        return {
          columns: [],
          rows: [],
          rowCount: db.getRowsModified(),
          executionTimeMs: Math.round(performance.now() - startTime),
