              {col.isPrimaryKey && <Key size={10} className="mr-1.5 text-yellow-400 fill-yellow-400/20" />}
              {col.isForeignKey && <Link size={10} className="mr-1.5 text-blue-400" />}
              <span className={`${col.isPrimaryKey ? 'text-slate-100 font-medium' : 'text-slate-400'}`}>
                {col.name}
              </span>
            </div>
            <span className="text-[10px] text-slate-600 font-mono ml-4">{col.type}</span>

            <Handle 
                type="source" 
                position={Position.Right} 
                id={`source-${col.name}`} 
                style={{ background: '#64748b', width: 6, height: 6, right: -6 }}
            />
          </div>
        ))}
      </div>
    </div>
  );
};

const nodeTypes = { tableNode: TableNode };

interface SchemaVisualizerProps {
  schema: DbSchema;
  dbName: string;
}

const SchemaVisualizer: React.FC<SchemaVisualizerProps> = ({ schema, dbName }) => {

  // --- Auto Layout Logic (Simple Grid) ---
  const { initialNodes, initialEdges } = useMemo(() => {
      const nodes: Node[] = [];
      const edges: Edge[] = [];
      const PADDING = 300;
      const COL_COUNT = 3;

      schema.tables.forEach((tbl, index) => {
          const row = Math.floor(index / COL_COUNT);
          const col = index % COL_COUNT;

          nodes.push({
              id: tbl.name,
              type: 'tableNode',
              position: { x: col * PADDING, y: row * PADDING },
              data: tbl
          });

          // Create Edges
          tbl.columns.forEach(col => {
              if (col.isForeignKey && col.references) {
                  edges.push({
                      id: `e-${tbl.name}-${col.name}-${col.references.table}`,
                      source: col.references.table,
                      sourceHandle: `source-${col.references.column}`,
                      target: tbl.name,
                      targetHandle: `target-${col.name}`,
                      animated: true,
                      style: { stroke: '#475569', strokeWidth: 1.5 },
                      markerEnd: { type: MarkerType.ArrowClosed, color: '#475569' },
                      type: 'smoothstep'
                  });
              }
          });
      });

      return { initialNodes: nodes, initialEdges: edges };
  }, [schema]);

  const [nodes, setNodes, onNodesChange] = useNodesState(initialNodes);
  const [edges, setEdges, onEdgesChange] = useEdgesState(initialEdges);

  // Update nodes if schema prop changes deeply (rare in this app structure, but good practice)
  React.useEffect(() => {
      setNodes(initialNodes);
      setEdges(initialEdges);
  }, [initialNodes, initialEdges]);

  if (schema.tables.length === 0) {
      return (
          <div className="flex flex-col items-center justify-center h-full text-slate-500 bg-slate-950">
              <Table size={48} className="mb-4 opacity-50" />
              <h3 className="text-xl font-medium">No Schema Data</h3>
              <p className="text-sm mt-2">Select a database to visualize its tables.</p>
          </div>
      );
  }

  return (
    <div className="w-full h-full bg-slate-950 relative">
        <div className="absolute top-4 right-4 z-10 bg-slate-800/80 backdrop-blur px-3 py-1.5 rounded-lg border border-slate-700 text-xs text-slate-300 font-mono">
            Schema: {dbName}
        </div>
        <ReactFlow
            nodes={nodes}
            edges={edges}
            onNodesChange={onNodesChange}
            onEdgesChange={onEdgesChange}
            nodeTypes={nodeTypes}
            fitView
            className="bg-slate-950"
            minZoom={0.2}
        >
            <Background color="#1e293b" gap={20} />
            <Controls className="bg-slate-800 border-slate-700 fill-slate-200" />
        </ReactFlow>
    </div>
  );
};

export default SchemaVisualizer;

import React, { useState, useEffect, useRef } from 'react';
import { Database, EditorTab, QueryResult, ChartConfig, PinnedChart, DashboardLayout, AppSettings, SavedQuery, DbSchema } from './types';
import { muulService } from './services/muulService';
import { exportService } from './services/exportService';
import { 
  Play, Plus, X, Save, Download, Database as DbIcon, 
  Activity, Ban, ChevronDown, ChevronUp, ChevronRight,
  LayoutDashboard, TerminalSquare, Settings, Bookmark, FolderOpen, Upload, Table as TableIcon,
  Network
} from 'lucide-react';
import SqlEditor, { SqlEditorRef } from './components/SqlEditor';
import ResultsPane from './components/ResultsPane';
import Dashboard from './components/Dashboard';
import SchemaVisualizer from './components/SchemaVisualizer';
import SettingsModal from './components/SettingsModal';

type LayoutMode = 'bottom' | 'right' | 'left' | 'float';
type ViewMode = 'editor' | 'dashboard' | 'schema';
type SidebarTab = 'db' | 'saved';

const App: React.FC = () => {
  // --- State ---
  const [currentView, setCurrentView] = useState<ViewMode>('editor');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('db');
  const [databases, setDatabases] = useState<Database[]>([]);
  const [selectedDbId, setSelectedDbId] = useState<string>('');

  // Tables state: key is dbId, value is array of table names
  const [dbTables, setDbTables] = useState<Record<string, string[]>>({});
  const [expandedDbIds, setExpandedDbIds] = useState<Set<string>>(new Set());

  // Schema state for Visualizer
  const [activeSchema, setActiveSchema] = useState<DbSchema>({ tables: [] });

  const [isDraggingFile, setIsDraggingFile] = useState(false);

  // App Settings
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [appSettings, setAppSettings] = useState<AppSettings>({
    editorFontSize: 14,
    themeAccent: 'blue',
    refreshRate: 0
  });

  // Saved Data
  const [savedQueries, setSavedQueries] = useState<SavedQuery[]>([
      { id: 'sq-1', name: 'Get All Users', content: 'SELECT * FROM users LIMIT 100;', dbId: 'db-1', createdAt: Date.now() }
  ]);

  // Dashboard Data State
  const [pinnedCharts, setPinnedCharts] = useState<PinnedChart[]>([]);
  const [dashboards, setDashboards] = useState<DashboardLayout[]>([
      {
          id: 'main-dash',
          title: 'Main Dashboard',
          isDefault: true,
          rows: [
              {
                  id: 'row-welcome',
                  widgets: [
                      { id: 'w-welcome', type: 'markdown', colSpan: 12, title: 'Welcome', content: '# Welcome to Muul SQL\nDrag and drop **.csv**, **.json**, or **.sqlite** files to instantly query them!'}
                  ]
              }
          ]
      }
  ]);
  const [activeDashboardId, setActiveDashboardId] = useState<string>('main-dash');

  // Editor State
  const [tabs, setTabs] = useState<EditorTab[]>([
    { 
      id: 'tab-1', 
      title: 'Query 1', 
      content: '', 
      isDirty: false, 
      isExecuting: false, 
      results: [],
      activeResultIndex: -1 
    }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab-1');
  const [resultViewMode, setResultViewMode] = useState<'table' | 'chart'>('table');
  const [isEditorExpanded, setIsEditorExpanded] = useState(true);

  // Layout State
  const [layout, setLayout] = useState<LayoutMode>('bottom');
  const [panelSize, setPanelSize] = useState(40); // Percentage for docked mode
  const [floatRect, setFloatRect] = useState({ x: 100, y: 100, w: 600, h: 400 });

  // --- Refs ---
  const editorRef = useRef<SqlEditorRef>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const dragInfo = useRef<{ 
    isDragging: boolean; 
    type: 'resize-dock' | 'move-float' | 'resize-float'; 
    startX: number; 
    startY: number; 
    startSize?: number;
    startRect?: typeof floatRect;
  }>({ isDragging: false, type: 'resize-dock', startX: 0, startY: 0 });

  // --- Effects ---
  useEffect(() => {
    muulService.getDatabases().then(dbs => {
      setDatabases(dbs);
      if (dbs.length > 0) {
          setSelectedDbId(dbs[0].id);
          // Auto expand the first one
          setExpandedDbIds(new Set([dbs[0].id]));
      }
    });
  }, []);

  // Fetch tables AND Schema when a DB is expanded or selected
  useEffect(() => {
      if (selectedDbId) {
          // Fetch simple table list
          if (!dbTables[selectedDbId]) {
              muulService.getDatabaseTables(selectedDbId).then(tables => {
                  setDbTables(prev => ({ ...prev, [selectedDbId]: tables }));
              });
          }
          // Fetch Full Schema (for Visualizer)
          muulService.getDatabaseSchema(selectedDbId).then(schema => {
              setActiveSchema(schema);
          });
      }
  }, [selectedDbId]);

  // Global mouse event handlers for dragging/resizing
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragInfo.current.isDragging) return;

      const { type, startX, startY, startSize, startRect } = dragInfo.current;
      const container = containerRef.current;

      if (type === 'resize-dock' && container && startSize !== undefined) {
        const rect = container.getBoundingClientRect();
        let delta = 0;
        let newSize = startSize;

        if (layout === 'bottom') {
           delta = (startY - e.clientY) / rect.height * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'right') {
           delta = (startX - e.clientX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'left') {
           delta = (e.clientX - startX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        }
        setPanelSize(newSize);
      } 
      else if (type === 'move-float' && startRect) {
        setFloatRect({
          ...startRect,
          x: startRect.x + (e.clientX - startX),
          y: startRect.y + (e.clientY - startY)
        });
      }
      else if (type === 'resize-float' && startRect) {
        setFloatRect({
          ...startRect,
          w: Math.max(300, startRect.w + (e.clientX - startX)),
          h: Math.max(200, startRect.h + (e.clientY - startY))
        });
      }
    };

    const handleMouseUp = () => {
      dragInfo.current.isDragging = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [layout]);

  // --- Drag & Drop Handlers for Files ---
  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    // Only leave if we actually left the window/container
    if (e.currentTarget === e.target) {
        setIsDraggingFile(false);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
  };

  const handleFileDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);

    const files = Array.from(e.dataTransfer.files);
    if (files.length === 0) return;

    for (const file of files) {
        if (file.name.endsWith('.sqlite') || file.name.endsWith('.db') || file.name.endsWith('.csv') || file.name.endsWith('.json')) {
            try {
                const newDb = await muulService.uploadDatabase(file);
                setDatabases(prev => [newDb, ...prev]);
                setSelectedDbId(newDb.id);
                setExpandedDbIds(prev => new Set(prev).add(newDb.id));

                // Fetch tables immediately
                const tables = await muulService.getDatabaseTables(newDb.id);
                setDbTables(prev => ({ ...prev, [newDb.id]: tables }));

            } catch (err: any) {
                alert(`Failed to load ${file.name}: ${err.message}`);
            }
        } else {
            alert(`File ${file.name} is not supported. Please drop .sqlite, .db, .csv, or .json files.`);
        }
    }
  };


  // --- Helpers ---
  const activeTab = tabs.find(t => t.id === activeTabId)!;
  const activeResult = activeTab?.activeResultIndex >= 0 
    ? activeTab.results[activeTab.activeResultIndex] 
    : null;
  const selectedDb = databases.find(d => d.id === selectedDbId);

  // --- Actions ---

  const handleDbClick = (dbId: string) => {
      setSelectedDbId(dbId);
      setExpandedDbIds(prev => {
          const next = new Set(prev);
          if (next.has(dbId)) next.delete(dbId);
          else next.add(dbId);
          return next;
      });
  };

  const handleTableClick = (tableName: string) => {
      // Check if there is an existing, unmodified tab for this table
      const existingTab = tabs.find(t => t.title === tableName && !t.isDirty);

      if (existingTab) {
          setActiveTabId(existingTab.id);
          setCurrentView('editor'); // Ensure we switch back to editor
          return;
      }

      const newId = `tab-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: tableName,
          content: `SELECT * FROM "${tableName}" LIMIT 100;`,
          isDirty: false, // Initially clean so we can detect if user modifies it later
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
  };

  const handleCreateTab = () => {
    const newId = `tab-${Date.now()}`;
    setTabs([...tabs, {
      id: newId, title: `Query ${tabs.length + 1}`, content: '', isDirty: false, isExecuting: false, results: [], activeResultIndex: -1
    }]);
    setActiveTabId(newId);
  };

  const handleOpenSavedQuery = (sq: SavedQuery) => {
      const newId = `tab-${Date.now()}`;
      setTabs([...tabs, {
          id: newId,
          title: sq.name,
          content: sq.content,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      if(sq.dbId) setSelectedDbId(sq.dbId);
      setCurrentView('editor');
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (tabs.length === 1) return;
    const newTabs = tabs.filter(t => t.id !== id);
    setTabs(newTabs);
    if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
  };

  const handleRunQuery = async () => {
    if (!selectedDbId) return alert("Please select a database first.");
    const editor = editorRef.current;
    if (!editor) return;

    const selection = editor.getSelection();
    let queriesToRun = selection.text.trim().length > 0 
        ? [selection.text] 
        : activeTab.content.split(';').map(q => q.trim()).filter(q => q.length > 0);

    if (queriesToRun.length === 0) return;

    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: true } : t));
    const executionId = Date.now().toString();

    try {
      const results: QueryResult[] = [];
      for (const query of queriesToRun) {
        const result = await muulService.executeQuery(selectedDbId, query, executionId);
        results.push(result);
        if (result.error) break; 
      }
      setTabs(prev => prev.map(t => t.id === activeTabId ? {
        ...t, isExecuting: false, results: [results[results.length - 1], ...t.results], activeResultIndex: 0
      } : t));
    } catch (e) {
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
    }
  };

  const handleCancelQuery = () => {
    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
  };

  const handleSaveQuery = () => {
      if(!activeTab.content.trim()) return alert("Query is empty.");
      const name = prompt("Save Query As:", activeTab.title);
      if(!name) return;

      const newSaved: SavedQuery = {
          id: `sq-${Date.now()}`,
          name,
          content: activeTab.content,
          dbId: selectedDbId,
          createdAt: Date.now()
      };
      setSavedQueries([...savedQueries, newSaved]);
      // Update current tab name
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, title: name, isDirty: false } : t));
  };

  const handleDownloadCSV = () => {
      if(!activeResult) return;
      exportService.downloadCSV(activeResult, `result-${Date.now()}.csv`);
  };

  // --- Pinning & Dashboard Management ---

  const handlePinChart = (config: ChartConfig) => {
    if (!activeResult || !selectedDbId) return;

    // 1. Create the Chart Definition
    const chartId = `chart-${Date.now()}`;
    const newPin: PinnedChart = {
      id: chartId,
      title: `${activeTab.title} Chart`,
      query: activeTab.content, // Simplified: uses whole content
      dbId: selectedDbId,
      config: config,
      createdAt: Date.now()
    };
    setPinnedCharts(prev => [...prev, newPin]);

    // 2. Add to Active Dashboard (or default)
    setDashboards(prev => {
        return prev.map(dash => {
            if (dash.id !== activeDashboardId) return dash;

            const newWidget = {
                id: `w-${Date.now()}`,
                type: 'chart' as const,
                colSpan: 6, // Default to half width
                content: chartId,
                title: newPin.title
            };

            const lastRow = dash.rows[dash.rows.length - 1];
            if (lastRow && lastRow.widgets.reduce((acc, w) => acc + w.colSpan, 0) <= 6) {
                // Fit in last row
                return {
                    ...dash,
                    rows: dash.rows.map(r => r.id === lastRow.id ? { ...r, widgets: [...r.widgets, newWidget] } : r)
                };
            } else {
                // New Row
                return {
                    ...dash,
                    rows: [...dash.rows, { id: `row-${Date.now()}`, widgets: [newWidget] }]
                };
            }
        });
    });

    alert("Chart pinned to active dashboard!");
  };

  const handleAddDashboard = (title: string) => {
      const newDash: DashboardLayout = {
          id: `dash-${Date.now()}`,
          title,
          isDefault: false,
          rows: []
      };
      setDashboards([...dashboards, newDash]);
      setActiveDashboardId(newDash.id);
  };

  const handleDeleteDashboard = (id: string) => {
      if (dashboards.length <= 1) return alert("Cannot delete the last dashboard.");
      const newDashboards = dashboards.filter(d => d.id !== id);
      setDashboards(newDashboards);
      if (activeDashboardId === id) setActiveDashboardId(newDashboards[0].id);
  };

  const handleUpdateDashboard = (updatedLayout: DashboardLayout) => {
      setDashboards(prev => prev.map(d => d.id === updatedLayout.id ? updatedLayout : d));
  };

  const handleRemoveChartDefinition = (id: string) => {
      setPinnedCharts(prev => prev.filter(c => c.id !== id));
      // Also remove widgets referencing this chart from ALL dashboards
      setDashboards(prev => prev.map(dash => ({
          ...dash,
          rows: dash.rows.map(row => ({
              ...row,
              widgets: row.widgets.filter(w => w.type !== 'chart' || w.content !== id)
          }))
      })));
  };

  const handleUpdateChartDefinition = (id: string, newConfig: ChartConfig) => {
      setPinnedCharts(prev => prev.map(c => c.id === id ? { ...c, config: newConfig } : c));
  };

  // --- Drag Starters ---
  const startDockResize = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { 
        isDragging: true, 
        type: 'resize-dock', 
        startX: e.clientX, 
        startY: e.clientY, 
        startSize: panelSize 
    };
    document.body.style.cursor = layout === 'bottom' ? 'row-resize' : 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const startFloatMove = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { isDragging: true, type: 'move-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  const startFloatResize = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragInfo.current = { isDragging: true, type: 'resize-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  return (
    <div 
        className={`flex h-screen w-screen bg-slate-950 text-slate-200 overflow-hidden font-sans ${appSettings.themeAccent}-accent relative`}
        onDragEnter={handleDragEnter}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleFileDrop}
    >

      {/* Drag Overlay */}
      {isDraggingFile && (
          <div className="absolute inset-0 z-[100] bg-blue-500/20 backdrop-blur-sm border-4 border-dashed border-blue-400 m-4 rounded-xl flex flex-col items-center justify-center pointer-events-none">
              <Upload size={64} className="text-blue-400 mb-4" />
              <h2 className="text-2xl font-bold text-white">Drop File to Import</h2>
              <p className="text-blue-200">Supports .csv, .json, .sqlite, .db</p>
          </div>
      )}

      {/* Settings Modal */}
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={appSettings} 
        onSave={setAppSettings}
      />

      {/* Activity Bar (Sidebar) */}
      <aside className="w-12 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-4 space-y-4 shrink-0 z-50">
        <div className="text-blue-500 mb-2"><DbIcon size={24} /></div>

        <button 
          onClick={() => setCurrentView('editor')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'editor' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="SQL Editor"
        >
          <TerminalSquare size={20} />
        </button>

        <button 
          onClick={() => setCurrentView('dashboard')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'dashboard' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="Dashboard"
        >
          <LayoutDashboard size={20} />
        </button>

        <button 
          onClick={() => setCurrentView('schema')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'schema' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="Schema Visualizer"
        >
          <Network size={20} />
        </button>

        <div className="h-px w-6 bg-slate-800 my-2"></div>

        {/* Saved Queries Toggle (Only meaningful in Editor View, effectively) */}
        <button 
            onClick={() => { setCurrentView('editor'); setSidebarTab('saved'); }}
            className={`p-2 rounded-lg transition-colors ${currentView === 'editor' && sidebarTab === 'saved' ? 'bg-slate-800 text-purple-400' : 'text-slate-500 hover:text-slate-300'}`}
            title="Saved Queries"
        >
            <Bookmark size={20} />
        </button>

        <div className="flex-1" />
        <button 
            onClick={() => setIsSettingsOpen(true)}
            className="p-2 text-slate-500 hover:text-slate-300 hover:bg-slate-800 rounded transition-colors"
        >
            <Settings size={20} />
        </button>
      </aside>

      {/* Explorer / Sidebar Panel (Conditional) */}
      {(currentView === 'editor' || currentView === 'schema') && (
          <div className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col min-h-0">
             <div className="h-10 flex items-center px-4 font-bold text-xs uppercase tracking-wider text-slate-500 border-b border-slate-800 shrink-0">
                {sidebarTab === 'db' ? 'Databases' : 'Saved Queries'}
             </div>

             {/* Database List */}
             {sidebarTab === 'db' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {databases.map(db => (
                        <div key={db.id} className="mb-1">
                            <div 
                                onClick={() => handleDbClick(db.id)}
                                className={`flex items-center p-2 rounded cursor-pointer transition-colors ${selectedDbId === db.id ? 'bg-slate-800 text-slate-200' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-300'}`}
                            >
                                <div className={`mr-2 transition-transform ${expandedDbIds.has(db.id) ? 'rotate-90' : ''}`}>
                                    <ChevronRight size={14} />
                                </div>
                                <DbIcon size={14} className="mr-2 text-blue-500/80" />
                                <div className="flex flex-col truncate">
                                    <span className="text-sm truncate font-medium">{db.name}</span>
                                </div>
                            </div>

                            {/* Table List (Indented) */}
                            {expandedDbIds.has(db.id) && (
                                <div className="ml-6 pl-2 border-l border-slate-800 mt-1 space-y-0.5">
                                    {dbTables[db.id] && dbTables[db.id].length > 0 ? (
                                        dbTables[db.id].map(tbl => (
                                            <div 
                                                key={tbl} 
                                                onClick={() => handleTableClick(tbl)}
                                                className="flex items-center px-2 py-1.5 text-xs text-slate-500 hover:text-blue-300 hover:bg-slate-800/50 rounded cursor-pointer group"
                                            >
                                                <TableIcon size={12} className="mr-2 opacity-50 group-hover:opacity-100" />
                                                <span className="truncate">{tbl}</span>
                                            </div>
                                        ))
                                    ) : (
                                        <div className="px-2 py-1 text-[10px] text-slate-600 italic">No tables found or loading...</div>
                                    )}
                                </div>
                            )}
                        </div>
                    ))}
                    <div className="mt-4 p-4 border border-dashed border-slate-800 rounded mx-2 text-center text-slate-600 text-xs select-none pointer-events-none">
                        Drop SQLite, CSV, or JSON file
                    </div>
                </div>
             )}

             {/* Saved Queries List */}
             {sidebarTab === 'saved' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {savedQueries.length === 0 && <div className="text-slate-600 text-xs text-center mt-4">No saved queries.</div>}
                    {savedQueries.map(sq => (
                        <div 
                            key={sq.id} 
                            onClick={() => handleOpenSavedQuery(sq)}
                            className="group flex items-start p-2 mb-1 rounded cursor-pointer transition-colors text-slate-400 hover:bg-slate-800 hover:text-slate-200"
                        >
                            <FolderOpen size={14} className="mr-2 mt-0.5 text-purple-400" />
                            <div className="flex flex-col truncate flex-1">
                                <span className="text-sm truncate font-medium">{sq.name}</span>
                                <span className="text-[10px] text-slate-500 truncate">{new Date(sq.createdAt).toLocaleDateString()}</span>
                            </div>
                        </div>
                    ))}
                    <button 
                        onClick={() => setSidebarTab('db')} 
                        className="mt-4 w-full flex items-center justify-center p-2 text-xs text-slate-500 hover:text-slate-300 border border-dashed border-slate-800 rounded hover:bg-slate-800"
                    >
                         Back to Databases
                    </button>
                </div>
             )}
          </div>
      )}

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 h-full overflow-hidden relative">

        {/* VIEW: DASHBOARD */}
        {currentView === 'dashboard' && (
             <Dashboard 
                dashboards={dashboards}
                pinnedCharts={pinnedCharts} 
                databases={databases}
                activeDashboardId={activeDashboardId}
                refreshRate={appSettings.refreshRate}
                onSetActiveDashboard={setActiveDashboardId}
                onAddDashboard={handleAddDashboard}
                onUpdateDashboard={handleUpdateDashboard}
                onDeleteDashboard={handleDeleteDashboard}
                onRemoveChartDefinition={handleRemoveChartDefinition}
                onUpdateChartDefinition={handleUpdateChartDefinition}
             />
        )}

        {/* VIEW: SCHEMA VISUALIZER */}
        {currentView === 'schema' && (
            <SchemaVisualizer schema={activeSchema} dbName={selectedDb?.name || 'Selected Database'} />
        )}

        {/* VIEW: EDITOR */}
        <div className={`flex-1 flex flex-col h-full w-full ${currentView === 'dashboard' || currentView === 'schema' ? 'hidden' : 'flex'}`}>
            <header className="h-14 border-b border-slate-800 bg-slate-900 flex items-center px-4 justify-between shrink-0 z-30 relative">
              <div className="flex items-center space-x-4">
                <div className="flex items-center text-blue-400 font-bold text-lg tracking-tight">
                  Muul<span className="text-slate-100">SQL</span>
                </div>
                <div className="h-6 w-px bg-slate-700 mx-2"></div>
                <div className="relative group">
                  <select 
                    value={selectedDbId}
                    onChange={(e) => setSelectedDbId(e.target.value)}
                    className="appearance-none bg-slate-800 hover:bg-slate-700 border border-slate-700 text-sm rounded py-1.5 pl-3 pr-8 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors w-64 cursor-pointer"
                  >
                    {databases.map(db => (
                      <option key={db.id} value={db.id}>{db.type.toUpperCase()} • {db.name}</option>
                    ))}
                  </select>
                  <Activity size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400" />
                </div>
              </div>

              <div className="flex items-center space-x-2">
                  {activeTab.isExecuting ? (
                      <button onClick={handleCancelQuery} className="flex items-center px-4 py-1.5 bg-red-600 hover:bg-red-700 text-white text-sm font-medium rounded shadow animate-pulse">
                        <Ban size={16} className="mr-2" /> Cancel
                      </button>
                  ) : (
                      <button onClick={handleRunQuery} className="flex items-center px-4 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium rounded shadow hover:shadow-blue-500/20 active:scale-95">
                        <Play size={16} className="mr-2 fill-current" /> Run
                      </button>
                  )}
                  <div className="h-6 w-px bg-slate-700 mx-2"></div>

                  {/* Save Button */}
                  <button 
                    onClick={handleSaveQuery} 
                    className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded transition-colors"
                    title="Save Query"
                  >
                    <Save size={18} />
                  </button>

                  {/* Download Button */}
                  <button 
                    onClick={handleDownloadCSV}
                    disabled={!activeResult}
                    className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded disabled:opacity-30 transition-colors"
                    title="Download Result CSV"
                  >
                    <Download size={18} />
                  </button>
              </div>
            </header>

            {/* Tabs Container */}
            <div className="flex items-center bg-slate-900 border-b border-slate-800 pr-2 pt-2 shrink-0">
              <div className="flex-1 flex overflow-x-auto no-scrollbar items-end px-2">
                  {tabs.map(tab => (
                    <div key={tab.id} onClick={() => setActiveTabId(tab.id)} className={`group flex items-center min-w-[150px] max-w-[250px] px-3 py-2 text-xs border-t border-r border-l rounded-t-md cursor-pointer select-none whitespace-nowrap ${activeTabId === tab.id ? 'bg-slate-850 border-slate-700 text-blue-400 font-medium' : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-800'}`}>
                      <span className="mr-2 truncate flex-1">{tab.title} {tab.isDirty && '*'}</span>
                      <button onClick={(e) => handleCloseTab(tab.id, e)} className={`opacity-0 group-hover:opacity-100 p-0.5 rounded-full hover:bg-slate-700 ${tabs.length === 1 ? 'hidden' : ''}`}><X size={12} /></button>
                    </div>
                  ))}
              </div>
              <div className="flex items-center border-l border-slate-800 pl-2 pb-1 space-x-1">
                  <button 
                      onClick={() => setIsEditorExpanded(!isEditorExpanded)} 
                      className={`p-1.5 hover:bg-slate-800 rounded transition-colors ${!isEditorExpanded ? 'text-blue-400' : 'text-slate-500'}`} 
                      title={isEditorExpanded ? "Collapse Editor" : "Expand Editor"}
                  >
                      {isEditorExpanded ? <ChevronDown size={16} /> : <ChevronUp size={16} />}
                  </button>
                  <button onClick={handleCreateTab} className="p-1.5 text-slate-500 hover:text-blue-400 hover:bg-slate-800 rounded transition-colors" title="New Tab"><Plus size={16} /></button>
              </div>
            </div>

            {/* Workspace Container */}
            <div 
              ref={containerRef}
              className={`flex-1 flex overflow-hidden bg-slate-950 relative ${
                  layout === 'bottom' ? 'flex-col' : 
                  layout === 'left' ? 'flex-row-reverse' : 
                  'flex-row'
              }`}
            >
              <div 
                  style={layout === 'bottom' ? {} : { display: isEditorExpanded ? 'flex' : 'none' }}
                  className={`
                      ${layout === 'float' ? 'w-full h-full' : 'flex-1'} 
                      flex flex-col min-h-0 min-w-0 z-0 transition-all duration-300
                      ${layout === 'bottom' && !isEditorExpanded ? '!flex-none !h-0 overflow-hidden' : ''}
                  `}
              >
                <div style={{ fontSize: `${appSettings.editorFontSize}px` }} className="h-full">
                    <SqlEditor 
                      ref={editorRef}
                      value={activeTab.content} 
                      onChange={c => setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: c, isDirty: true } : t))}
                      disabled={activeTab.isExecuting}
                      dbType={selectedDb?.type}
                    />
                </div>
                {activeTab.isExecuting && (
                    <div className="bg-slate-800/50 text-xs text-blue-300 px-4 py-1 border-t border-slate-800 flex items-center shrink-0">
                        <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse mr-2"></div>
                        Running query...
                    </div>
                )}
              </div>

              {layout !== 'float' && isEditorExpanded && (
                  <div 
                      onMouseDown={startDockResize}
                      className={`
                          ${layout === 'bottom' ? 'h-1.5 w-full cursor-row-resize' : 'w-1.5 h-full cursor-col-resize'} 
                          bg-slate-950 hover:bg-blue-600 transition-colors z-20 flex-shrink-0 border-slate-800
                          ${layout === 'bottom' ? 'border-t border-b' : 'border-l border-r'}
                      `} 
                  />
              )}

              {layout !== 'float' && (
                  <div 
                      style={layout === 'bottom' 
                          ? { height: isEditorExpanded ? `${panelSize}%` : '100%' } 
                          : { width: `${panelSize}%` }
                  } 
                  className="flex flex-col min-h-0 min-w-0 z-10 transition-all duration-300"
              >
                  <ResultsPane 
                      result={activeResult} 
                      viewMode={resultViewMode} 
                      setViewMode={setResultViewMode}
                      layout={layout}
                      setLayout={setLayout}
                      onPinChart={handlePinChart}
                  />
              </div>
              )}

              {layout === 'float' && (
                  <div 
                      style={{ top: floatRect.y, left: floatRect.x, width: floatRect.w, height: floatRect.h }}
                      className="absolute z-50 shadow-2xl border border-slate-700 rounded-lg overflow-hidden flex flex-col bg-slate-900 ring-1 ring-black/50"
                  >
                      <ResultsPane 
                          result={activeResult}
                          viewMode={resultViewMode}
                          setViewMode={setResultViewMode}
                          layout={layout}
                          setLayout={setLayout}
                          onHeaderMouseDown={startFloatMove}
                          onPinChart={handlePinChart}
                      />
                      <div 
                          onMouseDown={startFloatResize}
                          className="absolute bottom-0 right-0 w-5 h-5 cursor-nwse-resize bg-transparent hover:bg-blue-500/20 z-50 rounded-tl-lg"
                      />
                  </div>
              )}
            </div>

            <footer className="h-6 bg-slate-900 border-t border-slate-800 flex items-center px-4 text-[10px] text-slate-500 justify-between shrink-0 z-40">
              <div className="flex items-center space-x-4">
                  <span>Ready</span>
                  <span>{selectedDbId ? `Connected: ${selectedDb?.name}` : 'No Database Selected'}</span>
              </div>
              <div>Muul MessageHandler v1.0.0</div>
            </footer>
        </div>
      </div>
    </div>
  );
};

export default App;

