import initSqlJs from 'sql.js';
import Papa from 'papaparse';
import { parquetRead } from 'hyparquet';
import { DbEngine, QueryResult, DbSchema, TableDefinition, ColumnDefinition } from '../../types';

export class SqliteEngine implements DbEngine {
  private sqlPromise: Promise<any>;
  private instances: Map<string, any> = new Map(); // dbId -> SQL.Database

  constructor() {
    this.sqlPromise = initSqlJs({
      locateFile: file => `https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.8.0/${file}`
    });
  }

  async init() {
    await this.sqlPromise;
  }

  // Registers a new database instance (Called by MuulService)
  registerDatabase(id: string, db: any) {
    this.instances.set(id, db);
  }

  async createDatabaseFromFile(file: File): Promise<{ db: any, type: string }> {
     const SQL = await this.sqlPromise;

     if (file.name.endsWith('.sqlite') || file.name.endsWith('.db')) {
        const buffer = await file.arrayBuffer();
        return { db: new SQL.Database(new Uint8Array(buffer)), type: 'sqlite' };
     } 
     else if (file.name.endsWith('.csv')) {
        const text = await file.text();
        const parseResult = Papa.parse(text, { header: true, dynamicTyping: true, skipEmptyLines: true });
        const db = new SQL.Database();
        const tableName = this.sanitizeTableName(file.name);
        if (parseResult.meta.fields && parseResult.data.length > 0) {
            this.importDataToTable(db, tableName, parseResult.meta.fields, parseResult.data);
        }
        return { db, type: 'sqlite' };
     }
     else if (file.name.endsWith('.json')) {
        const text = await file.text();
        let data = JSON.parse(text);
        if (!Array.isArray(data)) {
             const keys = Object.keys(data);
             if (keys.length === 1 && Array.isArray(data[keys[0]])) data = data[keys[0]];
             else throw new Error("JSON must be an array of objects");
        }
        const db = new SQL.Database();
        if (data.length > 0) {
            const tableName = this.sanitizeTableName(file.name);
            const fields = Object.keys(data[0]);
            this.importDataToTable(db, tableName, fields, data);
        }
        return { db, type: 'sqlite' };
     }
     else if (file.name.endsWith('.parquet')) {
        const buffer = await file.arrayBuffer();

        const data = await new Promise<any[]>((resolve, reject) => {
            parquetRead({
                file: buffer,
                rowFormat: 'object',
                onComplete: (rows: any[]) => resolve(rows)
            }).catch(reject);
        });

        const db = new SQL.Database();
        if (data.length > 0) {
             const tableName = this.sanitizeTableName(file.name);
             const fields = Object.keys(data[0]);
             this.importDataToTable(db, tableName, fields, data);
        }
        return { db, type: 'sqlite' };
     }
     throw new Error("Unsupported file type");
  }

  async executeQuery(dbId: string, sql: string): Promise<QueryResult> {
    const db = this.instances.get(dbId);
    if (!db) throw new Error("Database instance not found");

    const startTime = performance.now();
    try {
        const results = db.exec(sql);
        if (results.length === 0) {
            return {
               columns: [], rows: [], rowCount: 0,
               executionTimeMs: Math.round(performance.now() - startTime),
               timestamp: Date.now()
           };
       }
       const lastRes = results[results.length - 1];
       return {
           columns: lastRes.columns,
           rows: lastRes.values,
           rowCount: lastRes.values.length,
           executionTimeMs: Math.round(performance.now() - startTime),
           timestamp: Date.now()
       };
    } catch (e: any) {
        return {
            columns: [], rows: [], rowCount: 0,
            executionTimeMs: Math.round(performance.now() - startTime),
            timestamp: Date.now(),
            error: e.message
        };
    }
  }

  async getSchema(dbId: string): Promise<DbSchema> {
    const db = this.instances.get(dbId);
    if (!db) return { tables: [] };

    try {
        // 1. Get List of Tables
        const tablesRes = db.exec("SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'");
        if (tablesRes.length === 0) return { tables: [] };

        const tableNames = tablesRes[0].values.flat();
        const tables: TableDefinition[] = [];

        for (const tableName of tableNames) {
            // 2. Get Columns Info
            // cid, name, type, notnull, dflt_value, pk
            const colsRes = db.exec(`PRAGMA table_info("${tableName}")`);
            const columns: ColumnDefinition[] = [];

            // 3. Get Foreign Keys
            // id, seq, table, from, to, on_update, on_delete, match
            let fks: any[] = [];
            try {
                const fkRes = db.exec(`PRAGMA foreign_key_list("${tableName}")`);
                if (fkRes.length > 0) {
                    // Convert rows to objects for easier lookup
                    const fkCols = fkRes[0].columns;
                    fks = fkRes[0].values.map((row: any[]) => {
                        const obj: any = {};
                        fkCols.forEach((c: string, i: number) => obj[c] = row[i]);
                        return obj;
                    });
                }
            } catch(e) { /* ignore */ }

            if (colsRes.length > 0) {
                const colData = colsRes[0].values;
                // row structure: [cid, name, type, notnull, dflt_value, pk]
                for (const row of colData) {
                    const name = row[1] as string;
                    const type = row[2] as string;
                    const isPk = (row[5] as number) > 0;

                    // Check if this column is a FK
                    const fkDef = fks.find((f: any) => f.from === name);

                    columns.push({
                        name,
                        type,
                        isPrimaryKey: isPk,
                        isForeignKey: !!fkDef,
                        references: fkDef ? { table: fkDef.table, column: fkDef.to } : undefined
                    });
                }
            }

            tables.push({ name: tableName as string, columns });
        }

        return { tables };

    } catch (e) {
        console.error("Error fetching schema", e);
        return { tables: [] };
    }
  }

  // --- Helpers ---
  private importDataToTable(db: any, tableName: string, fields: string[], data: any[]) {
      const columnsDef = fields.map(f => `"${f}" TEXT`).join(', '); 
      db.run(`CREATE TABLE "${tableName}" (${columnsDef});`);
      const placeholders = fields.map(() => '?').join(', ');
      const stmt = db.prepare(`INSERT INTO "${tableName}" VALUES (${placeholders})`);
      db.exec("BEGIN TRANSACTION");
      for (const row of data) {
          const values = fields.map(f => {
              const val = row[f];
              return (typeof val === 'object' && val !== null) ? JSON.stringify(val) : val;
          });
          stmt.run(values);
      }
      db.exec("COMMIT");
      stmt.free();
  }

  private sanitizeTableName(filename: string): string {
      return filename.replace(/[^a-zA-Z0-9]/g, '_').replace(/_(csv|json|parquet)$/i, '');
  }
}

import React, { useMemo, useState, useEffect } from 'react';
import { QueryResult, ChartConfig, ChartType } from '../types';
import { 
  BarChart, Bar, LineChart, Line, PieChart, Pie, AreaChart, Area,
  ScatterChart, Scatter, RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell
} from 'recharts';
import { 
  BarChart3, LineChart as LineChartIcon, PieChart as PieChartIcon, 
  Activity, ScatterChart as ScatterIcon, Hexagon,
  Pin, Save, Layers, Settings2, Sigma, ArrowRight
} from 'lucide-react';

interface DataVisualizerProps {
  result: QueryResult;
  initialConfig?: ChartConfig;
  onPin?: (config: ChartConfig) => void;
  onSave?: (config: ChartConfig) => void;
  onApplyAggregation?: (dimension: string, metric: string, func: string) => void;
  readOnly?: boolean; 
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#6366f1'];

const DataVisualizer: React.FC<DataVisualizerProps> = ({ result, initialConfig, onPin, onSave, onApplyAggregation, readOnly = false }) => {
  const [chartType, setChartType] = useState<ChartType>(initialConfig?.type || 'bar');
  const [xAxisKey, setXAxisKey] = useState<string>(initialConfig?.xAxisKey || '');
  const [dataKeys, setDataKeys] = useState<string[]>(initialConfig?.dataKeys || []);
  const [isStacked, setIsStacked] = useState<boolean>(!!initialConfig?.stackId);

  // Aggregation State
  const [aggDimension, setAggDimension] = useState<string>('');
  const [aggMetric, setAggMetric] = useState<string>('');
  const [aggFunc, setAggFunc] = useState<string>('COUNT');
  const [showAggPanel, setShowAggPanel] = useState(false);

  // Sync with props
  useEffect(() => {
    if (initialConfig) {
      setChartType(initialConfig.type);
      setXAxisKey(initialConfig.xAxisKey);
      setDataKeys(initialConfig.dataKeys);
      setIsStacked(!!initialConfig.stackId);
    }
  }, [initialConfig]);

  // Memoize data processing to avoid recalculation on every render
  const { numericColumns, stringColumns, formattedData } = useMemo(() => {
    if (!result || !result.rows.length) {
      return { numericColumns: [], stringColumns: [], formattedData: [] };
    }

    const cols = result.columns;
    const numCols: string[] = [];
    const strCols: string[] = [];

    // Analyze first row for types
    const sampleRow = result.rows[0];
    cols.forEach((col, idx) => {
      const val = sampleRow[idx];
      if (typeof val === 'number') numCols.push(col);
      else strCols.push(col);
    });

    // Transform array of arrays to array of objects
    const data = result.rows.map(row => {
      const obj: any = {};
      cols.forEach((col, idx) => {
        obj[col] = row[idx];
      });
      return obj;
    });

    return { numericColumns: numCols, stringColumns: strCols, formattedData: data };
  }, [result]);

  // Intelligent Defaults
  useEffect(() => {
    if (initialConfig || formattedData.length === 0) return;

    if (!xAxisKey) {
       // Prefer string column for X axis, otherwise first column
       const defaultX = stringColumns.length > 0 ? stringColumns[0] : result.columns[0];
       setXAxisKey(defaultX);
       setAggDimension(defaultX);
    }
    if (dataKeys.length === 0 && numericColumns.length > 0) {
       setDataKeys([numericColumns[0]]);
       setAggMetric(numericColumns[0]);
    } else if (result.columns.length > 0) {
       setAggMetric(result.columns[0]);
    }
  }, [formattedData, initialConfig]);

  if (result.error) return <div className="h-full flex items-center justify-center text-red-400 p-4">{result.error}</div>;
  if (result.rows.length === 0) return <div className="h-full flex items-center justify-center text-slate-500">No data to visualize</div>;

  // --- Handlers ---

  const handleDataKeyToggle = (key: string) => {
    setDataKeys(prev => 
      prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]
    );
  };

  const handleAggregationSubmit = () => {
    if (onApplyAggregation && aggDimension && aggMetric && aggFunc) {
      onApplyAggregation(aggDimension, aggMetric, aggFunc);
    }
  };

  const currentConfig: ChartConfig = {
    type: chartType,
    xAxisKey,
    dataKeys,
    stackId: isStacked ? 'a' : undefined
  };

  // --- Render Chart Content ---
  const renderChart = () => {
    const CommonAxisProps = {
      stroke: "#94a3b8",
      fontSize: 12,
      tickFormatter: (val: any) => `${val}`.length > 10 ? `${val}`.substring(0, 10) + '..' : val
    };

    const TooltipStyle = { 
        contentStyle: { backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9', borderRadius: '8px' },
        itemStyle: { color: '#e2e8f0' }
    };

    switch (chartType) {
      case 'line':
        return (
          <LineChart data={formattedData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.5} />
            <XAxis dataKey={xAxisKey} {...CommonAxisProps} />
            <YAxis {...CommonAxisProps} />
            <Tooltip {...TooltipStyle} />
            <Legend />
            {dataKeys.map((key, index) => (
              <Line 
                key={key} 
                type="monotone" 
                dataKey={key} 
                stroke={COLORS[index % COLORS.length]} 
                strokeWidth={2} 
                dot={{ r: 3 }} 
                activeDot={{ r: 5 }}
              />
            ))}
          </LineChart>
        );
      case 'area':
        return (
          <AreaChart data={formattedData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.5} />
            <XAxis dataKey={xAxisKey} {...CommonAxisProps} />
            <YAxis {...CommonAxisProps} />
            <Tooltip {...TooltipStyle} />
            <Legend />
            {dataKeys.map((key, index) => (
              <Area 
                key={key} 
                type="monotone" 
                dataKey={key} 
                stackId={isStacked ? "1" : undefined}
                stroke={COLORS[index % COLORS.length]} 
                fill={COLORS[index % COLORS.length]} 
                fillOpacity={isStacked ? 0.6 : 0.3}
              />
            ))}
          </AreaChart>
        );
      case 'pie':
        return (
          <PieChart>
             <Pie
                data={formattedData}
                dataKey={dataKeys[0] || numericColumns[0]}
                nameKey={xAxisKey}
                cx="50%"
                cy="50%"
                outerRadius={readOnly ? 80 : 100}
                fill="#8884d8"
                label={!readOnly}
              >
                {formattedData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip {...TooltipStyle} />
              {!readOnly && <Legend />}
          </PieChart>
        );
      case 'scatter':
         return (
           <ScatterChart>
             <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.5} />
             <XAxis type="category" dataKey={xAxisKey} name={xAxisKey} {...CommonAxisProps} />
             <YAxis type="number" dataKey={dataKeys[0]} name={dataKeys[0]} {...CommonAxisProps} />
             <Tooltip cursor={{ strokeDasharray: '3 3' }} {...TooltipStyle} />
             <Legend />
             {dataKeys.map((key, index) => (
                <Scatter key={key} name={key} data={formattedData} fill={COLORS[index % COLORS.length]} />
             ))}
           </ScatterChart>
         );
      case 'radar':
          return (
            <RadarChart cx="50%" cy="50%" outerRadius="80%" data={formattedData}>
              <PolarGrid stroke="#334155" />
              <PolarAngleAxis dataKey={xAxisKey} tick={{ fill: '#94a3b8', fontSize: 10 }} />
              <PolarRadiusAxis angle={30} domain={[0, 'auto']} tick={{ fill: '#94a3b8', fontSize: 10 }} />
              {dataKeys.map((key, index) => (
                <Radar
                    key={key}
                    name={key}
                    dataKey={key}
                    stroke={COLORS[index % COLORS.length]}
                    fill={COLORS[index % COLORS.length]}
                    fillOpacity={0.4}
                />
              ))}
              <Legend />
              <Tooltip {...TooltipStyle} />
            </RadarChart>
          );
      case 'bar':
      default:
        return (
          <BarChart data={formattedData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.5} />
            <XAxis dataKey={xAxisKey} {...CommonAxisProps} />
            <YAxis {...CommonAxisProps} />
            <Tooltip {...TooltipStyle} />
            <Legend />
            {dataKeys.map((key, index) => (
              <Bar 
                key={key} 
                dataKey={key} 
                stackId={isStacked ? "a" : undefined}
                fill={COLORS[index % COLORS.length]} 
                radius={isStacked ? [0,0,0,0] : [4, 4, 0, 0]}
              />
            ))}
          </BarChart>
        );
    }
  };

  return (
    <div className="h-full flex flex-col bg-slate-900">

      {/* Config Panel - Only visible when not readOnly */}
      {!readOnly && (
        <div className="p-3 border-b border-slate-800 bg-slate-850 flex flex-col space-y-2">

          <div className="flex flex-wrap items-center justify-between gap-4">

            {/* 1. Chart Type Selector */}
            <div className="flex space-x-1 bg-slate-800 p-1 rounded-lg">
               {[
                   { id: 'bar', icon: BarChart3, label: 'Bar' },
                   { id: 'line', icon: LineChartIcon, label: 'Line' },
                   { id: 'area', icon: Activity, label: 'Area' },
                   { id: 'pie', icon: PieChartIcon, label: 'Pie' },
                   { id: 'scatter', icon: ScatterIcon, label: 'Scatter' },
                   { id: 'radar', icon: Hexagon, label: 'Radar' },
               ].map((t) => (
                   <button 
                    key={t.id}
                    onClick={() => setChartType(t.id as ChartType)}
                    className={`p-2 rounded transition-colors ${chartType === t.id ? 'bg-slate-700 text-blue-400 shadow-sm' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-700/50'}`}
                    title={t.label}
                   >
                       <t.icon size={18} />
                   </button>
               ))}
            </div>

            {/* 2. Series Configuration */}
            <div className="flex flex-1 items-center space-x-4 min-w-[200px]">
                {/* X Axis */}
                <div className="flex flex-col">
                    <label className="text-[10px] text-slate-500 font-bold uppercase mb-0.5">X Axis</label>
                    <select 
                        value={xAxisKey} 
                        onChange={e => setXAxisKey(e.target.value)}
                        className="bg-slate-800 text-xs text-slate-200 border border-slate-700 rounded px-2 py-1.5 focus:border-blue-500 outline-none w-32"
                    >
                        {result.columns.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                </div>

                {/* Y Axis / Series (Multi-Select UI) */}
                <div className="flex flex-col flex-1">
                    <label className="text-[10px] text-slate-500 font-bold uppercase mb-0.5 flex items-center justify-between">
                        <span>Series / Values</span>
                        {(chartType === 'bar' || chartType === 'area') && (
                            <button 
                                onClick={() => setIsStacked(!isStacked)}
                                className={`flex items-center space-x-1 px-1.5 py-0.5 rounded text-[9px] border ${isStacked ? 'bg-blue-900/30 border-blue-600 text-blue-300' : 'border-slate-700 text-slate-500'}`}
                            >
                                <Layers size={10} /> <span>Stack</span>
                            </button>
                        )}
                    </label>
                    <div className="flex flex-wrap gap-2 max-h-[60px] overflow-y-auto no-scrollbar items-center">
                        {numericColumns.length > 0 ? numericColumns.map(col => (
                            <button
                                key={col}
                                onClick={() => handleDataKeyToggle(col)}
                                className={`flex items-center text-xs px-2 py-1 rounded-full border transition-all ${
                                    dataKeys.includes(col) 
                                    ? 'bg-blue-600 border-blue-500 text-white shadow-sm' 
                                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'
                                }`}
                            >
                                {col}
                            </button>
                        )) : <span className="text-xs text-slate-600 italic">No numeric columns found</span>}
                    </div>
                </div>
            </div>

            {/* 3. Action Buttons */}
            <div className="flex items-center space-x-2 border-l border-slate-800 pl-4">
                 <button
                    onClick={() => setShowAggPanel(!showAggPanel)}
                    className={`flex items-center px-3 py-1.5 rounded border transition-all text-xs ${showAggPanel ? 'bg-purple-900/30 border-purple-500 text-purple-300' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-slate-200'}`}
                    title="SQL Aggregation"
                 >
                     <Sigma size={14} className="mr-2" /> Summarize
                 </button>
                 {onPin && (
                   <button 
                     onClick={() => onPin(currentConfig)}
                     className="flex items-center px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs rounded border border-slate-700 transition-all hover:border-blue-500 hover:text-blue-400"
                   >
                     <Pin size={14} className="mr-2" /> Pin
                   </button>
                 )}
                 {onSave && (
                    <button 
                      onClick={() => onSave(currentConfig)}
                      className="flex items-center px-3 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-xs rounded shadow transition-all"
                    >
                      <Save size={14} className="mr-2" /> Save
                    </button>
                 )}
            </div>
          </div>

          {/* Aggregation Panel (Expandable) */}
          {showAggPanel && (
              <div className="flex items-center bg-slate-900/50 border border-slate-800 p-2 rounded-lg space-x-3 text-xs animate-in slide-in-from-top-2 duration-200">
                  <div className="flex flex-col">
                      <label className="text-[9px] uppercase text-slate-500 font-bold mb-0.5">Dimension (Group By)</label>
                      <select 
                        value={aggDimension}
                        onChange={(e) => setAggDimension(e.target.value)}
                        className="bg-slate-800 border border-slate-700 rounded px-2 py-1 outline-none focus:border-purple-500 text-slate-300 w-32"
                      >
                          {result.columns.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                  </div>
                  <div className="flex flex-col">
                      <label className="text-[9px] uppercase text-slate-500 font-bold mb-0.5">Measure (Value)</label>
                      <select 
                        value={aggMetric}
                        onChange={(e) => setAggMetric(e.target.value)}
                        className="bg-slate-800 border border-slate-700 rounded px-2 py-1 outline-none focus:border-purple-500 text-slate-300 w-32"
                      >
                           {result.columns.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                  </div>
                  <div className="flex flex-col">
                      <label className="text-[9px] uppercase text-slate-500 font-bold mb-0.5">Function</label>
                      <select 
                        value={aggFunc}
                        onChange={(e) => setAggFunc(e.target.value)}
                        className="bg-slate-800 border border-slate-700 rounded px-2 py-1 outline-none focus:border-purple-500 text-slate-300 w-24"
                      >
                          {['COUNT', 'SUM', 'AVG', 'MIN', 'MAX'].map(f => <option key={f} value={f}>{f}</option>)}
                      </select>
                  </div>
                  <div className="flex flex-col justify-end h-full pt-4">
                      <button 
                        onClick={handleAggregationSubmit}
                        className="flex items-center px-3 py-1 bg-purple-600 hover:bg-purple-500 text-white rounded shadow-sm hover:shadow-purple-500/20 transition-all"
                      >
                          <ArrowRight size={12} className="mr-1" /> Run Query
                      </button>
                  </div>
              </div>
          )}
        </div>
      )}

      {/* Render Area */}
      <div className="flex-1 min-h-0 p-2">
        <ResponsiveContainer width="100%" height="100%">
            {renderChart()}
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default DataVisualizer;

import React from 'react';
import { QueryResult, ChartConfig } from '../types';
import { 
  Play, Table as TableIcon, LayoutTemplate, 
  PanelBottom, PanelRight, PanelLeft, AppWindow, 
  GripHorizontal 
} from 'lucide-react';
import DataTable from './DataTable';
import DataVisualizer from './DataVisualizer';

interface ResultsPaneProps {
  result: QueryResult | null;
  viewMode: 'table' | 'chart';
  setViewMode: (mode: 'table' | 'chart') => void;
  layout: 'bottom' | 'right' | 'left' | 'float';
  setLayout: (layout: 'bottom' | 'right' | 'left' | 'float') => void;
  onHeaderMouseDown?: (e: React.MouseEvent) => void;
  onPinChart?: (config: ChartConfig) => void;
  onApplyAggregation?: (dimension: string, metric: string, func: string) => void;
}

const ResultsPane: React.FC<ResultsPaneProps> = ({ 
  result, 
  viewMode, 
  setViewMode, 
  layout, 
  setLayout,
  onHeaderMouseDown,
  onPinChart,
  onApplyAggregation
}) => {
  return (
    <div className="flex flex-col h-full w-full bg-slate-900 overflow-hidden relative shadow-inner">
      {/* Result Toolbar */}
      <div 
        className={`h-10 border-b border-slate-800 flex items-center justify-between px-4 bg-slate-850 select-none ${layout === 'float' ? 'cursor-move' : ''}`}
        onMouseDown={layout === 'float' ? onHeaderMouseDown : undefined}
      >
        <div className="flex items-center space-x-4">
            {layout === 'float' && <GripHorizontal size={14} className="text-slate-600 mr-2" />}
            <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Output</span>
             <div className="flex space-x-1 bg-slate-800 p-0.5 rounded ml-2" onMouseDown={e => e.stopPropagation()}>
                <button 
                    onClick={() => setViewMode('table')}
                    className={`px-3 py-1 text-xs rounded flex items-center ${viewMode === 'table' ? 'bg-slate-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
                >
                    <TableIcon size={12} className="mr-1.5" /> Table
                </button>
                <button 
                    onClick={() => setViewMode('chart')}
                    className={`px-3 py-1 text-xs rounded flex items-center ${viewMode === 'chart' ? 'bg-slate-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
                >
                    <LayoutTemplate size={12} className="mr-1.5" /> Chart
                </button>
            </div>
        </div>

        {/* Layout Controls */}
        <div className="flex items-center space-x-1 border-l border-slate-700 pl-4 ml-4" onMouseDown={e => e.stopPropagation()}>
            <button 
                onClick={() => setLayout('bottom')}
                className={`p-1.5 rounded ${layout === 'bottom' ? 'text-blue-400 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`}
                title="Dock Bottom"
            >
                <PanelBottom size={14} />
            </button>
            <button 
                onClick={() => setLayout('right')}
                className={`p-1.5 rounded ${layout === 'right' ? 'text-blue-400 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`}
                title="Dock Right"
            >
                <PanelRight size={14} />
            </button>
             <button 
                onClick={() => setLayout('left')}
                className={`p-1.5 rounded ${layout === 'left' ? 'text-blue-400 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`}
                title="Dock Left"
            >
                <PanelLeft size={14} />
            </button>
             <button 
                onClick={() => setLayout('float')}
                className={`p-1.5 rounded ${layout === 'float' ? 'text-blue-400 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`}
                title="Float Window"
            >
                <AppWindow size={14} />
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden relative bg-slate-900">
        {!result ? (
            <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 opacity-50 pointer-events-none">
                <Play size={48} className="mb-4 stroke-1" />
                <p>Run a query to see results</p>
            </div>
        ) : (
            <>
                {viewMode === 'table' ? (
                    <DataTable result={result} />
                ) : (
                    <DataVisualizer 
                      result={result} 
                      onPin={onPinChart} 
                      onApplyAggregation={onApplyAggregation}
                    />
                )}
            </>
        )}
      </div>
    </div>
  );
};

export default ResultsPane;

import React, { useState, useEffect, useRef } from 'react';
import { Database, EditorTab, QueryResult, ChartConfig, PinnedChart, DashboardLayout, AppSettings, SavedQuery, DbSchema, SchemaLayout } from './types';
import { muulService } from './services/muulService';
import { exportService } from './services/exportService';
import { 
  Play, Plus, X, Save, Download, Database as DbIcon, 
  Activity, Ban, ChevronDown, ChevronUp, ChevronRight,
  LayoutDashboard, TerminalSquare, Settings, Bookmark, FolderOpen, Upload, Table as TableIcon,
  Network
} from 'lucide-react';
import SqlEditor, { SqlEditorRef } from './components/SqlEditor';
import ResultsPane from './components/ResultsPane';
import Dashboard from './components/Dashboard';
import SchemaVisualizer from './components/SchemaVisualizer';
import SettingsModal from './components/SettingsModal';

type LayoutMode = 'bottom' | 'right' | 'left' | 'float';
type ViewMode = 'editor' | 'dashboard' | 'schema';
type SidebarTab = 'db' | 'saved';

const App: React.FC = () => {
  // --- State ---
  const [currentView, setCurrentView] = useState<ViewMode>('editor');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('db');
  const [databases, setDatabases] = useState<Database[]>([]);
  const [selectedDbId, setSelectedDbId] = useState<string>('');

  // Tables state: key is dbId, value is array of table names
  const [dbTables, setDbTables] = useState<Record<string, string[]>>({});
  const [expandedDbIds, setExpandedDbIds] = useState<Set<string>>(new Set());

  // Schema & Layouts for Visualizer
  const [activeSchema, setActiveSchema] = useState<DbSchema>({ tables: [] });
  const [schemaLayouts, setSchemaLayouts] = useState<SchemaLayout[]>([]);
  const [activeLayoutId, setActiveLayoutId] = useState<string | null>(null);

  const [isDraggingFile, setIsDraggingFile] = useState(false);

  // App Settings
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [appSettings, setAppSettings] = useState<AppSettings>({
    editorFontSize: 14,
    themeAccent: 'blue',
    refreshRate: 0
  });

  // Saved Data
  const [savedQueries, setSavedQueries] = useState<SavedQuery[]>([
      { id: 'sq-1', name: 'Get All Users', content: 'SELECT * FROM users LIMIT 100;', dbId: 'db-1', createdAt: Date.now() }
  ]);

  // Dashboard Data State
  const [pinnedCharts, setPinnedCharts] = useState<PinnedChart[]>([]);
  const [dashboards, setDashboards] = useState<DashboardLayout[]>([
      {
          id: 'main-dash',
          title: 'Main Dashboard',
          isDefault: true,
          rows: [
              {
                  id: 'row-welcome',
                  widgets: [
                      { id: 'w-welcome', type: 'markdown', colSpan: 12, title: 'Welcome', content: '# Welcome to Muul SQL\nDrag and drop **.csv**, **.json**, **.parquet**, or **.sqlite** files to instantly query them!'}
                  ]
              }
          ]
      }
  ]);
  const [activeDashboardId, setActiveDashboardId] = useState<string>('main-dash');

  // Editor State
  const [tabs, setTabs] = useState<EditorTab[]>([
    { 
      id: 'tab-1', 
      title: 'Query 1', 
      content: '', 
      isDirty: false, 
      isExecuting: false, 
      results: [],
      activeResultIndex: -1 
    }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab-1');
  const [resultViewMode, setResultViewMode] = useState<'table' | 'chart'>('table');
  const [isEditorExpanded, setIsEditorExpanded] = useState(true);

  // Layout State
  const [layout, setLayout] = useState<LayoutMode>('bottom');
  const [panelSize, setPanelSize] = useState(40); // Percentage for docked mode
  const [floatRect, setFloatRect] = useState({ x: 100, y: 100, w: 600, h: 400 });

  // --- Refs ---
  const editorRef = useRef<SqlEditorRef>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const dragInfo = useRef<{ 
    isDragging: boolean; 
    type: 'resize-dock' | 'move-float' | 'resize-float'; 
    startX: number; 
    startY: number; 
    startSize?: number;
    startRect?: typeof floatRect;
  }>({ isDragging: false, type: 'resize-dock', startX: 0, startY: 0 });

  // --- Effects ---
  useEffect(() => {
    muulService.getDatabases().then(dbs => {
      setDatabases(dbs);
      if (dbs.length > 0) {
          setSelectedDbId(dbs[0].id);
          // Auto expand the first one
          setExpandedDbIds(new Set([dbs[0].id]));
      }
    });
  }, []);

  // Fetch tables AND Schema when a DB is expanded or selected
  useEffect(() => {
      if (selectedDbId) {
          // Fetch simple table list
          if (!dbTables[selectedDbId]) {
              muulService.getDatabaseTables(selectedDbId).then(tables => {
                  setDbTables(prev => ({ ...prev, [selectedDbId]: tables }));
              });
          }
          // Fetch Full Schema (for Visualizer)
          muulService.getDatabaseSchema(selectedDbId).then(schema => {
              setActiveSchema(schema);

              // Ensure a default layout exists
              setSchemaLayouts(prev => {
                  const hasLayout = prev.some(l => l.dbId === selectedDbId);
                  if (!hasLayout && schema.tables.length > 0) {
                      const defaultLayout: SchemaLayout = {
                          id: `layout-${Date.now()}`,
                          name: 'Main Diagram',
                          dbId: selectedDbId,
                          tables: schema.tables.map(t => t.name),
                          createdAt: Date.now()
                      };
                      setActiveLayoutId(defaultLayout.id);
                      return [...prev, defaultLayout];
                  }
                  // If layouts exist but none active for this DB, activate first one
                  const dbLayouts = prev.filter(l => l.dbId === selectedDbId);
                  if (dbLayouts.length > 0 && (!activeLayoutId || !dbLayouts.find(l => l.id === activeLayoutId))) {
                      setActiveLayoutId(dbLayouts[0].id);
                  }
                  return prev;
              });
          });
      }
  }, [selectedDbId]);

  // Ensure activeLayoutId is valid when switching DBs manually
  useEffect(() => {
      if (selectedDbId) {
           const dbLayouts = schemaLayouts.filter(l => l.dbId === selectedDbId);
           if (dbLayouts.length > 0) {
               // If current active layout is not for this DB, switch to the first one for this DB
               const active = schemaLayouts.find(l => l.id === activeLayoutId);
               if (!active || active.dbId !== selectedDbId) {
                   setActiveLayoutId(dbLayouts[0].id);
               }
           } else {
               setActiveLayoutId(null);
           }
      }
  }, [selectedDbId, schemaLayouts]);


  // --- Layout Handlers ---
  const handleLayoutCreate = (name: string, tables: string[]) => {
      if (!selectedDbId) return;
      const newLayout: SchemaLayout = {
          id: `layout-${Date.now()}`,
          name,
          dbId: selectedDbId,
          tables,
          createdAt: Date.now()
      };
      setSchemaLayouts(prev => [...prev, newLayout]);
      setActiveLayoutId(newLayout.id);
  };

  const handleLayoutUpdate = (layoutId: string, tables: string[]) => {
      setSchemaLayouts(prev => prev.map(l => l.id === layoutId ? { ...l, tables } : l));
  };

  const handleLayoutDelete = (layoutId: string) => {
      const remaining = schemaLayouts.filter(l => l.id !== layoutId);
      setSchemaLayouts(remaining);

      // Select another layout if current was deleted
      if (activeLayoutId === layoutId) {
          const others = remaining.filter(l => l.dbId === selectedDbId);
          setActiveLayoutId(others.length > 0 ? others[0].id : null);
      }
  };


  // Global mouse event handlers for dragging/resizing
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragInfo.current.isDragging) return;

      const { type, startX, startY, startSize, startRect } = dragInfo.current;
      const container = containerRef.current;

      if (type === 'resize-dock' && container && startSize !== undefined) {
        const rect = container.getBoundingClientRect();
        let delta = 0;
        let newSize = startSize;

        if (layout === 'bottom') {
           delta = (startY - e.clientY) / rect.height * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'right') {
           delta = (startX - e.clientX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'left') {
           delta = (e.clientX - startX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        }
        setPanelSize(newSize);
      } 
      else if (type === 'move-float' && startRect) {
        setFloatRect({
          ...startRect,
          x: startRect.x + (e.clientX - startX),
          y: startRect.y + (e.clientY - startY)
        });
      }
      else if (type === 'resize-float' && startRect) {
        setFloatRect({
          ...startRect,
          w: Math.max(300, startRect.w + (e.clientX - startX)),
          h: Math.max(200, startRect.h + (e.clientY - startY))
        });
      }
    };

    const handleMouseUp = () => {
      dragInfo.current.isDragging = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [layout]);

  // --- Drag & Drop Handlers for Files ---
  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    // Only leave if we actually left the window/container
    if (e.currentTarget === e.target) {
        setIsDraggingFile(false);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
  };

  const handleFileDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);

    const files: File[] = Array.from(e.dataTransfer.files);
    if (files.length === 0) return;

    for (const file of files) {
        if (file.name.endsWith('.sqlite') || file.name.endsWith('.db') || file.name.endsWith('.csv') || file.name.endsWith('.json') || file.name.endsWith('.parquet')) {
            try {
                const newDb = await muulService.uploadDatabase(file);
                setDatabases(prev => [newDb, ...prev]);
                setSelectedDbId(newDb.id);
                setExpandedDbIds(prev => new Set(prev).add(newDb.id));

                // Fetch tables immediately
                const tables = await muulService.getDatabaseTables(newDb.id);
                setDbTables(prev => ({ ...prev, [newDb.id]: tables }));

            } catch (err: any) {
                alert(`Failed to load ${file.name}: ${err.message}`);
            }
        } else {
            alert(`File ${file.name} is not supported. Please drop .sqlite, .db, .csv, .json, or .parquet files.`);
        }
    }
  };


  // --- Helpers ---
  const activeTab = tabs.find(t => t.id === activeTabId)!;
  const activeResult = activeTab?.activeResultIndex >= 0 
    ? activeTab.results[activeTab.activeResultIndex] 
    : null;
  const selectedDb = databases.find(d => d.id === selectedDbId);

  // --- Actions ---

  const handleDbClick = (dbId: string) => {
      setSelectedDbId(dbId);
      setExpandedDbIds(prev => {
          const next = new Set(prev);
          if (next.has(dbId)) next.delete(dbId);
          else next.add(dbId);
          return next;
      });
  };

  const handleTableClick = (tableName: string) => {
      // Check if there is an existing, unmodified tab for this table
      const existingTab = tabs.find(t => t.title === tableName && !t.isDirty);

      if (existingTab) {
          setActiveTabId(existingTab.id);
          setCurrentView('editor'); // Ensure we switch back to editor
          return;
      }

      const newId = `tab-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: tableName,
          content: `SELECT * FROM "${tableName}" LIMIT 100;`,
          isDirty: false, // Initially clean so we can detect if user modifies it later
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
  };

  const handleCreateTab = () => {
    const newId = `tab-${Date.now()}`;
    setTabs([...tabs, {
      id: newId, title: `Query ${tabs.length + 1}`, content: '', isDirty: false, isExecuting: false, results: [], activeResultIndex: -1
    }]);
    setActiveTabId(newId);
  };

  const handleOpenSavedQuery = (sq: SavedQuery) => {
      const newId = `tab-${Date.now()}`;
      setTabs([...tabs, {
          id: newId,
          title: sq.name,
          content: sq.content,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      if(sq.dbId) setSelectedDbId(sq.dbId);
      setCurrentView('editor');
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (tabs.length === 1) return;
    const newTabs = tabs.filter(t => t.id !== id);
    setTabs(newTabs);
    if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
  };

  const executeTabQuery = async (tabId: string, content: string, selectionOnly: boolean = false) => {
    if (!selectedDbId) return alert("Please select a database first.");

    let queriesToRun = [content];
    if (selectionOnly) {
         // This logic is currently inside handleRunQuery mainly via ref,
         // but here we are called programmatically with content.
         queriesToRun = content.split(';').map(q => q.trim()).filter(q => q.length > 0);
    }

    if (queriesToRun.length === 0) return;

    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: true } : t));
    const executionId = Date.now().toString();

    try {
      const results: QueryResult[] = [];
      for (const query of queriesToRun) {
        const result = await muulService.executeQuery(selectedDbId, query, executionId);
        results.push(result);
        if (result.error) break; 
      }
      setTabs(prev => prev.map(t => t.id === tabId ? {
        ...t, isExecuting: false, results: [results[results.length - 1], ...t.results], activeResultIndex: 0
      } : t));
    } catch (e) {
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: false } : t));
    }
  };

  const handleRunQuery = async () => {
    const editor = editorRef.current;
    if (!editor) return;

    const selection = editor.getSelection();
    if (selection.text.trim().length > 0) {
        // Run specific selection but don't split by semicolon if selection
        // Actually executeTabQuery logic above splits by semicolon which might be wrong for selection
        // Let's keep logic simple:
        if (!selectedDbId) return alert("Please select a database first.");
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: true } : t));
        const result = await muulService.executeQuery(selectedDbId, selection.text, Date.now().toString());
        setTabs(prev => prev.map(t => t.id === activeTabId ? {
            ...t, isExecuting: false, results: [result, ...t.results], activeResultIndex: 0
        } : t));
    } else {
        // Run full content (support multiple statements)
        executeTabQuery(activeTabId, activeTab.content, true);
    }
  };

  const handleApplyAggregation = (dimension: string, metric: string, func: string) => {
      const currentQuery = activeTab.content.trim().replace(/;$/, '');
      if (!currentQuery) return;

      const newQuery = `SELECT \n  "${dimension}", \n  ${func}("${metric}") as "${metric}_${func}" \nFROM (\n${currentQuery}\n) \nGROUP BY "${dimension}"`;

      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: newQuery, isDirty: true } : t));

      // Execute immediately
      setTimeout(() => {
          executeTabQuery(activeTabId, newQuery, true);
      }, 50);
  };

  const handleCancelQuery = () => {
    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
  };

  const handleSaveQuery = () => {
      if(!activeTab.content.trim()) return alert("Query is empty.");
      const name = prompt("Save Query As:", activeTab.title);
      if(!name) return;

      const newSaved: SavedQuery = {
          id: `sq-${Date.now()}`,
          name,
          content: activeTab.content,
          dbId: selectedDbId,
          createdAt: Date.now()
      };
      setSavedQueries([...savedQueries, newSaved]);
      // Update current tab name
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, title: name, isDirty: false } : t));
  };

  const handleDownloadCSV = () => {
      if(!activeResult) return;
      exportService.downloadCSV(activeResult, `result-${Date.now()}.csv`);
  };

  // --- Pinning & Dashboard Management ---

  const handlePinChart = (config: ChartConfig) => {
    if (!activeResult || !selectedDbId) return;

    // 1. Create the Chart Definition
    const chartId = `chart-${Date.now()}`;
    const newPin: PinnedChart = {
      id: chartId,
      title: `${activeTab.title} Chart`,
      query: activeTab.content, // Simplified: uses whole content
      dbId: selectedDbId,
      config: config,
      createdAt: Date.now()
    };
    setPinnedCharts(prev => [...prev, newPin]);

    // 2. Add to Active Dashboard (or default)
    setDashboards(prev => {
        return prev.map(dash => {
            if (dash.id !== activeDashboardId) return dash;

            const newWidget = {
                id: `w-${Date.now()}`,
                type: 'chart' as const,
                colSpan: 6, // Default to half width
                content: chartId,
                title: newPin.title
            };

            const lastRow = dash.rows[dash.rows.length - 1];
            if (lastRow && lastRow.widgets.reduce((acc, w) => acc + w.colSpan, 0) <= 6) {
                // Fit in last row
                return {
                    ...dash,
                    rows: dash.rows.map(r => r.id === lastRow.id ? { ...r, widgets: [...r.widgets, newWidget] } : r)
                };
            } else {
                // New Row
                return {
                    ...dash,
                    rows: [...dash.rows, { id: `row-${Date.now()}`, widgets: [newWidget] }]
                };
            }
        });
    });

    alert("Chart pinned to active dashboard!");
  };

  const handleAddDashboard = (title: string) => {
      const newDash: DashboardLayout = {
          id: `dash-${Date.now()}`,
          title,
          isDefault: false,
          rows: []
      };
      setDashboards([...dashboards, newDash]);
      setActiveDashboardId(newDash.id);
  };

  const handleDeleteDashboard = (id: string) => {
      if (dashboards.length <= 1) return alert("Cannot delete the last dashboard.");
      const newDashboards = dashboards.filter(d => d.id !== id);
      setDashboards(newDashboards);
      if (activeDashboardId === id) setActiveDashboardId(newDashboards[0].id);
  };

  const handleUpdateDashboard = (updatedLayout: DashboardLayout) => {
      setDashboards(prev => prev.map(d => d.id === updatedLayout.id ? updatedLayout : d));
  };

  const handleRemoveChartDefinition = (id: string) => {
      setPinnedCharts(prev => prev.filter(c => c.id !== id));
      // Also remove widgets referencing this chart from ALL dashboards
      setDashboards(prev => prev.map(dash => ({
          ...dash,
          rows: dash.rows.map(row => ({
              ...row,
              widgets: row.widgets.filter(w => w.type !== 'chart' || w.content !== id)
          }))
      })));
  };

  const handleUpdateChartDefinition = (id: string, newConfig: ChartConfig) => {
      setPinnedCharts(prev => prev.map(c => c.id === id ? { ...c, config: newConfig } : c));
  };

  // --- Drag Starters ---
  const startDockResize = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { 
        isDragging: true, 
        type: 'resize-dock', 
        startX: e.clientX, 
        startY: e.clientY, 
        startSize: panelSize 
    };
    document.body.style.cursor = layout === 'bottom' ? 'row-resize' : 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const startFloatMove = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { isDragging: true, type: 'move-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  const startFloatResize = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragInfo.current = { isDragging: true, type: 'resize-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  return (
    <div 
        className={`flex h-screen w-screen bg-slate-950 text-slate-200 overflow-hidden font-sans ${appSettings.themeAccent}-accent relative`}
        onDragEnter={handleDragEnter}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleFileDrop}
    >

      {/* Drag Overlay */}
      {isDraggingFile && (
          <div className="absolute inset-0 z-[100] bg-blue-500/20 backdrop-blur-sm border-4 border-dashed border-blue-400 m-4 rounded-xl flex flex-col items-center justify-center pointer-events-none">
              <Upload size={64} className="text-blue-400 mb-4" />
              <h2 className="text-2xl font-bold text-white">Drop File to Import</h2>
              <p className="text-blue-200">Supports .csv, .json, .sqlite, .db, .parquet</p>
          </div>
      )}

      {/* Settings Modal */}
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={appSettings} 
        onSave={setAppSettings}
      />

      {/* Activity Bar (Sidebar) */}
      <aside className="w-12 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-4 space-y-4 shrink-0 z-50">
        <div className="text-blue-500 mb-2"><DbIcon size={24} /></div>

        <button 
          onClick={() => setCurrentView('editor')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'editor' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="SQL Editor"
        >
          <TerminalSquare size={20} />
        </button>

        <button 
          onClick={() => setCurrentView('dashboard')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'dashboard' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="Dashboard"
        >
          <LayoutDashboard size={20} />
        </button>

        <button 
          onClick={() => setCurrentView('schema')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'schema' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="Schema Visualizer"
        >
          <Network size={20} />
        </button>

        <div className="h-px w-6 bg-slate-800 my-2"></div>

        {/* Saved Queries Toggle (Only meaningful in Editor View, effectively) */}
        <button 
            onClick={() => { setCurrentView('editor'); setSidebarTab('saved'); }}
            className={`p-2 rounded-lg transition-colors ${currentView === 'editor' && sidebarTab === 'saved' ? 'bg-slate-800 text-purple-400' : 'text-slate-500 hover:text-slate-300'}`}
            title="Saved Queries"
        >
            <Bookmark size={20} />
        </button>

        <div className="flex-1" />
        <button 
            onClick={() => setIsSettingsOpen(true)}
            className="p-2 text-slate-500 hover:text-slate-300 hover:bg-slate-800 rounded transition-colors"
        >
            <Settings size={20} />
        </button>
      </aside>

      {/* Explorer / Sidebar Panel (Conditional) */}
      {(currentView === 'editor' || currentView === 'schema') && (
          <div className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col min-h-0">
             <div className="h-10 flex items-center px-4 font-bold text-xs uppercase tracking-wider text-slate-500 border-b border-slate-800 shrink-0">
                {sidebarTab === 'db' ? 'Databases' : 'Saved Queries'}
             </div>

             {/* Database List */}
             {sidebarTab === 'db' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {databases.map(db => (
                        <div key={db.id} className="mb-1">
                            <div 
                                onClick={() => handleDbClick(db.id)}
                                className={`flex items-center p-2 rounded cursor-pointer transition-colors ${selectedDbId === db.id ? 'bg-slate-800 text-slate-200' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-300'}`}
                            >
                                <div className={`mr-2 transition-transform ${expandedDbIds.has(db.id) ? 'rotate-90' : ''}`}>
                                    <ChevronRight size={14} />
                                </div>
                                <DbIcon size={14} className="mr-2 text-blue-500/80" />
                                <div className="flex flex-col truncate">
                                    <span className="text-sm truncate font-medium">{db.name}</span>
                                </div>
                            </div>

                            {/* Table List (Indented) */}
                            {expandedDbIds.has(db.id) && (
                                <div className="ml-6 pl-2 border-l border-slate-800 mt-1 space-y-0.5">
                                    {dbTables[db.id] && dbTables[db.id].length > 0 ? (
                                        dbTables[db.id].map(tbl => (
                                            <div 
                                                key={tbl} 
                                                onClick={() => handleTableClick(tbl)}
                                                className="flex items-center px-2 py-1.5 text-xs text-slate-500 hover:text-blue-300 hover:bg-slate-800/50 rounded cursor-pointer group"
                                            >
                                                <TableIcon size={12} className="mr-2 opacity-50 group-hover:opacity-100" />
                                                <span className="truncate">{tbl}</span>
                                            </div>
                                        ))
                                    ) : (
                                        <div className="px-2 py-1 text-[10px] text-slate-600 italic">No tables found or loading...</div>
                                    )}
                                </div>
                            )}
                        </div>
                    ))}
                    <div className="mt-4 p-4 border border-dashed border-slate-800 rounded mx-2 text-center text-slate-600 text-xs select-none pointer-events-none">
                        Drop SQLite, CSV, JSON, or Parquet file
                    </div>
                </div>
             )}

             {/* Saved Queries List */}
             {sidebarTab === 'saved' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {savedQueries.length === 0 && <div className="text-slate-600 text-xs text-center mt-4">No saved queries.</div>}
                    {savedQueries.map(sq => (
                        <div 
                            key={sq.id} 
                            onClick={() => handleOpenSavedQuery(sq)}
                            className="group flex items-start p-2 mb-1 rounded cursor-pointer transition-colors text-slate-400 hover:bg-slate-800 hover:text-slate-200"
                        >
                            <FolderOpen size={14} className="mr-2 mt-0.5 text-purple-400" />
                            <div className="flex flex-col truncate flex-1">
                                <span className="text-sm truncate font-medium">{sq.name}</span>
                                <span className="text-[10px] text-slate-500 truncate">{new Date(sq.createdAt).toLocaleDateString()}</span>
                            </div>
                        </div>
                    ))}
                    <button 
                        onClick={() => setSidebarTab('db')} 
                        className="mt-4 w-full flex items-center justify-center p-2 text-xs text-slate-500 hover:text-slate-300 border border-dashed border-slate-800 rounded hover:bg-slate-800"
                    >
                         Back to Databases
                    </button>
                </div>
             )}
          </div>
      )}

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 h-full overflow-hidden relative">

        {/* VIEW: DASHBOARD */}
        {currentView === 'dashboard' && (
             <Dashboard 
                dashboards={dashboards}
                pinnedCharts={pinnedCharts} 
                databases={databases}
                activeDashboardId={activeDashboardId}
                refreshRate={appSettings.refreshRate}
                onSetActiveDashboard={setActiveDashboardId}
                onAddDashboard={handleAddDashboard}
                onUpdateDashboard={handleUpdateDashboard}
                onDeleteDashboard={handleDeleteDashboard}
                onRemoveChartDefinition={handleRemoveChartDefinition}
                onUpdateChartDefinition={handleUpdateChartDefinition}
             />
        )}

        {/* VIEW: SCHEMA VISUALIZER */}
        {currentView === 'schema' && (
            <SchemaVisualizer 
                schema={activeSchema} 
                dbName={selectedDb?.name || 'Selected Database'}
                layouts={schemaLayouts.filter(l => l.dbId === selectedDbId)}
                activeLayoutId={activeLayoutId}
                onLayoutCreate={handleLayoutCreate}
                onLayoutSelect={setActiveLayoutId}
                onLayoutUpdate={handleLayoutUpdate}
                onLayoutDelete={handleLayoutDelete}
            />
        )}

        {/* VIEW: EDITOR */}
        <div className={`flex-1 flex flex-col h-full w-full ${currentView === 'dashboard' || currentView === 'schema' ? 'hidden' : 'flex'}`}>
            <header className="h-14 border-b border-slate-800 bg-slate-900 flex items-center px-4 justify-between shrink-0 z-30 relative">
              <div className="flex items-center space-x-4">
                <div className="flex items-center text-blue-400 font-bold text-lg tracking-tight">
                  Muul<span className="text-slate-100">SQL</span>
                </div>
                <div className="h-6 w-px bg-slate-700 mx-2"></div>
                <div className="relative group">
                  <select 
                    value={selectedDbId}
                    onChange={(e) => setSelectedDbId(e.target.value)}
                    className="appearance-none bg-slate-800 hover:bg-slate-700 border border-slate-700 text-xs rounded py-1.5 pl-3 pr-8 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors w-64 cursor-pointer"
                  >
                    {databases.map(db => (
                      <option key={db.id} value={db.id}>{db.type.toUpperCase()} • {db.name}</option>
                    ))}
                  </select>
                  <Activity size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400" />
                </div>
              </div>

              <div className="flex items-center space-x-2">
                  {activeTab.isExecuting ? (
                      <button onClick={handleCancelQuery} className="flex items-center px-4 py-1.5 bg-red-600 hover:bg-red-700 text-white text-sm font-medium rounded shadow animate-pulse">
                        <Ban size={16} className="mr-2" /> Cancel
                      </button>
                  ) : (
                      <button onClick={handleRunQuery} className="flex items-center px-4 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium rounded shadow hover:shadow-blue-500/20 active:scale-95">
                        <Play size={16} className="mr-2 fill-current" /> Run
                      </button>
                  )}
                  <div className="h-6 w-px bg-slate-700 mx-2"></div>

                  {/* Save Button */}
                  <button 
                    onClick={handleSaveQuery} 
                    className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded transition-colors"
                    title="Save Query"
                  >
                    <Save size={18} />
                  </button>

                  {/* Download Button */}
                  <button 
                    onClick={handleDownloadCSV}
                    disabled={!activeResult}
                    className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded disabled:opacity-30 transition-colors"
                    title="Download Result CSV"
                  >
                    <Download size={18} />
                  </button>
              </div>
            </header>

            {/* Tabs Container */}
            <div className="flex items-center bg-slate-900 border-b border-slate-800 pr-2 pt-2 shrink-0">
              <div className="flex-1 flex overflow-x-auto no-scrollbar items-end px-2">
                  {tabs.map(tab => (
                    <div key={tab.id} onClick={() => setActiveTabId(tab.id)} className={`group flex items-center min-w-[150px] max-w-[250px] px-3 py-2 text-xs border-t border-r border-l rounded-t-md cursor-pointer select-none whitespace-nowrap ${activeTabId === tab.id ? 'bg-slate-850 border-slate-700 text-blue-400 font-medium' : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-800'}`}>
                      <span className="mr-2 truncate flex-1">{tab.title} {tab.isDirty && '*'}</span>
                      <button onClick={(e) => handleCloseTab(tab.id, e)} className={`opacity-0 group-hover:opacity-100 p-0.5 rounded-full hover:bg-slate-700 ${tabs.length === 1 ? 'hidden' : ''}`}><X size={12} /></button>
                    </div>
                  ))}
              </div>
              <div className="flex items-center border-l border-slate-800 pl-2 pb-1 space-x-1">
                  <button 
                      onClick={() => setIsEditorExpanded(!isEditorExpanded)} 
                      className={`p-1.5 hover:bg-slate-800 rounded transition-colors ${!isEditorExpanded ? 'text-blue-400' : 'text-slate-500'}`} 
                      title={isEditorExpanded ? "Collapse Editor" : "Expand Editor"}
                  >
                      {isEditorExpanded ? <ChevronDown size={16} /> : <ChevronUp size={16} />}
                  </button>
                  <button onClick={handleCreateTab} className="p-1.5 text-slate-500 hover:text-blue-400 hover:bg-slate-800 rounded transition-colors" title="New Tab"><Plus size={16} /></button>
              </div>
            </div>

            {/* Workspace Container */}
            <div 
              ref={containerRef}
              className={`flex-1 flex overflow-hidden bg-slate-950 relative ${
                  layout === 'bottom' ? 'flex-col' : 
                  layout === 'left' ? 'flex-row-reverse' : 
                  'flex-row'
              }`}
            >
              <div 
                  style={layout === 'bottom' ? {} : { display: isEditorExpanded ? 'flex' : 'none' }}
                  className={`
                      ${layout === 'float' ? 'w-full h-full' : 'flex-1'} 
                      flex flex-col min-h-0 min-w-0 z-0 transition-all duration-300
                      ${layout === 'bottom' && !isEditorExpanded ? '!flex-none !h-0 overflow-hidden' : ''}
                  `}
              >
                <div style={{ fontSize: `${appSettings.editorFontSize}px` }} className="h-full">
                    <SqlEditor 
                      ref={editorRef}
                      value={activeTab.content} 
                      onChange={c => setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: c, isDirty: true } : t))}
                      disabled={activeTab.isExecuting}
                      dbType={selectedDb?.type}
                    />
                </div>
                {activeTab.isExecuting && (
                    <div className="bg-slate-800/50 text-xs text-blue-300 px-4 py-1 border-t border-slate-800 flex items-center shrink-0">
                        <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse mr-2"></div>
                        Running query...
                    </div>
                )}
              </div>

              {layout !== 'float' && isEditorExpanded && (
                  <div 
                      onMouseDown={startDockResize}
                      className={`
                          ${layout === 'bottom' ? 'h-1.5 w-full cursor-row-resize' : 'w-1.5 h-full cursor-col-resize'} 
                          bg-slate-950 hover:bg-blue-600 transition-colors z-20 flex-shrink-0 border-slate-800
                          ${layout === 'bottom' ? 'border-t border-b' : 'border-l border-r'}
                      `} 
                  />
              )}

              {layout !== 'float' && (
                  <div 
                      style={layout === 'bottom' 
                          ? { height: isEditorExpanded ? `${panelSize}%` : '100%' } 
                          : { width: `${panelSize}%` }
                  } 
                  className="flex flex-col min-h-0 min-w-0 z-10 transition-all duration-300"
              >
                  <ResultsPane 
                      result={activeResult} 
                      viewMode={resultViewMode} 
                      setViewMode={setResultViewMode}
                      layout={layout}
                      setLayout={setLayout}
                      onPinChart={handlePinChart}
                      onApplyAggregation={handleApplyAggregation}
                  />
              </div>
              )}

              {layout === 'float' && (
                  <div 
                      style={{ top: floatRect.y, left: floatRect.x, width: floatRect.w, height: floatRect.h }}
                      className="absolute z-50 shadow-2xl border border-slate-700 rounded-lg overflow-hidden flex flex-col bg-slate-900 ring-1 ring-black/50"
                  >
                      <ResultsPane 
                          result={activeResult}
                          viewMode={resultViewMode}
                          setViewMode={setResultViewMode}
                          layout={layout}
                          setLayout={setLayout}
                          onHeaderMouseDown={startFloatMove}
                          onPinChart={handlePinChart}
                          onApplyAggregation={handleApplyAggregation}
                      />
                      <div 
                          onMouseDown={startFloatResize}
                          className="absolute bottom-0 right-0 w-5 h-5 cursor-nwse-resize bg-transparent hover:bg-blue-500/20 z-50 rounded-tl-lg"
                      />
                  </div>
              )}
            </div>

            <footer className="h-6 bg-slate-900 border-t border-slate-800 flex items-center px-4 text-[10px] text-slate-500 justify-between shrink-0 z-40">
              <div className="flex items-center space-x-4">
                  <span>Ready</span>
                  <span>{selectedDbId ? `Connected: ${selectedDb?.name}` : 'No Database Selected'}</span>
              </div>
              <div>Muul MessageHandler v1.0.0</div>
            </footer>
        </div>
      </div>
    </div>
  );
};

export default App;

export interface Database {
  id: string;
  name: string;
  type: 'postgres' | 'mysql' | 'sqlite' | 'parquet' | 'mssql';
  connectionString?: string; // Optional, internal use
}

export interface QueryResult {
  columns: string[];
  rows: any[][];
  executionTimeMs: number;
  rowCount: number;
  error?: string;
  timestamp: number;
}

export interface EditorTab {
  id: string;
  title: string;
  content: string;
  isDirty: boolean;
  isExecuting: boolean;
  results: QueryResult[]; // History of results for this tab
  activeResultIndex: number; // Which result is currently showing
  linkedChartId?: string; // If set, this tab is editing an existing pinned chart
}

export interface PaginationConfig {
  page: number;
  pageSize: number;
}

// Visualization Configuration to be saved
export type ChartType = 'bar' | 'line' | 'area' | 'scatter' | 'radar' | 'pie';

export interface ChartConfig {
  type: ChartType;
  xAxisKey: string;
  dataKeys: string[];
  stackId?: string; // For stacked bars/areas
}

export interface PinnedChart {
  id: string;
  title: string;
  query: string;
  dbId: string;
  config: ChartConfig;
  createdAt: number;
}

// --- Saved Queries ---
export interface SavedQuery {
  id: string;
  name: string;
  content: string;
  dbId?: string;
  createdAt: number;
}

// --- Dashboard Layout Types ---

export type WidgetType = 'chart' | 'markdown';

export interface DashboardWidget {
  id: string;
  type: WidgetType;
  title?: string;
  colSpan: number; // 1 to 12
  content: string; // If type='chart', this is chartId. If type='markdown', this is text.
}

export interface DashboardRow {
  id: string;
  widgets: DashboardWidget[];
}

export interface DashboardLayout {
  id: string;
  title: string;
  rows: DashboardRow[];
  isDefault: boolean;
}

// --- App Settings ---
export interface AppSettings {
  editorFontSize: number;
  themeAccent: 'blue' | 'purple' | 'green' | 'orange';
  refreshRate: number; // Auto-refresh interval for dashboard in seconds (0 = off)
}

// Message types for Muul communication
export type MuulMessageType = 'DB_LIST' | 'DB_EXECUTE' | 'DB_CANCEL';

export interface MuulMessage {
  type: MuulMessageType;
  payload?: any;
  requestId?: string;
}

// --- Schema Visualization Types ---

export interface ColumnDefinition {
  name: string;
  type: string;
  isPrimaryKey: boolean;
  isForeignKey: boolean;
  references?: {
    table: string;
    column: string;
  };
}

export interface TableDefinition {
  name: string;
  columns: ColumnDefinition[];
}

export interface DbSchema {
  tables: TableDefinition[];
}

export interface SchemaLayout {
  id: string;
  name: string;
  dbId: string;
  tables: string[]; // List of table names visible in this layout
  createdAt: number;
}

export interface DbEngine {
  init(): Promise<void>;
  executeQuery(dbId: string, sql: string): Promise<QueryResult>;
  getSchema(dbId: string): Promise<DbSchema>;
}

import React, { useEffect, useState, useRef } from 'react';
import { PinnedChart, QueryResult, ChartConfig, Database, DashboardLayout, DashboardRow, DashboardWidget } from '../types';
import { muulService } from '../services/muulService';
import { exportService } from '../services/exportService';
import DataVisualizer from './DataVisualizer';
import MarkdownVisualizer from './MarkdownVisualizer';
import { 
  RefreshCw, Trash2, Edit, AlertCircle, Database as DbIcon, 
  Plus, Layout, Monitor, MoveHorizontal, X, FileText, BarChart3, GripVertical,
  Download, ExternalLink
} from 'lucide-react';

interface DashboardProps {
  dashboards: DashboardLayout[];
  pinnedCharts: PinnedChart[];
  databases: Database[];
  activeDashboardId: string;
  refreshRate: number; 
  onSetActiveDashboard: (id: string) => void;
  onAddDashboard: (title: string) => void;
  onUpdateDashboard: (layout: DashboardLayout) => void;
  onDeleteDashboard: (id: string) => void;
  onRemoveChartDefinition: (id: string) => void;
  onUpdateChartDefinition: (id: string, newConfig: ChartConfig) => void;
  onEditChart: (chartId: string) => void; // New prop
}

const Dashboard: React.FC<DashboardProps> = ({ 
  dashboards, 
  pinnedCharts, 
  databases, 
  activeDashboardId,
  refreshRate,
  onSetActiveDashboard,
  onAddDashboard,
  onUpdateDashboard,
  onDeleteDashboard,
  onRemoveChartDefinition,
  onUpdateChartDefinition,
  onEditChart
}) => {
  const [results, setResults] = useState<Record<string, QueryResult>>({});
  const [loading, setLoading] = useState<Record<string, boolean>>({});
  const [isDesignerMode, setIsDesignerMode] = useState(false);
  const [draggingItem, setDraggingItem] = useState<{ rowId: string; index: number } | null>(null);
  const refreshIntervalRef = useRef<number | null>(null);

  // --- Helpers ---
  const activeDashboard = dashboards.find(d => d.id === activeDashboardId) || dashboards[0];
  const getChartDef = (chartId: string) => pinnedCharts.find(c => c.id === chartId);
  const getDbName = (dbId?: string) => databases.find(d => d.id === dbId)?.name || 'Unknown DB';

  // --- Data Fetching ---
  const refreshChart = async (chartId: string) => {
    const chart = getChartDef(chartId);
    if (!chart) return;

    setLoading(prev => ({ ...prev, [chartId]: true }));
    try {
      const result = await muulService.executeQuery(chart.dbId, chart.query, `dash-${chart.id}-${Date.now()}`);
      setResults(prev => ({ ...prev, [chartId]: result }));
    } catch (error) {
       console.error("Dashboard execution error", error);
    } finally {
      setLoading(prev => ({ ...prev, [chartId]: false }));
    }
  };

  const handleRefreshAll = () => {
     if (!activeDashboard) return;
     activeDashboard.rows.forEach(row => {
         row.widgets.forEach(w => {
             if (w.type === 'chart') refreshChart(w.content);
         });
     });
  };

  // --- Effects ---

  // Initial load logic check
  useEffect(() => {
    if (!activeDashboard) return;

    // Collect needed charts
    const chartIds = new Set<string>();
    activeDashboard.rows.forEach(row => {
      row.widgets.forEach(w => {
        if (w.type === 'chart') chartIds.add(w.content);
      });
    });

    // Refresh if no data
    chartIds.forEach(id => {
      if (!results[id]) refreshChart(id);
    });
  }, [activeDashboard, pinnedCharts]);

  // Auto Refresh Logic
  useEffect(() => {
    if (refreshIntervalRef.current) {
        clearInterval(refreshIntervalRef.current);
        refreshIntervalRef.current = null;
    }

    if (refreshRate > 0) {
        refreshIntervalRef.current = window.setInterval(() => {
            console.log("Auto-refreshing dashboard...");
            handleRefreshAll();
        }, refreshRate * 1000);
    }

    return () => {
        if (refreshIntervalRef.current) clearInterval(refreshIntervalRef.current);
    }
  }, [refreshRate, activeDashboard]); // Re-setup if rate or dash changes

  // --- Export ---
  const handleExportPPT = () => {
      if (!activeDashboard) return;
      exportService.exportDashboardToPPT(activeDashboard, pinnedCharts, results);
  };

  // --- Designer Actions ---

  const handleAddRow = () => {
    const newRow: DashboardRow = {
        id: `row-${Date.now()}`,
        widgets: []
    };
    onUpdateDashboard({
        ...activeDashboard,
        rows: [...activeDashboard.rows, newRow]
    });
  };

  const handleDeleteRow = (rowId: string) => {
      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.filter(r => r.id !== rowId)
      });
  };

  const handleAddWidget = (rowId: string, type: 'chart' | 'markdown') => {
      let content = '';
      let title = 'New Widget';

      if (type === 'markdown') {
          content = '### New Markdown\nEdit this content...';
          title = 'Text Block';
      } else {
          if (pinnedCharts.length === 0) {
              alert("No pinned charts available to add. Go to SQL Editor to pin queries.");
              return;
          }
          const firstChart = pinnedCharts[0];
          content = firstChart.id;
          title = firstChart.title;
      }

      const newWidget: DashboardWidget = {
          id: `widget-${Date.now()}`,
          type,
          colSpan: 12, // Default full width
          content,
          title
      };

      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.map(r => 
            r.id === rowId ? { ...r, widgets: [...r.widgets, newWidget] } : r
          )
      });
  };

  const handleRemoveWidget = (rowId: string, widgetId: string) => {
      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.map(r => 
            r.id === rowId ? { ...r, widgets: r.widgets.filter(w => w.id !== widgetId) } : r
          )
      });
  };

  const handleChangeWidgetWidth = (rowId: string, widgetId: string, delta: number) => {
    onUpdateDashboard({
        ...activeDashboard,
        rows: activeDashboard.rows.map(r => {
            if (r.id !== rowId) return r;
            return {
                ...r,
                widgets: r.widgets.map(w => {
                    if (w.id !== widgetId) return w;
                    const newSpan = Math.max(1, Math.min(12, w.colSpan + delta));
                    return { ...w, colSpan: newSpan };
                })
            };
        })
    });
  };

  const handleMarkdownChange = (rowId: string, widgetId: string, newContent: string) => {
      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.map(r => {
              if (r.id !== rowId) return r;
              return {
                  ...r,
                  widgets: r.widgets.map(w => w.id === widgetId ? { ...w, content: newContent } : w)
              };
          })
      });
  };

  // --- Drag and Drop Logic ---

  const handleDragStart = (e: React.DragEvent, rowId: string, index: number) => {
      setDraggingItem({ rowId, index });
      e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault(); 
      e.dataTransfer.dropEffect = 'move';
  };

  const moveWidget = (sourceRowId: string, sourceIndex: number, targetRowId: string, targetIndex: number) => {
      const newRows = activeDashboard.rows.map(r => ({
          ...r,
          widgets: [...r.widgets]
      }));

      const sourceRow = newRows.find(r => r.id === sourceRowId);
      const targetRow = newRows.find(r => r.id === targetRowId);

      if (!sourceRow || !targetRow) return;

      const [widget] = sourceRow.widgets.splice(sourceIndex, 1);
      let finalIndex = targetIndex;
      if (sourceRowId === targetRowId && sourceIndex < targetIndex) {
          finalIndex--;
      }
      targetRow.widgets.splice(finalIndex, 0, widget);

      onUpdateDashboard({
          ...activeDashboard,
          rows: newRows
      });
  };

  const handleDropOnWidget = (e: React.DragEvent, targetRowId: string, targetIndex: number) => {
      e.preventDefault();
      e.stopPropagation();
      if (!draggingItem) return;
      moveWidget(draggingItem.rowId, draggingItem.index, targetRowId, targetIndex);
      setDraggingItem(null);
  };

  const handleDropOnRow = (e: React.DragEvent, targetRowId: string) => {
      e.preventDefault();
      e.stopPropagation();
      if (!draggingItem) return;
      const targetRow = activeDashboard.rows.find(r => r.id === targetRowId);
      if (targetRow) {
          moveWidget(draggingItem.rowId, draggingItem.index, targetRowId, targetRow.widgets.length);
      }
      setDraggingItem(null);
  };

  // --- Render ---

  return (
    <div className="flex flex-col h-full w-full bg-slate-950 overflow-hidden relative">

      {/* Dashboard Toolbar / Tabs */}
      <div className="h-14 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4 shrink-0">
          <div className="flex items-center space-x-1 overflow-x-auto no-scrollbar">
              {dashboards.map(d => (
                  <button
                    key={d.id}
                    onClick={() => onSetActiveDashboard(d.id)}
                    className={`px-4 py-2 text-sm rounded-t-lg border-t border-r border-l border-b-0 transition-colors ${
                        activeDashboardId === d.id 
                        ? 'bg-slate-950 border-slate-700 text-blue-400 font-medium translate-y-[1px]' 
                        : 'bg-transparent border-transparent text-slate-500 hover:text-slate-300 hover:bg-slate-800'
                    }`}
                  >
                      {d.title}
                  </button>
              ))}
              <button 
                onClick={() => {
                    const name = prompt("Dashboard Name:");
                    if(name) onAddDashboard(name);
                }} 
                className="p-2 ml-2 text-slate-500 hover:text-blue-400 hover:bg-slate-800 rounded"
              >
                  <Plus size={16} />
              </button>
          </div>

          <div className="flex items-center space-x-3">
               <button 
                onClick={handleExportPPT}
                className="flex items-center px-3 py-1.5 bg-orange-700/50 hover:bg-orange-600 text-orange-200 text-xs rounded border border-orange-600 transition-all"
                title="Export Dashboard to PowerPoint"
              >
                <Download size={14} className="mr-2" /> Export PPT
              </button>

              <div className="h-6 w-px bg-slate-800"></div>

              <button 
                onClick={() => setIsDesignerMode(!isDesignerMode)}
                className={`flex items-center px-3 py-1.5 text-xs rounded border transition-all ${
                    isDesignerMode 
                    ? 'bg-blue-900/30 border-blue-500 text-blue-400 shadow-[0_0_10px_rgba(59,130,246,0.2)]' 
                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-slate-200'
                }`}
              >
                  {isDesignerMode ? <Layout size={14} className="mr-2" /> : <Monitor size={14} className="mr-2" />}
                  {isDesignerMode ? 'Designer Active' : 'View Mode'}
              </button>

              <div className="h-6 w-px bg-slate-800"></div>

              <button 
                onClick={handleRefreshAll}
                className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded relative" 
                title={`Refresh Data ${refreshRate > 0 ? `(Auto: ${refreshRate}s)` : ''}`}
              >
                <RefreshCw size={16} className={refreshRate > 0 ? "text-green-400" : ""} />
                {refreshRate > 0 && <span className="absolute top-1 right-1 w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>}
              </button>
          </div>
      </div>

      {/* Workspace */}
      <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-950">

          {/* Dashboard Rows */}
          <div className="space-y-6 max-w-7xl mx-auto">
              {activeDashboard.rows.map((row, rowIndex) => (
                  <div 
                    key={row.id} 
                    className={`relative group/row ${isDesignerMode ? 'p-2 border border-dashed border-slate-700 rounded-xl bg-slate-900/30 min-h-[100px] transition-colors hover:border-blue-500/30' : ''}`}
                    onDragOver={isDesignerMode ? handleDragOver : undefined}
                    onDrop={isDesignerMode ? (e) => handleDropOnRow(e, row.id) : undefined}
                  >
                      {/* Row Controls */}
                      {isDesignerMode && (
                          <div className="absolute -top-3 left-4 bg-slate-800 text-xs text-slate-400 px-2 py-0.5 rounded border border-slate-700 flex items-center space-x-2 shadow-sm z-10">
                              <span className="font-mono">Row {rowIndex + 1}</span>
                              <div className="h-3 w-px bg-slate-600"></div>
                              <button onClick={() => handleDeleteRow(row.id)} className="hover:text-red-400"><Trash2 size={12} /></button>
                          </div>
                      )}

                      {/* Row Grid */}
                      <div className="grid grid-cols-12 gap-6 min-h-[50px]">
                          {row.widgets.length === 0 && isDesignerMode && (
                              <div className="col-span-12 flex items-center justify-center py-8 text-slate-600 border-2 border-dashed border-slate-800 rounded-lg pointer-events-none">
                                  Empty Row - Drop widget here or add new
                              </div>
                          )}

                          {row.widgets.map((widget, widgetIndex) => {
                              const chartDef = widget.type === 'chart' ? getChartDef(widget.content) : null;

                              return (
                                <div 
                                    key={widget.id} 
                                    className={`relative flex flex-col bg-slate-900 border border-slate-800 rounded-lg shadow-sm overflow-hidden min-h-[300px] transition-all 
                                        ${isDesignerMode ? 'cursor-grab active:cursor-grabbing hover:border-blue-500' : ''}
                                        ${draggingItem?.rowId === row.id && draggingItem?.index === widgetIndex ? 'opacity-40 border-dashed border-slate-600' : ''}
                                    `}
                                    style={{ gridColumn: `span ${widget.colSpan} / span ${widget.colSpan}` }}
                                    draggable={isDesignerMode}
                                    onDragStart={(e) => isDesignerMode && handleDragStart(e, row.id, widgetIndex)}
                                    onDragOver={isDesignerMode ? handleDragOver : undefined}
                                    onDrop={isDesignerMode ? (e) => handleDropOnWidget(e, row.id, widgetIndex) : undefined}
                                >
                                    {/* Widget Header */}
                                    <div className="h-9 px-3 flex items-center justify-between bg-slate-850 border-b border-slate-800 shrink-0 select-none">
                                        <div className="flex items-center space-x-2 overflow-hidden">
                                            {isDesignerMode && <GripVertical size={14} className="text-slate-600 cursor-grab" />}
                                            {widget.type === 'chart' && (
                                                <div className={`w-2 h-2 rounded-full shrink-0 ${loading[widget.content] ? 'bg-yellow-500 animate-pulse' : results[widget.content]?.error ? 'bg-red-500' : 'bg-green-500'}`} />
                                            )}
                                            <span className="text-xs font-bold text-slate-300 truncate">{widget.title || (chartDef?.title)}</span>
                                        </div>

                                        {isDesignerMode && (
                                            <div className="flex items-center space-x-1" onMouseDown={e => e.stopPropagation()}>
                                                <button onClick={() => handleChangeWidgetWidth(row.id, widget.id, -1)} disabled={widget.colSpan <= 1} className="p-1 hover:bg-slate-700 rounded text-slate-500 disabled:opacity-30"><MoveHorizontal size={12} className="rotate-180" /></button>
                                                <span className="text-[10px] font-mono text-slate-500 w-4 text-center">{widget.colSpan}</span>
                                                <button onClick={() => handleChangeWidgetWidth(row.id, widget.id, 1)} disabled={widget.colSpan >= 12} className="p-1 hover:bg-slate-700 rounded text-slate-500 disabled:opacity-30"><MoveHorizontal size={12} /></button>
                                                <div className="w-px h-3 bg-slate-700 mx-1"></div>
                                                <button onClick={() => handleRemoveWidget(row.id, widget.id)} className="p-1 hover:bg-red-900/50 hover:text-red-400 rounded text-slate-500"><X size={12} /></button>
                                            </div>
                                        )}

                                        {!isDesignerMode && widget.type === 'chart' && (
                                            <div className="flex items-center space-x-1">
                                                <button 
                                                    onClick={() => onEditChart(widget.content)} 
                                                    className="p-1 text-slate-500 hover:text-purple-400 rounded hover:bg-slate-800"
                                                    title="Edit Query & Chart"
                                                >
                                                    <ExternalLink size={12} />
                                                </button>
                                                <button onClick={() => refreshChart(widget.content)} className="p-1 text-slate-500 hover:text-blue-400 rounded hover:bg-slate-800">
                                                    <RefreshCw size={12} />
                                                </button>
                                            </div>
                                        )}
                                    </div>

                                    {/* Widget Content */}
                                    <div className="flex-1 relative overflow-hidden" onMouseDown={e => isDesignerMode && e.stopPropagation()}>
                                        {widget.type === 'markdown' ? (
                                            <MarkdownVisualizer 
                                                content={widget.content} 
                                                onChange={(val) => handleMarkdownChange(row.id, widget.id, val)}
                                                isDesignerMode={isDesignerMode}
                                            />
                                        ) : (
                                            /* Chart Logic */
                                            <>
                                                {loading[widget.content] && !results[widget.content] ? (
                                                    <div className="absolute inset-0 flex items-center justify-center text-slate-600">
                                                        <RefreshCw className="animate-spin" />
                                                    </div>
                                                ) : results[widget.content]?.error ? (
                                                     <div className="absolute inset-0 flex flex-col items-center justify-center text-red-400 p-4 text-center">
                                                        <AlertCircle size={24} className="mb-2 opacity-50" />
                                                        <span className="text-xs font-mono">{results[widget.content].error}</span>
                                                    </div>
                                                ) : results[widget.content] && chartDef ? (
                                                    <DataVisualizer 
                                                        result={results[widget.content]} 
                                                        initialConfig={chartDef.config} 
                                                        readOnly={true} // Dashboard is mostly read-only for charts unless we open a full editor
                                                    />
                                                ) : (
                                                    <div className="absolute inset-0 flex items-center justify-center text-slate-600 text-xs">
                                                        {chartDef ? 'Waiting for data...' : 'Chart definition not found'}
                                                    </div>
                                                )}
                                            </>
                                        )}
                                    </div>

                                    {/* Chart Footer Info */}
                                    {widget.type === 'chart' && chartDef && (
                                        <div className="h-6 bg-slate-900 border-t border-slate-800 px-3 flex items-center justify-between text-[10px] text-slate-600 font-mono">
                                            <span className="truncate">{getDbName(chartDef.dbId)}</span>
                                            {results[widget.content] && <span>{results[widget.content].executionTimeMs}ms</span>}
                                        </div>
                                    )}
                                </div>
                              );
                          })}
                      </div>

                      {/* Add Widget Controls (Row Level) */}
                      {isDesignerMode && (
                          <div className="mt-2 flex justify-center opacity-0 group-hover/row:opacity-100 transition-opacity">
                              <div className="bg-slate-800 rounded-full border border-slate-700 p-1 flex space-x-1 shadow-lg transform translate-y-1/2">
                                  <button 
                                    onClick={() => handleAddWidget(row.id, 'chart')}
                                    className="px-3 py-1 text-xs rounded-full hover:bg-blue-600 hover:text-white text-slate-300 flex items-center transition-colors"
                                  >
                                      <BarChart3 size={12} className="mr-1" /> Add Chart
                                  </button>
                                  <div className="w-px bg-slate-700 my-1"></div>
                                  <button 
                                    onClick={() => handleAddWidget(row.id, 'markdown')}
                                    className="px-3 py-1 text-xs rounded-full hover:bg-purple-600 hover:text-white text-slate-300 flex items-center transition-colors"
                                  >
                                      <FileText size={12} className="mr-1" /> Add Text
                                  </button>
                              </div>
                          </div>
                      )}
                  </div>
              ))}

              {/* Add Row Button (Bottom) */}
              {isDesignerMode && (
                  <button 
                    onClick={handleAddRow}
                    className="w-full py-4 border-2 border-dashed border-slate-800 hover:border-slate-600 hover:bg-slate-900 rounded-xl flex items-center justify-center text-slate-500 hover:text-slate-300 transition-all"
                  >
                      <Plus size={20} className="mr-2" /> Add Layout Row
                  </button>
              )}
          </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useMemo, useState, useEffect } from 'react';
import { QueryResult, ChartConfig, ChartType } from '../types';
import { 
  BarChart, Bar, LineChart, Line, PieChart, Pie, AreaChart, Area,
  ScatterChart, Scatter, RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell
} from 'recharts';
import { 
  BarChart3, LineChart as LineChartIcon, PieChart as PieChartIcon, 
  Activity, ScatterChart as ScatterIcon, Hexagon,
  Pin, Save, Layers, Settings2, Sigma, ArrowRight, RefreshCw
} from 'lucide-react';

interface DataVisualizerProps {
  result: QueryResult;
  initialConfig?: ChartConfig;
  onPin?: (config: ChartConfig) => void;
  onSave?: (config: ChartConfig) => void;
  onUpdate?: (config: ChartConfig) => void; // New prop for updating
  onApplyAggregation?: (dimension: string, metric: string, func: string) => void;
  readOnly?: boolean; 
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#6366f1'];

const DataVisualizer: React.FC<DataVisualizerProps> = ({ result, initialConfig, onPin, onSave, onUpdate, onApplyAggregation, readOnly = false }) => {
  const [chartType, setChartType] = useState<ChartType>(initialConfig?.type || 'bar');
  const [xAxisKey, setXAxisKey] = useState<string>(initialConfig?.xAxisKey || '');
  const [dataKeys, setDataKeys] = useState<string[]>(initialConfig?.dataKeys || []);
  const [isStacked, setIsStacked] = useState<boolean>(!!initialConfig?.stackId);

  // Aggregation State
  const [aggDimension, setAggDimension] = useState<string>('');
  const [aggMetric, setAggMetric] = useState<string>('');
  const [aggFunc, setAggFunc] = useState<string>('COUNT');
  const [showAggPanel, setShowAggPanel] = useState(false);

  // Sync with props
  useEffect(() => {
    if (initialConfig) {
      setChartType(initialConfig.type);
      setXAxisKey(initialConfig.xAxisKey);
      setDataKeys(initialConfig.dataKeys);
      setIsStacked(!!initialConfig.stackId);
    }
  }, [initialConfig]);

  // Memoize data processing to avoid recalculation on every render
  const { numericColumns, stringColumns, formattedData } = useMemo(() => {
    if (!result || !result.rows.length) {
      return { numericColumns: [], stringColumns: [], formattedData: [] };
    }

    const cols = result.columns;
    const numCols: string[] = [];
    const strCols: string[] = [];

    // Analyze first row for types
    const sampleRow = result.rows[0];
    cols.forEach((col, idx) => {
      const val = sampleRow[idx];
      if (typeof val === 'number') numCols.push(col);
      else strCols.push(col);
    });

    // Transform array of arrays to array of objects
    const data = result.rows.map(row => {
      const obj: any = {};
      cols.forEach((col, idx) => {
        obj[col] = row[idx];
      });
      return obj;
    });

    return { numericColumns: numCols, stringColumns: strCols, formattedData: data };
  }, [result]);

  // Intelligent Defaults
  useEffect(() => {
    if (initialConfig || formattedData.length === 0) return;

    if (!xAxisKey) {
       // Prefer string column for X axis, otherwise first column
       const defaultX = stringColumns.length > 0 ? stringColumns[0] : result.columns[0];
       setXAxisKey(defaultX);
       setAggDimension(defaultX);
    }
    if (dataKeys.length === 0 && numericColumns.length > 0) {
       setDataKeys([numericColumns[0]]);
       setAggMetric(numericColumns[0]);
    } else if (result.columns.length > 0) {
       setAggMetric(result.columns[0]);
    }
  }, [formattedData, initialConfig]);

  if (result.error) return <div className="h-full flex items-center justify-center text-red-400 p-4">{result.error}</div>;
  if (result.rows.length === 0) return <div className="h-full flex items-center justify-center text-slate-500">No data to visualize</div>;

  // --- Handlers ---

  const handleDataKeyToggle = (key: string) => {
    setDataKeys(prev => 
      prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]
    );
  };

  const handleAggregationSubmit = () => {
    if (onApplyAggregation && aggDimension && aggMetric && aggFunc) {
      onApplyAggregation(aggDimension, aggMetric, aggFunc);
    }
  };

  const currentConfig: ChartConfig = {
    type: chartType,
    xAxisKey,
    dataKeys,
    stackId: isStacked ? 'a' : undefined
  };

  // --- Render Chart Content ---
  const renderChart = () => {
    const CommonAxisProps = {
      stroke: "#94a3b8",
      fontSize: 12,
      tickFormatter: (val: any) => `${val}`.length > 10 ? `${val}`.substring(0, 10) + '..' : val
    };

    const TooltipStyle = { 
        contentStyle: { backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9', borderRadius: '8px' },
        itemStyle: { color: '#e2e8f0' }
    };

    switch (chartType) {
      case 'line':
        return (
          <LineChart data={formattedData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.5} />
            <XAxis dataKey={xAxisKey} {...CommonAxisProps} />
            <YAxis {...CommonAxisProps} />
            <Tooltip {...TooltipStyle} />
            <Legend />
            {dataKeys.map((key, index) => (
              <Line 
                key={key} 
                type="monotone" 
                dataKey={key} 
                stroke={COLORS[index % COLORS.length]} 
                strokeWidth={2} 
                dot={{ r: 3 }} 
                activeDot={{ r: 5 }}
              />
            ))}
          </LineChart>
        );
      case 'area':
        return (
          <AreaChart data={formattedData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.5} />
            <XAxis dataKey={xAxisKey} {...CommonAxisProps} />
            <YAxis {...CommonAxisProps} />
            <Tooltip {...TooltipStyle} />
            <Legend />
            {dataKeys.map((key, index) => (
              <Area 
                key={key} 
                type="monotone" 
                dataKey={key} 
                stackId={isStacked ? "1" : undefined}
                stroke={COLORS[index % COLORS.length]} 
                fill={COLORS[index % COLORS.length]} 
                fillOpacity={isStacked ? 0.6 : 0.3}
              />
            ))}
          </AreaChart>
        );
      case 'pie':
        return (
          <PieChart>
             <Pie
                data={formattedData}
                dataKey={dataKeys[0] || numericColumns[0]}
                nameKey={xAxisKey}
                cx="50%"
                cy="50%"
                outerRadius={readOnly ? 80 : 100}
                fill="#8884d8"
                label={!readOnly}
              >
                {formattedData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip {...TooltipStyle} />
              {!readOnly && <Legend />}
          </PieChart>
        );
      case 'scatter':
         return (
           <ScatterChart>
             <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.5} />
             <XAxis type="category" dataKey={xAxisKey} name={xAxisKey} {...CommonAxisProps} />
             <YAxis type="number" dataKey={dataKeys[0]} name={dataKeys[0]} {...CommonAxisProps} />
             <Tooltip cursor={{ strokeDasharray: '3 3' }} {...TooltipStyle} />
             <Legend />
             {dataKeys.map((key, index) => (
                <Scatter key={key} name={key} data={formattedData} fill={COLORS[index % COLORS.length]} />
             ))}
           </ScatterChart>
         );
      case 'radar':
          return (
            <RadarChart cx="50%" cy="50%" outerRadius="80%" data={formattedData}>
              <PolarGrid stroke="#334155" />
              <PolarAngleAxis dataKey={xAxisKey} tick={{ fill: '#94a3b8', fontSize: 10 }} />
              <PolarRadiusAxis angle={30} domain={[0, 'auto']} tick={{ fill: '#94a3b8', fontSize: 10 }} />
              {dataKeys.map((key, index) => (
                <Radar
                    key={key}
                    name={key}
                    dataKey={key}
                    stroke={COLORS[index % COLORS.length]}
                    fill={COLORS[index % COLORS.length]}
                    fillOpacity={0.4}
                />
              ))}
              <Legend />
              <Tooltip {...TooltipStyle} />
            </RadarChart>
          );
      case 'bar':
      default:
        return (
          <BarChart data={formattedData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.5} />
            <XAxis dataKey={xAxisKey} {...CommonAxisProps} />
            <YAxis {...CommonAxisProps} />
            <Tooltip {...TooltipStyle} />
            <Legend />
            {dataKeys.map((key, index) => (
              <Bar 
                key={key} 
                dataKey={key} 
                stackId={isStacked ? "a" : undefined}
                fill={COLORS[index % COLORS.length]} 
                radius={isStacked ? [0,0,0,0] : [4, 4, 0, 0]}
              />
            ))}
          </BarChart>
        );
    }
  };

  return (
    <div className="h-full flex flex-col bg-slate-900">

      {/* Config Panel - Only visible when not readOnly */}
      {!readOnly && (
        <div className="p-3 border-b border-slate-800 bg-slate-850 flex flex-col space-y-2">

          <div className="flex flex-wrap items-center justify-between gap-4">

            {/* 1. Chart Type Selector */}
            <div className="flex space-x-1 bg-slate-800 p-1 rounded-lg">
               {[
                   { id: 'bar', icon: BarChart3, label: 'Bar' },
                   { id: 'line', icon: LineChartIcon, label: 'Line' },
                   { id: 'area', icon: Activity, label: 'Area' },
                   { id: 'pie', icon: PieChartIcon, label: 'Pie' },
                   { id: 'scatter', icon: ScatterIcon, label: 'Scatter' },
                   { id: 'radar', icon: Hexagon, label: 'Radar' },
               ].map((t) => (
                   <button 
                    key={t.id}
                    onClick={() => setChartType(t.id as ChartType)}
                    className={`p-2 rounded transition-colors ${chartType === t.id ? 'bg-slate-700 text-blue-400 shadow-sm' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-700/50'}`}
                    title={t.label}
                   >
                       <t.icon size={18} />
                   </button>
               ))}
            </div>

            {/* 2. Series Configuration */}
            <div className="flex flex-1 items-center space-x-4 min-w-[200px]">
                {/* X Axis */}
                <div className="flex flex-col">
                    <label className="text-[10px] text-slate-500 font-bold uppercase mb-0.5">X Axis</label>
                    <select 
                        value={xAxisKey} 
                        onChange={e => setXAxisKey(e.target.value)}
                        className="bg-slate-800 text-xs text-slate-200 border border-slate-700 rounded px-2 py-1.5 focus:border-blue-500 outline-none w-32"
                    >
                        {result.columns.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                </div>

                {/* Y Axis / Series (Multi-Select UI) */}
                <div className="flex flex-col flex-1">
                    <label className="text-[10px] text-slate-500 font-bold uppercase mb-0.5 flex items-center justify-between">
                        <span>Series / Values</span>
                        {(chartType === 'bar' || chartType === 'area') && (
                            <button 
                                onClick={() => setIsStacked(!isStacked)}
                                className={`flex items-center space-x-1 px-1.5 py-0.5 rounded text-[9px] border ${isStacked ? 'bg-blue-900/30 border-blue-600 text-blue-300' : 'border-slate-700 text-slate-500'}`}
                            >
                                <Layers size={10} /> <span>Stack</span>
                            </button>
                        )}
                    </label>
                    <div className="flex flex-wrap gap-2 max-h-[60px] overflow-y-auto no-scrollbar items-center">
                        {numericColumns.length > 0 ? numericColumns.map(col => (
                            <button
                                key={col}
                                onClick={() => handleDataKeyToggle(col)}
                                className={`flex items-center text-xs px-2 py-1 rounded-full border transition-all ${
                                    dataKeys.includes(col) 
                                    ? 'bg-blue-600 border-blue-500 text-white shadow-sm' 
                                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'
                                }`}
                            >
                                {col}
                            </button>
                        )) : <span className="text-xs text-slate-600 italic">No numeric columns found</span>}
                    </div>
                </div>
            </div>

            {/* 3. Action Buttons */}
            <div className="flex items-center space-x-2 border-l border-slate-800 pl-4">
                 <button
                    onClick={() => setShowAggPanel(!showAggPanel)}
                    className={`flex items-center px-3 py-1.5 rounded border transition-all text-xs ${showAggPanel ? 'bg-purple-900/30 border-purple-500 text-purple-300' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-slate-200'}`}
                    title="SQL Aggregation"
                 >
                     <Sigma size={14} className="mr-2" /> Summarize
                 </button>

                 {onUpdate ? (
                     <button 
                        onClick={() => onUpdate(currentConfig)}
                        className="flex items-center px-3 py-1.5 bg-green-600 hover:bg-green-500 text-white text-xs rounded border border-green-500 shadow transition-all animate-in fade-in"
                     >
                        <RefreshCw size={14} className="mr-2" /> Update Chart
                     </button>
                 ) : onPin && (
                   <button 
                     onClick={() => onPin(currentConfig)}
                     className="flex items-center px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs rounded border border-slate-700 transition-all hover:border-blue-500 hover:text-blue-400"
                   >
                     <Pin size={14} className="mr-2" /> Pin
                   </button>
                 )}
                 {onSave && (
                    <button 
                      onClick={() => onSave(currentConfig)}
                      className="flex items-center px-3 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-xs rounded shadow transition-all"
                    >
                      <Save size={14} className="mr-2" /> Save
                    </button>
                 )}
            </div>
          </div>

          {/* Aggregation Panel (Expandable) */}
          {showAggPanel && (
              <div className="flex items-center bg-slate-900/50 border border-slate-800 p-2 rounded-lg space-x-3 text-xs animate-in slide-in-from-top-2 duration-200">
                  <div className="flex flex-col">
                      <label className="text-[9px] uppercase text-slate-500 font-bold mb-0.5">Dimension (Group By)</label>
                      <select 
                        value={aggDimension}
                        onChange={(e) => setAggDimension(e.target.value)}
                        className="bg-slate-800 border border-slate-700 rounded px-2 py-1 outline-none focus:border-purple-500 text-slate-300 w-32"
                      >
                          {result.columns.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                  </div>
                  <div className="flex flex-col">
                      <label className="text-[9px] uppercase text-slate-500 font-bold mb-0.5">Measure (Value)</label>
                      <select 
                        value={aggMetric}
                        onChange={(e) => setAggMetric(e.target.value)}
                        className="bg-slate-800 border border-slate-700 rounded px-2 py-1 outline-none focus:border-purple-500 text-slate-300 w-32"
                      >
                           {result.columns.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                  </div>
                  <div className="flex flex-col">
                      <label className="text-[9px] uppercase text-slate-500 font-bold mb-0.5">Function</label>
                      <select 
                        value={aggFunc}
                        onChange={(e) => setAggFunc(e.target.value)}
                        className="bg-slate-800 border border-slate-700 rounded px-2 py-1 outline-none focus:border-purple-500 text-slate-300 w-24"
                      >
                          {['COUNT', 'SUM', 'AVG', 'MIN', 'MAX'].map(f => <option key={f} value={f}>{f}</option>)}
                      </select>
                  </div>
                  <div className="flex flex-col justify-end h-full pt-4">
                      <button 
                        onClick={handleAggregationSubmit}
                        className="flex items-center px-3 py-1 bg-purple-600 hover:bg-purple-500 text-white rounded shadow-sm hover:shadow-purple-500/20 transition-all"
                      >
                          <ArrowRight size={12} className="mr-1" /> Run Query
                      </button>
                  </div>
              </div>
          )}
        </div>
      )}

      {/* Render Area */}
      <div className="flex-1 min-h-0 p-2">
        <ResponsiveContainer width="100%" height="100%">
            {renderChart()}
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default DataVisualizer;

import React from 'react';
import { QueryResult, ChartConfig } from '../types';
import { 
  Play, Table as TableIcon, LayoutTemplate, 
  PanelBottom, PanelRight, PanelLeft, AppWindow, 
  GripHorizontal 
} from 'lucide-react';
import DataTable from './DataTable';
import DataVisualizer from './DataVisualizer';

interface ResultsPaneProps {
  result: QueryResult | null;
  viewMode: 'table' | 'chart';
  setViewMode: (mode: 'table' | 'chart') => void;
  layout: 'bottom' | 'right' | 'left' | 'float';
  setLayout: (layout: 'bottom' | 'right' | 'left' | 'float') => void;
  onHeaderMouseDown?: (e: React.MouseEvent) => void;
  onPinChart?: (config: ChartConfig) => void;
  onUpdateChart?: (config: ChartConfig) => void; // New prop
  onApplyAggregation?: (dimension: string, metric: string, func: string) => void;
}

const ResultsPane: React.FC<ResultsPaneProps> = ({ 
  result, 
  viewMode, 
  setViewMode, 
  layout, 
  setLayout,
  onHeaderMouseDown,
  onPinChart,
  onUpdateChart,
  onApplyAggregation
}) => {
  return (
    <div className="flex flex-col h-full w-full bg-slate-900 overflow-hidden relative shadow-inner">
      {/* Result Toolbar */}
      <div 
        className={`h-10 border-b border-slate-800 flex items-center justify-between px-4 bg-slate-850 select-none ${layout === 'float' ? 'cursor-move' : ''}`}
        onMouseDown={layout === 'float' ? onHeaderMouseDown : undefined}
      >
        <div className="flex items-center space-x-4">
            {layout === 'float' && <GripHorizontal size={14} className="text-slate-600 mr-2" />}
            <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Output</span>
             <div className="flex space-x-1 bg-slate-800 p-0.5 rounded ml-2" onMouseDown={e => e.stopPropagation()}>
                <button 
                    onClick={() => setViewMode('table')}
                    className={`px-3 py-1 text-xs rounded flex items-center ${viewMode === 'table' ? 'bg-slate-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
                >
                    <TableIcon size={12} className="mr-1.5" /> Table
                </button>
                <button 
                    onClick={() => setViewMode('chart')}
                    className={`px-3 py-1 text-xs rounded flex items-center ${viewMode === 'chart' ? 'bg-slate-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
                >
                    <LayoutTemplate size={12} className="mr-1.5" /> Chart
                </button>
            </div>
        </div>

        {/* Layout Controls */}
        <div className="flex items-center space-x-1 border-l border-slate-700 pl-4 ml-4" onMouseDown={e => e.stopPropagation()}>
            <button 
                onClick={() => setLayout('bottom')}
                className={`p-1.5 rounded ${layout === 'bottom' ? 'text-blue-400 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`}
                title="Dock Bottom"
            >
                <PanelBottom size={14} />
            </button>
            <button 
                onClick={() => setLayout('right')}
                className={`p-1.5 rounded ${layout === 'right' ? 'text-blue-400 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`}
                title="Dock Right"
            >
                <PanelRight size={14} />
            </button>
             <button 
                onClick={() => setLayout('left')}
                className={`p-1.5 rounded ${layout === 'left' ? 'text-blue-400 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`}
                title="Dock Left"
            >
                <PanelLeft size={14} />
            </button>
             <button 
                onClick={() => setLayout('float')}
                className={`p-1.5 rounded ${layout === 'float' ? 'text-blue-400 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`}
                title="Float Window"
            >
                <AppWindow size={14} />
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden relative bg-slate-900">
        {!result ? (
            <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 opacity-50 pointer-events-none">
                <Play size={48} className="mb-4 stroke-1" />
                <p>Run a query to see results</p>
            </div>
        ) : (
            <>
                {viewMode === 'table' ? (
                    <DataTable result={result} />
                ) : (
                    <DataVisualizer 
                      result={result} 
                      onPin={onPinChart} 
                      onUpdate={onUpdateChart}
                      onApplyAggregation={onApplyAggregation}
                    />
                )}
            </>
        )}
      </div>
    </div>
  );
};

export default ResultsPane;

import React, { useState, useEffect, useRef } from 'react';
import { Database, EditorTab, QueryResult, ChartConfig, PinnedChart, DashboardLayout, AppSettings, SavedQuery, DbSchema, SchemaLayout } from './types';
import { muulService } from './services/muulService';
import { exportService } from './services/exportService';
import { 
  Play, Plus, X, Save, Download, Database as DbIcon, 
  Activity, Ban, ChevronDown, ChevronUp, ChevronRight,
  LayoutDashboard, TerminalSquare, Settings, Bookmark, FolderOpen, Upload, Table as TableIcon,
  Network
} from 'lucide-react';
import SqlEditor, { SqlEditorRef } from './components/SqlEditor';
import ResultsPane from './components/ResultsPane';
import Dashboard from './components/Dashboard';
import SchemaVisualizer from './components/SchemaVisualizer';
import SettingsModal from './components/SettingsModal';

type LayoutMode = 'bottom' | 'right' | 'left' | 'float';
type ViewMode = 'editor' | 'dashboard' | 'schema';
type SidebarTab = 'db' | 'saved';

const App: React.FC = () => {
  // --- State ---
  const [currentView, setCurrentView] = useState<ViewMode>('editor');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('db');
  const [databases, setDatabases] = useState<Database[]>([]);
  const [selectedDbId, setSelectedDbId] = useState<string>('');

  // Tables state: key is dbId, value is array of table names
  const [dbTables, setDbTables] = useState<Record<string, string[]>>({});
  const [expandedDbIds, setExpandedDbIds] = useState<Set<string>>(new Set());

  // Schema & Layouts for Visualizer
  const [activeSchema, setActiveSchema] = useState<DbSchema>({ tables: [] });
  const [schemaLayouts, setSchemaLayouts] = useState<SchemaLayout[]>([]);
  const [activeLayoutId, setActiveLayoutId] = useState<string | null>(null);

  const [isDraggingFile, setIsDraggingFile] = useState(false);

  // App Settings
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [appSettings, setAppSettings] = useState<AppSettings>({
    editorFontSize: 14,
    themeAccent: 'blue',
    refreshRate: 0
  });

  // Saved Data
  const [savedQueries, setSavedQueries] = useState<SavedQuery[]>([
      { id: 'sq-1', name: 'Get All Users', content: 'SELECT * FROM users LIMIT 100;', dbId: 'db-1', createdAt: Date.now() }
  ]);

  // Dashboard Data State
  const [pinnedCharts, setPinnedCharts] = useState<PinnedChart[]>([]);
  const [dashboards, setDashboards] = useState<DashboardLayout[]>([
      {
          id: 'main-dash',
          title: 'Main Dashboard',
          isDefault: true,
          rows: [
              {
                  id: 'row-welcome',
                  widgets: [
                      { id: 'w-welcome', type: 'markdown', colSpan: 12, title: 'Welcome', content: '# Welcome to Muul SQL\nDrag and drop **.csv**, **.json**, **.parquet**, or **.sqlite** files to instantly query them!'}
                  ]
              }
          ]
      }
  ]);
  const [activeDashboardId, setActiveDashboardId] = useState<string>('main-dash');

  // Editor State
  const [tabs, setTabs] = useState<EditorTab[]>([
    { 
      id: 'tab-1', 
      title: 'Query 1', 
      content: '', 
      isDirty: false, 
      isExecuting: false, 
      results: [],
      activeResultIndex: -1 
    }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab-1');
  const [resultViewMode, setResultViewMode] = useState<'table' | 'chart'>('table');
  const [isEditorExpanded, setIsEditorExpanded] = useState(true);

  // Layout State
  const [layout, setLayout] = useState<LayoutMode>('bottom');
  const [panelSize, setPanelSize] = useState(40); // Percentage for docked mode
  const [floatRect, setFloatRect] = useState({ x: 100, y: 100, w: 600, h: 400 });

  // --- Refs ---
  const editorRef = useRef<SqlEditorRef>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const dragInfo = useRef<{ 
    isDragging: boolean; 
    type: 'resize-dock' | 'move-float' | 'resize-float'; 
    startX: number; 
    startY: number; 
    startSize?: number;
    startRect?: typeof floatRect;
  }>({ isDragging: false, type: 'resize-dock', startX: 0, startY: 0 });

  // --- Effects ---
  useEffect(() => {
    muulService.getDatabases().then(dbs => {
      setDatabases(dbs);
      if (dbs.length > 0) {
          setSelectedDbId(dbs[0].id);
          // Auto expand the first one
          setExpandedDbIds(new Set([dbs[0].id]));
      }
    });
  }, []);

  // Fetch tables AND Schema when a DB is expanded or selected
  useEffect(() => {
      if (selectedDbId) {
          // Fetch simple table list
          if (!dbTables[selectedDbId]) {
              muulService.getDatabaseTables(selectedDbId).then(tables => {
                  setDbTables(prev => ({ ...prev, [selectedDbId]: tables }));
              });
          }
          // Fetch Full Schema (for Visualizer)
          muulService.getDatabaseSchema(selectedDbId).then(schema => {
              setActiveSchema(schema);

              // Ensure a default layout exists
              setSchemaLayouts(prev => {
                  const hasLayout = prev.some(l => l.dbId === selectedDbId);
                  if (!hasLayout && schema.tables.length > 0) {
                      const defaultLayout: SchemaLayout = {
                          id: `layout-${Date.now()}`,
                          name: 'Main Diagram',
                          dbId: selectedDbId,
                          tables: schema.tables.map(t => t.name),
                          createdAt: Date.now()
                      };
                      setActiveLayoutId(defaultLayout.id);
                      return [...prev, defaultLayout];
                  }
                  // If layouts exist but none active for this DB, activate first one
                  const dbLayouts = prev.filter(l => l.dbId === selectedDbId);
                  if (dbLayouts.length > 0 && (!activeLayoutId || !dbLayouts.find(l => l.id === activeLayoutId))) {
                      setActiveLayoutId(dbLayouts[0].id);
                  }
                  return prev;
              });
          });
      }
  }, [selectedDbId]);

  // Ensure activeLayoutId is valid when switching DBs manually
  useEffect(() => {
      if (selectedDbId) {
           const dbLayouts = schemaLayouts.filter(l => l.dbId === selectedDbId);
           if (dbLayouts.length > 0) {
               // If current active layout is not for this DB, switch to the first one for this DB
               const active = schemaLayouts.find(l => l.id === activeLayoutId);
               if (!active || active.dbId !== selectedDbId) {
                   setActiveLayoutId(dbLayouts[0].id);
               }
           } else {
               setActiveLayoutId(null);
           }
      }
  }, [selectedDbId, schemaLayouts]);


  // --- Layout Handlers ---
  const handleLayoutCreate = (name: string, tables: string[]) => {
      if (!selectedDbId) return;
      const newLayout: SchemaLayout = {
          id: `layout-${Date.now()}`,
          name,
          dbId: selectedDbId,
          tables,
          createdAt: Date.now()
      };
      setSchemaLayouts(prev => [...prev, newLayout]);
      setActiveLayoutId(newLayout.id);
  };

  const handleLayoutUpdate = (layoutId: string, tables: string[]) => {
      setSchemaLayouts(prev => prev.map(l => l.id === layoutId ? { ...l, tables } : l));
  };

  const handleLayoutDelete = (layoutId: string) => {
      const remaining = schemaLayouts.filter(l => l.id !== layoutId);
      setSchemaLayouts(remaining);

      // Select another layout if current was deleted
      if (activeLayoutId === layoutId) {
          const others = remaining.filter(l => l.dbId === selectedDbId);
          setActiveLayoutId(others.length > 0 ? others[0].id : null);
      }
  };


  // Global mouse event handlers for dragging/resizing
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragInfo.current.isDragging) return;

      const { type, startX, startY, startSize, startRect } = dragInfo.current;
      const container = containerRef.current;

      if (type === 'resize-dock' && container && startSize !== undefined) {
        const rect = container.getBoundingClientRect();
        let delta = 0;
        let newSize = startSize;

        if (layout === 'bottom') {
           delta = (startY - e.clientY) / rect.height * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'right') {
           delta = (startX - e.clientX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'left') {
           delta = (e.clientX - startX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        }
        setPanelSize(newSize);
      } 
      else if (type === 'move-float' && startRect) {
        setFloatRect({
          ...startRect,
          x: startRect.x + (e.clientX - startX),
          y: startRect.y + (e.clientY - startY)
        });
      }
      else if (type === 'resize-float' && startRect) {
        setFloatRect({
          ...startRect,
          w: Math.max(300, startRect.w + (e.clientX - startX)),
          h: Math.max(200, startRect.h + (e.clientY - startY))
        });
      }
    };

    const handleMouseUp = () => {
      dragInfo.current.isDragging = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [layout]);

  // --- Drag & Drop Handlers for Files ---
  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    // Only leave if we actually left the window/container
    if (e.currentTarget === e.target) {
        setIsDraggingFile(false);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
  };

  const handleFileDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);

    const files: File[] = Array.from(e.dataTransfer.files);
    if (files.length === 0) return;

    for (const file of files) {
        if (file.name.endsWith('.sqlite') || file.name.endsWith('.db') || file.name.endsWith('.csv') || file.name.endsWith('.json') || file.name.endsWith('.parquet')) {
            try {
                const newDb = await muulService.uploadDatabase(file);
                setDatabases(prev => [newDb, ...prev]);
                setSelectedDbId(newDb.id);
                setExpandedDbIds(prev => new Set(prev).add(newDb.id));

                // Fetch tables immediately
                const tables = await muulService.getDatabaseTables(newDb.id);
                setDbTables(prev => ({ ...prev, [newDb.id]: tables }));

            } catch (err: any) {
                alert(`Failed to load ${file.name}: ${err.message}`);
            }
        } else {
            alert(`File ${file.name} is not supported. Please drop .sqlite, .db, .csv, .json, or .parquet files.`);
        }
    }
  };


  // --- Helpers ---
  const activeTab = tabs.find(t => t.id === activeTabId)!;
  const activeResult = activeTab?.activeResultIndex >= 0 
    ? activeTab.results[activeTab.activeResultIndex] 
    : null;
  const selectedDb = databases.find(d => d.id === selectedDbId);

  // --- Actions ---

  const handleDbClick = (dbId: string) => {
      setSelectedDbId(dbId);
      setExpandedDbIds(prev => {
          const next = new Set(prev);
          if (next.has(dbId)) next.delete(dbId);
          else next.add(dbId);
          return next;
      });
  };

  const handleTableClick = (tableName: string) => {
      // Check if there is an existing, unmodified tab for this table
      const existingTab = tabs.find(t => t.title === tableName && !t.isDirty);

      if (existingTab) {
          setActiveTabId(existingTab.id);
          setCurrentView('editor'); // Ensure we switch back to editor
          return;
      }

      const newId = `tab-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: tableName,
          content: `SELECT * FROM "${tableName}" LIMIT 100;`,
          isDirty: false, // Initially clean so we can detect if user modifies it later
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
  };

  const handleCreateTab = () => {
    const newId = `tab-${Date.now()}`;
    setTabs([...tabs, {
      id: newId, title: `Query ${tabs.length + 1}`, content: '', isDirty: false, isExecuting: false, results: [], activeResultIndex: -1
    }]);
    setActiveTabId(newId);
  };

  const handleOpenSavedQuery = (sq: SavedQuery) => {
      const newId = `tab-${Date.now()}`;
      setTabs([...tabs, {
          id: newId,
          title: sq.name,
          content: sq.content,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      if(sq.dbId) setSelectedDbId(sq.dbId);
      setCurrentView('editor');
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (tabs.length === 1) return;
    const newTabs = tabs.filter(t => t.id !== id);
    setTabs(newTabs);
    if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
  };

  const executeTabQuery = async (tabId: string, content: string, selectionOnly: boolean = false) => {
    if (!selectedDbId) return alert("Please select a database first.");

    let queriesToRun = [content];
    if (selectionOnly) {
         // This logic is currently inside handleRunQuery mainly via ref,
         // but here we are called programmatically with content.
         queriesToRun = content.split(';').map(q => q.trim()).filter(q => q.length > 0);
    }

    if (queriesToRun.length === 0) return;

    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: true } : t));
    const executionId = Date.now().toString();

    try {
      const results: QueryResult[] = [];
      for (const query of queriesToRun) {
        const result = await muulService.executeQuery(selectedDbId, query, executionId);
        results.push(result);
        if (result.error) break; 
      }
      setTabs(prev => prev.map(t => t.id === tabId ? {
        ...t, isExecuting: false, results: [results[results.length - 1], ...t.results], activeResultIndex: 0
      } : t));
    } catch (e) {
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: false } : t));
    }
  };

  const handleRunQuery = async () => {
    const editor = editorRef.current;
    if (!editor) return;

    const selection = editor.getSelection();
    if (selection.text.trim().length > 0) {
        // Run specific selection but don't split by semicolon if selection
        // Actually executeTabQuery logic above splits by semicolon which might be wrong for selection
        // Let's keep logic simple:
        if (!selectedDbId) return alert("Please select a database first.");
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: true } : t));
        const result = await muulService.executeQuery(selectedDbId, selection.text, Date.now().toString());
        setTabs(prev => prev.map(t => t.id === activeTabId ? {
            ...t, isExecuting: false, results: [result, ...t.results], activeResultIndex: 0
        } : t));
    } else {
        // Run full content (support multiple statements)
        executeTabQuery(activeTabId, activeTab.content, true);
    }
  };

  const handleApplyAggregation = (dimension: string, metric: string, func: string) => {
      const currentQuery = activeTab.content.trim().replace(/;$/, '');
      if (!currentQuery) return;

      const newQuery = `SELECT \n  "${dimension}", \n  ${func}("${metric}") as "${metric}_${func}" \nFROM (\n${currentQuery}\n) \nGROUP BY "${dimension}"`;

      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: newQuery, isDirty: true } : t));

      // Execute immediately
      setTimeout(() => {
          executeTabQuery(activeTabId, newQuery, true);
      }, 50);
  };

  const handleCancelQuery = () => {
    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
  };

  const handleSaveQuery = () => {
      if(!activeTab.content.trim()) return alert("Query is empty.");
      const name = prompt("Save Query As:", activeTab.title);
      if(!name) return;

      const newSaved: SavedQuery = {
          id: `sq-${Date.now()}`,
          name,
          content: activeTab.content,
          dbId: selectedDbId,
          createdAt: Date.now()
      };
      setSavedQueries([...savedQueries, newSaved]);
      // Update current tab name
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, title: name, isDirty: false } : t));
  };

  const handleDownloadCSV = () => {
      if(!activeResult) return;
      exportService.downloadCSV(activeResult, `result-${Date.now()}.csv`);
  };

  // --- Pinning & Dashboard Management ---

  const handlePinChart = (config: ChartConfig) => {
    if (!activeResult || !selectedDbId) return;

    // 1. Create the Chart Definition
    const chartId = `chart-${Date.now()}`;
    const newPin: PinnedChart = {
      id: chartId,
      title: `${activeTab.title} Chart`,
      query: activeTab.content, // Simplified: uses whole content
      dbId: selectedDbId,
      config: config,
      createdAt: Date.now()
    };
    setPinnedCharts(prev => [...prev, newPin]);

    // 2. Add to Active Dashboard (or default)
    setDashboards(prev => {
        return prev.map(dash => {
            if (dash.id !== activeDashboardId) return dash;

            const newWidget = {
                id: `w-${Date.now()}`,
                type: 'chart' as const,
                colSpan: 6, // Default to half width
                content: chartId,
                title: newPin.title
            };

            const lastRow = dash.rows[dash.rows.length - 1];
            if (lastRow && lastRow.widgets.reduce((acc, w) => acc + w.colSpan, 0) <= 6) {
                // Fit in last row
                return {
                    ...dash,
                    rows: dash.rows.map(r => r.id === lastRow.id ? { ...r, widgets: [...r.widgets, newWidget] } : r)
                };
            } else {
                // New Row
                return {
                    ...dash,
                    rows: [...dash.rows, { id: `row-${Date.now()}`, widgets: [newWidget] }]
                };
            }
        });
    });

    alert("Chart pinned to active dashboard!");
  };

  const handleUpdatePinnedChart = (newConfig: ChartConfig) => {
    if (!activeTab.linkedChartId || !selectedDbId) return;

    // Update the PinnedChart definition
    setPinnedCharts(prev => prev.map(c => {
        if (c.id === activeTab.linkedChartId) {
            return {
                ...c,
                query: activeTab.content, // Update query with current editor content
                config: newConfig, // Update visual config
                dbId: selectedDbId // Ensure DB ID is synced if changed
            };
        }
        return c;
    }));

    alert("Chart updated successfully!");
  };

  const handleEditChart = (chartId: string) => {
      const chart = pinnedCharts.find(c => c.id === chartId);
      if (!chart) return;

      const newId = `tab-edit-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: `Edit: ${chart.title}`,
          content: chart.query,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1,
          linkedChartId: chart.id // Link this tab to the chart
      }]);
      setActiveTabId(newId);

      // Ensure we switch to the DB used by the chart
      if (chart.dbId) setSelectedDbId(chart.dbId);

      setCurrentView('editor');

      // Auto-run to show current state
      setTimeout(() => {
          executeTabQuery(newId, chart.query);
          setResultViewMode('chart'); // Switch to chart view immediately
      }, 100);
  };

  const handleAddDashboard = (title: string) => {
      const newDash: DashboardLayout = {
          id: `dash-${Date.now()}`,
          title,
          isDefault: false,
          rows: []
      };
      setDashboards([...dashboards, newDash]);
      setActiveDashboardId(newDash.id);
  };

  const handleDeleteDashboard = (id: string) => {
      if (dashboards.length <= 1) return alert("Cannot delete the last dashboard.");
      const newDashboards = dashboards.filter(d => d.id !== id);
      setDashboards(newDashboards);
      if (activeDashboardId === id) setActiveDashboardId(newDashboards[0].id);
  };

  const handleUpdateDashboard = (updatedLayout: DashboardLayout) => {
      setDashboards(prev => prev.map(d => d.id === updatedLayout.id ? updatedLayout : d));
  };

  const handleRemoveChartDefinition = (id: string) => {
      setPinnedCharts(prev => prev.filter(c => c.id !== id));
      // Also remove widgets referencing this chart from ALL dashboards
      setDashboards(prev => prev.map(dash => ({
          ...dash,
          rows: dash.rows.map(row => ({
              ...row,
              widgets: row.widgets.filter(w => w.type !== 'chart' || w.content !== id)
          }))
      })));
  };

  const handleUpdateChartDefinition = (id: string, newConfig: ChartConfig) => {
      setPinnedCharts(prev => prev.map(c => c.id === id ? { ...c, config: newConfig } : c));
  };

  // --- Drag Starters ---
  const startDockResize = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { 
        isDragging: true, 
        type: 'resize-dock', 
        startX: e.clientX, 
        startY: e.clientY, 
        startSize: panelSize 
    };
    document.body.style.cursor = layout === 'bottom' ? 'row-resize' : 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const startFloatMove = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { isDragging: true, type: 'move-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  const startFloatResize = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragInfo.current = { isDragging: true, type: 'resize-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  return (
    <div 
        className={`flex h-screen w-screen bg-slate-950 text-slate-200 overflow-hidden font-sans ${appSettings.themeAccent}-accent relative`}
        onDragEnter={handleDragEnter}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleFileDrop}
    >

      {/* Drag Overlay */}
      {isDraggingFile && (
          <div className="absolute inset-0 z-[100] bg-blue-500/20 backdrop-blur-sm border-4 border-dashed border-blue-400 m-4 rounded-xl flex flex-col items-center justify-center pointer-events-none">
              <Upload size={64} className="text-blue-400 mb-4" />
              <h2 className="text-2xl font-bold text-white">Drop File to Import</h2>
              <p className="text-blue-200">Supports .csv, .json, .sqlite, .db, .parquet</p>
          </div>
      )}

      {/* Settings Modal */}
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={appSettings} 
        onSave={setAppSettings}
      />

      {/* Activity Bar (Sidebar) */}
      <aside className="w-12 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-4 space-y-4 shrink-0 z-50">
        <div className="text-blue-500 mb-2"><DbIcon size={24} /></div>

        <button 
          onClick={() => setCurrentView('editor')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'editor' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="SQL Editor"
        >
          <TerminalSquare size={20} />
        </button>

        <button 
          onClick={() => setCurrentView('dashboard')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'dashboard' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="Dashboard"
        >
          <LayoutDashboard size={20} />
        </button>

        <button 
          onClick={() => setCurrentView('schema')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'schema' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="Schema Visualizer"
        >
          <Network size={20} />
        </button>

        <div className="h-px w-6 bg-slate-800 my-2"></div>

        {/* Saved Queries Toggle (Only meaningful in Editor View, effectively) */}
        <button 
            onClick={() => { setCurrentView('editor'); setSidebarTab('saved'); }}
            className={`p-2 rounded-lg transition-colors ${currentView === 'editor' && sidebarTab === 'saved' ? 'bg-slate-800 text-purple-400' : 'text-slate-500 hover:text-slate-300'}`}
            title="Saved Queries"
        >
            <Bookmark size={20} />
        </button>

        <div className="flex-1" />
        <button 
            onClick={() => setIsSettingsOpen(true)}
            className="p-2 text-slate-500 hover:text-slate-300 hover:bg-slate-800 rounded transition-colors"
        >
            <Settings size={20} />
        </button>
      </aside>

      {/* Explorer / Sidebar Panel (Conditional) */}
      {(currentView === 'editor' || currentView === 'schema') && (
          <div className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col min-h-0">
             <div className="h-10 flex items-center px-4 font-bold text-xs uppercase tracking-wider text-slate-500 border-b border-slate-800 shrink-0">
                {sidebarTab === 'db' ? 'Databases' : 'Saved Queries'}
             </div>

             {/* Database List */}
             {sidebarTab === 'db' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {databases.map(db => (
                        <div key={db.id} className="mb-1">
                            <div 
                                onClick={() => handleDbClick(db.id)}
                                className={`flex items-center p-2 rounded cursor-pointer transition-colors ${selectedDbId === db.id ? 'bg-slate-800 text-slate-200' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-300'}`}
                            >
                                <div className={`mr-2 transition-transform ${expandedDbIds.has(db.id) ? 'rotate-90' : ''}`}>
                                    <ChevronRight size={14} />
                                </div>
                                <DbIcon size={14} className="mr-2 text-blue-500/80" />
                                <div className="flex flex-col truncate">
                                    <span className="text-sm truncate font-medium">{db.name}</span>
                                </div>
                            </div>

                            {/* Table List (Indented) */}
                            {expandedDbIds.has(db.id) && (
                                <div className="ml-6 pl-2 border-l border-slate-800 mt-1 space-y-0.5">
                                    {dbTables[db.id] && dbTables[db.id].length > 0 ? (
                                        dbTables[db.id].map(tbl => (
                                            <div 
                                                key={tbl} 
                                                onClick={() => handleTableClick(tbl)}
                                                className="flex items-center px-2 py-1.5 text-xs text-slate-500 hover:text-blue-300 hover:bg-slate-800/50 rounded cursor-pointer group"
                                            >
                                                <TableIcon size={12} className="mr-2 opacity-50 group-hover:opacity-100" />
                                                <span className="truncate">{tbl}</span>
                                            </div>
                                        ))
                                    ) : (
                                        <div className="px-2 py-1 text-[10px] text-slate-600 italic">No tables found or loading...</div>
                                    )}
                                </div>
                            )}
                        </div>
                    ))}
                    <div className="mt-4 p-4 border border-dashed border-slate-800 rounded mx-2 text-center text-slate-600 text-xs select-none pointer-events-none">
                        Drop SQLite, CSV, JSON, or Parquet file
                    </div>
                </div>
             )}

             {/* Saved Queries List */}
             {sidebarTab === 'saved' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {savedQueries.length === 0 && <div className="text-slate-600 text-xs text-center mt-4">No saved queries.</div>}
                    {savedQueries.map(sq => (
                        <div 
                            key={sq.id} 
                            onClick={() => handleOpenSavedQuery(sq)}
                            className="group flex items-start p-2 mb-1 rounded cursor-pointer transition-colors text-slate-400 hover:bg-slate-800 hover:text-slate-200"
                        >
                            <FolderOpen size={14} className="mr-2 mt-0.5 text-purple-400" />
                            <div className="flex flex-col truncate flex-1">
                                <span className="text-sm truncate font-medium">{sq.name}</span>
                                <span className="text-[10px] text-slate-500 truncate">{new Date(sq.createdAt).toLocaleDateString()}</span>
                            </div>
                        </div>
                    ))}
                    <button 
                        onClick={() => setSidebarTab('db')} 
                        className="mt-4 w-full flex items-center justify-center p-2 text-xs text-slate-500 hover:text-slate-300 border border-dashed border-slate-800 rounded hover:bg-slate-800"
                    >
                         Back to Databases
                    </button>
                </div>
             )}
          </div>
      )}

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 h-full overflow-hidden relative">

        {/* VIEW: DASHBOARD */}
        {currentView === 'dashboard' && (
             <Dashboard 
                dashboards={dashboards}
                pinnedCharts={pinnedCharts} 
                databases={databases}
                activeDashboardId={activeDashboardId}
                refreshRate={appSettings.refreshRate}
                onSetActiveDashboard={setActiveDashboardId}
                onAddDashboard={handleAddDashboard}
                onUpdateDashboard={handleUpdateDashboard}
                onDeleteDashboard={handleDeleteDashboard}
                onRemoveChartDefinition={handleRemoveChartDefinition}
                onUpdateChartDefinition={handleUpdateChartDefinition}
                onEditChart={handleEditChart}
             />
        )}

        {/* VIEW: SCHEMA VISUALIZER */}
        {currentView === 'schema' && (
            <SchemaVisualizer 
                schema={activeSchema} 
                dbName={selectedDb?.name || 'Selected Database'}
                layouts={schemaLayouts.filter(l => l.dbId === selectedDbId)}
                activeLayoutId={activeLayoutId}
                onLayoutCreate={handleLayoutCreate}
                onLayoutSelect={setActiveLayoutId}
                onLayoutUpdate={handleLayoutUpdate}
                onLayoutDelete={handleLayoutDelete}
            />
        )}

        {/* VIEW: EDITOR */}
        <div className={`flex-1 flex flex-col h-full w-full ${currentView === 'dashboard' || currentView === 'schema' ? 'hidden' : 'flex'}`}>
            <header className="h-14 border-b border-slate-800 bg-slate-900 flex items-center px-4 justify-between shrink-0 z-30 relative">
              <div className="flex items-center space-x-4">
                <div className="flex items-center text-blue-400 font-bold text-lg tracking-tight">
                  Muul<span className="text-slate-100">SQL</span>
                </div>
                <div className="h-6 w-px bg-slate-700 mx-2"></div>
                <div className="relative group">
                  <select 
                    value={selectedDbId}
                    onChange={(e) => setSelectedDbId(e.target.value)}
                    className="appearance-none bg-slate-800 hover:bg-slate-700 border border-slate-700 text-xs rounded py-1.5 pl-3 pr-8 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors w-64 cursor-pointer"
                  >
                    {databases.map(db => (
                      <option key={db.id} value={db.id}>{db.type.toUpperCase()} • {db.name}</option>
                    ))}
                  </select>
                  <Activity size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400" />
                </div>
              </div>

              <div className="flex items-center space-x-2">
                  {activeTab.isExecuting ? (
                      <button onClick={handleCancelQuery} className="flex items-center px-4 py-1.5 bg-red-600 hover:bg-red-700 text-white text-sm font-medium rounded shadow animate-pulse">
                        <Ban size={16} className="mr-2" /> Cancel
                      </button>
                  ) : (
                      <button onClick={handleRunQuery} className="flex items-center px-4 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium rounded shadow hover:shadow-blue-500/20 active:scale-95">
                        <Play size={16} className="mr-2 fill-current" /> Run
                      </button>
                  )}
                  <div className="h-6 w-px bg-slate-700 mx-2"></div>

                  {/* Save Button */}
                  <button 
                    onClick={handleSaveQuery} 
                    className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded transition-colors"
                    title="Save Query"
                  >
                    <Save size={18} />
                  </button>

                  {/* Download Button */}
                  <button 
                    onClick={handleDownloadCSV}
                    disabled={!activeResult}
                    className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded disabled:opacity-30 transition-colors"
                    title="Download Result CSV"
                  >
                    <Download size={18} />
                  </button>
              </div>
            </header>

            {/* Tabs Container */}
            <div className="flex items-center bg-slate-900 border-b border-slate-800 pr-2 pt-2 shrink-0">
              <div className="flex-1 flex overflow-x-auto no-scrollbar items-end px-2">
                  {tabs.map(tab => (
                    <div key={tab.id} onClick={() => setActiveTabId(tab.id)} className={`group flex items-center min-w-[150px] max-w-[250px] px-3 py-2 text-xs border-t border-r border-l rounded-t-md cursor-pointer select-none whitespace-nowrap ${activeTabId === tab.id ? 'bg-slate-850 border-slate-700 text-blue-400 font-medium' : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-800'}`}>
                      <span className="mr-2 truncate flex-1">{tab.title} {tab.isDirty && '*'}</span>
                      <button onClick={(e) => handleCloseTab(tab.id, e)} className={`opacity-0 group-hover:opacity-100 p-0.5 rounded-full hover:bg-slate-700 ${tabs.length === 1 ? 'hidden' : ''}`}><X size={12} /></button>
                    </div>
                  ))}
              </div>
              <div className="flex items-center border-l border-slate-800 pl-2 pb-1 space-x-1">
                  <button 
                      onClick={() => setIsEditorExpanded(!isEditorExpanded)} 
                      className={`p-1.5 hover:bg-slate-800 rounded transition-colors ${!isEditorExpanded ? 'text-blue-400' : 'text-slate-500'}`} 
                      title={isEditorExpanded ? "Collapse Editor" : "Expand Editor"}
                  >
                      {isEditorExpanded ? <ChevronDown size={16} /> : <ChevronUp size={16} />}
                  </button>
                  <button onClick={handleCreateTab} className="p-1.5 text-slate-500 hover:text-blue-400 hover:bg-slate-800 rounded transition-colors" title="New Tab"><Plus size={16} /></button>
              </div>
            </div>

            {/* Workspace Container */}
            <div 
              ref={containerRef}
              className={`flex-1 flex overflow-hidden bg-slate-950 relative ${
                  layout === 'bottom' ? 'flex-col' : 
                  layout === 'left' ? 'flex-row-reverse' : 
                  'flex-row'
              }`}
            >
              <div 
                  style={layout === 'bottom' ? {} : { display: isEditorExpanded ? 'flex' : 'none' }}
                  className={`
                      ${layout === 'float' ? 'w-full h-full' : 'flex-1'} 
                      flex flex-col min-h-0 min-w-0 z-0 transition-all duration-300
                      ${layout === 'bottom' && !isEditorExpanded ? '!flex-none !h-0 overflow-hidden' : ''}
                  `}
              >
                <div style={{ fontSize: `${appSettings.editorFontSize}px` }} className="h-full">
                    <SqlEditor 
                      ref={editorRef}
                      value={activeTab.content} 
                      onChange={c => setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: c, isDirty: true } : t))}
                      disabled={activeTab.isExecuting}
                      dbType={selectedDb?.type}
                    />
                </div>
                {activeTab.isExecuting && (
                    <div className="bg-slate-800/50 text-xs text-blue-300 px-4 py-1 border-t border-slate-800 flex items-center shrink-0">
                        <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse mr-2"></div>
                        Running query...
                    </div>
                )}
              </div>

              {layout !== 'float' && isEditorExpanded && (
                  <div 
                      onMouseDown={startDockResize}
                      className={`
                          ${layout === 'bottom' ? 'h-1.5 w-full cursor-row-resize' : 'w-1.5 h-full cursor-col-resize'} 
                          bg-slate-950 hover:bg-blue-600 transition-colors z-20 flex-shrink-0 border-slate-800
                          ${layout === 'bottom' ? 'border-t border-b' : 'border-l border-r'}
                      `} 
                  />
              )}

              {layout !== 'float' && (
                  <div 
                      style={layout === 'bottom' 
                          ? { height: isEditorExpanded ? `${panelSize}%` : '100%' } 
                          : { width: `${panelSize}%` }
                  } 
                  className="flex flex-col min-h-0 min-w-0 z-10 transition-all duration-300"
              >
                  <ResultsPane 
                      result={activeResult} 
                      viewMode={resultViewMode} 
                      setViewMode={setResultViewMode}
                      layout={layout}
                      setLayout={setLayout}
                      onPinChart={activeTab.linkedChartId ? undefined : handlePinChart}
                      onUpdateChart={activeTab.linkedChartId ? handleUpdatePinnedChart : undefined}
                      onApplyAggregation={handleApplyAggregation}
                  />
              </div>
              )}

              {layout === 'float' && (
                  <div 
                      style={{ top: floatRect.y, left: floatRect.x, width: floatRect.w, height: floatRect.h }}
                      className="absolute z-50 shadow-2xl border border-slate-700 rounded-lg overflow-hidden flex flex-col bg-slate-900 ring-1 ring-black/50"
                  >
                      <ResultsPane 
                          result={activeResult}
                          viewMode={resultViewMode}
                          setViewMode={setResultViewMode}
                          layout={layout}
                          setLayout={setLayout}
                          onHeaderMouseDown={startFloatMove}
                          onPinChart={activeTab.linkedChartId ? undefined : handlePinChart}
                          onUpdateChart={activeTab.linkedChartId ? handleUpdatePinnedChart : undefined}
                          onApplyAggregation={handleApplyAggregation}
                      />
                      <div 
                          onMouseDown={startFloatResize}
                          className="absolute bottom-0 right-0 w-5 h-5 cursor-nwse-resize bg-transparent hover:bg-blue-500/20 z-50 rounded-tl-lg"
                      />
                  </div>
              )}
            </div>

            <footer className="h-6 bg-slate-900 border-t border-slate-800 flex items-center px-4 text-[10px] text-slate-500 justify-between shrink-0 z-40">
              <div className="flex items-center space-x-4">
                  <span>Ready</span>
                  <span>{selectedDbId ? `Connected: ${selectedDb?.name}` : 'No Database Selected'}</span>
              </div>
              <div>Muul MessageHandler v1.0.0</div>
            </footer>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Database, EditorTab, QueryResult, ChartConfig, PinnedChart, DashboardLayout, AppSettings, SavedQuery, DbSchema, SchemaLayout } from './types';
import { muulService } from './services/muulService';
import { exportService } from './services/exportService';
import { 
  Play, Plus, X, Save, Download, Database as DbIcon, 
  Activity, Ban, ChevronDown, ChevronUp, ChevronRight,
  LayoutDashboard, TerminalSquare, Settings, Bookmark, FolderOpen, Upload, Table as TableIcon,
  Network
} from 'lucide-react';
import SqlEditor, { SqlEditorRef } from './components/SqlEditor';
import ResultsPane from './components/ResultsPane';
import Dashboard from './components/Dashboard';
import SchemaVisualizer from './components/SchemaVisualizer';
import SettingsModal from './components/SettingsModal';

type LayoutMode = 'bottom' | 'right' | 'left' | 'float';
type ViewMode = 'editor' | 'dashboard' | 'schema';
type SidebarTab = 'db' | 'saved';

const App: React.FC = () => {
  // --- State ---
  const [currentView, setCurrentView] = useState<ViewMode>('editor');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('db');
  const [databases, setDatabases] = useState<Database[]>([]);
  const [selectedDbId, setSelectedDbId] = useState<string>('');

  // Tables state: key is dbId, value is array of table names
  const [dbTables, setDbTables] = useState<Record<string, string[]>>({});
  const [expandedDbIds, setExpandedDbIds] = useState<Set<string>>(new Set());

  // Schema & Layouts for Visualizer
  const [activeSchema, setActiveSchema] = useState<DbSchema>({ tables: [] });
  const [schemaLayouts, setSchemaLayouts] = useState<SchemaLayout[]>([]);
  const [activeLayoutId, setActiveLayoutId] = useState<string | null>(null);

  const [isDraggingFile, setIsDraggingFile] = useState(false);

  // App Settings
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [appSettings, setAppSettings] = useState<AppSettings>({
    editorFontSize: 14,
    themeAccent: 'blue',
    refreshRate: 0
  });

  // Saved Data
  const [savedQueries, setSavedQueries] = useState<SavedQuery[]>([
      { id: 'sq-1', name: 'Get All Users', content: 'SELECT * FROM users LIMIT 100;', dbId: 'db-1', createdAt: Date.now() }
  ]);

  // Dashboard Data State
  const [pinnedCharts, setPinnedCharts] = useState<PinnedChart[]>([]);
  const [dashboards, setDashboards] = useState<DashboardLayout[]>([
      {
          id: 'main-dash',
          title: 'Main Dashboard',
          isDefault: true,
          rows: [
              {
                  id: 'row-welcome',
                  widgets: [
                      { id: 'w-welcome', type: 'markdown', colSpan: 12, title: 'Welcome', content: '# Welcome to Muul SQL\nDrag and drop **.csv**, **.json**, **.parquet**, or **.sqlite** files to instantly query them!'}
                  ]
              }
          ]
      }
  ]);
  const [activeDashboardId, setActiveDashboardId] = useState<string>('main-dash');

  // Editor State
  const [tabs, setTabs] = useState<EditorTab[]>([
    { 
      id: 'tab-1', 
      title: 'Query 1', 
      content: '', 
      isDirty: false, 
      isExecuting: false, 
      results: [],
      activeResultIndex: -1 
    }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab-1');
  const [resultViewMode, setResultViewMode] = useState<'table' | 'chart'>('table');
  const [isEditorExpanded, setIsEditorExpanded] = useState(true);

  // Layout State
  const [layout, setLayout] = useState<LayoutMode>('bottom');
  const [panelSize, setPanelSize] = useState(40); // Percentage for docked mode
  const [floatRect, setFloatRect] = useState({ x: 100, y: 100, w: 600, h: 400 });

  // --- Refs ---
  const editorRef = useRef<SqlEditorRef>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const dragInfo = useRef<{ 
    isDragging: boolean; 
    type: 'resize-dock' | 'move-float' | 'resize-float'; 
    startX: number; 
    startY: number; 
    startSize?: number;
    startRect?: typeof floatRect;
  }>({ isDragging: false, type: 'resize-dock', startX: 0, startY: 0 });

  // --- Effects ---
  useEffect(() => {
    muulService.getDatabases().then(dbs => {
      setDatabases(dbs);
      if (dbs.length > 0) {
          setSelectedDbId(dbs[0].id);
          // Auto expand the first one
          setExpandedDbIds(new Set([dbs[0].id]));
      }
    });
  }, []);

  // Fetch tables AND Schema when a DB is expanded or selected
  useEffect(() => {
      if (selectedDbId) {
          // Fetch simple table list
          if (!dbTables[selectedDbId]) {
              muulService.getDatabaseTables(selectedDbId).then(tables => {
                  setDbTables(prev => ({ ...prev, [selectedDbId]: tables }));
              });
          }
          // Fetch Full Schema (for Visualizer)
          muulService.getDatabaseSchema(selectedDbId).then(schema => {
              setActiveSchema(schema);

              // Ensure a default layout exists
              setSchemaLayouts(prev => {
                  const hasLayout = prev.some(l => l.dbId === selectedDbId);
                  if (!hasLayout && schema.tables.length > 0) {
                      const defaultLayout: SchemaLayout = {
                          id: `layout-${Date.now()}`,
                          name: 'Main Diagram',
                          dbId: selectedDbId,
                          tables: schema.tables.map(t => t.name),
                          createdAt: Date.now()
                      };
                      setActiveLayoutId(defaultLayout.id);
                      return [...prev, defaultLayout];
                  }
                  // If layouts exist but none active for this DB, activate first one
                  const dbLayouts = prev.filter(l => l.dbId === selectedDbId);
                  if (dbLayouts.length > 0 && (!activeLayoutId || !dbLayouts.find(l => l.id === activeLayoutId))) {
                      setActiveLayoutId(dbLayouts[0].id);
                  }
                  return prev;
              });
          });
      }
  }, [selectedDbId]);

  // Ensure activeLayoutId is valid when switching DBs manually
  useEffect(() => {
      if (selectedDbId) {
           const dbLayouts = schemaLayouts.filter(l => l.dbId === selectedDbId);
           if (dbLayouts.length > 0) {
               // If current active layout is not for this DB, switch to the first one for this DB
               const active = schemaLayouts.find(l => l.id === activeLayoutId);
               if (!active || active.dbId !== selectedDbId) {
                   setActiveLayoutId(dbLayouts[0].id);
               }
           } else {
               setActiveLayoutId(null);
           }
      }
  }, [selectedDbId, schemaLayouts]);


  // --- Layout Handlers ---
  const handleLayoutCreate = (name: string, tables: string[]) => {
      if (!selectedDbId) return;
      const newLayout: SchemaLayout = {
          id: `layout-${Date.now()}`,
          name,
          dbId: selectedDbId,
          tables,
          createdAt: Date.now()
      };
      setSchemaLayouts(prev => [...prev, newLayout]);
      setActiveLayoutId(newLayout.id);
  };

  const handleLayoutUpdate = (layoutId: string, tables: string[]) => {
      setSchemaLayouts(prev => prev.map(l => l.id === layoutId ? { ...l, tables } : l));
  };

  const handleLayoutDelete = (layoutId: string) => {
      const remaining = schemaLayouts.filter(l => l.id !== layoutId);
      setSchemaLayouts(remaining);

      // Select another layout if current was deleted
      if (activeLayoutId === layoutId) {
          const others = remaining.filter(l => l.dbId === selectedDbId);
          setActiveLayoutId(others.length > 0 ? others[0].id : null);
      }
  };


  // Global mouse event handlers for dragging/resizing
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragInfo.current.isDragging) return;

      const { type, startX, startY, startSize, startRect } = dragInfo.current;
      const container = containerRef.current;

      if (type === 'resize-dock' && container && startSize !== undefined) {
        const rect = container.getBoundingClientRect();
        let delta = 0;
        let newSize = startSize;

        if (layout === 'bottom') {
           delta = (startY - e.clientY) / rect.height * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'right') {
           delta = (startX - e.clientX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'left') {
           delta = (e.clientX - startX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        }
        setPanelSize(newSize);
      } 
      else if (type === 'move-float' && startRect) {
        setFloatRect({
          ...startRect,
          x: startRect.x + (e.clientX - startX),
          y: startRect.y + (e.clientY - startY)
        });
      }
      else if (type === 'resize-float' && startRect) {
        setFloatRect({
          ...startRect,
          w: Math.max(300, startRect.w + (e.clientX - startX)),
          h: Math.max(200, startRect.h + (e.clientY - startY))
        });
      }
    };

    const handleMouseUp = () => {
      dragInfo.current.isDragging = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [layout]);

  // --- Drag & Drop Handlers for Files ---
  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    // Only leave if we actually left the window/container
    if (e.currentTarget === e.target) {
        setIsDraggingFile(false);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
  };

  const handleFileDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);

    const files: File[] = Array.from(e.dataTransfer.files);
    if (files.length === 0) return;

    for (const file of files) {
        if (file.name.endsWith('.sqlite') || file.name.endsWith('.db') || file.name.endsWith('.csv') || file.name.endsWith('.json') || file.name.endsWith('.parquet')) {
            try {
                const newDb = await muulService.uploadDatabase(file);
                setDatabases(prev => [newDb, ...prev]);
                setSelectedDbId(newDb.id);
                setExpandedDbIds(prev => new Set(prev).add(newDb.id));

                // Fetch tables immediately
                const tables = await muulService.getDatabaseTables(newDb.id);
                setDbTables(prev => ({ ...prev, [newDb.id]: tables }));

            } catch (err: any) {
                alert(`Failed to load ${file.name}: ${err.message}`);
            }
        } else {
            alert(`File ${file.name} is not supported. Please drop .sqlite, .db, .csv, .json, or .parquet files.`);
        }
    }
  };


  // --- Helpers ---
  const activeTab = tabs.find(t => t.id === activeTabId)!;
  const activeResult = activeTab?.activeResultIndex >= 0 
    ? activeTab.results[activeTab.activeResultIndex] 
    : null;
  const selectedDb = databases.find(d => d.id === selectedDbId);

  // --- Actions ---

  const handleDbClick = (dbId: string) => {
      setSelectedDbId(dbId);
      setExpandedDbIds(prev => {
          const next = new Set(prev);
          if (next.has(dbId)) next.delete(dbId);
          else next.add(dbId);
          return next;
      });
  };

  const handleTableClick = (tableName: string) => {
      // Check if there is an existing, unmodified tab for this table
      const existingTab = tabs.find(t => t.title === tableName && !t.isDirty);

      if (existingTab) {
          setActiveTabId(existingTab.id);
          setCurrentView('editor'); // Ensure we switch back to editor
          return;
      }

      const newId = `tab-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: tableName,
          content: `SELECT * FROM "${tableName}" LIMIT 100;`,
          isDirty: false, // Initially clean so we can detect if user modifies it later
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
  };

  const handleCreateTab = () => {
    const newId = `tab-${Date.now()}`;
    setTabs([...tabs, {
      id: newId, title: `Query ${tabs.length + 1}`, content: '', isDirty: false, isExecuting: false, results: [], activeResultIndex: -1
    }]);
    setActiveTabId(newId);
  };

  const handleOpenSavedQuery = (sq: SavedQuery) => {
      const newId = `tab-${Date.now()}`;
      setTabs([...tabs, {
          id: newId,
          title: sq.name,
          content: sq.content,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      if(sq.dbId) setSelectedDbId(sq.dbId);
      setCurrentView('editor');
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (tabs.length === 1) return;
    const newTabs = tabs.filter(t => t.id !== id);
    setTabs(newTabs);
    if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
  };

  const executeTabQuery = async (tabId: string, content: string, selectionOnly: boolean = false) => {
    if (!selectedDbId) return alert("Please select a database first.");

    let queriesToRun = [content];
    if (selectionOnly) {
         // This logic is currently inside handleRunQuery mainly via ref,
         // but here we are called programmatically with content.
         queriesToRun = content.split(';').map(q => q.trim()).filter(q => q.length > 0);
    }

    if (queriesToRun.length === 0) return;

    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: true } : t));
    const executionId = Date.now().toString();

    try {
      const results: QueryResult[] = [];
      for (const query of queriesToRun) {
        const result = await muulService.executeQuery(selectedDbId, query, executionId);
        results.push(result);
        if (result.error) break; 
      }
      setTabs(prev => prev.map(t => t.id === tabId ? {
        ...t, isExecuting: false, results: [results[results.length - 1], ...t.results], activeResultIndex: 0
      } : t));
    } catch (e) {
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: false } : t));
    }
  };

  const handleRunQuery = async () => {
    const editor = editorRef.current;
    if (!editor) return;

    const selection = editor.getSelection();
    if (selection.text.trim().length > 0) {
        // Run specific selection but don't split by semicolon if selection
        // Actually executeTabQuery logic above splits by semicolon which might be wrong for selection
        // Let's keep logic simple:
        if (!selectedDbId) return alert("Please select a database first.");
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: true } : t));
        const result = await muulService.executeQuery(selectedDbId, selection.text, Date.now().toString());
        setTabs(prev => prev.map(t => t.id === activeTabId ? {
            ...t, isExecuting: false, results: [result, ...t.results], activeResultIndex: 0
        } : t));
    } else {
        // Run full content (support multiple statements)
        executeTabQuery(activeTabId, activeTab.content, true);
    }
  };

  const handleApplyAggregation = (dimension: string, metric: string, func: string) => {
      const currentQuery = activeTab.content.trim().replace(/;$/, '');
      if (!currentQuery) return;

      const newQuery = `SELECT \n  "${dimension}", \n  ${func}("${metric}") as "${metric}_${func}" \nFROM (\n${currentQuery}\n) \nGROUP BY "${dimension}"`;

      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: newQuery, isDirty: true } : t));

      // Execute immediately
      setTimeout(() => {
          executeTabQuery(activeTabId, newQuery, true);
      }, 50);
  };

  const handleCancelQuery = () => {
    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
  };

  const handleSaveQuery = () => {
      if(!activeTab.content.trim()) return alert("Query is empty.");
      const name = prompt("Save Query As:", activeTab.title);
      if(!name) return;

      const newSaved: SavedQuery = {
          id: `sq-${Date.now()}`,
          name,
          content: activeTab.content,
          dbId: selectedDbId,
          createdAt: Date.now()
      };
      setSavedQueries([...savedQueries, newSaved]);
      // Update current tab name
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, title: name, isDirty: false } : t));
  };

  const handleDownloadCSV = () => {
      if(!activeResult) return;
      exportService.downloadCSV(activeResult, `result-${Date.now()}.csv`);
  };

  // --- Pinning & Dashboard Management ---

  const handlePinChart = (config: ChartConfig) => {
    if (!activeResult || !selectedDbId) return;

    // Check if chart with same title exists or user is already editing a chart
    const existingChartIndex = pinnedCharts.findIndex(c => 
        c.id === activeTab.linkedChartId || c.title === activeTab.title
    );

    if (existingChartIndex >= 0) {
        const existingChart = pinnedCharts[existingChartIndex];

        // If not explicitly linked but names match, confirm update
        if (!activeTab.linkedChartId) {
             if (!window.confirm(`A pinned chart named "${existingChart.title}" already exists. Do you want to update it?`)) {
                 return; // Abort
             }
        }

        // Perform Update
        const updatedChart = {
            ...existingChart,
            query: activeTab.content,
            config: config,
            dbId: selectedDbId
        };

        setPinnedCharts(prev => prev.map(c => c.id === existingChart.id ? updatedChart : c));

        // Link this tab to the existing chart
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, linkedChartId: existingChart.id } : t));

        alert("Dashboard chart updated!");
    } else {
        // Create New Chart Pin
        const chartId = `chart-${Date.now()}`;
        const newPin: PinnedChart = {
          id: chartId,
          title: activeTab.title,
          query: activeTab.content, // Simplified: uses whole content
          dbId: selectedDbId,
          config: config,
          createdAt: Date.now()
        };
        setPinnedCharts(prev => [...prev, newPin]);

        // Link this tab to the new chart immediately
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, linkedChartId: chartId } : t));

        // Add to Dashboard
        setDashboards(prev => {
            return prev.map(dash => {
                if (dash.id !== activeDashboardId) return dash;

                const newWidget = {
                    id: `w-${Date.now()}`,
                    type: 'chart' as const,
                    colSpan: 6, // Default to half width
                    content: chartId,
                    title: newPin.title
                };

                const lastRow = dash.rows[dash.rows.length - 1];
                if (lastRow && lastRow.widgets.reduce((acc, w) => acc + w.colSpan, 0) <= 6) {
                    // Fit in last row
                    return {
                        ...dash,
                        rows: dash.rows.map(r => r.id === lastRow.id ? { ...r, widgets: [...r.widgets, newWidget] } : r)
                    };
                } else {
                    // New Row
                    return {
                        ...dash,
                        rows: [...dash.rows, { id: `row-${Date.now()}`, widgets: [newWidget] }]
                    };
                }
            });
        });

        alert("Chart pinned to dashboard!");
    }
  };

  const handleUpdatePinnedChart = (newConfig: ChartConfig) => {
    if (!activeTab.linkedChartId || !selectedDbId) return;

    // Update the PinnedChart definition
    setPinnedCharts(prev => prev.map(c => {
        if (c.id === activeTab.linkedChartId) {
            return {
                ...c,
                query: activeTab.content, // Update query with current editor content
                config: newConfig, // Update visual config
                dbId: selectedDbId // Ensure DB ID is synced if changed
            };
        }
        return c;
    }));

    alert("Chart updated successfully!");
  };

  const handleEditChart = (chartId: string) => {
      const chart = pinnedCharts.find(c => c.id === chartId);
      if (!chart) return;

      const newId = `tab-edit-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: chart.title, // Keep original title to enable name matching
          content: chart.query,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1,
          linkedChartId: chart.id // Link this tab to the chart
      }]);
      setActiveTabId(newId);

      // Ensure we switch to the DB used by the chart
      if (chart.dbId) setSelectedDbId(chart.dbId);

      setCurrentView('editor');

      // Auto-run to show current state
      setTimeout(() => {
          executeTabQuery(newId, chart.query);
          setResultViewMode('chart'); // Switch to chart view immediately
      }, 100);
  };

  const handleAddDashboard = (title: string) => {
      const newDash: DashboardLayout = {
          id: `dash-${Date.now()}`,
          title,
          isDefault: false,
          rows: []
      };
      setDashboards([...dashboards, newDash]);
      setActiveDashboardId(newDash.id);
  };

  const handleDeleteDashboard = (id: string) => {
      if (dashboards.length <= 1) return alert("Cannot delete the last dashboard.");
      const newDashboards = dashboards.filter(d => d.id !== id);
      setDashboards(newDashboards);
      if (activeDashboardId === id) setActiveDashboardId(newDashboards[0].id);
  };

  const handleUpdateDashboard = (updatedLayout: DashboardLayout) => {
      setDashboards(prev => prev.map(d => d.id === updatedLayout.id ? updatedLayout : d));
  };

  const handleRemoveChartDefinition = (id: string) => {
      setPinnedCharts(prev => prev.filter(c => c.id !== id));
      // Also remove widgets referencing this chart from ALL dashboards
      setDashboards(prev => prev.map(dash => ({
          ...dash,
          rows: dash.rows.map(row => ({
              ...row,
              widgets: row.widgets.filter(w => w.type !== 'chart' || w.content !== id)
          }))
      })));
  };

  const handleUpdateChartDefinition = (id: string, newConfig: ChartConfig) => {
      setPinnedCharts(prev => prev.map(c => c.id === id ? { ...c, config: newConfig } : c));
  };

  // --- Drag Starters ---
  const startDockResize = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { 
        isDragging: true, 
        type: 'resize-dock', 
        startX: e.clientX, 
        startY: e.clientY, 
        startSize: panelSize 
    };
    document.body.style.cursor = layout === 'bottom' ? 'row-resize' : 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const startFloatMove = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { isDragging: true, type: 'move-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  const startFloatResize = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragInfo.current = { isDragging: true, type: 'resize-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  return (
    <div 
        className={`flex h-screen w-screen bg-slate-950 text-slate-200 overflow-hidden font-sans ${appSettings.themeAccent}-accent relative`}
        onDragEnter={handleDragEnter}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleFileDrop}
    >

      {/* Drag Overlay */}
      {isDraggingFile && (
          <div className="absolute inset-0 z-[100] bg-blue-500/20 backdrop-blur-sm border-4 border-dashed border-blue-400 m-4 rounded-xl flex flex-col items-center justify-center pointer-events-none">
              <Upload size={64} className="text-blue-400 mb-4" />
              <h2 className="text-2xl font-bold text-white">Drop File to Import</h2>
              <p className="text-blue-200">Supports .csv, .json, .sqlite, .db, .parquet</p>
          </div>
      )}

      {/* Settings Modal */}
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={appSettings} 
        onSave={setAppSettings}
      />

      {/* Activity Bar (Sidebar) */}
      <aside className="w-12 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-4 space-y-4 shrink-0 z-50">
        <div className="text-blue-500 mb-2"><DbIcon size={24} /></div>

        <button 
          onClick={() => setCurrentView('editor')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'editor' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="SQL Editor"
        >
          <TerminalSquare size={20} />
        </button>

        <button 
          onClick={() => setCurrentView('dashboard')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'dashboard' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="Dashboard"
        >
          <LayoutDashboard size={20} />
        </button>

        <button 
          onClick={() => setCurrentView('schema')}
          className={`p-2 rounded-lg transition-colors ${currentView === 'schema' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`}
          title="Schema Visualizer"
        >
          <Network size={20} />
        </button>

        <div className="h-px w-6 bg-slate-800 my-2"></div>

        {/* Saved Queries Toggle (Only meaningful in Editor View, effectively) */}
        <button 
            onClick={() => { setCurrentView('editor'); setSidebarTab('saved'); }}
            className={`p-2 rounded-lg transition-colors ${currentView === 'editor' && sidebarTab === 'saved' ? 'bg-slate-800 text-purple-400' : 'text-slate-500 hover:text-slate-300'}`}
            title="Saved Queries"
        >
            <Bookmark size={20} />
        </button>

        <div className="flex-1" />
        <button 
            onClick={() => setIsSettingsOpen(true)}
            className="p-2 text-slate-500 hover:text-slate-300 hover:bg-slate-800 rounded transition-colors"
        >
            <Settings size={20} />
        </button>
      </aside>

      {/* Explorer / Sidebar Panel (Conditional) */}
      {(currentView === 'editor' || currentView === 'schema') && (
          <div className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col min-h-0">
             <div className="h-10 flex items-center px-4 font-bold text-xs uppercase tracking-wider text-slate-500 border-b border-slate-800 shrink-0">
                {sidebarTab === 'db' ? 'Databases' : 'Saved Queries'}
             </div>

             {/* Database List */}
             {sidebarTab === 'db' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {databases.map(db => (
                        <div key={db.id} className="mb-1">
                            <div 
                                onClick={() => handleDbClick(db.id)}
                                className={`flex items-center p-2 rounded cursor-pointer transition-colors ${selectedDbId === db.id ? 'bg-slate-800 text-slate-200' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-300'}`}
                            >
                                <div className={`mr-2 transition-transform ${expandedDbIds.has(db.id) ? 'rotate-90' : ''}`}>
                                    <ChevronRight size={14} />
                                </div>
                                <DbIcon size={14} className="mr-2 text-blue-500/80" />
                                <div className="flex flex-col truncate">
                                    <span className="text-sm truncate font-medium">{db.name}</span>
                                </div>
                            </div>

                            {/* Table List (Indented) */}
                            {expandedDbIds.has(db.id) && (
                                <div className="ml-6 pl-2 border-l border-slate-800 mt-1 space-y-0.5">
                                    {dbTables[db.id] && dbTables[db.id].length > 0 ? (
                                        dbTables[db.id].map(tbl => (
                                            <div 
                                                key={tbl} 
                                                onClick={() => handleTableClick(tbl)}
                                                className="flex items-center px-2 py-1.5 text-xs text-slate-500 hover:text-blue-300 hover:bg-slate-800/50 rounded cursor-pointer group"
                                            >
                                                <TableIcon size={12} className="mr-2 opacity-50 group-hover:opacity-100" />
                                                <span className="truncate">{tbl}</span>
                                            </div>
                                        ))
                                    ) : (
                                        <div className="px-2 py-1 text-[10px] text-slate-600 italic">No tables found or loading...</div>
                                    )}
                                </div>
                            )}
                        </div>
                    ))}
                    <div className="mt-4 p-4 border border-dashed border-slate-800 rounded mx-2 text-center text-slate-600 text-xs select-none pointer-events-none">
                        Drop SQLite, CSV, JSON, or Parquet file
                    </div>
                </div>
             )}

             {/* Saved Queries List */}
             {sidebarTab === 'saved' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {savedQueries.length === 0 && <div className="text-slate-600 text-xs text-center mt-4">No saved queries.</div>}
                    {savedQueries.map(sq => (
                        <div 
                            key={sq.id} 
                            onClick={() => handleOpenSavedQuery(sq)}
                            className="group flex items-start p-2 mb-1 rounded cursor-pointer transition-colors text-slate-400 hover:bg-slate-800 hover:text-slate-200"
                        >
                            <FolderOpen size={14} className="mr-2 mt-0.5 text-purple-400" />
                            <div className="flex flex-col truncate flex-1">
                                <span className="text-sm truncate font-medium">{sq.name}</span>
                                <span className="text-[10px] text-slate-500 truncate">{new Date(sq.createdAt).toLocaleDateString()}</span>
                            </div>
                        </div>
                    ))}
                    <button 
                        onClick={() => setSidebarTab('db')} 
                        className="mt-4 w-full flex items-center justify-center p-2 text-xs text-slate-500 hover:text-slate-300 border border-dashed border-slate-800 rounded hover:bg-slate-800"
                    >
                         Back to Databases
                    </button>
                </div>
             )}
          </div>
      )}

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 h-full overflow-hidden relative">

        {/* VIEW: DASHBOARD */}
        {currentView === 'dashboard' && (
             <Dashboard 
                dashboards={dashboards}
                pinnedCharts={pinnedCharts} 
                databases={databases}
                activeDashboardId={activeDashboardId}
                refreshRate={appSettings.refreshRate}
                onSetActiveDashboard={setActiveDashboardId}
                onAddDashboard={handleAddDashboard}
                onUpdateDashboard={handleUpdateDashboard}
                onDeleteDashboard={handleDeleteDashboard}
                onRemoveChartDefinition={handleRemoveChartDefinition}
                onUpdateChartDefinition={handleUpdateChartDefinition}
                onEditChart={handleEditChart}
             />
        )}

        {/* VIEW: SCHEMA VISUALIZER */}
        {currentView === 'schema' && (
            <SchemaVisualizer 
                schema={activeSchema} 
                dbName={selectedDb?.name || 'Selected Database'}
                layouts={schemaLayouts.filter(l => l.dbId === selectedDbId)}
                activeLayoutId={activeLayoutId}
                onLayoutCreate={handleLayoutCreate}
                onLayoutSelect={setActiveLayoutId}
                onLayoutUpdate={handleLayoutUpdate}
                onLayoutDelete={handleLayoutDelete}
            />
        )}

        {/* VIEW: EDITOR */}
        <div className={`flex-1 flex flex-col h-full w-full ${currentView === 'dashboard' || currentView === 'schema' ? 'hidden' : 'flex'}`}>
            <header className="h-14 border-b border-slate-800 bg-slate-900 flex items-center px-4 justify-between shrink-0 z-30 relative">
              <div className="flex items-center space-x-4">
                <div className="flex items-center text-blue-400 font-bold text-lg tracking-tight">
                  Muul<span className="text-slate-100">SQL</span>
                </div>
                <div className="h-6 w-px bg-slate-700 mx-2"></div>
                <div className="relative group">
                  <select 
                    value={selectedDbId}
                    onChange={(e) => setSelectedDbId(e.target.value)}
                    className="appearance-none bg-slate-800 hover:bg-slate-700 border border-slate-700 text-xs rounded py-1.5 pl-3 pr-8 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors w-64 cursor-pointer"
                  >
                    {databases.map(db => (
                      <option key={db.id} value={db.id}>{db.type.toUpperCase()} • {db.name}</option>
                    ))}
                  </select>
                  <Activity size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400" />
                </div>
              </div>

              <div className="flex items-center space-x-2">
                  {activeTab.isExecuting ? (
                      <button onClick={handleCancelQuery} className="flex items-center px-4 py-1.5 bg-red-600 hover:bg-red-700 text-white text-sm font-medium rounded shadow animate-pulse">
                        <Ban size={16} className="mr-2" /> Cancel
                      </button>
                  ) : (
                      <button onClick={handleRunQuery} className="flex items-center px-4 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium rounded shadow hover:shadow-blue-500/20 active:scale-95">
                        <Play size={16} className="mr-2 fill-current" /> Run
                      </button>
                  )}
                  <div className="h-6 w-px bg-slate-700 mx-2"></div>

                  {/* Save Button */}
                  <button 
                    onClick={handleSaveQuery} 
                    className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded transition-colors"
                    title="Save Query"
                  >
                    <Save size={18} />
                  </button>

                  {/* Download Button */}
                  <button 
                    onClick={handleDownloadCSV}
                    disabled={!activeResult}
                    className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded disabled:opacity-30 transition-colors"
                    title="Download Result CSV"
                  >
                    <Download size={18} />
                  </button>
              </div>
            </header>

            {/* Tabs Container */}
            <div className="flex items-center bg-slate-900 border-b border-slate-800 pr-2 pt-2 shrink-0">
              <div className="flex-1 flex overflow-x-auto no-scrollbar items-end px-2">
                  {tabs.map(tab => (
                    <div key={tab.id} onClick={() => setActiveTabId(tab.id)} className={`group flex items-center min-w-[150px] max-w-[250px] px-3 py-2 text-xs border-t border-r border-l rounded-t-md cursor-pointer select-none whitespace-nowrap ${activeTabId === tab.id ? 'bg-slate-850 border-slate-700 text-blue-400 font-medium' : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-800'}`}>
                      <span className="mr-2 truncate flex-1">{tab.title} {tab.isDirty && '*'}</span>
                      <button onClick={(e) => handleCloseTab(tab.id, e)} className={`opacity-0 group-hover:opacity-100 p-0.5 rounded-full hover:bg-slate-700 ${tabs.length === 1 ? 'hidden' : ''}`}><X size={12} /></button>
                    </div>
                  ))}
              </div>
              <div className="flex items-center border-l border-slate-800 pl-2 pb-1 space-x-1">
                  <button 
                      onClick={() => setIsEditorExpanded(!isEditorExpanded)} 
                      className={`p-1.5 hover:bg-slate-800 rounded transition-colors ${!isEditorExpanded ? 'text-blue-400' : 'text-slate-500'}`} 
                      title={isEditorExpanded ? "Collapse Editor" : "Expand Editor"}
                  >
                      {isEditorExpanded ? <ChevronDown size={16} /> : <ChevronUp size={16} />}
                  </button>
                  <button onClick={handleCreateTab} className="p-1.5 text-slate-500 hover:text-blue-400 hover:bg-slate-800 rounded transition-colors" title="New Tab"><Plus size={16} /></button>
              </div>
            </div>

            {/* Workspace Container */}
            <div 
              ref={containerRef}
              className={`flex-1 flex overflow-hidden bg-slate-950 relative ${
                  layout === 'bottom' ? 'flex-col' : 
                  layout === 'left' ? 'flex-row-reverse' : 
                  'flex-row'
              }`}
            >
              <div 
                  style={layout === 'bottom' ? {} : { display: isEditorExpanded ? 'flex' : 'none' }}
                  className={`
                      ${layout === 'float' ? 'w-full h-full' : 'flex-1'} 
                      flex flex-col min-h-0 min-w-0 z-0 transition-all duration-300
                      ${layout === 'bottom' && !isEditorExpanded ? '!flex-none !h-0 overflow-hidden' : ''}
                  `}
              >
                <div style={{ fontSize: `${appSettings.editorFontSize}px` }} className="h-full">
                    <SqlEditor 
                      ref={editorRef}
                      value={activeTab.content} 
                      onChange={c => setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: c, isDirty: true } : t))}
                      disabled={activeTab.isExecuting}
                      dbType={selectedDb?.type}
                    />
                </div>
                {activeTab.isExecuting && (
                    <div className="bg-slate-800/50 text-xs text-blue-300 px-4 py-1 border-t border-slate-800 flex items-center shrink-0">
                        <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse mr-2"></div>
                        Running query...
                    </div>
                )}
              </div>

              {layout !== 'float' && isEditorExpanded && (
                  <div 
                      onMouseDown={startDockResize}
                      className={`
                          ${layout === 'bottom' ? 'h-1.5 w-full cursor-row-resize' : 'w-1.5 h-full cursor-col-resize'} 
                          bg-slate-950 hover:bg-blue-600 transition-colors z-20 flex-shrink-0 border-slate-800
                          ${layout === 'bottom' ? 'border-t border-b' : 'border-l border-r'}
                      `} 
                  />
              )}

              {layout !== 'float' && (
                  <div 
                      style={layout === 'bottom' 
                          ? { height: isEditorExpanded ? `${panelSize}%` : '100%' } 
                          : { width: `${panelSize}%` }
                  } 
                  className="flex flex-col min-h-0 min-w-0 z-10 transition-all duration-300"
              >
                  <ResultsPane 
                      result={activeResult} 
                      viewMode={resultViewMode} 
                      setViewMode={setResultViewMode}
                      layout={layout}
                      setLayout={setLayout}
                      onPinChart={activeTab.linkedChartId ? undefined : handlePinChart}
                      onUpdateChart={activeTab.linkedChartId ? handleUpdatePinnedChart : undefined}
                      onApplyAggregation={handleApplyAggregation}
                  />
              </div>
              )}

              {layout === 'float' && (
                  <div 
                      style={{ top: floatRect.y, left: floatRect.x, width: floatRect.w, height: floatRect.h }}
                      className="absolute z-50 shadow-2xl border border-slate-700 rounded-lg overflow-hidden flex flex-col bg-slate-900 ring-1 ring-black/50"
                  >
                      <ResultsPane 
                          result={activeResult}
                          viewMode={resultViewMode}
                          setViewMode={setResultViewMode}
                          layout={layout}
                          setLayout={setLayout}
                          onHeaderMouseDown={startFloatMove}
                          onPinChart={activeTab.linkedChartId ? undefined : handlePinChart}
                          onUpdateChart={activeTab.linkedChartId ? handleUpdatePinnedChart : undefined}
                          onApplyAggregation={handleApplyAggregation}
                      />
                      <div 
                          onMouseDown={startFloatResize}
                          className="absolute bottom-0 right-0 w-5 h-5 cursor-nwse-resize bg-transparent hover:bg-blue-500/20 z-50 rounded-tl-lg"
                      />
                  </div>
              )}
            </div>

            <footer className="h-6 bg-slate-900 border-t border-slate-800 flex items-center px-4 text-[10px] text-slate-500 justify-between shrink-0 z-40">
              <div className="flex items-center space-x-4">
                  <span>Ready</span>
                  <span>{selectedDbId ? `Connected: ${selectedDb?.name}` : 'No Database Selected'}</span>
              </div>
              <div>Muul MessageHandler v1.0.0</div>
            </footer>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useState, useRef } from 'react';
import { PinnedChart, QueryResult, ChartConfig, Database, DashboardLayout, DashboardRow, DashboardWidget } from '../types';
import { muulService } from '../services/muulService';
import { exportService } from '../services/exportService';
import DataVisualizer from './DataVisualizer';
import MarkdownVisualizer from './MarkdownVisualizer';
import { 
  RefreshCw, Trash2, Edit, AlertCircle, Database as DbIcon, 
  Plus, Layout, Monitor, MoveHorizontal, X, FileText, BarChart3, GripVertical,
  Download
} from 'lucide-react';

interface DashboardProps {
  dashboards: DashboardLayout[];
  pinnedCharts: PinnedChart[];
  databases: Database[];
  activeDashboardId: string;
  refreshRate: number; 
  onSetActiveDashboard: (id: string) => void;
  onAddDashboard: (title: string) => void;
  onUpdateDashboard: (layout: DashboardLayout) => void;
  onDeleteDashboard: (id: string) => void;
  onRemoveChartDefinition: (id: string) => void;
  onUpdateChartDefinition: (id: string, newConfig: ChartConfig) => void;
  onEditChart: (chartId: string) => void; // New prop
}

const Dashboard: React.FC<DashboardProps> = ({ 
  dashboards, 
  pinnedCharts, 
  databases, 
  activeDashboardId,
  refreshRate,
  onSetActiveDashboard,
  onAddDashboard,
  onUpdateDashboard,
  onDeleteDashboard,
  onRemoveChartDefinition,
  onUpdateChartDefinition,
  onEditChart
}) => {
  const [results, setResults] = useState<Record<string, QueryResult>>({});
  const [loading, setLoading] = useState<Record<string, boolean>>({});
  const [isDesignerMode, setIsDesignerMode] = useState(false);
  const [draggingItem, setDraggingItem] = useState<{ rowId: string; index: number } | null>(null);
  const refreshIntervalRef = useRef<number | null>(null);

  // --- Helpers ---
  const activeDashboard = dashboards.find(d => d.id === activeDashboardId) || dashboards[0];
  const getChartDef = (chartId: string) => pinnedCharts.find(c => c.id === chartId);
  const getDbName = (dbId?: string) => databases.find(d => d.id === dbId)?.name || 'Unknown DB';

  // --- Data Fetching ---
  const refreshChart = async (chartId: string) => {
    const chart = getChartDef(chartId);
    if (!chart) return;

    setLoading(prev => ({ ...prev, [chartId]: true }));
    try {
      const result = await muulService.executeQuery(chart.dbId, chart.query, `dash-${chart.id}-${Date.now()}`);
      setResults(prev => ({ ...prev, [chartId]: result }));
    } catch (error) {
       console.error("Dashboard execution error", error);
    } finally {
      setLoading(prev => ({ ...prev, [chartId]: false }));
    }
  };

  const handleRefreshAll = () => {
     if (!activeDashboard) return;
     activeDashboard.rows.forEach(row => {
         row.widgets.forEach(w => {
             if (w.type === 'chart') refreshChart(w.content);
         });
     });
  };

  // --- Effects ---

  // Initial load logic check
  useEffect(() => {
    if (!activeDashboard) return;

    // Collect needed charts
    const chartIds = new Set<string>();
    activeDashboard.rows.forEach(row => {
      row.widgets.forEach(w => {
        if (w.type === 'chart') chartIds.add(w.content);
      });
    });

    // Refresh if no data
    chartIds.forEach(id => {
      if (!results[id]) refreshChart(id);
    });
  }, [activeDashboard, pinnedCharts]);

  // Auto Refresh Logic
  useEffect(() => {
    if (refreshIntervalRef.current) {
        clearInterval(refreshIntervalRef.current);
        refreshIntervalRef.current = null;
    }

    if (refreshRate > 0) {
        refreshIntervalRef.current = window.setInterval(() => {
            console.log("Auto-refreshing dashboard...");
            handleRefreshAll();
        }, refreshRate * 1000);
    }

    return () => {
        if (refreshIntervalRef.current) clearInterval(refreshIntervalRef.current);
    }
  }, [refreshRate, activeDashboard]); // Re-setup if rate or dash changes

  // --- Export ---
  const handleExportPPT = () => {
      if (!activeDashboard) return;
      exportService.exportDashboardToPPT(activeDashboard, pinnedCharts, results);
  };

  // --- Designer Actions ---

  const handleAddRow = () => {
    const newRow: DashboardRow = {
        id: `row-${Date.now()}`,
        widgets: []
    };
    onUpdateDashboard({
        ...activeDashboard,
        rows: [...activeDashboard.rows, newRow]
    });
  };

  const handleDeleteRow = (rowId: string) => {
      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.filter(r => r.id !== rowId)
      });
  };

  const handleAddWidget = (rowId: string, type: 'chart' | 'markdown') => {
      let content = '';
      let title = 'New Widget';

      if (type === 'markdown') {
          content = '### New Markdown\nEdit this content...';
          title = 'Text Block';
      } else {
          if (pinnedCharts.length === 0) {
              alert("No pinned charts available to add. Go to SQL Editor to pin queries.");
              return;
          }
          const firstChart = pinnedCharts[0];
          content = firstChart.id;
          title = firstChart.title;
      }

      const newWidget: DashboardWidget = {
          id: `widget-${Date.now()}`,
          type,
          colSpan: 12, // Default full width
          content,
          title
      };

      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.map(r => 
            r.id === rowId ? { ...r, widgets: [...r.widgets, newWidget] } : r
          )
      });
  };

  const handleRemoveWidget = (rowId: string, widgetId: string) => {
      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.map(r => 
            r.id === rowId ? { ...r, widgets: r.widgets.filter(w => w.id !== widgetId) } : r
          )
      });
  };

  const handleChangeWidgetWidth = (rowId: string, widgetId: string, delta: number) => {
    onUpdateDashboard({
        ...activeDashboard,
        rows: activeDashboard.rows.map(r => {
            if (r.id !== rowId) return r;
            return {
                ...r,
                widgets: r.widgets.map(w => {
                    if (w.id !== widgetId) return w;
                    const newSpan = Math.max(1, Math.min(12, w.colSpan + delta));
                    return { ...w, colSpan: newSpan };
                })
            };
        })
    });
  };

  const handleMarkdownChange = (rowId: string, widgetId: string, newContent: string) => {
      onUpdateDashboard({
          ...activeDashboard,
          rows: activeDashboard.rows.map(r => {
              if (r.id !== rowId) return r;
              return {
                  ...r,
                  widgets: r.widgets.map(w => w.id === widgetId ? { ...w, content: newContent } : w)
              };
          })
      });
  };

  // --- Drag and Drop Logic ---

  const handleDragStart = (e: React.DragEvent, rowId: string, index: number) => {
      setDraggingItem({ rowId, index });
      e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault(); 
      e.dataTransfer.dropEffect = 'move';
  };

  const moveWidget = (sourceRowId: string, sourceIndex: number, targetRowId: string, targetIndex: number) => {
      const newRows = activeDashboard.rows.map(r => ({
          ...r,
          widgets: [...r.widgets]
      }));

      const sourceRow = newRows.find(r => r.id === sourceRowId);
      const targetRow = newRows.find(r => r.id === targetRowId);

      if (!sourceRow || !targetRow) return;

      const [widget] = sourceRow.widgets.splice(sourceIndex, 1);
      let finalIndex = targetIndex;
      if (sourceRowId === targetRowId && sourceIndex < targetIndex) {
          finalIndex--;
      }
      targetRow.widgets.splice(finalIndex, 0, widget);

      onUpdateDashboard({
          ...activeDashboard,
          rows: newRows
      });
  };

  const handleDropOnWidget = (e: React.DragEvent, targetRowId: string, targetIndex: number) => {
      e.preventDefault();
      e.stopPropagation();
      if (!draggingItem) return;
      moveWidget(draggingItem.rowId, draggingItem.index, targetRowId, targetIndex);
      setDraggingItem(null);
  };

  const handleDropOnRow = (e: React.DragEvent, targetRowId: string) => {
      e.preventDefault();
      e.stopPropagation();
      if (!draggingItem) return;
      const targetRow = activeDashboard.rows.find(r => r.id === targetRowId);
      if (targetRow) {
          moveWidget(draggingItem.rowId, draggingItem.index, targetRowId, targetRow.widgets.length);
      }
      setDraggingItem(null);
  };

  // --- Render ---

  return (
    <div className="flex flex-col h-full w-full bg-slate-950 overflow-hidden relative">

      {/* Dashboard Toolbar / Tabs */}
      <div className="h-14 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4 shrink-0">
          <div className="flex items-center space-x-1 overflow-x-auto no-scrollbar">
              {dashboards.map(d => (
                  <button
                    key={d.id}
                    onClick={() => onSetActiveDashboard(d.id)}
                    className={`px-4 py-2 text-sm rounded-t-lg border-t border-r border-l border-b-0 transition-colors ${
                        activeDashboardId === d.id 
                        ? 'bg-slate-950 border-slate-700 text-blue-400 font-medium translate-y-[1px]' 
                        : 'bg-transparent border-transparent text-slate-500 hover:text-slate-300 hover:bg-slate-800'
                    }`}
                  >
                      {d.title}
                  </button>
              ))}
              <button 
                onClick={() => {
                    const name = prompt("Dashboard Name:");
                    if(name) onAddDashboard(name);
                }} 
                className="p-2 ml-2 text-slate-500 hover:text-blue-400 hover:bg-slate-800 rounded"
              >
                  <Plus size={16} />
              </button>
          </div>

          <div className="flex items-center space-x-3">
               <button 
                onClick={handleExportPPT}
                className="flex items-center px-3 py-1.5 bg-orange-700/50 hover:bg-orange-600 text-orange-200 text-xs rounded border border-orange-600 transition-all"
                title="Export Dashboard to PowerPoint"
              >
                <Download size={14} className="mr-2" /> Export PPT
              </button>

              <div className="h-6 w-px bg-slate-800"></div>

              <button 
                onClick={() => setIsDesignerMode(!isDesignerMode)}
                className={`flex items-center px-3 py-1.5 text-xs rounded border transition-all ${
                    isDesignerMode 
                    ? 'bg-blue-900/30 border-blue-500 text-blue-400 shadow-[0_0_10px_rgba(59,130,246,0.2)]' 
                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-slate-200'
                }`}
              >
                  {isDesignerMode ? <Layout size={14} className="mr-2" /> : <Monitor size={14} className="mr-2" />}
                  {isDesignerMode ? 'Designer Active' : 'View Mode'}
              </button>

              <div className="h-6 w-px bg-slate-800"></div>

              <button 
                onClick={handleRefreshAll}
                className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded relative" 
                title={`Refresh Data ${refreshRate > 0 ? `(Auto: ${refreshRate}s)` : ''}`}
              >
                <RefreshCw size={16} className={refreshRate > 0 ? "text-green-400" : ""} />
                {refreshRate > 0 && <span className="absolute top-1 right-1 w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>}
              </button>
          </div>
      </div>

      {/* Workspace */}
      <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-950">

          {/* Dashboard Rows */}
          <div className="space-y-6 max-w-7xl mx-auto">
              {activeDashboard.rows.map((row, rowIndex) => (
                  <div 
                    key={row.id} 
                    className={`relative group/row ${isDesignerMode ? 'p-2 border border-dashed border-slate-700 rounded-xl bg-slate-900/30 min-h-[100px] transition-colors hover:border-blue-500/30' : ''}`}
                    onDragOver={isDesignerMode ? handleDragOver : undefined}
                    onDrop={isDesignerMode ? (e) => handleDropOnRow(e, row.id) : undefined}
                  >
                      {/* Row Controls */}
                      {isDesignerMode && (
                          <div className="absolute -top-3 left-4 bg-slate-800 text-xs text-slate-400 px-2 py-0.5 rounded border border-slate-700 flex items-center space-x-2 shadow-sm z-10">
                              <span className="font-mono">Row {rowIndex + 1}</span>
                              <div className="h-3 w-px bg-slate-600"></div>
                              <button onClick={() => handleDeleteRow(row.id)} className="hover:text-red-400"><Trash2 size={12} /></button>
                          </div>
                      )}

                      {/* Row Grid */}
                      <div className="grid grid-cols-12 gap-6 min-h-[50px]">
                          {row.widgets.length === 0 && isDesignerMode && (
                              <div className="col-span-12 flex items-center justify-center py-8 text-slate-600 border-2 border-dashed border-slate-800 rounded-lg pointer-events-none">
                                  Empty Row - Drop widget here or add new
                              </div>
                          )}

                          {row.widgets.map((widget, widgetIndex) => {
                              const chartDef = widget.type === 'chart' ? getChartDef(widget.content) : null;

                              return (
                                <div 
                                    key={widget.id} 
                                    className={`relative flex flex-col bg-slate-900 border border-slate-800 rounded-lg shadow-sm overflow-hidden min-h-[300px] transition-all 
                                        ${isDesignerMode ? 'cursor-grab active:cursor-grabbing hover:border-blue-500' : ''}
                                        ${draggingItem?.rowId === row.id && draggingItem?.index === widgetIndex ? 'opacity-40 border-dashed border-slate-600' : ''}
                                    `}
                                    style={{ gridColumn: `span ${widget.colSpan} / span ${widget.colSpan}` }}
                                    draggable={isDesignerMode}
                                    onDragStart={(e) => isDesignerMode && handleDragStart(e, row.id, widgetIndex)}
                                    onDragOver={isDesignerMode ? handleDragOver : undefined}
                                    onDrop={isDesignerMode ? (e) => handleDropOnWidget(e, row.id, widgetIndex) : undefined}
                                >
                                    {/* Widget Header */}
                                    <div className="h-9 px-3 flex items-center justify-between bg-slate-850 border-b border-slate-800 shrink-0 select-none">
                                        <div className="flex items-center space-x-2 overflow-hidden">
                                            {isDesignerMode && <GripVertical size={14} className="text-slate-600 cursor-grab" />}
                                            {widget.type === 'chart' && (
                                                <div className={`w-2 h-2 rounded-full shrink-0 ${loading[widget.content] ? 'bg-yellow-500 animate-pulse' : results[widget.content]?.error ? 'bg-red-500' : 'bg-green-500'}`} />
                                            )}
                                            <span className="text-xs font-bold text-slate-300 truncate">{widget.title || (chartDef?.title)}</span>
                                        </div>

                                        {isDesignerMode && (
                                            <div className="flex items-center space-x-1" onMouseDown={e => e.stopPropagation()}>
                                                <button onClick={() => handleChangeWidgetWidth(row.id, widget.id, -1)} disabled={widget.colSpan <= 1} className="p-1 hover:bg-slate-700 rounded text-slate-500 disabled:opacity-30"><MoveHorizontal size={12} className="rotate-180" /></button>
                                                <span className="text-[10px] font-mono text-slate-500 w-4 text-center">{widget.colSpan}</span>
                                                <button onClick={() => handleChangeWidgetWidth(row.id, widget.id, 1)} disabled={widget.colSpan >= 12} className="p-1 hover:bg-slate-700 rounded text-slate-500 disabled:opacity-30"><MoveHorizontal size={12} /></button>
                                                <div className="w-px h-3 bg-slate-700 mx-1"></div>
                                                <button onClick={() => handleRemoveWidget(row.id, widget.id)} className="p-1 hover:bg-red-900/50 hover:text-red-400 rounded text-slate-500"><X size={12} /></button>
                                            </div>
                                        )}

                                        {!isDesignerMode && widget.type === 'chart' && (
                                            <div className="flex items-center space-x-1">
                                                <button 
                                                    onClick={() => onEditChart(widget.content)} 
                                                    className="p-1 text-slate-500 hover:text-purple-400 rounded hover:bg-slate-800"
                                                    title="Edit Query & Chart"
                                                >
                                                    <Edit size={12} />
                                                </button>
                                                <button onClick={() => refreshChart(widget.content)} className="p-1 text-slate-500 hover:text-blue-400 rounded hover:bg-slate-800">
                                                    <RefreshCw size={12} />
                                                </button>
                                            </div>
                                        )}
                                    </div>

                                    {/* Widget Content */}
                                    <div className="flex-1 relative overflow-hidden" onMouseDown={e => isDesignerMode && e.stopPropagation()}>
                                        {widget.type === 'markdown' ? (
                                            <MarkdownVisualizer 
                                                content={widget.content} 
                                                onChange={(val) => handleMarkdownChange(row.id, widget.id, val)}
                                                isDesignerMode={isDesignerMode}
                                            />
                                        ) : (
                                            /* Chart Logic */
                                            <>
                                                {loading[widget.content] && !results[widget.content] ? (
                                                    <div className="absolute inset-0 flex items-center justify-center text-slate-600">
                                                        <RefreshCw className="animate-spin" />
                                                    </div>
                                                ) : results[widget.content]?.error ? (
                                                     <div className="absolute inset-0 flex flex-col items-center justify-center text-red-400 p-4 text-center">
                                                        <AlertCircle size={24} className="mb-2 opacity-50" />
                                                        <span className="text-xs font-mono">{results[widget.content].error}</span>
                                                    </div>
                                                ) : results[widget.content] && chartDef ? (
                                                    <DataVisualizer 
                                                        result={results[widget.content]} 
                                                        initialConfig={chartDef.config} 
                                                        readOnly={true} // Dashboard is mostly read-only for charts unless we open a full editor
                                                    />
                                                ) : (
                                                    <div className="absolute inset-0 flex items-center justify-center text-slate-600 text-xs">
                                                        {chartDef ? 'Waiting for data...' : 'Chart definition not found'}
                                                    </div>
                                                )}
                                            </>
                                        )}
                                    </div>

                                    {/* Chart Footer Info */}
                                    {widget.type === 'chart' && chartDef && (
                                        <div className="h-6 bg-slate-900 border-t border-slate-800 px-3 flex items-center justify-between text-[10px] text-slate-600 font-mono">
                                            <span className="truncate">{getDbName(chartDef.dbId)}</span>
                                            {results[widget.content] && <span>{results[widget.content].executionTimeMs}ms</span>}
                                        </div>
                                    )}
                                </div>
                              );
                          })}
                      </div>

                      {/* Add Widget Controls (Row Level) */}
                      {isDesignerMode && (
                          <div className="mt-2 flex justify-center opacity-0 group-hover/row:opacity-100 transition-opacity">
                              <div className="bg-slate-800 rounded-full border border-slate-700 p-1 flex space-x-1 shadow-lg transform translate-y-1/2">
                                  <button 
                                    onClick={() => handleAddWidget(row.id, 'chart')}
                                    className="px-3 py-1 text-xs rounded-full hover:bg-blue-600 hover:text-white text-slate-300 flex items-center transition-colors"
                                  >
                                      <BarChart3 size={12} className="mr-1" /> Add Chart
                                  </button>
                                  <div className="w-px bg-slate-700 my-1"></div>
                                  <button 
                                    onClick={() => handleAddWidget(row.id, 'markdown')}
