export type DbDialect = 'postgres' | 'mysql' | 'sqlite' | 'mssql' | 'parquet';

export interface IntrospectionQueries {
  getTables: string;
  getColumns: (tableName: string) => string;
  getForeignKeys: (tableName: string) => string;
}

export const DialectRegistry: Record<DbDialect, IntrospectionQueries> = {
  postgres: {
    getTables: `
      SELECT table_name as name 
      FROM information_schema.tables 
      WHERE table_schema = 'public' AND table_type = 'BASE TABLE'`,
    getColumns: (table) => `
      SELECT column_name as name, data_type as type, 
             (is_nullable = 'NO') as notnull,
             column_default as dflt_value,
             EXISTS (
               SELECT 1 FROM information_schema.key_column_usage kcu
               JOIN information_schema.table_constraints tc ON kcu.constraint_name = tc.constraint_name
               WHERE kcu.table_name = '${table}' AND kcu.column_name = column_name AND tc.constraint_type = 'PRIMARY KEY'
             ) as pk
      FROM information_schema.columns 
      WHERE table_name = '${table}'`,
    getForeignKeys: (table) => `
      SELECT kcu.column_name as "from", ccu.table_name as "table", ccu.column_name as "to"
      FROM information_schema.key_column_usage kcu
      JOIN information_schema.table_constraints tc ON kcu.constraint_name = tc.constraint_name
      JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_name = tc.constraint_name
      WHERE tc.constraint_type = 'FOREIGN KEY' AND kcu.table_name = '${table}'`
  },
  mysql: {
    getTables: "SHOW TABLES",
    getColumns: (table) => `DESCRIBE \`${table}\``,
    getForeignKeys: (table) => `
      SELECT COLUMN_NAME as 'from', REFERENCED_TABLE_NAME as 'table', REFERENCED_COLUMN_NAME as 'to'
      FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE
      WHERE TABLE_NAME = '${table}' AND REFERENCED_TABLE_NAME IS NOT NULL`
  },
  mssql: {
    getTables: "SELECT name FROM sys.tables WHERE is_ms_shipped = 0",
    getColumns: (table) => `
      SELECT name, TYPE_NAME(system_type_id) as type, is_nullable as notnull, is_identity as pk
      FROM sys.columns WHERE object_id = OBJECT_ID('${table}')`,
    getForeignKeys: (table) => `
      SELECT f.name AS constraint_name, OBJECT_NAME(f.parent_object_id) AS "from_table", 
             COL_NAME(fc.parent_object_id, fc.parent_column_id) AS "from", 
             OBJECT_NAME (f.referenced_object_id) AS "table", 
             COL_NAME(f.referenced_object_id, f.referenced_column_id) AS "to"
      FROM sys.foreign_keys AS f
      INNER JOIN sys.foreign_key_columns AS fc ON f.object_id = fc.constraint_object_id
      WHERE OBJECT_NAME(f.parent_object_id) = '${table}'`
  },
  sqlite: {
    getTables: "SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'",
    getColumns: (table) => `PRAGMA table_info("${table}")`,
    getForeignKeys: (table) => `PRAGMA foreign_key_list("${table}")`
  },
  parquet: {
    getTables: "SELECT name FROM sqlite_master WHERE type='table'",
    getColumns: (table) => `PRAGMA table_info("${table}")`,
    getForeignKeys: () => "SELECT 1 WHERE 1=0" // Parquet usually doesn't have FKs in this context
  }
};

import initSqlJs from 'sql.js';
import Papa from 'papaparse';
import { parquetRead } from 'hyparquet';
import * as fflate from 'fflate';
import { DbEngine, QueryResult, DbSchema, TableDefinition, ColumnDefinition } from '../../types';
import { DialectRegistry } from '../dialects/SqlDialects';

export class SqliteEngine implements DbEngine {
  private sqlPromise: Promise<any>;
  private instances: Map<string, any> = new Map(); // dbId -> SQL.Database

  constructor() {
    this.sqlPromise = initSqlJs({
      locateFile: file => `https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.8.0/${file}`
    });
  }

  async init() {
    await this.sqlPromise;
  }

  registerDatabase(id: string, db: any) {
    this.instances.set(id, db);
  }

  async createDatabaseFromFile(file: File): Promise<{ db: any, type: string }> {
     const SQL = await this.sqlPromise;

     if (file.name.endsWith('.sqlite') || file.name.endsWith('.db')) {
        const buffer = await file.arrayBuffer();
        return { db: new SQL.Database(new Uint8Array(buffer)), type: 'sqlite' };
     } 
     else if (file.name.endsWith('.csv')) {
        const text = await file.text();
        const parseResult = Papa.parse(text, { header: true, dynamicTyping: true, skipEmptyLines: true });
        const db = new SQL.Database();
        const tableName = this.sanitizeTableName(file.name);
        if (parseResult.meta.fields && parseResult.data.length > 0) {
            this.importDataToTable(db, tableName, parseResult.meta.fields, parseResult.data);
        }
        return { db, type: 'sqlite' };
     }
     else if (file.name.endsWith('.json')) {
        const text = await file.text();
        let data = JSON.parse(text);
        if (!Array.isArray(data)) {
             const keys = Object.keys(data);
             if (keys.length === 1 && Array.isArray(data[keys[0]])) data = data[keys[0]];
             else throw new Error("JSON must be an array of objects");
        }
        const db = new SQL.Database();
        if (data.length > 0) {
            const tableName = this.sanitizeTableName(file.name);
            const fields = Object.keys(data[0]);
            this.importDataToTable(db, tableName, fields, data);
        }
        return { db, type: 'sqlite' };
     }
     else if (file.name.endsWith('.parquet')) {
        const buffer = await file.arrayBuffer();

        const compressors = {
          GZIP: (data: Uint8Array) => fflate.gunzipSync(data)
        };

        const data = await new Promise<any[]>((resolve, reject) => {
            try {
                // IMPORTANT: hyparquet's parquetRead expects an object that provides bytes.
                // We wrap the ArrayBuffer to ensure compatibility and avoid DataView errors.
                const uint8Array = new Uint8Array(buffer);
                parquetRead({
                    file: uint8Array,
                    compressors,
                    onComplete: (rows: any[]) => resolve(rows)
                });
            } catch (e) {
                console.error("Parquet read error:", e);
                reject(e);
            }
        });

        const db = new SQL.Database();
        if (data && data.length > 0) {
             const tableName = this.sanitizeTableName(file.name);
             const fields = Object.keys(data[0]);
             this.importDataToTable(db, tableName, fields, data);
        }
        return { db, type: 'sqlite' };
     }
     throw new Error("Unsupported file type");
  }

  async executeQuery(dbId: string, sql: string): Promise<QueryResult> {
    const db = this.instances.get(dbId);
    if (!db) throw new Error("Database instance not found");

    const startTime = performance.now();
    try {
        const results = db.exec(sql);
        if (results.length === 0) {
            return {
               columns: [], rows: [], rowCount: 0,
               executionTimeMs: Math.round(performance.now() - startTime),
               timestamp: Date.now()
           };
       }
       const lastRes = results[results.length - 1];
       return {
           columns: lastRes.columns,
           rows: lastRes.values,
           rowCount: lastRes.values.length,
           executionTimeMs: Math.round(performance.now() - startTime),
           timestamp: Date.now()
       };
    } catch (e: any) {
        return {
            columns: [], rows: [], rowCount: 0,
            executionTimeMs: Math.round(performance.now() - startTime),
            timestamp: Date.now(),
            error: e.message
        };
    }
  }

  async getSchema(dbId: string): Promise<DbSchema> {
    const db = this.instances.get(dbId);
    if (!db) return { tables: [] };

    const dialect = DialectRegistry.sqlite;

    try {
        const tablesRes = db.exec(dialect.getTables);
        if (tablesRes.length === 0) return { tables: [] };

        const tableNames = tablesRes[0].values.flat();
        const tables: TableDefinition[] = [];

        for (const tableName of tableNames) {
            const colsRes = db.exec(dialect.getColumns(tableName as string));
            const columns: ColumnDefinition[] = [];

            let fks: any[] = [];
            try {
                const fkRes = db.exec(dialect.getForeignKeys(tableName as string));
                if (fkRes.length > 0) {
                    const fkCols = fkRes[0].columns;
                    fks = fkRes[0].values.map((row: any[]) => {
                        const obj: any = {};
                        fkCols.forEach((c: string, i: number) => obj[c] = row[i]);
                        return obj;
                    });
                }
            } catch(e) { /* ignore */ }

            if (colsRes.length > 0) {
                const colData = colsRes[0].values;
                for (const row of colData) {
                    const name = row[1] as string;
                    const type = row[2] as string;
                    const isPk = (row[5] as number) > 0;
                    const fkDef = fks.find((f: any) => f.from === name);

                    columns.push({
                        name,
                        type,
                        isPrimaryKey: isPk,
                        isForeignKey: !!fkDef,
                        references: fkDef ? { table: fkDef.table, column: fkDef.to } : undefined
                    });
                }
            }
            tables.push({ name: tableName as string, columns });
        }
        return { tables };
    } catch (e) {
        console.error("Error fetching schema", e);
        return { tables: [] };
    }
  }

  private importDataToTable(db: any, tableName: string, fields: string[], data: any[]) {
      const columnsDef = fields.map(f => `"${f}" TEXT`).join(', '); 
      db.run(`CREATE TABLE "${tableName}" (${columnsDef});`);
      const placeholders = fields.map(() => '?').join(', ');
      const stmt = db.prepare(`INSERT INTO "${tableName}" VALUES (${placeholders})`);
      db.exec("BEGIN TRANSACTION");
      for (const row of data) {
          const values = fields.map(f => {
              const val = row[f];
              if (val === undefined || val === null) return null;
              return (typeof val === 'object') ? JSON.stringify(val) : val;
          });
          stmt.run(values);
      }
      db.exec("COMMIT");
      stmt.free();
  }

  private sanitizeTableName(filename: string): string {
      return filename.replace(/[^a-zA-Z0-9]/g, '_').replace(/_(csv|json|parquet)$/i, '');
  }
}

