      { id: 'pg-expensive', category: 'Expensive Queries', title: 'Top 10 Slow Queries', description: 'Identify queries with highest total execution time (requires pg_stat_statements).', query: 'SELECT query, calls, total_exec_time, mean_exec_time FROM pg_stat_statements ORDER BY total_exec_time DESC LIMIT 10;' },
      { id: 'pg-frag', category: 'Fragmentation', title: 'Table & Index Bloat', description: 'Estimated fragmentation/bloat in tables. High bloat indicates need for VACUUM.', query: 'SELECT schemaname, relname, n_dead_tup, n_live_tup, (n_dead_tup::float / NULLIF(n_live_tup + n_dead_tup, 0)) as bloat_ratio FROM pg_stat_all_tables WHERE schemaname = "public" ORDER BY n_dead_tup DESC;' },
      { id: 'pg-2', category: 'Storage', title: 'Database Size', description: 'Total disk space consumed by the database.', query: 'SELECT pg_database.datname, pg_size_pretty(pg_database_size(pg_database.datname)) AS size FROM pg_database;' }
