      { id: 'my-frag', category: 'Fragmentation', title: 'Data Fragmentation', description: 'Find tables that have "Data Free" space (need OPTIMIZE TABLE).', query: 'SELECT TABLE_NAME, DATA_FREE, DATA_LENGTH FROM information_schema.TABLES WHERE TABLE_SCHEMA = DATABASE() AND DATA_FREE > 0 ORDER BY DATA_FREE DESC;' }
    ]
  },
  mssql: {
    getTables: "SELECT name FROM sys.tables WHERE is_ms_shipped = 0",
