    insights: [
      { id: 'ms-frag', category: 'Fragmentation', title: 'Index Fragmentation (>30%)', description: 'Highly fragmented indexes causing poor IO performance.', query: 'SELECT OBJECT_NAME(ind.OBJECT_ID) AS TableName, ind.name AS IndexName, indexstats.avg_fragmentation_in_percent FROM sys.dm_db_index_physical_stats(DB_ID(), NULL, NULL, NULL, "DETAILED") indexstats INNER JOIN sys.indexes ind ON ind.object_id = indexstats.object_id AND ind.index_id = indexstats.index_id WHERE indexstats.avg_fragmentation_in_percent > 30 ORDER BY indexstats.avg_fragmentation_in_percent DESC;' },
      { id: 'ms-expensive', category: 'Expensive Queries', title: 'Most CPU Intensive Queries', description: 'Top 10 queries by total worker time (CPU).', query: 'SELECT TOP 10 text AS [Query], last_execution_time, total_worker_time/execution_count AS [Avg CPU] FROM sys.dm_exec_query_stats CROSS APPLY sys.dm_exec_sql_text(sql_handle) ORDER BY [Avg CPU] DESC;' },
      { id: 'ms-plan', category: 'Performance', title: 'Cached Query Plans', description: 'View execution plans currently stored in the plan cache.', query: 'SELECT TOP 10 st.text, qp.query_plan FROM sys.dm_exec_cached_plans CROSS APPLY sys.dm_exec_sql_text(plan_handle) AS st CROSS APPLY sys.dm_exec_query_plan(plan_handle) AS qp;' },
      { id: 'ms-1', category: 'Indexes', title: 'Missing Index Suggestions', description: 'Indexes recommended by the SQL Server optimizer.', query: 'SELECT mid.statement AS [Table], mid.equality_columns, mid.inequality_columns, mid.included_columns FROM sys.dm_db_missing_index_details AS mid;' }
