import React from 'react';
import { DialectRegistry, DbDialect, DbaInsight } from '../services/dialects/SqlDialects';
import { Gauge, ShieldAlert, Zap, HardDrive, Search, Activity, Split, TrendingUp, Cpu } from 'lucide-react';

interface DbaPanelProps {
  dialect: DbDialect;
  onSelectInsight: (query: string, title: string) => void;
}

const DbaPanel: React.FC<DbaPanelProps> = ({ dialect, onSelectInsight }) => {
  const insights = DialectRegistry[dialect]?.insights || [];

  const categories = Array.from(new Set(insights.map(i => i.category)));

  const getIcon = (category: string) => {
    switch (category) {
      case 'Performance': return <Zap size={14} className="text-yellow-500" />;
      case 'Storage': return <HardDrive size={14} className="text-blue-500" />;
      case 'Indexes': return <Search size={14} className="text-purple-500" />;
      case 'Fragmentation': return <Split size={14} className="text-red-500" />;
      case 'Expensive Queries': return <TrendingUp size={14} className="text-amber-500" />;
      case 'System': return <Cpu size={14} className="text-cyan-500" />;
      default: return <Activity size={14} className="text-green-500" />;
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 animate-in slide-in-from-left-2 duration-200 border-r border-slate-800">
      <div className="p-4 border-b border-slate-800 bg-slate-850">
        <div className="flex items-center text-blue-400 mb-1">
          <ShieldAlert size={18} className="mr-2" />
          <h2 className="font-bold text-sm uppercase tracking-wider">DBA Control</h2>
        </div>
        <p className="text-[10px] text-slate-500 italic">Advanced DMVs for {dialect.toUpperCase()}</p>
      </div>

      <div className="flex-1 overflow-y-auto p-2 space-y-4 scrollbar-hide">
        {categories.map(cat => (
          <div key={cat} className="space-y-1">
            <h3 className="px-2 py-1 text-[10px] font-bold text-slate-600 uppercase tracking-widest flex items-center bg-slate-800/20 rounded">
               {getIcon(cat)} <span className="ml-2">{cat}</span>
            </h3>
            <div className="space-y-0.5">
              {insights.filter(i => i.category === cat).map(i => (
                <button
                  key={i.id}
                  onClick={() => onSelectInsight(i.query, i.title)}
                  className="w-full text-left p-2 rounded hover:bg-slate-800 transition-all group flex flex-col border border-transparent hover:border-slate-700"
                >
                  <span className="text-xs font-semibold text-slate-300 group-hover:text-blue-400">{i.title}</span>
                  <span className="text-[10px] text-slate-500 line-clamp-2 leading-tight mt-0.5">{i.description}</span>
                </button>
              ))}
            </div>
          </div>
        ))}

        {insights.length === 0 && (
          <div className="flex flex-col items-center justify-center py-20 text-slate-600 text-center px-4">
             <Gauge size={40} className="mb-2 opacity-10" />
             <p className="text-xs font-medium">No admin insights for this engine.</p>
          </div>
        )}
      </div>

      <div className="p-3 bg-slate-950 border-t border-slate-800">
        <div className="flex items-center p-2 rounded bg-blue-900/10 border border-blue-500/20">
          <TrendingUp size={12} className="text-blue-400 mr-2 shrink-0" />
          <span className="text-[10px] text-blue-300 leading-tight">Queries are optimized for diagnostic performance.</span>
        </div>
      </div>
    </div>
  );
};

export default DbaPanel;

import { DbEngine, QueryResult, DbSchema } from '../../types';

export class MockEngine implements DbEngine {

  async init() {
      // no-op
  }

  async executeQuery(dbId: string, sql: string): Promise<QueryResult> {
      // Simulate network delay
      await new Promise(r => setTimeout(r, 400));

      const lowerSql = sql.toLowerCase();

      // Fragmentation Mock
      if (lowerSql.includes('fragmentation') || lowerSql.includes('bloat')) {
          return {
              columns: ['TableName', 'IndexName', 'Fragmentation %', 'Status'],
              rows: [
                  ['users', 'PK_users', 42.5, 'Critical'],
                  ['orders', 'IX_orders_user_id', 12.2, 'Healthy'],
                  ['products', 'IX_products_sku', 8.9, 'Healthy'],
                  ['reviews', 'PK_reviews', 31.4, 'Warning']
              ],
              rowCount: 4,
              executionTimeMs: 180,
              timestamp: Date.now()
          };
      }

      // Expensive Queries Mock
      if (lowerSql.includes('sys.dm_exec_query_stats') || lowerSql.includes('total_worker_time') || lowerSql.includes('pg_stat_statements')) {
          return {
              columns: ['Query', 'Executions', 'Avg CPU (ms)', 'Last Run'],
              rows: [
                  ['SELECT * FROM orders WHERE status = "pending" JOIN users...', 4500, 120.5, '2023-10-27 10:15'],
                  ['UPDATE products SET stock = stock - 1 WHERE id = ...', 12000, 45.2, '2023-10-27 10:20'],
                  ['SELECT SUM(total) FROM orders GROUP BY user_id...', 80, 890.1, '2023-10-27 09:00'],
                  ['DELETE FROM logs WHERE created_at < ...', 1, 4500.0, '2023-10-26 23:59']
              ],
              rowCount: 4,
              executionTimeMs: 250,
              timestamp: Date.now()
          };
      }

      // Query Plans Mock
      if (lowerSql.includes('query_plan') || lowerSql.includes('sys.dm_exec_cached_plans')) {
          return {
              columns: ['QueryText', 'QueryPlan'],
              rows: [
                ['SELECT * FROM users', '<ShowPlanXML xmlns="http://schemas.microsoft.com/..."><BatchSequence>...</BatchSequence></ShowPlanXML>'],
                ['SELECT count(*) FROM orders', '<ShowPlanXML>...</ShowPlanXML>']
              ],
              rowCount: 2,
              executionTimeMs: 400,
              timestamp: Date.now()
          };
      }

      // Simple Mock Logic for general SELECT
      if (lowerSql.includes('select')) {
         const rowCount = 20;
         return {
             columns: ['id', 'name', 'status', 'created_at'],
             rows: Array.from({length: rowCount}, (_, i) => [i, `Item ${i}`, i % 2 === 0 ? 'active' : 'inactive', '2023-01-01']),
             rowCount,
             executionTimeMs: 120,
             timestamp: Date.now()
         };
      }

      return {
          columns: [], rows: [], rowCount: 0, executionTimeMs: 50, timestamp: Date.now()
      };
  }

  async getSchema(dbId: string): Promise<DbSchema> {
      // Return a rich mock schema for visualization
      return {
          tables: [
              {
                  name: 'users',
                  columns: [
                      { name: 'id', type: 'uuid', isPrimaryKey: true, isForeignKey: false },
                      { name: 'email', type: 'varchar', isPrimaryKey: false, isForeignKey: false },
                      { name: 'full_name', type: 'varchar', isPrimaryKey: false, isForeignKey: false },
                      { name: 'role', type: 'varchar', isPrimaryKey: false, isForeignKey: false },
                      { name: 'created_at', type: 'timestamp', isPrimaryKey: false, isForeignKey: false }
                  ]
              },
              {
                  name: 'orders',
                  columns: [
                      { name: 'id', type: 'uuid', isPrimaryKey: true, isForeignKey: false },
                      { name: 'user_id', type: 'uuid', isPrimaryKey: false, isForeignKey: true, references: { table: 'users', column: 'id' } },
                      { name: 'status', type: 'varchar', isPrimaryKey: false, isForeignKey: false },
                      { name: 'total', type: 'decimal', isPrimaryKey: false, isForeignKey: false }
                  ]
              },
              {
                  name: 'order_items',
                  columns: [
                      { name: 'id', type: 'uuid', isPrimaryKey: true, isForeignKey: false },
                      { name: 'order_id', type: 'uuid', isPrimaryKey: false, isForeignKey: true, references: { table: 'orders', column: 'id' } },
                      { name: 'product_id', type: 'uuid', isPrimaryKey: false, isForeignKey: true, references: { table: 'products', column: 'id' } },
                      { name: 'quantity', type: 'integer', isPrimaryKey: false, isForeignKey: false }
                  ]
              },
              {
                  name: 'products',
                  columns: [
                      { name: 'id', type: 'uuid', isPrimaryKey: true, isForeignKey: false },
                      { name: 'name', type: 'varchar', isPrimaryKey: false, isForeignKey: false },
                      { name: 'sku', type: 'varchar', isPrimaryKey: false, isForeignKey: false },
                      { name: 'price', type: 'decimal', isPrimaryKey: false, isForeignKey: false }
                  ]
              },
              {
                  name: 'reviews',
                  columns: [
                      { name: 'id', type: 'uuid', isPrimaryKey: true, isForeignKey: false },
                      { name: 'product_id', type: 'uuid', isPrimaryKey: false, isForeignKey: true, references: { table: 'products', column: 'id' } },
                      { name: 'rating', type: 'integer', isPrimaryKey: false, isForeignKey: false },
                      { name: 'comment', type: 'text', isPrimaryKey: false, isForeignKey: false }
                  ]
              }
          ]
      };
  }
}

