import React, { useState, useEffect } from 'react';
import { DialectRegistry, DbDialect, DbaInsight } from '../services/dialects/SqlDialects';
import { dbaHistoryService } from '../services/dbaHistoryService';
import { DbaHistoryRecord } from '../types';
import { 
  Gauge, ShieldAlert, Zap, HardDrive, Search, 
  Activity, Split, TrendingUp, Cpu, History, 
  Database as DbIcon, Server, Camera, Trash2, ChevronRight,
  LayoutGrid
} from 'lucide-react';

interface DbaPanelProps {
  dialect: DbDialect;
  dbId: string;
  dbName: string;
  onSelectInsight: (insight: DbaInsight) => void;
  onViewHistory: (record: DbaHistoryRecord) => void;
  onLaunchDashboard: () => void; // New prop
  customInsights?: Partial<Record<string, DbaInsight[]>>;
}

const DbaPanel: React.FC<DbaPanelProps> = ({ dialect, dbId, dbName, onSelectInsight, onViewHistory, onLaunchDashboard, customInsights }) => {
  const [activeView, setActiveView] = useState<'insights' | 'history'>('insights');
  const [context, setContext] = useState<'server' | 'database'>('database');
  const [history, setHistory] = useState<DbaHistoryRecord[]>([]);

  useEffect(() => {
    setHistory(dbaHistoryService.getHistory(dbId));
  }, [dbId, activeView]);

  const getInsights = () => {
    const registryInsights = DialectRegistry[dialect]?.insights || [];
    const custom = customInsights?.[dialect];
    return custom ? custom : registryInsights;
  };

  const insights = getInsights().filter(i => i.context === context);
  const categories = Array.from(new Set(insights.map(i => i.category)));

  const getIcon = (category: string) => {
    switch (category) {
      case 'Performance': return <Zap size={14} className="text-yellow-500" />;
      case 'Storage': return <HardDrive size={14} className="text-blue-500" />;
      case 'Indexes': return <Search size={14} className="text-purple-500" />;
      case 'Fragmentation': return <Split size={14} className="text-red-500" />;
      case 'Expensive Queries': return <TrendingUp size={14} className="text-amber-500" />;
      case 'System': return <Cpu size={14} className="text-cyan-500" />;
      default: return <Activity size={14} className="text-green-500" />;
    }
  };

  const handleDeleteHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    dbaHistoryService.deleteRecord(id);
    setHistory(prev => prev.filter(r => r.id !== id));
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 animate-in slide-in-from-left-2 duration-200 border-r border-slate-800 shrink-0 overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-slate-800 bg-slate-850">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center text-blue-400">
            <ShieldAlert size={18} className="mr-2" />
            <h2 className="font-bold text-sm uppercase tracking-wider">DBA Studio</h2>
          </div>
          <div className="flex bg-slate-900 p-0.5 rounded border border-slate-700">
            <button 
              onClick={() => setActiveView('insights')}
              className={`p-1 rounded transition-colors ${activeView === 'insights' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-slate-300'}`}
              title="Diagnostic Insights"
            >
              <Zap size={14} />
            </button>
            <button 
              onClick={() => setActiveView('history')}
              className={`p-1 rounded transition-colors ${activeView === 'history' ? 'bg-slate-700 text-purple-400' : 'text-slate-500 hover:text-slate-300'}`}
              title="Snapshot History"
            >
              <History size={14} />
            </button>
          </div>
        </div>

        {/* Dashboard CTA */}
        <button 
          onClick={onLaunchDashboard}
          className="w-full mb-3 flex items-center justify-center p-2 rounded bg-blue-600 hover:bg-blue-500 text-white text-[11px] font-bold uppercase transition-all shadow-lg shadow-blue-900/20"
        >
          <LayoutGrid size={14} className="mr-2" /> Performance Dashboard
        </button>

        {activeView === 'insights' && (
          <div className="flex p-0.5 bg-slate-900 rounded-lg border border-slate-800">
             <button 
               onClick={() => setContext('database')}
               className={`flex-1 flex items-center justify-center py-1.5 text-[10px] font-bold uppercase rounded ${context === 'database' ? 'bg-slate-700 text-white' : 'text-slate-500 hover:bg-slate-800'}`}
             >
               <DbIcon size={12} className="mr-1.5" /> Database
             </button>
             <button 
               onClick={() => setContext('server')}
               className={`flex-1 flex items-center justify-center py-1.5 text-[10px] font-bold uppercase rounded ${context === 'server' ? 'bg-slate-700 text-white' : 'text-slate-500 hover:bg-slate-800'}`}
             >
               <Server size={12} className="mr-1.5" /> Server
             </button>
          </div>
        )}
      </div>

      <div className="flex-1 overflow-y-auto p-2 scrollbar-hide">
        {activeView === 'insights' ? (
          <div className="space-y-4">
            {categories.map(cat => (
              <div key={cat} className="space-y-1">
                <h3 className="px-2 py-1 text-[10px] font-bold text-slate-600 uppercase tracking-widest flex items-center bg-slate-800/20 rounded">
                   {getIcon(cat)} <span className="ml-2">{cat}</span>
                </h3>
                <div className="space-y-0.5">
                  {insights.filter(i => i.category === cat).map(i => (
                    <button
                      key={i.id}
                      onClick={() => onSelectInsight(i)}
                      className="w-full text-left p-2 rounded hover:bg-slate-800 transition-all group flex flex-col border border-transparent hover:border-slate-700"
                    >
                      <div className="flex items-center justify-between">
                        <span className="text-xs font-semibold text-slate-300 group-hover:text-blue-400">{i.title}</span>
                        {i.impact === 'High' && <span className="w-1.5 h-1.5 rounded-full bg-red-500" title="High Impact" />}
                      </div>
                      <span className="text-[10px] text-slate-500 line-clamp-2 leading-tight mt-0.5">{i.description}</span>
                    </button>
                  ))}
                </div>
              </div>
            ))}
            {insights.length === 0 && (
              <div className="flex flex-col items-center justify-center py-20 text-slate-600 text-center px-4">
                 <Gauge size={40} className="mb-2 opacity-10" />
                 <p className="text-xs font-medium">No diagnostic insights available.</p>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-2">
            {history.length > 0 ? (
              history.map(record => (
                <div 
                  key={record.id}
                  onClick={() => onViewHistory(record)}
                  className="w-full p-2.5 rounded bg-slate-800/40 hover:bg-slate-800 border border-slate-700/50 hover:border-blue-500/50 transition-all cursor-pointer group"
                >
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-[10px] font-bold text-blue-400 uppercase">{record.insightTitle}</span>
                    <button 
                      onClick={(e) => handleDeleteHistory(record.id, e)}
                      className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-400 transition-opacity"
                    >
                      <Trash2 size={12} />
                    </button>
                  </div>
                  <div className="flex items-center text-[10px] text-slate-500">
                    <Activity size={10} className="mr-1" />
                    <span>{new Date(record.timestamp).toLocaleString()}</span>
                  </div>
                </div>
              ))
            ) : (
              <div className="flex flex-col items-center justify-center py-20 text-slate-600 text-center px-4">
                 <Camera size={40} className="mb-2 opacity-10" />
                 <p className="text-xs font-medium">No snapshots taken yet.</p>
              </div>
            )}
          </div>
        )}
      </div>

      <div className="p-3 bg-slate-950 border-t border-slate-800">
        <div className="flex items-center p-2 rounded bg-blue-900/10 border border-blue-500/20">
          <Activity size={12} className="text-blue-400 mr-2 shrink-0" />
          <span className="text-[10px] text-blue-300 leading-tight">Connected: <span className="text-white font-mono">{dbName}</span></span>
        </div>
      </div>
    </div>
  );
};

export default DbaPanel;

import React, { useState, useEffect, useRef } from 'react';
import { Database, EditorTab, QueryResult, ChartConfig, PinnedChart, DashboardLayout, AppSettings, SavedQuery, DbSchema, SchemaLayout, DbaHistoryRecord } from './types';
import { muulService } from './services/muulService';
import { exportService } from './services/exportService';
import { dbaHistoryService } from './services/dbaHistoryService';
import { DbaInsight } from './services/dialects/SqlDialects';
import { 
  Play, Plus, X, Save, Download, Database as DbIcon, 
  Activity, Ban, ChevronDown, ChevronUp, ChevronRight,
  LayoutDashboard, TerminalSquare, Settings, Bookmark, FolderOpen, Upload, Table as TableIcon,
  Network, Leaf, ShieldAlert, Camera
} from 'lucide-react';
import SqlEditor, { SqlEditorRef } from './components/SqlEditor';
import ResultsPane from './components/ResultsPane';
import Dashboard from './components/Dashboard';
import SchemaVisualizer from './components/SchemaVisualizer';
import SettingsModal from './components/SettingsModal';
import DbaPanel from './components/DbaPanel';
import DbaPerformanceDashboard from './components/DbaPerformanceDashboard';

type LayoutMode = 'bottom' | 'right' | 'left' | 'float';
type ViewMode = 'editor' | 'dashboard' | 'schema' | 'dba-perf';
type SidebarTab = 'db' | 'saved' | 'dba';

const App: React.FC = () => {
  // --- State ---
  const [currentView, setCurrentView] = useState<ViewMode>('editor');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('db');
  const [databases, setDatabases] = useState<Database[]>([]);
  const [selectedDbId, setSelectedDbId] = useState<string>('');

  const [dbTables, setDbTables] = useState<Record<string, string[]>>({});
  const [expandedDbIds, setExpandedDbIds] = useState<Set<string>>(new Set());

  const [activeSchema, setActiveSchema] = useState<DbSchema>({ tables: [] });
  const [schemaLayouts, setSchemaLayouts] = useState<SchemaLayout[]>([]);
  const [activeLayoutId, setActiveLayoutId] = useState<string | null>(null);

  const [isDraggingFile, setIsDraggingFile] = useState(false);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [appSettings, setAppSettings] = useState<AppSettings>(() => {
    const saved = localStorage.getItem('muul_settings');
    return saved ? JSON.parse(saved) : {
      editorFontSize: 14,
      themeAccent: 'blue',
      refreshRate: 0,
      customInsights: {}
    };
  });

  useEffect(() => {
    localStorage.setItem('muul_settings', JSON.stringify(appSettings));
  }, [appSettings]);

  const [savedQueries, setSavedQueries] = useState<SavedQuery[]>([
      { id: 'sq-1', name: 'Get All Users', content: 'SELECT * FROM users LIMIT 100;', dbId: 'db-1', createdAt: Date.now() }
  ]);

  const [pinnedCharts, setPinnedCharts] = useState<PinnedChart[]>([]);
  const [dashboards, setDashboards] = useState<DashboardLayout[]>([
      {
          id: 'main-dash',
          title: 'Main Dashboard',
          isDefault: true,
          rows: [
              {
                  id: 'row-welcome',
                  widgets: [
                      { id: 'w-welcome', type: 'markdown', colSpan: 12, title: 'Welcome', content: '# Welcome to Muul SQL\nDrag and drop **.csv**, **.json**, **.parquet**, or **.sqlite** files to instantly query them!'}
                  ]
              }
          ]
      }
  ]);
  const [activeDashboardId, setActiveDashboardId] = useState<string>('main-dash');

  const [tabs, setTabs] = useState<EditorTab[]>([
    { 
      id: 'tab-1', 
      title: 'Query 1', 
      content: '', 
      isDirty: false, 
      isExecuting: false, 
      results: [],
      activeResultIndex: -1 
    }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab-1');
  const [resultViewMode, setResultViewMode] = useState<'table' | 'chart'>('table');
  const [isEditorExpanded, setIsEditorExpanded] = useState(true);

  const [layout, setLayout] = useState<LayoutMode>('bottom');
  const [panelSize, setPanelSize] = useState(40); 
  const [floatRect, setFloatRect] = useState({ x: 100, y: 100, w: 600, h: 400 });

  const editorRef = useRef<SqlEditorRef>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const dragInfo = useRef<{ 
    isDragging: boolean; 
    type: 'resize-dock' | 'move-float' | 'resize-float'; 
    startX: number; 
    startY: number; 
    startSize?: number;
    startRect?: typeof floatRect;
  }>({ isDragging: false, type: 'resize-dock', startX: 0, startY: 0 });

  useEffect(() => {
    muulService.getDatabases().then(dbs => {
      setDatabases(dbs);
      if (dbs.length > 0) {
          setSelectedDbId(dbs[0].id);
          setExpandedDbIds(new Set([dbs[0].id]));
      }
    });
  }, []);

  useEffect(() => {
      if (selectedDbId) {
          if (!dbTables[selectedDbId]) {
              muulService.getDatabaseTables(selectedDbId).then(tables => {
                  setDbTables(prev => ({ ...prev, [selectedDbId]: tables }));
              });
          }
          muulService.getDatabaseSchema(selectedDbId).then(schema => {
              setActiveSchema(schema);
              setSchemaLayouts(prev => {
                  const hasLayout = prev.some(l => l.dbId === selectedDbId);
                  if (!hasLayout && schema.tables.length > 0) {
                      const defaultLayout: SchemaLayout = {
                          id: `layout-${Date.now()}`,
                          name: 'Main Diagram',
                          dbId: selectedDbId,
                          tables: schema.tables.map(t => t.name),
                          createdAt: Date.now()
                      };
                      setActiveLayoutId(defaultLayout.id);
                      return [...prev, defaultLayout];
                  }
                  const dbLayouts = prev.filter(l => l.dbId === selectedDbId);
                  if (dbLayouts.length > 0 && (!activeLayoutId || !dbLayouts.find(l => l.id === activeLayoutId))) {
                      setActiveLayoutId(dbLayouts[0].id);
                  }
                  return prev;
              });
          });
      }
  }, [selectedDbId]);

  useEffect(() => {
      if (selectedDbId) {
           const dbLayouts = schemaLayouts.filter(l => l.dbId === selectedDbId);
           if (dbLayouts.length > 0) {
               const active = schemaLayouts.find(l => l.id === activeLayoutId);
               if (!active || active.dbId !== selectedDbId) {
                   setActiveLayoutId(dbLayouts[0].id);
               }
           } else {
               setActiveLayoutId(null);
           }
      }
  }, [selectedDbId, schemaLayouts]);

  const handleLayoutCreate = (name: string, tables: string[]) => {
      if (!selectedDbId) return;
      const newLayout: SchemaLayout = {
          id: `layout-${Date.now()}`,
          name,
          dbId: selectedDbId,
          tables,
          createdAt: Date.now()
      };
      setSchemaLayouts(prev => [...prev, newLayout]);
      setActiveLayoutId(newLayout.id);
  };

  const handleLayoutUpdate = (layoutId: string, tables: string[]) => {
      setSchemaLayouts(prev => prev.map(l => l.id === layoutId ? { ...l, tables } : l));
  };

  const handleLayoutDelete = (layoutId: string) => {
      const remaining = schemaLayouts.filter(l => l.id !== layoutId);
      setSchemaLayouts(remaining);
      if (activeLayoutId === layoutId) {
          const others = remaining.filter(l => l.dbId === selectedDbId);
          setActiveLayoutId(others.length > 0 ? others[0].id : null);
      }
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragInfo.current.isDragging) return;

      const { type, startX, startY, startSize, startRect } = dragInfo.current;
      const container = containerRef.current;

      if (type === 'resize-dock' && container && startSize !== undefined) {
        const rect = container.getBoundingClientRect();
        let delta = 0;
        let newSize = startSize;

        if (layout === 'bottom') {
           delta = (startY - e.clientY) / rect.height * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'right') {
           delta = (startX - e.clientX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'left') {
           delta = (e.clientX - startX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        }
        setPanelSize(newSize);
      } 
      else if (type === 'move-float' && startRect) {
        setFloatRect({
          ...startRect,
          x: startRect.x + (e.clientX - startX),
          y: startRect.y + (e.clientY - startY)
        });
      }
      else if (type === 'resize-float' && startRect) {
        setFloatRect({
          ...startRect,
          w: Math.max(300, startRect.w + (e.clientX - startX)),
          h: Math.max(200, startRect.h + (e.clientY - startY))
        });
      }
    };

    const handleMouseUp = () => {
      dragInfo.current.isDragging = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [layout]);

  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.currentTarget === e.target) {
        setIsDraggingFile(false);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
  };

  const handleFileDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);

    const files: File[] = Array.from(e.dataTransfer.files);
    if (files.length === 0) return;

    for (const file of files) {
        if (file.name.endsWith('.sqlite') || file.name.endsWith('.db') || file.name.endsWith('.csv') || file.name.endsWith('.json') || file.name.endsWith('.parquet')) {
            try {
                const newDb = await muulService.uploadDatabase(file);
                setDatabases(prev => [newDb, ...prev]);
                setSelectedDbId(newDb.id);
                setExpandedDbIds(prev => new Set(prev).add(newDb.id));
                const tables = await muulService.getDatabaseTables(newDb.id);
                setDbTables(prev => ({ ...prev, [newDb.id]: tables }));
            } catch (err: any) {
                alert(`Failed to load ${file.name}: ${err.message}`);
            }
        } else {
            alert(`File ${file.name} is not supported.`);
        }
    }
  };

  const activeTab = tabs.find(t => t.id === activeTabId)!;
  const activeResult = activeTab?.activeResultIndex >= 0 
    ? activeTab.results[activeTab.activeResultIndex] 
    : null;
  const selectedDb = databases.find(d => d.id === selectedDbId);

  const handleDbClick = (dbId: string) => {
      setSelectedDbId(dbId);
      setExpandedDbIds(prev => {
          const next = new Set(prev);
          if (next.has(dbId)) next.delete(dbId);
          else next.add(dbId);
          return next;
      });
  };

  const handleTableClick = (tableName: string) => {
      const existingTab = tabs.find(t => t.title === tableName && !t.isDirty);
      if (existingTab) {
          setActiveTabId(existingTab.id);
          setCurrentView('editor');
          return;
      }

      const isMongo = selectedDb?.type === 'mongodb';
      const content = isMongo 
          ? `db.${tableName}.find({}).limit(100)`
          : `SELECT * FROM "${tableName}" LIMIT 100;`;

      const newId = `tab-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: tableName,
          content,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
  };

  const handleCreateTab = () => {
    const newId = `tab-${Date.now()}`;
    setTabs([...tabs, {
      id: newId, title: `Query ${tabs.length + 1}`, content: '', isDirty: false, isExecuting: false, results: [], activeResultIndex: -1
    }]);
    setActiveTabId(newId);
  };

  const handleOpenSavedQuery = (sq: SavedQuery) => {
      const newId = `tab-${Date.now()}`;
      setTabs([...tabs, {
          id: newId,
          title: sq.name,
          content: sq.content,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      if(sq.dbId) setSelectedDbId(sq.dbId);
      setCurrentView('editor');
  };

  const handleSelectDbaInsight = (insight: DbaInsight) => {
      const newId = `dba-${insight.id}-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: `Diagnostic: ${insight.title}`,
          content: insight.query,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
      setTimeout(() => {
          executeTabQuery(newId, insight.query, false);
      }, 50);
  };

  const handleViewHistoryRecord = (record: DbaHistoryRecord) => {
      const newId = `hist-${record.id}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: `Snapshot: ${record.insightTitle}`,
          content: `-- Snapshot from ${new Date(record.timestamp).toLocaleString()}\n${record.data.rowCount} rows captured.\n\n${record.data.columns.join(' | ')}`,
          isDirty: false,
          isExecuting: false,
          results: [record.data],
          activeResultIndex: 0
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
  };

  const handleCaptureSnapshot = () => {
      if (!activeResult || !selectedDbId || !selectedDb) return;
      const title = activeTab.title.replace('Diagnostic: ', '').replace('Snapshot: ', '');
      dbaHistoryService.saveSnapshot(selectedDbId, selectedDb.name, activeTab.id, title, activeResult);
      alert("Diagnostic snapshot captured to history.");
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (tabs.length === 1) return;
    const newTabs = tabs.filter(t => t.id !== id);
    setTabs(newTabs);
    if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
  };

  const executeTabQuery = async (tabId: string, content: string, selectionOnly: boolean = false) => {
    if (!selectedDbId) return alert("Please select a database first.");

    let queriesToRun = [content];
    if (selectionOnly && selectedDb?.type !== 'mongodb') {
         queriesToRun = content.split(';').map(q => q.trim()).filter(q => q.length > 0);
    }

    if (queriesToRun.length === 0) return;

    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: true } : t));
    const executionId = Date.now().toString();

    try {
      const results: QueryResult[] = [];
      for (const query of queriesToRun) {
        const result = await muulService.executeQuery(selectedDbId, query, executionId);
        results.push(result);
        if (result.error) break; 
      }
      setTabs(prev => prev.map(t => t.id === tabId ? {
        ...t, isExecuting: false, results: [results[results.length - 1], ...t.results], activeResultIndex: 0
      } : t));
    } catch (e) {
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: false } : t));
    }
  };

  const handleRunQuery = async () => {
    const editor = editorRef.current;
    if (!editor) return;

    const selection = editor.getSelection();
    if (selection.text.trim().length > 0) {
        if (!selectedDbId) return alert("Please select a database first.");
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: true } : t));
        const result = await muulService.executeQuery(selectedDbId, selection.text, Date.now().toString());
        setTabs(prev => prev.map(t => t.id === activeTabId ? {
            ...t, isExecuting: false, results: [result, ...t.results], activeResultIndex: 0
        } : t));
    } else {
        executeTabQuery(activeTabId, activeTab.content, true);
    }
  };

  const handleApplyAggregation = (dimension: string, metric: string, func: string) => {
      const currentQuery = activeTab.content.trim().replace(/;$/, '');
      if (!currentQuery) return;

      const newQuery = `SELECT \n  "${dimension}", \n  ${func}("${metric}") as "${metric}_${func}" \nFROM (\n${currentQuery}\n) \nGROUP BY "${dimension}"`;

      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: newQuery, isDirty: true } : t));

      setTimeout(() => {
          executeTabQuery(activeTabId, newQuery, true);
      }, 50);
  };

  const handleCancelQuery = () => {
    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
  };

  const handleSaveQuery = () => {
      if(!activeTab.content.trim()) return alert("Query is empty.");
      const name = prompt("Save Query As:", activeTab.title);
      if(!name) return;

      const newSaved: SavedQuery = {
          id: `sq-${Date.now()}`,
          name,
          content: activeTab.content,
          dbId: selectedDbId,
          createdAt: Date.now()
      };
      setSavedQueries([...savedQueries, newSaved]);
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, title: name, isDirty: false } : t));
  };

  const handleDownloadCSV = () => {
      if(!activeResult) return;
      exportService.downloadCSV(activeResult, `result-${Date.now()}.csv`);
  };

  const handlePinChart = (config: ChartConfig) => {
    if (!activeResult || !selectedDbId) return;
    const existingChart = pinnedCharts.find(c => 
        c.id === activeTab.linkedChartId || c.title === activeTab.title
    );
    if (existingChart) {
        const confirmUpdate = activeTab.linkedChartId 
            ? true 
            : window.confirm(`A pinned chart named "${existingChart.title}" already exists. Do you want to update it?`);
        if (!confirmUpdate) return;
        const updatedChart = { ...existingChart, query: activeTab.content, config: config, dbId: selectedDbId };
        setPinnedCharts(prev => prev.map(c => c.id === existingChart.id ? updatedChart : c));
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, linkedChartId: existingChart.id } : t));
        alert("Chart definition updated on dashboard!");
    } else {
        const chartId = `chart-${Date.now()}`;
        const newPin: PinnedChart = {
          id: chartId,
          title: activeTab.title,
          query: activeTab.content,
          dbId: selectedDbId,
          config: config,
          createdAt: Date.now()
        };
        setPinnedCharts(prev => [...prev, newPin]);
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, linkedChartId: chartId } : t));

        setDashboards(prev => {
            return prev.map(dash => {
                if (dash.id !== activeDashboardId) return dash;
                const newWidget = { id: `w-${Date.now()}`, type: 'chart' as const, colSpan: 6, content: chartId, title: newPin.title };
                const lastRow = dash.rows[dash.rows.length - 1];
                if (lastRow && lastRow.widgets.reduce((acc, w) => acc + w.colSpan, 0) <= 6) {
                    return { ...dash, rows: dash.rows.map(r => r.id === lastRow.id ? { ...r, widgets: [...r.widgets, newWidget] } : r) };
                } else {
                    return { ...dash, rows: [...dash.rows, { id: `row-${Date.now()}`, widgets: [newWidget] }] };
                }
            });
        });
        alert("Chart pinned to dashboard!");
    }
  };

  const handleUpdatePinnedChart = (newConfig: ChartConfig) => {
    if (!activeTab.linkedChartId || !selectedDbId) return;
    setPinnedCharts(prev => prev.map(c => {
        if (c.id === activeTab.linkedChartId) {
            return { ...c, query: activeTab.content, config: newConfig, dbId: selectedDbId };
        }
        return c;
    }));
    alert("Chart updated successfully!");
  };

  const handleEditChart = (chartId: string) => {
      const chart = pinnedCharts.find(c => c.id === chartId);
      if (!chart) return;
      const newId = `tab-edit-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: chart.title,
          content: chart.query,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1,
          linkedChartId: chart.id
      }]);
      setActiveTabId(newId);
      if (chart.dbId) setSelectedDbId(chart.dbId);
      setCurrentView('editor');
      setTimeout(() => {
          executeTabQuery(newId, chart.query);
          setResultViewMode('chart');
      }, 100);
  };

  const handleAddDashboard = (title: string) => {
      const newDash: DashboardLayout = { id: `dash-${Date.now()}`, title, isDefault: false, rows: [] };
      setDashboards([...dashboards, newDash]);
      setActiveDashboardId(newDash.id);
  };

  const handleDeleteDashboard = (id: string) => {
      if (dashboards.length <= 1) return alert("Cannot delete the last dashboard.");
      const newDashboards = dashboards.filter(d => d.id !== id);
      setDashboards(newDashboards);
      if (activeDashboardId === id) setActiveDashboardId(newDashboards[0].id);
  };

  const handleUpdateDashboard = (updatedLayout: DashboardLayout) => {
      setDashboards(prev => prev.map(d => d.id === updatedLayout.id ? updatedLayout : d));
  };

  const handleRemoveChartDefinition = (id: string) => {
      setPinnedCharts(prev => prev.filter(c => c.id !== id));
      setDashboards(prev => prev.map(dash => ({
          ...dash,
          rows: dash.rows.map(row => ({
              ...row,
              widgets: row.widgets.filter(w => w.type !== 'chart' || w.content !== id)
          }))
      })));
  };

  const handleUpdateChartDefinition = (id: string, newConfig: ChartConfig) => {
      setPinnedCharts(prev => prev.map(c => id === c.id ? { ...c, config: newConfig } : c));
  };

  const startDockResize = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { isDragging: true, type: 'resize-dock', startX: e.clientX, startY: e.clientY, startSize: panelSize };
    document.body.style.cursor = layout === 'bottom' ? 'row-resize' : 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const startFloatMove = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { isDragging: true, type: 'move-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  const startFloatResize = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragInfo.current = { isDragging: true, type: 'resize-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  const renderDbIcon = (type: string) => {
    if (type === 'mongodb') return <Leaf size={14} className="mr-2 text-green-500" />;
    return <DbIcon size={14} className="mr-2 text-blue-500/80" />;
  };

  return (
    <div 
        className={`flex h-screen w-screen bg-slate-950 text-slate-200 overflow-hidden font-sans ${appSettings.themeAccent}-accent relative`}
        onDragEnter={handleDragEnter}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleFileDrop}
    >
      {isDraggingFile && (
          <div className="absolute inset-0 z-[100] bg-blue-500/20 backdrop-blur-sm border-4 border-dashed border-blue-400 m-4 rounded-xl flex flex-col items-center justify-center pointer-events-none">
              <Upload size={64} className="text-blue-400 mb-4" />
              <h2 className="text-2xl font-bold text-white">Drop File to Import</h2>
              <p className="text-blue-200">Supports .csv, .json, .sqlite, .db, .parquet</p>
          </div>
      )}

      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} settings={appSettings} onSave={setAppSettings} />

      <aside className="w-12 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-4 space-y-4 shrink-0 z-50">
        <div className="text-blue-500 mb-2"><DbIcon size={24} /></div>
        <button onClick={() => setCurrentView('editor')} className={`p-2 rounded-lg transition-colors ${currentView === 'editor' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`} title="SQL Editor"><TerminalSquare size={20} /></button>
        <button onClick={() => setCurrentView('dashboard')} className={`p-2 rounded-lg transition-colors ${currentView === 'dashboard' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`} title="Dashboard"><LayoutDashboard size={20} /></button>
        <button onClick={() => setCurrentView('dba-perf')} className={`p-2 rounded-lg transition-colors ${currentView === 'dba-perf' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`} title="Performance Pulse"><Activity size={20} /></button>
        <button onClick={() => setCurrentView('schema')} className={`p-2 rounded-lg transition-colors ${currentView === 'schema' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`} title="Schema Visualizer"><Network size={20} /></button>
        <div className="h-px w-6 bg-slate-800 my-2"></div>
        <button onClick={() => { setCurrentView('editor'); setSidebarTab('saved'); }} className={`p-2 rounded-lg transition-colors ${currentView === 'editor' && sidebarTab === 'saved' ? 'bg-slate-800 text-purple-400' : 'text-slate-500 hover:text-slate-300'}`} title="Saved Queries"><Bookmark size={20} /></button>
        <button onClick={() => { setCurrentView('editor'); setSidebarTab('dba'); }} className={`p-2 rounded-lg transition-colors ${currentView === 'editor' && sidebarTab === 'dba' ? 'bg-slate-800 text-blue-400' : 'text-slate-500 hover:text-slate-300'}`} title="DBA Insights"><ShieldAlert size={20} /></button>
        <div className="flex-1" />
        <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-slate-500 hover:text-slate-300 hover:bg-slate-800 rounded transition-colors"><Settings size={20} /></button>
      </aside>

      {(currentView === 'editor' || currentView === 'schema') && (
          <div className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col min-h-0 shrink-0">
             <div className="h-10 flex items-center px-4 font-bold text-xs uppercase tracking-wider text-slate-500 border-b border-slate-800 shrink-0">
                {sidebarTab === 'db' ? 'Databases' : sidebarTab === 'saved' ? 'Saved Queries' : 'DBA Studio'}
             </div>
             {sidebarTab === 'db' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {databases.map(db => (
                        <div key={db.id} className="mb-1">
                            <div onClick={() => handleDbClick(db.id)} className={`flex items-center p-2 rounded cursor-pointer transition-colors ${selectedDbId === db.id ? 'bg-slate-800 text-slate-200' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-300'}`}>
                                <div className={`mr-2 transition-transform ${expandedDbIds.has(db.id) ? 'rotate-90' : ''}`}><ChevronRight size={14} /></div>
                                {renderDbIcon(db.type)}
                                <div className="flex flex-col truncate">
                                    <span className="text-sm truncate font-medium">{db.name}</span>
                                </div>
                            </div>
                            {expandedDbIds.has(db.id) && (
                                <div className="ml-6 pl-2 border-l border-slate-800 mt-1 space-y-0.5">
                                    {dbTables[db.id] && dbTables[db.id].length > 0 ? (
                                        dbTables[db.id].map(tbl => (
                                            <div key={tbl} onClick={() => handleTableClick(tbl)} className="flex items-center px-2 py-1.5 text-xs text-slate-500 hover:text-blue-300 hover:bg-slate-800/50 rounded cursor-pointer group">
                                                <TableIcon size={12} className="mr-2 opacity-50 group-hover:opacity-100" />
                                                <span className="truncate">{tbl}</span>
                                            </div>
                                        ))
                                    ) : ( <div className="px-2 py-1 text-[10px] text-slate-600 italic">No tables found...</div> )}
                                </div>
                            )}
                        </div>
                    ))}
                </div>
             )}
             {sidebarTab === 'saved' && (
                <div className="flex-1 overflow-y-auto p-2">
                    {savedQueries.map(sq => (
                        <div key={sq.id} onClick={() => handleOpenSavedQuery(sq)} className="group flex items-start p-2 mb-1 rounded cursor-pointer transition-colors text-slate-400 hover:bg-slate-800 hover:text-slate-200">
                            <FolderOpen size={14} className="mr-2 mt-0.5 text-purple-400" />
                            <div className="flex flex-col truncate flex-1">
                                <span className="text-sm truncate font-medium">{sq.name}</span>
                                <span className="text-[10px] text-slate-500 truncate">{new Date(sq.createdAt).toLocaleDateString()}</span>
                            </div>
                        </div>
                    ))}
                </div>
             )}
             {sidebarTab === 'dba' && (
                <DbaPanel 
                  dialect={selectedDb?.type || 'sqlite'} 
                  dbId={selectedDbId}
                  dbName={selectedDb?.name || ''}
                  onSelectInsight={handleSelectDbaInsight} 
                  onViewHistory={handleViewHistoryRecord}
                  onLaunchDashboard={() => setCurrentView('dba-perf')}
                  customInsights={appSettings.customInsights}
                />
             )}
          </div>
      )}

      <div className="flex-1 flex flex-col min-w-0 h-full overflow-hidden relative">
        {currentView === 'dashboard' && (
             <Dashboard dashboards={dashboards} pinnedCharts={pinnedCharts} databases={databases} activeDashboardId={activeDashboardId} refreshRate={appSettings.refreshRate} onSetActiveDashboard={setActiveDashboardId} onAddDashboard={handleAddDashboard} onUpdateDashboard={handleUpdateDashboard} onDeleteDashboard={handleDeleteDashboard} onRemoveChartDefinition={handleRemoveChartDefinition} onUpdateChartDefinition={handleUpdateChartDefinition} onEditChart={handleEditChart} />
        )}
        {currentView === 'schema' && (
            <SchemaVisualizer schema={activeSchema} dbName={selectedDb?.name || 'Selected Database'} layouts={schemaLayouts.filter(l => l.dbId === selectedDbId)} activeLayoutId={activeLayoutId} onLayoutCreate={handleLayoutCreate} onLayoutSelect={setActiveLayoutId} onLayoutUpdate={handleLayoutUpdate} onLayoutDelete={handleLayoutDelete} />
        )}
        {currentView === 'dba-perf' && selectedDb && (
            <DbaPerformanceDashboard database={selectedDb} customInsights={appSettings.customInsights} />
        )}
        <div className={`flex-1 flex flex-col h-full w-full ${currentView === 'dashboard' || currentView === 'schema' || currentView === 'dba-perf' ? 'hidden' : 'flex'}`}>
            <header className="h-14 border-b border-slate-800 bg-slate-900 flex items-center px-4 justify-between shrink-0 z-30 relative">
              <div className="flex items-center space-x-4">
                <div className="flex items-center text-blue-400 font-bold text-lg tracking-tight">Muul<span className="text-slate-100">SQL</span></div>
                <div className="h-6 w-px bg-slate-700 mx-2"></div>
                <div className="relative group">
                  <select value={selectedDbId} onChange={(e) => setSelectedDbId(e.target.value)} className="appearance-none bg-slate-800 hover:bg-slate-700 border border-slate-700 text-xs rounded py-1.5 pl-3 pr-8 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors w-64 cursor-pointer">
                    {databases.map(db => (
                      <option key={db.id} value={db.id}>{db.type.toUpperCase()} • {db.name}</option>
                    ))}
                  </select>
                  <Activity size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400" />
                </div>
              </div>
              <div className="flex items-center space-x-2">
                  {activeTab.isExecuting ? (
                      <button onClick={handleCancelQuery} className="flex items-center px-4 py-1.5 bg-red-600 hover:bg-red-700 text-white text-sm font-medium rounded shadow animate-pulse"><Ban size={16} className="mr-2" /> Cancel</button>
                  ) : (
                      <button onClick={handleRunQuery} className="flex items-center px-4 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium rounded shadow hover:shadow-blue-500/20 active:scale-95"><Play size={16} className="mr-2 fill-current" /> Run</button>
                  )}
                  <div className="h-6 w-px bg-slate-700 mx-2"></div>
                  <button onClick={handleCaptureSnapshot} disabled={!activeResult || sidebarTab !== 'dba'} className="p-2 text-slate-400 hover:text-blue-400 hover:bg-slate-800 rounded disabled:opacity-30 transition-colors" title="Capture Snapshot to DBA History"><Camera size={18} /></button>
                  <button onClick={handleSaveQuery} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded transition-colors" title="Save Query"><Save size={18} /></button>
                  <button onClick={handleDownloadCSV} disabled={!activeResult} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded disabled:opacity-30 transition-colors" title="Download Result CSV"><Download size={18} /></button>
              </div>
            </header>
            <div className="flex items-center bg-slate-900 border-b border-slate-800 pr-2 pt-2 shrink-0">
              <div className="flex-1 flex overflow-x-auto no-scrollbar items-end px-2">
                  {tabs.map(tab => (
                    <div key={tab.id} onClick={() => setActiveTabId(tab.id)} className={`group flex items-center min-w-[150px] max-w-[250px] px-3 py-2 text-xs border-t border-r border-l rounded-t-md cursor-pointer select-none whitespace-nowrap ${activeTabId === tab.id ? 'bg-slate-850 border-slate-700 text-blue-400 font-medium' : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-800'}`}>
                      <span className="mr-2 truncate flex-1">{tab.title} {tab.isDirty && '*'}</span>
                      <button onClick={(e) => handleCloseTab(tab.id, e)} className={`opacity-0 group-hover:opacity-100 p-0.5 rounded-full hover:bg-slate-700 ${tabs.length === 1 ? 'hidden' : ''}`}><X size={12} /></button>
                    </div>
                  ))}
              </div>
              <div className="flex items-center border-l border-slate-800 pl-2 pb-1 space-x-1">
                  <button onClick={() => setIsEditorExpanded(!isEditorExpanded)} className={`p-1.5 hover:bg-slate-800 rounded transition-colors ${!isEditorExpanded ? 'text-blue-400' : 'text-slate-500'}`} title={isEditorExpanded ? "Collapse Editor" : "Expand Editor"}>{isEditorExpanded ? <ChevronDown size={16} /> : <ChevronUp size={16} />}</button>
                  <button onClick={handleCreateTab} className="p-1.5 text-slate-500 hover:text-blue-400 hover:bg-slate-800 rounded transition-colors" title="New Tab"><Plus size={16} /></button>
              </div>
            </div>
            <div ref={containerRef} className={`flex-1 flex overflow-hidden bg-slate-950 relative ${layout === 'bottom' ? 'flex-col' : layout === 'left' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div style={layout === 'bottom' ? {} : { display: isEditorExpanded ? 'flex' : 'none' }} className={` ${layout === 'float' ? 'w-full h-full' : 'flex-1'} flex flex-col min-h-0 min-w-0 z-0 transition-all duration-300 ${layout === 'bottom' && !isEditorExpanded ? '!flex-none !h-0 overflow-hidden' : ''}`}>
                <div style={{ fontSize: `${appSettings.editorFontSize}px` }} className="h-full">
                    <SqlEditor ref={editorRef} value={activeTab.content} onChange={c => setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: c, isDirty: true } : t))} disabled={activeTab.isExecuting} dbType={selectedDb?.type} />
                </div>
                {activeTab.isExecuting && <div className="bg-slate-800/50 text-xs text-blue-300 px-4 py-1 border-t border-slate-800 flex items-center shrink-0"><div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse mr-2"></div>Running query...</div>}
              </div>
              {layout !== 'float' && isEditorExpanded && <div onMouseDown={startDockResize} className={` ${layout === 'bottom' ? 'h-1.5 w-full cursor-row-resize' : 'w-1.5 h-full cursor-col-resize'} bg-slate-950 hover:bg-blue-600 transition-colors z-20 flex-shrink-0 border-slate-800 ${layout === 'bottom' ? 'border-t border-b' : 'border-l border-r'}`} />}
              {layout !== 'float' && (
                  <div style={layout === 'bottom' ? { height: isEditorExpanded ? `${panelSize}%` : '100%' } : { width: `${panelSize}%` }} className="flex flex-col min-h-0 min-w-0 z-10 transition-all duration-300">
                  <ResultsPane result={activeResult} viewMode={resultViewMode} setViewMode={setResultViewMode} layout={layout} setLayout={setLayout} onPinChart={activeTab.linkedChartId ? undefined : handlePinChart} onUpdateChart={activeTab.linkedChartId ? handleUpdatePinnedChart : undefined} onApplyAggregation={handleApplyAggregation} />
              </div>
              )}
              {layout === 'float' && (
                  <div style={{ top: floatRect.y, left: floatRect.x, width: floatRect.w, height: floatRect.h }} className="absolute z-50 shadow-2xl border border-slate-700 rounded-lg overflow-hidden flex flex-col bg-slate-900 ring-1 ring-black/50">
                      <ResultsPane result={activeResult} viewMode={resultViewMode} setViewMode={setResultViewMode} layout={layout} setLayout={setLayout} onHeaderMouseDown={startFloatMove} onPinChart={activeTab.linkedChartId ? undefined : handlePinChart} onUpdateChart={activeTab.linkedChartId ? handleUpdatePinnedChart : undefined} onApplyAggregation={handleApplyAggregation} />
                      <div onMouseDown={startFloatResize} className="absolute bottom-0 right-0 w-5 h-5 cursor-nwse-resize bg-transparent hover:bg-blue-500/20 z-50 rounded-tl-lg" />
                  </div>
              )}
            </div>
            <footer className="h-6 bg-slate-900 border-t border-slate-800 flex items-center px-4 text-[10px] text-slate-500 justify-between shrink-0 z-40">
              <div className="flex items-center space-x-4"><span>Ready</span><span>{selectedDbId ? `Connected: ${selectedDb?.name}` : 'No Database Selected'}</span></div>
              <div>Muul MessageHandler v1.0.0</div>
            </footer>
        </div>
      </div>
    </div>
  );
};

export default App;

export type DbDialect = 'postgres' | 'mysql' | 'sqlite' | 'mssql' | 'parquet' | 'mongodb';

export interface DbaInsight {
  id: string;
  category: 'Performance' | 'Storage' | 'Indexes' | 'Fragmentation' | 'Expensive Queries' | 'System' | 'Locks' | 'Wait Stats';
  context: 'server' | 'database';
  title: string;
  description: string;
  query: string;
  minVersion?: string;
  impact: 'High' | 'Medium' | 'Low';
}

export interface IntrospectionQueries {
  getTables: string;
  getColumns: (tableName: string) => string;
  getForeignKeys: (tableName: string) => string;
  insights: DbaInsight[];
}

export const DialectRegistry: Record<DbDialect, IntrospectionQueries> = {
  postgres: {
    getTables: `SELECT table_name as name FROM information_schema.tables WHERE table_schema = 'public' AND table_type = 'BASE TABLE'`,
    getColumns: (table) => `SELECT column_name as name, data_type as type, (is_nullable = 'NO') as notnull FROM information_schema.columns WHERE table_name = '${table}'`,
    getForeignKeys: (table) => `SELECT kcu.column_name as "from", ccu.table_name as "table" FROM information_schema.key_column_usage kcu JOIN information_schema.table_constraints tc ON kcu.constraint_name = tc.constraint_name JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_name = tc.constraint_name WHERE tc.constraint_type = 'FOREIGN KEY' AND kcu.table_name = '${table}'`,
    insights: [
      { id: 'pg-missing-indexes', context: 'database', category: 'Indexes', title: 'Missing Indexes (High Scans)', description: 'Tables with high sequential scans and large row counts that likely need indexing.', query: 'SELECT relname AS table_name, seq_scan, seq_tup_read, idx_scan, n_live_tup FROM pg_stat_user_tables WHERE seq_scan > 100 AND n_live_tup > 10000 ORDER BY seq_tup_read DESC;', impact: 'High' },
      { id: 'pg-cache-hit', context: 'server', category: 'Performance', title: 'Cache Hit Ratio', description: 'Percentage of data served from memory vs disk.', query: 'SELECT sum(heap_blks_hit) / (sum(heap_blks_hit) + sum(heap_blks_read) + 1) * 100 as ratio_pct FROM pg_statio_user_tables;', impact: 'High' },
      { id: 'pg-table-bloat', context: 'database', category: 'Fragmentation', title: 'Estimated Table Bloat', description: 'Detects tables with high dead tuple counts needing VACUUM.', query: 'SELECT schemaname, relname, n_dead_tup, n_live_tup, round(100*n_dead_tup/(n_live_tup+n_dead_tup+1),2) AS bloat_ratio FROM pg_stat_all_tables WHERE n_live_tup > 1000 ORDER BY n_dead_tup DESC;', impact: 'Medium' },
      { id: 'pg-active-sessions', context: 'server', category: 'System', title: 'Long Running Queries', description: 'Queries active for more than 5 minutes.', query: 'SELECT pid, now() - query_start AS duration, query, state FROM pg_stat_activity WHERE state != \'idle\' AND now() - query_start > interval \'5 minutes\';', impact: 'Medium' },
      { id: 'pg-index-usage', context: 'database', category: 'Indexes', title: 'Unused Indexes', description: 'Indexes that consume storage but are never used by the planner.', query: 'SELECT relname AS table, indexrelname AS index, idx_scan, pg_size_pretty(pg_relation_size(indexrelid)) AS size FROM pg_stat_user_indexes JOIN pg_index USING (indexrelid) WHERE idx_scan = 0 AND indisunique IS FALSE;', impact: 'Low' },
      { id: 'pg-locks-wait', context: 'server', category: 'Locks', title: 'Blocking Sessions', description: 'Identify sessions holding locks that block other processes.', query: 'SELECT blocked_locks.pid AS blocked_pid, blocking_locks.pid AS blocking_pid, blocked_activity.query AS blocked_query FROM pg_catalog.pg_locks blocked_locks JOIN pg_catalog.pg_stat_activity blocked_activity ON blocked_locks.pid = blocked_activity.pid JOIN pg_catalog.pg_locks blocking_locks ON blocking_locks.locktype = blocked_locks.locktype AND blocking_locks.DATABASE IS NOT DISTINCT FROM blocked_locks.DATABASE AND blocking_locks.pid != blocked_locks.pid JOIN pg_catalog.pg_stat_activity blocking_activity ON blocking_locks.pid = blocking_activity.pid WHERE NOT blocked_locks.granted;', impact: 'High' }
    ]
  },
  mysql: {
    getTables: "SHOW TABLES",
    getColumns: (table) => `DESCRIBE \`${table}\``,
    getForeignKeys: (table) => `SELECT 1`,
    insights: [
      { id: 'my-missing-indexes', context: 'database', category: 'Indexes', title: 'Missing Index Report', description: 'Identifies tables with full table scans using Performance Schema.', query: 'SELECT OBJECT_SCHEMA, OBJECT_NAME, COUNT_STAR, SUM_TIMER_WAIT FROM performance_schema.table_io_waits_summary_by_index_usage WHERE INDEX_NAME IS NULL AND COUNT_STAR > 0 ORDER BY SUM_TIMER_WAIT DESC;', impact: 'High' },
      { id: 'my-redundant-indexes', context: 'database', category: 'Indexes', title: 'Redundant Indexes', description: 'Indexes that are prefixes of other indexes.', query: 'SELECT table_schema, table_name, index_name, column_name FROM information_schema.statistics WHERE non_unique = 1 ORDER BY table_schema, table_name, index_name, seq_in_index;', impact: 'Medium' },
      { id: 'my-buffer-pool', context: 'server', category: 'Performance', title: 'Buffer Pool Health', description: 'Efficiency of the InnoDB buffer pool usage.', query: 'SELECT variable_name, variable_value FROM information_schema.global_status WHERE variable_name IN (\'Innodb_buffer_pool_read_requests\', \'Innodb_buffer_pool_reads\');', impact: 'High' },
      { id: 'my-slow-queries', context: 'server', category: 'Expensive Queries', title: 'Top 10 Latency Queries', description: 'Most time-consuming queries normalized by digest.', query: 'SELECT DIGEST_TEXT, COUNT_STAR, AVG_TIMER_WAIT/1000000000 as avg_ms FROM performance_schema.events_statements_summary_by_digest ORDER BY AVG_TIMER_WAIT DESC LIMIT 10;', impact: 'High' }
    ]
  },
  mssql: {
    getTables: "SELECT name FROM sys.tables WHERE is_ms_shipped = 0",
    getColumns: (table) => `SELECT name, TYPE_NAME(system_type_id) as type FROM sys.columns WHERE object_id = OBJECT_ID('${table}')`,
    getForeignKeys: (table) => `SELECT name FROM sys.foreign_keys`,
    insights: [
      { id: 'ms-missing-indexes', context: 'database', category: 'Indexes', title: 'Missing Index Impact', description: 'Identifies missing indexes with high potential performance gain.', query: 'SELECT TOP 20 migs.avg_user_impact * (migs.user_seeks + migs.user_scans) AS [Impact], mid.[statement] AS [Table], mid.equality_columns, mid.inequality_columns, mid.included_columns FROM sys.dm_db_missing_index_group_stats AS migs JOIN sys.dm_db_missing_index_groups AS mig ON migs.group_handle = mig.index_group_handle JOIN sys.dm_db_missing_index_details AS mid ON mig.index_handle = mid.index_handle ORDER BY [Impact] DESC;', impact: 'High' },
      { id: 'ms-ple', context: 'server', category: 'Performance', title: 'Page Life Expectancy', description: 'Memory pressure indicator. Values below 300 suggest significant pressure.', query: 'SELECT cntr_value FROM sys.dm_os_performance_counters WHERE counter_name = \'Page life expectancy\' AND object_name LIKE \'%Buffer Manager%\';', impact: 'High' },
      { id: 'ms-waits', context: 'server', category: 'Wait Stats', title: 'Wait Statistics (Bottlenecks)', description: 'Primary server bottlenecks by total wait time.', query: 'SELECT TOP 10 wait_type, wait_time_ms / 1000.0 AS wait_sec, 100.0 * wait_time_ms / SUM(wait_time_ms) OVER() AS percentage FROM sys.dm_os_wait_stats WHERE wait_type NOT IN (\'CLR_SEMAPHORE\',\'LAZYWRITER_SLEEP\') ORDER BY wait_time_ms DESC;', impact: 'High' },
      { id: 'ms-io-stalls', context: 'server', category: 'Performance', title: 'Disk I/O Stalls', description: 'Identifies files with high latency for reads or writes.', query: 'SELECT DB_NAME(vfs.database_id) AS [DB], mf.name AS [File], vfs.io_stall_read_ms / vfs.num_of_reads AS [AvgReadStall], vfs.io_stall_write_ms / vfs.num_of_writes AS [AvgWriteStall] FROM sys.dm_io_virtual_file_stats(NULL,NULL) AS vfs JOIN sys.master_files AS mf ON vfs.database_id = mf.database_id AND vfs.file_id = mf.file_id ORDER BY [AvgReadStall] DESC;', impact: 'Medium' }
    ]
  },
  sqlite: {
    getTables: "SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'",
    getColumns: (table) => `PRAGMA table_info("${table}")`,
    getForeignKeys: (table) => `PRAGMA foreign_key_list("${table}")`,
    insights: [
      { id: 'sq-missing-indexes', context: 'database', category: 'Indexes', title: 'Potential Missing Indexes', description: 'Tables without indexes on large datasets.', query: 'SELECT name FROM sqlite_master WHERE type="table" AND name NOT IN (SELECT tbl_name FROM sqlite_master WHERE type="index");', impact: 'Medium' },
      { id: 'sq-integrity', context: 'database', category: 'System', title: 'Integrity Check', description: 'Check database for corruption.', query: 'PRAGMA integrity_check;', impact: 'High' },
      { id: 'sq-freelist', context: 'database', category: 'Storage', title: 'Wasted Page Count', description: 'Pages that can be reclaimed via VACUUM.', query: 'PRAGMA freelist_count;', impact: 'Low' }
    ]
  },
  parquet: { getTables: "SELECT name FROM sqlite_master WHERE type='table'", getColumns: (table) => `PRAGMA table_info("${table}")`, getForeignKeys: (table) => `SELECT 1 WHERE 1=0`, insights: [] },
  mongodb: {
    getTables: "db.getCollectionNames()",
    getColumns: (table) => "db.collection.findOne()",
    getForeignKeys: (table) => "db.collection.getIndexes()",
    insights: [
      { id: 'mg-missing-indexes', context: 'database', category: 'Indexes', title: 'Slow Queries (No Index)', description: 'Queries performing collection scans.', query: 'db.system.profile.find({planSummary: "COLLSCAN"}).limit(10)', impact: 'High' },
      { id: 'mg-op-lat', context: 'server', category: 'Performance', title: 'Global Op Latency', description: 'Avg latency for read/write/command ops.', query: 'db.serverStatus().opLatencies', impact: 'High' }
    ]
  }
};

import React, { useState, useEffect } from 'react';
import { Database, QueryResult } from '../types';
import { muulService } from '../services/muulService';
import { DialectRegistry, DbaInsight } from '../services/dialects/SqlDialects';
import DataTable from './DataTable';
import DataVisualizer from './DataVisualizer';
import { 
  Activity, AlertTriangle, CheckCircle, 
  RefreshCw, Server, Zap, HardDrive, ShieldAlert,
  Code, ChevronDown, ChevronUp, Info
} from 'lucide-react';

interface DbaPerformanceDashboardProps {
  database: Database;
  customInsights?: Partial<Record<string, DbaInsight[]>>;
}

const DbaPerformanceDashboard: React.FC<DbaPerformanceDashboardProps> = ({ database, customInsights }) => {
  const [results, setResults] = useState<Record<string, QueryResult>>({});
  const [loading, setLoading] = useState<Record<string, boolean>>({});
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [showSql, setShowSql] = useState<Record<string, boolean>>({});

  const getInsights = () => {
    const registryInsights = DialectRegistry[database.type]?.insights || [];
    const custom = customInsights?.[database.type];
    return custom ? custom : registryInsights;
  };

  const dashboardInsights = getInsights().slice(0, 6); // Show top 6 for expanded dashboard

  const refreshAll = async () => {
    setIsRefreshing(true);
    const newResults: Record<string, QueryResult> = { ...results };
    const newLoading: Record<string, boolean> = {};

    dashboardInsights.forEach(i => newLoading[i.id] = true);
    setLoading(newLoading);

    await Promise.all(dashboardInsights.map(async (insight) => {
      try {
        const res = await muulService.executeQuery(database.id, insight.query, `dba-dash-${insight.id}`);
        newResults[insight.id] = res;
      } catch (e) {
        console.error(`DBA Dash Error [${insight.title}]:`, e);
      } finally {
        setLoading(prev => ({ ...prev, [insight.id]: false }));
      }
    }));

    setResults(newResults);
    setIsRefreshing(false);
  };

  useEffect(() => {
    refreshAll();
  }, [database.id]);

  const toggleSql = (id: string) => {
    setShowSql(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const renderWidget = (insight: DbaInsight) => {
    const result = results[insight.id];
    const isLoading = loading[insight.id];
    const isShowingSql = showSql[insight.id];

    const impactColor = 
      insight.impact === 'High' ? 'bg-red-500/20 text-red-400 border-red-500/30' : 
      insight.impact === 'Medium' ? 'bg-amber-500/20 text-amber-400 border-amber-500/30' : 
      'bg-blue-500/20 text-blue-400 border-blue-500/30';

    return (
      <div key={insight.id} className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden flex flex-col shadow-lg transition-all hover:border-slate-700">
        <div className="px-4 py-3 bg-slate-850 border-b border-slate-800 flex items-center justify-between shrink-0">
          <div className="flex items-center space-x-3">
            <div className={`px-1.5 py-0.5 rounded text-[9px] font-black uppercase border ${impactColor}`}>
               {insight.impact} Impact
            </div>
            <h3 className="text-xs font-bold text-slate-200 uppercase tracking-wider">{insight.title}</h3>
          </div>
          <div className="flex items-center space-x-2">
            <button 
                onClick={() => toggleSql(insight.id)} 
                className={`p-1 rounded transition-colors ${isShowingSql ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}
                title="View Diagnostic SQL"
            >
                <Code size={14} />
            </button>
            {isLoading && <RefreshCw size={12} className="animate-spin text-blue-400" />}
          </div>
        </div>

        <div className="flex-1 min-h-[300px] relative flex flex-col">
          {isShowingSql && (
              <div className="absolute inset-0 z-20 bg-slate-950/95 p-4 overflow-auto border-b border-slate-800 animate-in slide-in-from-top duration-200">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Diagnostic SQL Engine</span>
                    <button onClick={() => toggleSql(insight.id)} className="text-slate-400 hover:text-white"><ChevronUp size={14}/></button>
                  </div>
                  <pre className="text-[11px] font-mono text-blue-300 whitespace-pre-wrap break-all leading-relaxed bg-slate-900 p-3 rounded-lg border border-slate-800 shadow-inner">
                      {insight.query}
                  </pre>
                  <p className="mt-3 text-[10px] text-slate-500 italic flex items-start">
                    <Info size={12} className="mr-2 mt-0.5 shrink-0" />
                    {insight.description}
                  </p>
              </div>
          )}

          <div className="flex-1 flex flex-col min-h-0">
            {!result ? (
                <div className="flex-1 flex items-center justify-center text-slate-600 text-[10px] uppercase tracking-widest animate-pulse">
                Probing Diagnostic Hub...
                </div>
            ) : result.error ? (
                <div className="flex-1 flex flex-col items-center justify-center p-6 text-center">
                <AlertTriangle size={32} className="text-red-500 mb-3 opacity-50" />
                <p className="text-[10px] text-red-400 font-mono line-clamp-4 bg-red-900/10 p-4 rounded-lg border border-red-500/20">{result.error}</p>
                </div>
            ) : (
                // Force Table view for many diagnostics, Chart for specific KPIs
                result.rowCount > 0 && result.columns.some(c => c.toLowerCase().includes('ratio') || c.toLowerCase().includes('pct')) && result.rowCount <= 20 ? (
                <div className="flex-1 min-h-0">
                    <DataVisualizer result={result} readOnly={true} initialConfig={{ type: 'bar', xAxisKey: result.columns[0], dataKeys: [result.columns.find(c => typeof result.rows[0][result.columns.indexOf(c)] === 'number')!] }} />
                </div>
                ) : (
                <div className="flex-1 overflow-auto bg-slate-950/50">
                    <div className="transform scale-[0.9] origin-top h-[111%] w-[111%]">
                        <DataTable result={result} />
                    </div>
                </div>
                )
            )}
          </div>
        </div>

        <div className="px-3 py-2 bg-slate-950 border-t border-slate-800 text-[9px] text-slate-500 flex justify-between items-center shrink-0">
          <div className="flex items-center">
             <Server size={10} className="mr-1.5 opacity-50" />
             <span className="font-bold uppercase tracking-tighter text-slate-600">{insight.category}</span>
          </div>
          {result && <span className="font-mono bg-slate-900 px-2 py-0.5 rounded border border-slate-800">{result.rowCount} rows in {result.executionTimeMs}ms</span>}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full w-full bg-slate-950 overflow-hidden animate-in fade-in duration-500">
      {/* Dashboard Top Stats Bar */}
      <div className="p-6 pb-2 grid grid-cols-1 md:grid-cols-4 gap-4 shrink-0">
        {[
          { label: 'DB Engine', value: database.type.toUpperCase(), icon: <Server size={14}/>, color: 'text-blue-400' },
          { label: 'Latency', value: 'Optimal', icon: <Zap size={14}/>, color: 'text-green-400' },
          { label: 'Health Pulse', value: 'Monitoring', icon: <Activity size={14}/>, color: 'text-purple-400' },
          { label: 'Identity', value: 'Senior DBA', icon: <ShieldAlert size={14}/>, color: 'text-orange-400' },
        ].map((stat, i) => (
          <div key={i} className="bg-slate-900 border border-slate-800 p-4 rounded-xl flex items-center justify-between group hover:border-blue-500/30 transition-all shadow-md">
            <div>
              <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{stat.label}</p>
              <p className={`text-lg font-black ${stat.color}`}>{stat.value}</p>
            </div>
            <div className={`p-2 bg-slate-800 rounded-lg ${stat.color} opacity-50 group-hover:opacity-100 transition-opacity`}>
              {stat.icon}
            </div>
          </div>
        ))}
      </div>

      {/* Main Grid */}
      <div className="flex-1 overflow-y-auto p-6 pt-2 scrollbar-thin">
        <div className="flex items-center justify-between mb-4">
           <div className="flex items-center">
              <Activity size={18} className="text-blue-500 mr-2" />
              <h2 className="text-sm font-bold text-slate-300 uppercase tracking-widest">Diagnostic Infrastructure Pulse</h2>
           </div>
           <button 
             onClick={refreshAll}
             disabled={isRefreshing}
             className="flex items-center px-6 py-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white text-xs font-bold rounded-lg shadow-xl shadow-blue-900/20 transition-all active:scale-95"
           >
             <RefreshCw size={14} className={`mr-2 ${isRefreshing ? 'animate-spin' : ''}`} /> Run Global Audit
           </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-6 pb-6">
          {dashboardInsights.map(renderWidget)}
        </div>

        {dashboardInsights.length === 0 && (
          <div className="flex flex-col items-center justify-center py-20 text-slate-700">
            <HardDrive size={48} className="mb-4 opacity-20" />
            <p className="font-bold uppercase tracking-widest text-xs">No Audit Definitions Found</p>
          </div>
        )}
      </div>

      <footer className="h-10 bg-slate-900 border-t border-slate-800 px-6 flex items-center justify-between text-[10px] text-slate-500 shrink-0">
         <div className="flex items-center">
            <CheckCircle size={10} className="text-green-500 mr-2" />
            <span>Infrastructure Healthy: Monitoring <span className="text-white font-mono ml-1">{database.name}</span></span>
         </div>
         <div className="font-mono bg-slate-950 px-2 py-1 rounded border border-slate-800">DBA HUD v3.0 // DIAGNOSTIC_LAYER_ACTIVE</div>
      </footer>
    </div>
  );
};

export default DbaPerformanceDashboard;

export type DbDialect = 'postgres' | 'mysql' | 'sqlite' | 'mssql' | 'parquet' | 'mongodb';

export interface DbaInsight {
  id: string;
  category: 'Performance' | 'Storage' | 'Indexes' | 'Fragmentation' | 'Expensive Queries' | 'System' | 'Locks' | 'Wait Stats';
  context: 'server' | 'database';
  title: string;
  description: string;
  query: string;
  minVersion?: string;
  impact: 'High' | 'Medium' | 'Low';
}

export interface IntrospectionQueries {
  getTables: string;
  getColumns: (tableName: string) => string;
  getForeignKeys: (tableName: string) => string;
  insights: DbaInsight[];
}

export const DialectRegistry: Record<DbDialect, IntrospectionQueries> = {
  postgres: {
    getTables: `SELECT table_name as name FROM information_schema.tables WHERE table_schema = 'public' AND table_type = 'BASE TABLE'`,
    getColumns: (table) => `SELECT column_name as name, data_type as type, (is_nullable = 'NO') as notnull FROM information_schema.columns WHERE table_name = '${table}'`,
    getForeignKeys: (table) => `SELECT kcu.column_name as "from", ccu.table_name as "table" FROM information_schema.key_column_usage kcu JOIN information_schema.table_constraints tc ON kcu.constraint_name = tc.constraint_name JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_name = tc.constraint_name WHERE tc.constraint_type = 'FOREIGN KEY' AND kcu.table_name = '${table}'`,
    insights: [
      { id: 'pg-missing-idx', context: 'database', category: 'Indexes', title: 'Missing Indexes', description: 'Large tables with high sequential scans.', query: 'SELECT relname AS "Table", seq_scan AS "Total Seq Scans", seq_tup_read AS "Tuples Read", n_live_tup AS "Rows" FROM pg_stat_user_tables WHERE seq_scan > 50 AND n_live_tup > 10000 ORDER BY seq_tup_read DESC LIMIT 10;', impact: 'High' },
      { id: 'pg-cache', context: 'server', category: 'Performance', title: 'Buffer Cache Hit Rate', description: 'Percentage of data served from RAM.', query: 'SELECT sum(heap_blks_hit) / (sum(heap_blks_hit) + sum(heap_blks_read) + 1) * 100 as "Hit Rate (%)" FROM pg_statio_user_tables;', impact: 'High' },
      { id: 'pg-bloat', context: 'database', category: 'Fragmentation', title: 'Table Bloat Estimate', description: 'Unused space held by MVCC dead tuples.', query: 'SELECT relname AS "Table", n_dead_tup AS "Dead Tuples", n_live_tup AS "Live Tuples", round(n_dead_tup * 100 / (n_live_tup + n_dead_tup + 1), 2) AS "Bloat %" FROM pg_stat_user_tables WHERE n_dead_tup > 1000 ORDER BY n_dead_tup DESC;', impact: 'Medium' },
      { id: 'pg-locks', context: 'server', category: 'Locks', title: 'Current Lock Waits', description: 'Processes blocked by other sessions.', query: 'SELECT pid, usename, state, wait_event_type, wait_event, query FROM pg_stat_activity WHERE wait_event IS NOT NULL;', impact: 'High' }
    ]
  },
  mysql: {
    getTables: "SHOW TABLES",
    getColumns: (table) => `DESCRIBE \`${table}\``,
    getForeignKeys: (table) => `SELECT 1`,
    insights: [
      { id: 'my-missing-idx', context: 'database', category: 'Indexes', title: 'Missing Indexes', description: 'Queries using full table scans.', query: 'SELECT OBJECT_SCHEMA, OBJECT_NAME, COUNT_STAR AS "Total Scans", SUM_TIMER_WAIT/1000000000 AS "Wait (ms)" FROM performance_schema.table_io_waits_summary_by_index_usage WHERE INDEX_NAME IS NULL AND COUNT_STAR > 0 ORDER BY SUM_TIMER_WAIT DESC LIMIT 10;', impact: 'High' },
      { id: 'my-buffer', context: 'server', category: 'Performance', title: 'InnoDB Buffer Usage', description: 'Efficiency of the data cache.', query: 'SELECT (1 - (Variable_value / (SELECT Variable_value FROM information_schema.global_status WHERE Variable_name = "Innodb_buffer_pool_read_requests"))) * 100 AS "Hit Rate (%)" FROM information_schema.global_status WHERE Variable_name = "Innodb_buffer_pool_reads";', impact: 'High' },
      { id: 'my-slow', context: 'server', category: 'Expensive Queries', title: 'Slow Query Digest', description: 'Top latency queries.', query: 'SELECT DIGEST_TEXT, COUNT_STAR, AVG_TIMER_WAIT/1000000000 as "Avg ms" FROM performance_schema.events_statements_summary_by_digest ORDER BY SUM_TIMER_WAIT DESC LIMIT 10;', impact: 'High' }
    ]
  },
  mssql: {
    getTables: "SELECT name FROM sys.tables WHERE is_ms_shipped = 0",
    getColumns: (table) => `SELECT name, TYPE_NAME(system_type_id) as type FROM sys.columns WHERE object_id = OBJECT_ID('${table}')`,
    getForeignKeys: (table) => `SELECT name FROM sys.foreign_keys`,
    insights: [
      { id: 'ms-missing-idx', context: 'database', category: 'Indexes', title: 'Missing Indexes', description: 'Indexes recommended by the optimizer.', query: 'SELECT TOP 10 migs.avg_user_impact * (migs.user_seeks + migs.user_scans) AS "Rank", mid.[statement] AS "Table", mid.equality_columns FROM sys.dm_db_missing_index_group_stats AS migs JOIN sys.dm_db_missing_index_groups AS mig ON migs.group_handle = mig.index_group_handle JOIN sys.dm_db_missing_index_details AS mid ON mig.index_handle = mid.index_handle ORDER BY 1 DESC;', impact: 'High' },
      { id: 'ms-waits', context: 'server', category: 'Wait Stats', title: 'Server Wait Stats', description: 'Global bottlenecks.', query: 'SELECT TOP 5 wait_type, wait_time_ms / 1000.0 AS "Wait Sec", waiting_tasks_count FROM sys.dm_os_wait_stats WHERE wait_type NOT IN (\'CLR_SEMAPHORE\',\'LAZYWRITER_SLEEP\') ORDER BY wait_time_ms DESC;', impact: 'High' },
      { id: 'ms-io', context: 'server', category: 'Performance', title: 'I/O Stall Analytics', description: 'File-level latency.', query: 'SELECT DB_NAME(database_id) AS "DB", file_id, io_stall_read_ms / num_of_reads AS "Read Latency", io_stall_write_ms / num_of_writes AS "Write Latency" FROM sys.dm_io_virtual_file_stats(NULL, NULL) WHERE num_of_reads > 0 AND num_of_writes > 0 ORDER BY 3 DESC;', impact: 'Medium' }
    ]
  },
  sqlite: {
    getTables: "SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'",
    getColumns: (table) => `PRAGMA table_info("${table}")`,
    getForeignKeys: (table) => `PRAGMA foreign_key_list("${table}")`,
    insights: [
      { id: 'sq-integrity', context: 'database', category: 'System', title: 'Integrity Check', description: 'Database corruption scan.', query: 'PRAGMA integrity_check;', impact: 'High' },
      { id: 'sq-idx', context: 'database', category: 'Indexes', title: 'Missing Indexes', description: 'Tables without defined indexes.', query: 'SELECT name FROM sqlite_master WHERE type="table" AND name NOT IN (SELECT tbl_name FROM sqlite_master WHERE type="index");', impact: 'Medium' }
    ]
  },
  parquet: { getTables: "SELECT name FROM sqlite_master WHERE type='table'", getColumns: (table) => `PRAGMA table_info("${table}")`, getForeignKeys: (table) => `SELECT 1 WHERE 1=0`, insights: [] },
  mongodb: {
    getTables: "db.getCollectionNames()",
    getColumns: (table) => "db.collection.findOne()",
    getForeignKeys: (table) => "db.collection.getIndexes()",
    insights: [
      { id: 'mg-slow', context: 'database', category: 'Expensive Queries', title: 'Slow Operations', description: 'Ops exceeding 100ms.', query: 'db.system.profile.find({millis: {$gt: 100}}).sort({ts: -1}).limit(10)', impact: 'High' },
      { id: 'mg-idx', context: 'database', category: 'Indexes', title: 'Collection Scans', description: 'Queries missing indexes.', query: 'db.system.profile.find({planSummary: "COLLSCAN"}).limit(10)', impact: 'High' }
    ]
  }
};

import React, { useState, useEffect } from 'react';
import { Database, QueryResult } from '../types';
import { muulService } from '../services/muulService';
import { DialectRegistry, DbaInsight } from '../services/dialects/SqlDialects';
import DataTable from './DataTable';
import DataVisualizer from './DataVisualizer';
import { 
  Activity, AlertTriangle, CheckCircle, 
  RefreshCw, Server, Zap, HardDrive, ShieldAlert,
  Code, ChevronDown, ChevronUp, Info, Terminal
} from 'lucide-react';

interface DbaPerformanceDashboardProps {
  database: Database;
  customInsights?: Partial<Record<string, DbaInsight[]>>;
}

const DbaPerformanceDashboard: React.FC<DbaPerformanceDashboardProps> = ({ database, customInsights }) => {
  const [results, setResults] = useState<Record<string, QueryResult>>({});
  const [loading, setLoading] = useState<Record<string, boolean>>({});
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [showSql, setShowSql] = useState<Record<string, boolean>>({});

  const getInsights = () => {
    const registryInsights = DialectRegistry[database.type]?.insights || [];
    const custom = customInsights?.[database.type];
    return custom ? custom : registryInsights;
  };

  const dashboardInsights = getInsights();

  const refreshAll = async () => {
    setIsRefreshing(true);
    const newResults: Record<string, QueryResult> = { ...results };
    const newLoading: Record<string, boolean> = {};

    dashboardInsights.forEach(i => newLoading[i.id] = true);
    setLoading(newLoading);

    await Promise.all(dashboardInsights.map(async (insight) => {
      try {
        const res = await muulService.executeQuery(database.id, insight.query, `dba-dash-${insight.id}`);
        newResults[insight.id] = res;
      } catch (e) {
        console.error(`DBA Dash Error [${insight.title}]:`, e);
      } finally {
        setLoading(prev => ({ ...prev, [insight.id]: false }));
      }
    }));

    setResults(newResults);
    setIsRefreshing(false);
  };

  useEffect(() => {
    refreshAll();
  }, [database.id]);

  const toggleSql = (id: string) => {
    setShowSql(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const renderWidget = (insight: DbaInsight) => {
    const result = results[insight.id];
    const isLoading = loading[insight.id];
    const isShowingSql = showSql[insight.id];

    // Senior DBA Heuristic: 
    // If it has few rows and numeric columns -> Chart
    // If it has many columns or long lists (like missing indexes) -> Table
    const isChartable = result && 
                        result.rowCount > 0 && 
                        result.rowCount < 15 && 
                        result.columns.some(c => c.toLowerCase().includes('%') || c.toLowerCase().includes('rate') || c.toLowerCase().includes('lat'));

    return (
      <div key={insight.id} className="bg-slate-900 border border-slate-800 rounded shadow-2xl flex flex-col transition-all hover:border-slate-600">
        {/* Header - High Density */}
        <div className="px-3 py-1.5 bg-slate-850 border-b border-slate-800 flex items-center justify-between shrink-0">
          <div className="flex items-center space-x-2">
            <Terminal size={12} className="text-slate-500" />
            <h3 className="text-[10px] font-black text-slate-300 uppercase tracking-tighter">{insight.title}</h3>
          </div>
          <div className="flex items-center space-x-2">
            <button 
                onClick={() => toggleSql(insight.id)} 
