             <button onClick={() => setLayout('left')} className={`p-1.5 rounded ${layout === 'left' ? 'text-blue-400 bg-slate-800' : 'text-slate-500 hover:text-slate-300'}`} title="Dock Left"><PanelLeft size={14} /></button>
