  const [activeSchema, setActiveSchema] = useState<DbSchema>({ tables: [] });
  const [schemaLayouts, setSchemaLayouts] = useState<SchemaLayout[]>([]);
  const [activeLayoutId, setActiveLayoutId] = useState<string | null>(null);

  const [isDraggingFile, setIsDraggingFile] = useState(false);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [appSettings, setAppSettings] = useState<AppSettings>(() => {
    const saved = localStorage.getItem('muul_settings');
    return saved ? JSON.parse(saved) : {
      editorFontSize: 14,
      themeAccent: 'blue',
      refreshRate: 0,
      customInsights: {}
    };
  });

  useEffect(() => {
    localStorage.setItem('muul_settings', JSON.stringify(appSettings));
  }, [appSettings]);

  const [savedQueries, setSavedQueries] = useState<SavedQuery[]>([
      { id: 'sq-1', name: 'Get All Users', content: 'SELECT * FROM users LIMIT 100;', dbId: 'db-1', createdAt: Date.now() }
  ]);

  const [pinnedCharts, setPinnedCharts] = useState<PinnedChart[]>([]);
  const [dashboards, setDashboards] = useState<DashboardLayout[]>([
      {
          id: 'main-dash',
          title: 'Main Dashboard',
          isDefault: true,
          rows: [
              {
                  id: 'row-welcome',
                  widgets: [
                      { id: 'w-welcome', type: 'markdown', colSpan: 12, title: 'Welcome', content: '# Welcome to Muul SQL\nDrag and drop **.csv**, **.json**, **.parquet**, or **.sqlite** files to instantly query them!'}
                  ]
              }
          ]
      }
  ]);
  const [activeDashboardId, setActiveDashboardId] = useState<string>('main-dash');

  const [tabs, setTabs] = useState<EditorTab[]>([
    { 
      id: 'tab-1', 
      title: 'Query 1', 
      content: '', 
      isDirty: false, 
      isExecuting: false, 
      results: [],
      activeResultIndex: -1 
    }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab-1');
  const [resultViewMode, setResultViewMode] = useState<'table' | 'chart'>('table');
  const [isEditorExpanded, setIsEditorExpanded] = useState(true);

  const [layout, setLayout] = useState<LayoutMode>('bottom');
  const [panelSize, setPanelSize] = useState(40); 
  const [floatRect, setFloatRect] = useState({ x: 100, y: 100, w: 600, h: 400 });

  const editorRef = useRef<SqlEditorRef>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const dragInfo = useRef<{ 
    isDragging: boolean; 
    type: 'resize-dock' | 'move-float' | 'resize-float'; 
    startX: number; 
    startY: number; 
    startSize?: number;
    startRect?: typeof floatRect;
  }>({ isDragging: false, type: 'resize-dock', startX: 0, startY: 0 });

  // Combined dropdown options derived from both local DBs and browser credentials
  const dropdownOptions = useMemo(() => {
      const localOptions = databases.map(db => ({
          value: db.id,
          label: db.name,
          type: db.type,
          source: 'local'
      }));
      const browserOptions = browserCredentials.map(cred => ({
          value: cred.id,
          label: cred.connectionName || cred.id,
          type: cred.dbType || 'sql',
          source: 'browser'
      }));
      return [...browserOptions, ...localOptions];
  }, [databases, browserCredentials]);

  // Helper to find the currently selected source object
  const selectedCredential = useMemo(() => 
      browserCredentials.find(c => c.id === selectedDbId),
  [browserCredentials, selectedDbId]);

  const selectedDb = useMemo(() => 
      databases.find(d => d.id === selectedDbId),
  [databases, selectedDbId]);

  useEffect(() => {
    // Initial data loading
    muulService.getDatabases().then(dbs => {
      setDatabases(dbs);
      if (dbs.length > 0 && !selectedDbId) {
          setSelectedDbId(dbs[0].id);
          setExpandedDbIds(new Set([dbs[0].id]));
      }
    });

    // Muul Browser detection and credential fetching
    detectMuulBrowser().then(async (detected) => {
        setIsMuulBrowser(detected);
        if (detected) {
            const credentials = await fetchSavedCredentials();
            setBrowserCredentials(credentials);
            if (credentials.length > 0) {
                setSelectedDbId(credentials[0].id);
            }
        }
    });
  }, []);

  useEffect(() => {
      if (selectedDbId && selectedDb) {
          if (!dbTables[selectedDbId]) {
              muulService.getDatabaseTables(selectedDbId).then(tables => {
                  setDbTables(prev => ({ ...prev, [selectedDbId]: tables }));
              });
          }
          muulService.getDatabaseSchema(selectedDbId).then(schema => {
              setActiveSchema(schema);
              setSchemaLayouts(prev => {
                  const hasLayout = prev.some(l => l.dbId === selectedDbId);
                  if (!hasLayout && schema.tables.length > 0) {
                      const defaultLayout: SchemaLayout = {
                          id: `layout-${Date.now()}`,
                          name: 'Main Diagram',
                          dbId: selectedDbId,
                          tables: schema.tables.map(t => t.name),
                          createdAt: Date.now()
                      };
                      setActiveLayoutId(defaultLayout.id);
                      return [...prev, defaultLayout];
                  }
                  const dbLayouts = prev.filter(l => l.dbId === selectedDbId);
                  if (dbLayouts.length > 0 && (!activeLayoutId || !dbLayouts.find(l => l.id === activeLayoutId))) {
                      setActiveLayoutId(dbLayouts[0].id);
                  }
                  return prev;
              });
          });
      }
  }, [selectedDbId, selectedDb]);

  useEffect(() => {
      if (selectedDbId) {
           const dbLayouts = schemaLayouts.filter(l => l.dbId === selectedDbId);
           if (dbLayouts.length > 0) {
               const active = schemaLayouts.find(l => l.id === activeLayoutId);
               if (!active || active.dbId !== selectedDbId) {
                   setActiveLayoutId(dbLayouts[0].id);
               }
           } else {
               setActiveLayoutId(null);
           }
      }
  }, [selectedDbId, schemaLayouts]);

  const handleLayoutCreate = (name: string, tables: string[]) => {
      if (!selectedDbId) return;
      const newLayout: SchemaLayout = {
          id: `layout-${Date.now()}`,
          name,
          dbId: selectedDbId,
          tables,
          createdAt: Date.now()
      };
      setSchemaLayouts(prev => [...prev, newLayout]);
      setActiveLayoutId(newLayout.id);
  };

  const handleLayoutUpdate = (layoutId: string, tables: string[]) => {
      setSchemaLayouts(prev => prev.map(l => l.id === layoutId ? { ...l, tables } : l));
  };

  const handleLayoutDelete = (layoutId: string) => {
      const remaining = schemaLayouts.filter(l => l.id !== layoutId);
      setSchemaLayouts(remaining);
      if (activeLayoutId === layoutId) {
          const others = remaining.filter(l => l.dbId === selectedDbId);
          setActiveLayoutId(others.length > 0 ? others[0].id : null);
      }
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragInfo.current.isDragging) return;

      const { type, startX, startY, startSize, startRect } = dragInfo.current;
      const container = containerRef.current;

      if (type === 'resize-dock' && container && startSize !== undefined) {
        const rect = container.getBoundingClientRect();
        let delta = 0;
        let newSize = startSize;

        if (layout === 'bottom') {
           delta = (startY - e.clientY) / rect.height * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'right') {
           delta = (startX - e.clientX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        } else if (layout === 'left') {
           delta = (e.clientX - startX) / rect.width * 100;
           newSize = Math.min(90, Math.max(10, startSize + delta));
        }
        setPanelSize(newSize);
      } 
      else if (type === 'move-float' && startRect) {
        setFloatRect({
          ...startRect,
          x: startRect.x + (e.clientX - startX),
          y: startRect.y + (e.clientY - startY)
        });
      }
      else if (type === 'resize-float' && startRect) {
        setFloatRect({
          ...startRect,
          w: Math.max(300, startRect.w + (e.clientX - startX)),
          h: Math.max(200, startRect.h + (e.clientY - startY))
        });
      }
    };

    const handleMouseUp = () => {
      dragInfo.current.isDragging = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [layout]);

  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.currentTarget === e.target) {
        setIsDraggingFile(false);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
  };

  const handleFileDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);

    const files: File[] = Array.from(e.dataTransfer.files);
    if (files.length === 0) return;

    for (const file of files) {
        if (file.name.endsWith('.sqlite') || file.name.endsWith('.db') || file.name.endsWith('.csv') || file.name.endsWith('.json') || file.name.endsWith('.parquet')) {
            try {
                const newDb = await muulService.uploadDatabase(file);
                setDatabases(prev => [newDb, ...prev]);
                setSelectedDbId(newDb.id);
                setExpandedDbIds(prev => new Set(prev).add(newDb.id));
                const tables = await muulService.getDatabaseTables(newDb.id);
                setDbTables(prev => ({ ...prev, [newDb.id]: tables }));
            } catch (err: any) {
                alert(`Failed to load ${file.name}: ${err.message}`);
            }
        } else {
            alert(`File ${file.name} is not supported.`);
        }
    }
  };

  const activeTab = tabs.find(t => t.id === activeTabId)!;
  const activeResult = activeTab?.activeResultIndex >= 0 
    ? activeTab.results[activeTab.activeResultIndex] 
    : null;

  const handleDbClick = (dbId: string) => {
      setSelectedDbId(dbId);
      setExpandedDbIds(prev => {
          const next = new Set(prev);
          if (next.has(dbId)) next.delete(dbId);
          else next.add(dbId);
          return next;
      });
  };

  const handleTableClick = (tableName: string) => {
      const existingTab = tabs.find(t => t.title === tableName && !t.isDirty);
      if (existingTab) {
          setActiveTabId(existingTab.id);
          setCurrentView('editor');
          return;
      }

      const isMongo = selectedDb?.type === 'mongodb';
      const content = isMongo 
          ? `db.${tableName}.find({}).limit(100)`
          : `SELECT * FROM "${tableName}" LIMIT 100;`;

      const newId = `tab-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: tableName,
          content,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
  };

  const handleCreateTab = () => {
    const newId = `tab-${Date.now()}`;
    setTabs([...tabs, {
      id: newId, title: `Query ${tabs.length + 1}`, content: '', isDirty: false, isExecuting: false, results: [], activeResultIndex: -1
    }]);
    setActiveTabId(newId);
  };

  const handleOpenSavedQuery = (sq: SavedQuery) => {
      const newId = `tab-${Date.now()}`;
      setTabs([...tabs, {
          id: newId,
          title: sq.name,
          content: sq.content,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      if(sq.dbId) setSelectedDbId(sq.dbId);
      setCurrentView('editor');
  };

  const handleSelectDbaInsight = (insight: DbaInsight) => {
      const newId = `dba-${insight.id}-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: `Diagnostic: ${insight.title}`,
          content: insight.query,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
      setTimeout(() => {
          executeTabQuery(newId, insight.query, false);
      }, 50);
  };

  const handleViewHistoryRecord = (record: DbaHistoryRecord) => {
      const newId = `hist-${record.id}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: `Snapshot: ${record.insightTitle}`,
          content: `-- Snapshot from ${new Date(record.timestamp).toLocaleString()}\n${record.data.rowCount} rows captured.\n\n${record.data.columns.join(' | ')}`,
          isDirty: false,
          isExecuting: false,
          results: [record.data],
          activeResultIndex: 0
      }]);
      setActiveTabId(newId);
      setCurrentView('editor');
  };

  const handleCaptureSnapshot = () => {
      if (!activeResult || !selectedDbId || (!selectedDb && !selectedCredential)) return;
      const title = activeTab.title.replace('Diagnostic: ', '').replace('Snapshot: ', '');
      const dbName = selectedDb?.name || selectedCredential?.connectionName || 'Unknown';
      dbaHistoryService.saveSnapshot(selectedDbId, dbName, activeTab.id, title, activeResult);
      alert("Diagnostic snapshot captured to history.");
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (tabs.length === 1) return;
    const newTabs = tabs.filter(t => t.id !== id);
    setTabs(newTabs);
    if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
  };

  const executeTabQuery = async (tabId: string, content: string, selectionOnly: boolean = false) => {
    if (!selectedDbId) return alert("Please select a database first.");

    let queriesToRun = [content];
    if (selectionOnly && selectedDb?.type !== 'mongodb' && !selectedCredential) {
         queriesToRun = content.split(';').map(q => q.trim()).filter(q => q.length > 0);
    }

    if (queriesToRun.length === 0) return;

    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: true } : t));
    const executionId = Date.now().toString();

    try {
      const results: QueryResult[] = [];
      for (const query of queriesToRun) {
        const result = await muulService.executeQuery(selectedDbId, query, executionId, selectedCredential);
        results.push(result);
        if (result.error) break; 
      }
      setTabs(prev => prev.map(t => t.id === tabId ? {
        ...t, isExecuting: false, results: [results[results.length - 1], ...t.results], activeResultIndex: 0
      } : t));
    } catch (e) {
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, isExecuting: false } : t));
    }
  };

  const handleRunQuery = async () => {
    const editor = editorRef.current;
    if (!editor) return;

    const selection = editor.getSelection();
    if (selection.text.trim().length > 0) {
        if (!selectedDbId) return alert("Please select a database first.");
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: true } : t));
        const result = await muulService.executeQuery(selectedDbId, selection.text, Date.now().toString(), selectedCredential);
        setTabs(prev => prev.map(t => t.id === activeTabId ? {
            ...t, isExecuting: false, results: [result, ...t.results], activeResultIndex: 0
        } : t));
    } else {
        executeTabQuery(activeTabId, activeTab.content, true);
    }
  };

  const handleApplyAggregation = (dimension: string, metric: string, func: string) => {
      const currentQuery = activeTab.content.trim().replace(/;$/, '');
      if (!currentQuery) return;

      const newQuery = `SELECT \n  "${dimension}", \n  ${func}("${metric}") as "${metric}_${func}" \nFROM (\n${currentQuery}\n) \nGROUP BY "${dimension}"`;

      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, content: newQuery, isDirty: true } : t));

      setTimeout(() => {
          executeTabQuery(activeTabId, newQuery, true);
      }, 50);
  };

  const handleCancelQuery = () => {
    setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, isExecuting: false } : t));
  };

  const handleSaveQuery = () => {
      if(!activeTab.content.trim()) return alert("Query is empty.");
      const name = prompt("Save Query As:", activeTab.title);
      if(!name) return;

      const newSaved: SavedQuery = {
          id: `sq-${Date.now()}`,
          name,
          content: activeTab.content,
          dbId: selectedDbId,
          createdAt: Date.now()
      };
      setSavedQueries([...savedQueries, newSaved]);
      setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, title: name, isDirty: false } : t));
  };

  const handleDownloadCSV = () => {
      if(!activeResult) return;
      exportService.downloadCSV(activeResult, `result-${Date.now()}.csv`);
  };

  const handlePinChart = (config: ChartConfig) => {
    if (!activeResult || !selectedDbId) return;
    const existingChart = pinnedCharts.find(c => 
        c.id === activeTab.linkedChartId || c.title === activeTab.title
    );
    if (existingChart) {
        const confirmUpdate = activeTab.linkedChartId 
            ? true 
            : window.confirm(`A pinned chart named "${existingChart.title}" already exists. Do you want to update it?`);
        if (!confirmUpdate) return;
        const updatedChart = { ...existingChart, query: activeTab.content, config: config, dbId: selectedDbId };
        setPinnedCharts(prev => prev.map(c => c.id === existingChart.id ? updatedChart : c));
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, linkedChartId: existingChart.id } : t));
        alert("Chart definition updated on dashboard!");
    } else {
        const chartId = `chart-${Date.now()}`;
        const newPin: PinnedChart = {
          id: chartId,
          title: activeTab.title,
          query: activeTab.content,
          dbId: selectedDbId,
          config: config,
          createdAt: Date.now()
        };
        setPinnedCharts(prev => [...prev, newPin]);
        setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, linkedChartId: chartId } : t));

        setDashboards(prev => {
            return prev.map(dash => {
                if (dash.id !== activeDashboardId) return dash;
                const newWidget = { id: `w-${Date.now()}`, type: 'chart' as const, colSpan: 6, content: chartId, title: newPin.title };
                const lastRow = dash.rows[dash.rows.length - 1];
                if (lastRow && lastRow.widgets.reduce((acc, w) => acc + w.colSpan, 0) <= 6) {
                    return { ...dash, rows: dash.rows.map(r => r.id === lastRow.id ? { ...r, widgets: [...r.widgets, newWidget] } : r) };
                } else {
                    return { ...dash, rows: [...dash.rows, { id: `row-${Date.now()}`, widgets: [newWidget] }] };
                }
            });
        });
        alert("Chart pinned to dashboard!");
    }
  };

  const handleUpdatePinnedChart = (newConfig: ChartConfig) => {
    if (!activeTab.linkedChartId || !selectedDbId) return;
    setPinnedCharts(prev => prev.map(c => {
        if (c.id === activeTab.linkedChartId) {
            return { ...c, query: activeTab.content, config: newConfig, dbId: selectedDbId };
        }
        return c;
    }));
    alert("Chart updated successfully!");
  };

  const handleEditChart = (chartId: string) => {
      const chart = pinnedCharts.find(c => c.id === chartId);
      if (!chart) return;
      const newId = `tab-edit-${Date.now()}`;
      setTabs(prev => [...prev, {
          id: newId,
          title: chart.title,
          content: chart.query,
          isDirty: false,
          isExecuting: false,
          results: [],
          activeResultIndex: -1,
          linkedChartId: chart.id
      }]);
      setActiveTabId(newId);
      if (chart.dbId) setSelectedDbId(chart.dbId);
      setCurrentView('editor');
      setTimeout(() => {
          executeTabQuery(newId, chart.query);
          setResultViewMode('chart');
      }, 100);
  };

  const handleAddDashboard = (title: string) => {
      const newDash: DashboardLayout = { id: `dash-${Date.now()}`, title, isDefault: false, rows: [] };
      setDashboards([...dashboards, newDash]);
      setActiveDashboardId(newDash.id);
  };

  const handleDeleteDashboard = (id: string) => {
      if (dashboards.length <= 1) return alert("Cannot delete the last dashboard.");
      const newDashboards = dashboards.filter(d => d.id !== id);
      setDashboards(newDashboards);
      if (activeDashboardId === id) setActiveDashboardId(newDashboards[0].id);
  };

  const handleUpdateDashboard = (updatedLayout: DashboardLayout) => {
      setDashboards(prev => prev.map(d => d.id === updatedLayout.id ? updatedLayout : d));
  };

  const handleRemoveChartDefinition = (id: string) => {
      setPinnedCharts(prev => prev.filter(c => c.id !== id));
      setDashboards(prev => prev.map(dash => ({
          ...dash,
          rows: dash.rows.map(row => ({
              ...row,
              widgets: row.widgets.filter(w => w.type !== 'chart' || w.content !== id)
          }))
      })));
  };

  const handleUpdateChartDefinition = (id: string, newConfig: ChartConfig) => {
      setPinnedCharts(prev => prev.map(c => id === c.id ? { ...c, config: newConfig } : c));
  };

  const startDockResize = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { isDragging: true, type: 'resize-dock', startX: e.clientX, startY: e.clientY, startSize: panelSize };
    document.body.style.cursor = layout === 'bottom' ? 'row-resize' : 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const startFloatMove = (e: React.MouseEvent) => {
    e.preventDefault();
    dragInfo.current = { isDragging: true, type: 'move-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  const startFloatResize = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragInfo.current = { isDragging: true, type: 'resize-float', startX: e.clientX, startY: e.clientY, startRect: floatRect };
  };

  const renderDbIcon = (type: string, source?: string) => {
    if (source === 'browser') return <Globe size={14} className="mr-2 text-indigo-400" />;
    if (type === 'mongodb') return <Leaf size={14} className="mr-2 text-green-500" />;
    return <DbIcon size={14} className="mr-2 text-blue-500/80" />;
  };

  return (
    <div 
        className={`flex flex-col h-screen w-screen bg-slate-950 text-slate-200 overflow-hidden font-sans ${appSettings.themeAccent}-accent relative`}
        onDragEnter={handleDragEnter}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleFileDrop}
    >
      {/* Muul Browser Banner */}
      {isMuulBrowser && (
        <div className="bg-[#137333] text-white py-1.5 px-4 text-xs font-bold flex items-center justify-center shrink-0 z-[60] shadow-lg">
          <ShieldAlert size={14} className="mr-2" />
          Muul SQL Studio connected to Muul Browser
        </div>
      )}

      {isDraggingFile && (
          <div className="absolute inset-0 z-[100] bg-blue-500/20 backdrop-blur-sm border-4 border-dashed border-blue-400 m-4 rounded-xl flex flex-col items-center justify-center pointer-events-none">
              <Upload size={64} className="text-blue-400 mb-4" />
              <h2 className="text-2xl font-bold text-white">Drop File to Import</h2>
              <p className="text-blue-200">Supports .csv, .json, .sqlite, .db, .parquet</p>
          </div>
      )}

      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} settings={appSettings} onSave={setAppSettings} />

      <div className="flex-1 flex overflow-hidden">
        <aside className="w-12 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-4 space-y-4 shrink-0 z-50">
          <div className="text-blue-500 mb-2"><DbIcon size={24} /></div>
          <button onClick={() => setCurrentView('editor')} className={`p-2 rounded-lg transition-colors ${currentView === 'editor' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`} title="SQL Editor"><TerminalSquare size={20} /></button>
          <button onClick={() => setCurrentView('dashboard')} className={`p-2 rounded-lg transition-colors ${currentView === 'dashboard' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`} title="Dashboard"><LayoutDashboard size={20} /></button>
          <button onClick={() => setCurrentView('dba-perf')} className={`p-2 rounded-lg transition-colors ${currentView === 'dba-perf' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`} title="Performance Pulse"><Activity size={20} /></button>
          <button onClick={() => setCurrentView('schema')} className={`p-2 rounded-lg transition-colors ${currentView === 'schema' ? 'bg-slate-800 text-slate-100 border-l-2 border-blue-500 rounded-l-none' : 'text-slate-500 hover:text-slate-300'}`} title="Schema Visualizer"><Network size={20} /></button>
          <div className="h-px w-6 bg-slate-800 my-2"></div>
          <button onClick={() => { setCurrentView('editor'); setSidebarTab('saved'); }} className={`p-2 rounded-lg transition-colors ${currentView === 'editor' && sidebarTab === 'saved' ? 'bg-slate-800 text-purple-400' : 'text-slate-500 hover:text-slate-300'}`} title="Saved Queries"><Bookmark size={20} /></button>
          <button onClick={() => { setCurrentView('editor'); setSidebarTab('dba'); }} className={`p-2 rounded-lg transition-colors ${currentView === 'editor' && sidebarTab === 'dba' ? 'bg-slate-800 text-blue-400' : 'text-slate-500 hover:text-slate-300'}`} title="DBA Insights"><ShieldAlert size={20} /></button>
          <div className="flex-1" />
          <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-slate-500 hover:text-slate-300 hover:bg-slate-800 rounded transition-colors"><Settings size={20} /></button>
        </aside>

        {(currentView === 'editor' || currentView === 'schema') && (
            <div className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col min-h-0 shrink-0">
               <div className="h-10 flex items-center px-4 font-bold text-xs uppercase tracking-wider text-slate-500 border-b border-slate-800 shrink-0">
                  {sidebarTab === 'db' ? 'Databases' : sidebarTab === 'saved' ? 'Saved Queries' : 'DBA Studio'}
               </div>
               {sidebarTab === 'db' && (
                  <div className="flex-1 overflow-y-auto p-2">
                      {/* Browser Credential Section */}
                      {browserCredentials.length > 0 && (
                          <div className="mb-4">
                             <div className="px-2 py-1 text-[10px] text-indigo-400 font-bold uppercase tracking-widest border-b border-slate-800/50 mb-1">Muul Saved</div>
                             {browserCredentials.map(cred => (
                                <div key={cred.id} onClick={() => setSelectedDbId(cred.id)} className={`flex items-center p-2 rounded cursor-pointer transition-colors ${selectedDbId === cred.id ? 'bg-slate-800 text-slate-200' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-300'}`}>
                                   <div className="mr-2"><ChevronRight size={14} className="opacity-0" /></div>
                                   {renderDbIcon(cred.dbType || '', 'browser')}
                                   <span className="text-sm truncate font-medium">{cred.connectionName || cred.id}</span>
                                </div>
                             ))}
                          </div>
                      )}

                      {/* Local Section */}
                      <div className="px-2 py-1 text-[10px] text-slate-500 font-bold uppercase tracking-widest border-b border-slate-800/50 mb-1">Local & Mock</div>
                      {databases.map(db => (
                          <div key={db.id} className="mb-1">
                              <div onClick={() => handleDbClick(db.id)} className={`flex items-center p-2 rounded cursor-pointer transition-colors ${selectedDbId === db.id ? 'bg-slate-800 text-slate-200' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-300'}`}>
                                  <div className={`mr-2 transition-transform ${expandedDbIds.has(db.id) ? 'rotate-90' : ''}`}><ChevronRight size={14} /></div>
                                  {renderDbIcon(db.type)}
                                  <div className="flex flex-col truncate">
                                      <span className="text-sm truncate font-medium">{db.name}</span>
                                  </div>
                              </div>
                              {expandedDbIds.has(db.id) && (
                                  <div className="ml-6 pl-2 border-l border-slate-800 mt-1 space-y-0.5">
                                      {dbTables[db.id] && dbTables[db.id].length > 0 ? (
                                          dbTables[db.id].map(tbl => (
                                              <div key={tbl} onClick={() => handleTableClick(tbl)} className="flex items-center px-2 py-1.5 text-xs text-slate-500 hover:text-blue-300 hover:bg-slate-800/50 rounded cursor-pointer group">
                                                  <TableIcon size={12} className="mr-2 opacity-50 group-hover:opacity-100" />
                                                  <span className="truncate">{tbl}</span>
                                              </div>
                                          ))
                                      ) : ( <div className="px-2 py-1 text-[10px] text-slate-600 italic">No tables found...</div> )}
                                  </div>
                              )}
                          </div>
                      ))}
                  </div>
               )}
               {sidebarTab === 'saved' && (
                  <div className="flex-1 overflow-y-auto p-2">
                      {savedQueries.map(sq => (
                          <div key={sq.id} onClick={() => handleOpenSavedQuery(sq)} className="group flex items-start p-2 mb-1 rounded cursor-pointer transition-colors text-slate-400 hover:bg-slate-800 hover:text-slate-200">
                              <FolderOpen size={14} className="mr-2 mt-0.5 text-purple-400" />
                              <div className="flex flex-col truncate flex-1">
                                  <span className="text-sm truncate font-medium">{sq.name}</span>
                                  <span className="text-[10px] text-slate-500 truncate">{new Date(sq.createdAt).toLocaleDateString()}</span>
                              </div>
                          </div>
                      ))}
                  </div>
               )}
               {sidebarTab === 'dba' && (
                  <DbaPanel 
                    dialect={selectedDb?.type || 'sqlite'} 
                    dbId={selectedDbId}
                    dbName={selectedDb?.name || selectedCredential?.connectionName || ''}
                    onSelectInsight={handleSelectDbaInsight} 
                    onViewHistory={handleViewHistoryRecord}
                    onLaunchDashboard={() => setCurrentView('dba-perf')}
                    customInsights={appSettings.customInsights}
                  />
               )}
            </div>
        )}

        <div className="flex-1 flex flex-col min-w-0 h-full overflow-hidden relative">
          {currentView === 'dashboard' && (
               <Dashboard dashboards={dashboards} pinnedCharts={pinnedCharts} databases={databases} activeDashboardId={activeDashboardId} refreshRate={appSettings.refreshRate} onSetActiveDashboard={setActiveDashboardId} onAddDashboard={handleAddDashboard} onUpdateDashboard={handleUpdateDashboard} onDeleteDashboard={handleDeleteDashboard} onRemoveChartDefinition={handleRemoveChartDefinition} onUpdateChartDefinition={handleUpdateChartDefinition} onEditChart={handleEditChart} />
          )}
          {currentView === 'schema' && (
              <SchemaVisualizer schema={activeSchema} dbName={selectedDb?.name || selectedCredential?.connectionName || 'Selected Database'} layouts={schemaLayouts.filter(l => l.dbId === selectedDbId)} activeLayoutId={activeLayoutId} onLayoutCreate={handleLayoutCreate} onLayoutSelect={setActiveLayoutId} onLayoutUpdate={handleLayoutUpdate} onLayoutDelete={handleLayoutDelete} />
          )}
          {currentView === 'dba-perf' && (selectedDb || selectedCredential) && (
              <DbaPerformanceDashboard database={(selectedDb || { id: selectedDbId, name: selectedCredential?.connectionName, type: selectedCredential?.dbType }) as any} customInsights={appSettings.customInsights} />
          )}
          <div className={`flex-1 flex flex-col h-full w-full ${currentView === 'dashboard' || currentView === 'schema' || currentView === 'dba-perf' ? 'hidden' : 'flex'}`}>
              <header className="h-14 border-b border-slate-800 bg-slate-900 flex items-center px-4 justify-between shrink-0 z-30 relative">
                <div className="flex items-center space-x-4">
                  <div className="flex items-center text-blue-400 font-bold text-lg tracking-tight">Muul<span className="text-slate-100">SQL</span></div>
                  <div className="h-6 w-px bg-slate-700 mx-2"></div>
                  <div className="relative group">
                    <select 
                        value={selectedDbId} 
                        onChange={(e) => setSelectedDbId(e.target.value)} 
                        className="appearance-none bg-slate-800 hover:bg-slate-700 border border-slate-700 text-xs rounded py-1.5 pl-3 pr-8 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors w-64 cursor-pointer"
                    >
                      {dropdownOptions.map(opt => (
                        <option key={opt.value} value={opt.value}>
                            {opt.source === 'browser' ? '🌐 ' : ''}{opt.label}
                        </option>
                      ))}
                    </select>
                    <Activity size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400" />
                  </div>
                </div>
                <div className="flex items-center space-x-2">
                    {activeTab.isExecuting ? (
                        <button onClick={handleCancelQuery} className="flex items-center px-4 py-1.5 bg-red-600 hover:bg-red-700 text-white text-sm font-medium rounded shadow animate-pulse"><Ban size={16} className="mr-2" /> Cancel</button>
                    ) : (
                        <button onClick={handleRunQuery} className="flex items-center px-4 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium rounded shadow hover:shadow-blue-500/20 active:scale-95"><Play size={16} className="mr-2 fill-current" /> Run</button>
                    )}
                    <div className="h-6 w-px bg-slate-700 mx-2"></div>
                    <button onClick={handleCaptureSnapshot} disabled={!activeResult || sidebarTab !== 'dba'} className="p-2 text-slate-400 hover:text-blue-400 hover:bg-slate-800 rounded disabled:opacity-30 transition-colors" title="Capture Snapshot to DBA History"><Camera size={18} /></button>
                    <button onClick={handleSaveQuery} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded transition-colors" title="Save Query"><Save size={18} /></button>
                    <button onClick={handleDownloadCSV} disabled={!activeResult} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded disabled:opacity-30 transition-colors" title="Download Result CSV"><Download size={18} /></button>
                </div>
              </header>
              <div className="flex items-center bg-slate-900 border-b border-slate-800 pr-2 pt-2 shrink-0">
                <div className="flex-1 flex overflow-x-auto no-scrollbar items-end px-2">
                    {tabs.map(tab => (
