import { CredentialEntry } from '../vite-env';

export interface ImportProgress {
  total: number;
  current: number;
  status: 'idle' | 'parsing' | 'creating' | 'inserting' | 'completed' | 'error';
  error?: string;
}

export class RemoteImportService {
  private sanitize(id: string): string {
    return id.trim().replace(/[^a-zA-Z0-9_]/g, '_');
  }

  private quoteIdentifier(id: string, dbType?: string): string {
    const sanitized = this.sanitize(id);
    switch (dbType?.toLowerCase()) {
      case 'mysql':
      case 'mariadb':
        return `\`${sanitized}\``;
      case 'mssql':
      case 'sqlserver':
        return `[${sanitized}]`;
      default: // Postgres, SQLite, General
        return `"${sanitized}"`;
    }
  }

  private escapeValue(val: any): string {
    if (val === null || val === undefined || val === '') return 'NULL';
    if (typeof val === 'number' || typeof val === 'boolean') return String(val);
    const str = String(val).replace(/'/g, "''");
    return `'${str}'`;
  }

  async executeRemote(credential: CredentialEntry, sql: string, batchIdx: number): Promise<any> {
    const bridge = (window as any).externalMessage;
    if (!bridge?.send) throw new Error("Muul Browser bridge not available");

    const payload = {
      credentialId: credential.id,
      connectionname: credential.connectionName,
      sql,
      params: [],
      requestId: `import-${Date.now()}-${batchIdx}`
    };

    const res = await bridge.send(JSON.stringify(payload));
    if (res?.ok === false || res?.error) {
      throw new Error(res.error || "Remote execution failed");
    }
    return res;
  }

  async importCsv(
    credential: CredentialEntry,
    tableName: string,
    headers: string[],
    data: any[],
    createTable: boolean,
    onProgress: (p: ImportProgress) => void
  ) {
    const total = data.length;
    const dbType = credential.dbType;
    const qTable = this.quoteIdentifier(tableName, dbType);
    const qHeaders = headers.map(h => this.quoteIdentifier(h, dbType));

    try {
      // 1. Create Table
      if (createTable) {
        onProgress({ total, current: 0, status: 'creating' });
        const colDefs = qHeaders.map(h => `${h} TEXT`).join(', ');
        const createSql = `CREATE TABLE IF NOT EXISTS ${qTable} (${colDefs});`;
        await this.executeRemote(credential, createSql, 0);
      }

      // 2. Batched Insert
      const BATCH_SIZE = 200;
      onProgress({ total, current: 0, status: 'inserting' });

      for (let i = 0; i < total; i += BATCH_SIZE) {
        const batch = data.slice(i, i + BATCH_SIZE);

        // Build Multi-row Insert
        // Note: For extreme safety across dialects, we could do individual inserts,
        // but multi-row is standard for these engines.
        const valueStrings = batch.map(row => {
          const vals = headers.map(h => this.escapeValue(row[h]));
          return `(${vals.join(',')})`;
        });

        const insertSql = `INSERT INTO ${qTable} (${qHeaders.join(',')}) VALUES ${valueStrings.join(',')};`;

        await this.executeRemote(credential, insertSql, i + 1);
        onProgress({ total, current: Math.min(i + BATCH_SIZE, total), status: 'inserting' });
      }

      onProgress({ total, current: total, status: 'completed' });
    } catch (err: any) {
      onProgress({ total, current: 0, status: 'error', error: err.message });
      throw err;
    }
  }
}

