import React, { useState, useCallback } from 'react';
import Papa from 'papaparse';
import { CredentialEntry } from '../vite-env';
import { remoteImportService, ImportProgress } from '../services/remoteImportService';
import { X, Upload, FileType, Database, CheckCircle, AlertTriangle, RefreshCw, Layers } from 'lucide-react';

interface RemoteCsvImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  credential: CredentialEntry | null;
  onSuccess: () => void;
}

const RemoteCsvImportModal: React.FC<RemoteCsvImportModalProps> = ({ isOpen, onClose, credential, onSuccess }) => {
  const [file, setFile] = useState<File | null>(null);
  const [tableName, setTableName] = useState('');
  const [createTable, setCreateTable] = useState(true);
  const [progress, setProgress] = useState<ImportProgress>({ total: 0, current: 0, status: 'idle' });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) {
      setFile(selected);
      const name = selected.name.replace(/\.[^/.]+$/, "").replace(/[^a-zA-Z0-9]/g, "_");
      setTableName(name);
    }
  };

  const runImport = async () => {
    if (!file || !credential) return;

    setProgress({ total: 0, current: 0, status: 'parsing' });

    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: async (results) => {
        try {
          const headers = results.meta.fields || [];
          const data = results.data;

          await remoteImportService.importCsv(
            credential,
            tableName,
            headers,
            data,
            createTable,
            (p) => setProgress(p)
          );

          setTimeout(() => {
            onSuccess();
          }, 1500);
        } catch (err) {
          console.error("Import failed", err);
        }
      },
      error: (err) => {
        setProgress({ total: 0, current: 0, status: 'error', error: err.message });
      }
    });
  };

  if (!isOpen) return null;

  const isProcessing = progress.status !== 'idle' && progress.status !== 'completed' && progress.status !== 'error';
  const percent = progress.total > 0 ? Math.round((progress.current / progress.total) * 100) : 0;

  return (
    <div className="fixed inset-0 z-[110] bg-black/80 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-lg rounded-2xl shadow-2xl flex flex-col overflow-hidden">

        {/* Header */}
        <div className="px-6 py-4 border-b border-slate-800 bg-slate-850 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400">
              <Upload size={20} />
            </div>
            <div>
              <h2 className="text-sm font-bold text-white uppercase tracking-tight">Import CSV to Remote</h2>
              <p className="text-[10px] text-slate-500 font-mono">{credential?.connectionName}</p>
            </div>
          </div>
          <button onClick={onClose} disabled={isProcessing} className="p-2 hover:bg-slate-800 rounded-full text-slate-500 transition-colors">
            <X size={18} />
          </button>
        </div>

        <div className="p-6 space-y-6">
          {progress.status === 'idle' ? (
            <>
              {/* File Dropzone */}
              <div className="relative group">
                <input 
                  type="file" 
                  accept=".csv" 
                  onChange={handleFileChange}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                />
                <div className={`
                  border-2 border-dashed rounded-xl p-8 flex flex-col items-center justify-center transition-all
                  ${file ? 'border-blue-500 bg-blue-500/5' : 'border-slate-800 bg-slate-950 group-hover:border-slate-600'}
                `}>
                  <FileType size={32} className={file ? 'text-blue-400 mb-2' : 'text-slate-700 mb-2'} />
                  <span className="text-xs font-bold text-slate-400">
                    {file ? file.name : 'Drop CSV file here or click to browse'}
                  </span>
                  {file && <span className="text-[10px] text-slate-600 mt-1">{(file.size / 1024).toFixed(1)} KB</span>}
                </div>
              </div>

              {/* Config */}
              <div className="space-y-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] uppercase font-black text-slate-500 tracking-widest">Target Table Name</label>
                  <div className="relative">
                    <Database size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600" />
                    <input 
                      type="text"
                      value={tableName}
                      onChange={(e) => setTableName(e.target.value)}
                      placeholder="e.g. imported_users"
                      className="w-full bg-slate-950 border border-slate-800 rounded-lg py-2 pl-9 pr-4 text-xs text-white focus:border-blue-500 outline-none transition-all"
                    />
                  </div>
                </div>

                <label className="flex items-center space-x-3 cursor-pointer group">
                   <div className="relative">
                      <input 
                        type="checkbox" 
                        checked={createTable} 
                        onChange={e => setCreateTable(e.target.checked)}
                        className="sr-only"
                      />
                      <div className={`w-10 h-5 rounded-full transition-colors ${createTable ? 'bg-blue-600' : 'bg-slate-800'}`}></div>
                      <div className={`absolute left-1 top-1 w-3 h-3 bg-white rounded-full transition-transform ${createTable ? 'translate-x-5' : 'translate-x-0'}`}></div>
                   </div>
                   <span className="text-xs text-slate-400 group-hover:text-slate-200 transition-colors font-medium">Create table if not exists</span>
                </label>
              </div>
            </>
          ) : (
            /* Progress State */
            <div className="py-8 flex flex-col items-center text-center">
              {progress.status === 'completed' ? (
                <div className="flex flex-col items-center animate-in zoom-in duration-300">
                  <div className="w-16 h-16 bg-green-500/20 text-green-500 rounded-full flex items-center justify-center mb-4">
                    <CheckCircle size={32} />
                  </div>
                  <h3 className="text-sm font-bold text-white">Import Successful</h3>
                  <p className="text-xs text-slate-500 mt-1">Added {progress.total} rows to {tableName}</p>
                </div>
              ) : progress.status === 'error' ? (
                <div className="flex flex-col items-center animate-in shake duration-300">
                  <div className="w-16 h-16 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4">
                    <AlertTriangle size={32} />
                  </div>
                  <h3 className="text-sm font-bold text-white">Import Failed</h3>
                  <p className="text-xs text-red-400 mt-2 px-4 font-mono leading-tight">{progress.error}</p>
                  <button 
                    onClick={() => setProgress({ total: 0, current: 0, status: 'idle' })}
                    className="mt-6 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-xs text-white rounded-lg transition-all"
                  >
                    Try Again
                  </button>
                </div>
              ) : (
                <div className="w-full space-y-6">
                  <div className="relative h-2 w-full bg-slate-800 rounded-full overflow-hidden shadow-inner">
                    <div 
                      className="absolute left-0 top-0 h-full bg-blue-600 transition-all duration-300 shadow-[0_0_10px_rgba(37,99,235,0.5)]"
                      style={{ width: `${percent}%` }}
                    />
                  </div>
                  <div className="flex flex-col items-center">
                    <RefreshCw size={24} className="text-blue-500 animate-spin mb-3" />
                    <span className="text-xs font-black text-slate-300 uppercase tracking-[0.2em]">
                      {progress.status === 'parsing' ? 'Parsing CSV...' : 
                       progress.status === 'creating' ? 'Preparing Schema...' : 
                       `Transmitting Data: ${percent}%`}
                    </span>
                    <span className="text-[10px] text-slate-500 font-mono mt-1">
                      {progress.current} / {progress.total} records
                    </span>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        {progress.status === 'idle' && (
          <div className="px-6 py-4 bg-slate-850 border-t border-slate-800 flex justify-end space-x-3">
            <button 
              onClick={onClose}
              className="px-4 py-2 text-xs font-bold text-slate-400 hover:text-white transition-colors"
            >
              Cancel
            </button>
            <button 
              onClick={runImport}
              disabled={!file || !tableName}
              className="px-6 py-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white text-xs font-bold rounded-xl shadow-lg shadow-blue-900/20 transition-all active:scale-95 flex items-center"
            >
              <Layers size={14} className="mr-2" /> Start Import
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

