import { CredentialEntry } from '../vite-env';
import { DbSchema, TableDefinition, ColumnDefinition } from '../types';

export class RemoteSchemaService {
  private async executeRemote(credential: CredentialEntry, sql: string, idSuffix: string): Promise<any> {
    const bridge = (window as any).externalMessage;
    if (!bridge?.send) throw new Error("Muul Browser bridge not available");

    const payload = {
      credentialId: credential.id,
      connectionname: credential.connectionName,
      sql,
      params: [],
      requestId: `meta-${Date.now()}-${idSuffix}`
    };

    const res = await bridge.send(JSON.stringify(payload));
    if (res?.ok === false || res?.error) {
      throw new Error(res.error || "Remote metadata fetch failed");
    }
    return res;
  }

  private getTablesQuery(dbType?: string): string {
    const type = dbType?.toLowerCase();
    if (type === 'mysql' || type === 'mariadb') {
      return "SELECT table_name as `name` FROM information_schema.tables WHERE table_schema = DATABASE() AND table_type = 'BASE TABLE'";
    }
    if (type === 'mssql' || type === 'sqlserver') {
      return "SELECT name FROM sys.tables WHERE is_ms_shipped = 0";
    }
    // Default/Postgres
    return "SELECT table_name as \"name\" FROM information_schema.tables WHERE table_schema = 'public' AND table_type = 'BASE TABLE'";
  }

  private getColumnsQuery(dbType?: string): string {
    const type = dbType?.toLowerCase();
    if (type === 'mysql' || type === 'mariadb') {
      return `
        SELECT 
          table_name as \`tableName\`, 
          column_name as \`name\`, 
          data_type as \`type\`, 
          column_key = 'PRI' as \`isPk\`
        FROM information_schema.columns 
        WHERE table_schema = DATABASE()
        ORDER BY table_name, ordinal_position`;
    }
    if (type === 'mssql' || type === 'sqlserver') {
      return `
        SELECT 
          t.name AS [tableName],
          c.name AS [name],
          TYPE_NAME(c.user_type_id) AS [type],
          ISNULL((SELECT 1 FROM sys.index_columns ic 
                  JOIN sys.indexes i ON ic.object_id = i.object_id AND ic.index_id = i.index_id
                  WHERE i.is_primary_key = 1 AND ic.column_id = c.column_id AND ic.object_id = t.object_id), 0) AS [isPk]
        FROM sys.columns c
        JOIN sys.tables t ON c.object_id = t.object_id
        WHERE t.is_ms_shipped = 0
        ORDER BY t.name, c.column_id`;
    }
    // Postgres
    return `
      SELECT 
        cols.table_name as "tableName", 
        cols.column_name as "name", 
        cols.data_type as "type",
        (SELECT COUNT(*) FROM information_schema.key_column_usage kcu
         JOIN information_schema.table_constraints tc ON kcu.constraint_name = tc.constraint_name
         WHERE kcu.table_name = cols.table_name AND kcu.column_name = cols.column_name 
         AND tc.constraint_type = 'PRIMARY KEY') > 0 as "isPk"
      FROM information_schema.columns cols
      WHERE cols.table_schema = 'public'
      ORDER BY cols.table_name, cols.ordinal_position`;
  }

  // Helper to find column index case-insensitively
  private findCol(cols: string[], target: string): number {
    const lowTarget = target.toLowerCase();
    return cols.findIndex(c => c.toLowerCase() === lowTarget);
  }

  async getRemoteTables(credential: CredentialEntry): Promise<{ name: string }[]> {
    const query = this.getTablesQuery(credential.dbType);
    const result = await this.executeRemote(credential, query, 'tables');
    const nameIdx = this.findCol(result.columns, 'name');

    if (nameIdx === -1) return [];
    return result.rows.map((row: any[]) => ({ name: row[nameIdx] }));
  }

  async getRemoteSchema(credential: CredentialEntry): Promise<DbSchema> {
    const tableList = await this.getRemoteTables(credential);
    const colQuery = this.getColumnsQuery(credential.dbType);
    const colResult = await this.executeRemote(credential, colQuery, 'cols');

    const tIdx = this.findCol(colResult.columns, 'tableName');
    const nIdx = this.findCol(colResult.columns, 'name');
    const typeIdx = this.findCol(colResult.columns, 'type');
    const pkIdx = this.findCol(colResult.columns, 'isPk');

    // Group columns by table
    const tableMap = new Map<string, ColumnDefinition[]>();

    colResult.rows.forEach((row: any[]) => {
      const tableName = row[tIdx];
      const column: ColumnDefinition = {
        name: row[nIdx],
        type: row[typeIdx],
        isPrimaryKey: row[pkIdx] === true || row[pkIdx] === 1 || row[pkIdx] === '1' || row[pkIdx] === 't',
        isForeignKey: false
      };

      if (!tableMap.has(tableName)) {
        tableMap.set(tableName, []);
      }
      tableMap.get(tableName)?.push(column);
    });

    const tables: TableDefinition[] = tableList.map(t => ({
      name: t.name,
      columns: tableMap.get(t.name) || []
    }));

    return { tables };
  }
}

