import { CredentialEntry } from '../vite-env';
import { DbSchema, TableDefinition, ColumnDefinition } from '../types';

export interface NormalizedResult {
  columns: string[];
  rows: any[][];
}

export class RemoteSchemaService {
  /**
   * Normalizes bridge responses which can come as array-of-objects or array-of-arrays.
   * Ensures the rest of the app receives the standard columns[] + rows[][] format.
   */
  public normalize(res: any): NormalizedResult {
    if (!res || !res.rows || res.rows.length === 0) {
      return { columns: res?.columns || [], rows: [] };
    }

    let columns: string[] = res.columns || [];
    let rows = res.rows;

    // Handle array-of-objects format (common in some browser drivers)
    if (!Array.isArray(rows[0]) && typeof rows[0] === 'object' && rows[0] !== null) {
      // If columns aren't explicitly provided, infer them from the first object
      if (columns.length === 0) {
        columns = Object.keys(rows[0]);
      }
      // Convert objects to arrays based on the column order
      rows = rows.map((r: any) => columns.map((colName) => r[colName]));
    }

    return { columns, rows };
  }

  private async executeRemote(credential: CredentialEntry, sql: string, idSuffix: string): Promise<NormalizedResult> {
    const bridge = (window as any).externalMessage;
    if (!bridge?.send) throw new Error("Muul Browser bridge not available");

    const payload = {
      credentialId: credential.id,
      connectionname: credential.connectionName,
      sql,
      params: [],
      requestId: `meta-${Date.now()}-${idSuffix}`
    };

    const res = await bridge.send(JSON.stringify(payload));
    if (res?.ok === false || res?.error) {
      throw new Error(res.error || "Remote metadata fetch failed");
    }

    return this.normalize(res);
  }

  private getTablesQuery(dbType?: string): string {
    const type = dbType?.toLowerCase();
    if (type === 'mysql' || type === 'mariadb') {
      return "SELECT table_name as `name` FROM information_schema.tables WHERE table_schema = DATABASE() AND table_type = 'BASE TABLE'";
    }
    if (type === 'mssql' || type === 'sqlserver') {
      return "SELECT name FROM sys.tables WHERE is_ms_shipped = 0";
    }
    return "SELECT table_name as \"name\" FROM information_schema.tables WHERE table_schema = 'public' AND table_type = 'BASE TABLE'";
  }

  private getColumnsQuery(dbType?: string): string {
    const type = dbType?.toLowerCase();
    if (type === 'mysql' || type === 'mariadb') {
      return `
        SELECT 
          table_name as \`tableName\`, 
          column_name as \`name\`, 
          data_type as \`type\`, 
          column_key = 'PRI' as \`isPk\`
        FROM information_schema.columns 
        WHERE table_schema = DATABASE()
        ORDER BY table_name, ordinal_position`;
    }
    if (type === 'mssql' || type === 'sqlserver') {
      return `
        SELECT 
          t.name AS [tableName],
          c.name AS [name],
          TYPE_NAME(c.user_type_id) AS [type],
          ISNULL((SELECT 1 FROM sys.index_columns ic 
                  JOIN sys.indexes i ON ic.object_id = i.object_id AND ic.index_id = i.index_id
                  WHERE i.is_primary_key = 1 AND ic.column_id = c.column_id AND ic.object_id = t.object_id), 0) AS [isPk]
        FROM sys.columns c
        JOIN sys.tables t ON c.object_id = t.object_id
        WHERE t.is_ms_shipped = 0
        ORDER BY t.name, c.column_id`;
    }
    return `
      SELECT 
        cols.table_name as "tableName", 
        cols.column_name as "name", 
        cols.data_type as "type",
        (SELECT COUNT(*) FROM information_schema.key_column_usage kcu
         JOIN information_schema.table_constraints tc ON kcu.constraint_name = tc.constraint_name
         WHERE kcu.table_name = cols.table_name AND kcu.column_name = cols.column_name 
         AND tc.constraint_type = 'PRIMARY KEY') > 0 as "isPk"
      FROM information_schema.columns cols
      WHERE cols.table_schema = 'public'
      ORDER BY cols.table_name, cols.ordinal_position`;
  }

  private findCol(cols: string[], target: string): number {
    const lowTarget = target.toLowerCase();
    return cols.findIndex(c => c.toLowerCase() === lowTarget);
  }

  async getRemoteTables(credential: CredentialEntry): Promise<{ name: string }[]> {
    const result = await this.executeRemote(credential, this.getTablesQuery(credential.dbType), 'tables');
    const nameIdx = this.findCol(result.columns, 'name');

    if (nameIdx === -1) return [];
    return result.rows.map((row) => ({ name: row[nameIdx] }));
  }

  async getRemoteSchema(credential: CredentialEntry): Promise<DbSchema> {
    const tableList = await this.getRemoteTables(credential);
    const colResult = await this.executeRemote(credential, this.getColumnsQuery(credential.dbType), 'cols');

    const tIdx = this.findCol(colResult.columns, 'tableName');
    const nIdx = this.findCol(colResult.columns, 'name');
    const typeIdx = this.findCol(colResult.columns, 'type');
    const pkIdx = this.findCol(colResult.columns, 'isPk');

    const tableMap = new Map<string, ColumnDefinition[]>();

    colResult.rows.forEach((row) => {
      const tableName = row[tIdx];
      const column: ColumnDefinition = {
        name: row[nIdx],
        type: row[typeIdx],
        isPrimaryKey: row[pkIdx] === true || row[pkIdx] === 1 || row[pkIdx] === '1' || row[pkIdx] === 't',
        isForeignKey: false
      };

      if (!tableMap.has(tableName)) {
        tableMap.set(tableName, []);
      }
      tableMap.get(tableName)?.push(column);
    });

    const tables: TableDefinition[] = tableList.map(t => ({
      name: t.name,
      columns: tableMap.get(t.name) || []
    }));

    return { tables };
  }
}

export const remoteSchemaService = new RemoteSchemaService();

import { Database, QueryResult, DbSchema } from '../types';
import { SqliteEngine } from './engines/SqliteEngine';
import { MockEngine } from './engines/MockEngine';
import { MongoEngine } from './engines/MongoEngine';
import { CredentialEntry } from '../vite-env';
import { remoteSchemaService } from './remoteSchemaService';

class MuulService {
  private sqliteEngine: SqliteEngine;
  private mockEngine: MockEngine;
  private mongoEngine: MongoEngine;

  private realDatabases: Map<string, { name: string, type: string }> = new Map();
  private virtualIdCounter = 1;

  constructor() {
    this.sqliteEngine = new SqliteEngine();
    this.mockEngine = new MockEngine();
    this.mongoEngine = new MongoEngine();
  }

  async getDatabases(): Promise<Database[]> {
    const systemDbs: Database[] = [
      { id: 'db-1', name: 'Production DB (Mock SQL)', type: 'postgres' },
      { id: 'db-2', name: 'Analytics Parquet (Mock)', type: 'parquet' },
      { id: 'db-mongo', name: 'User Store (Mock MongoDB)', type: 'mongodb' },
    ];
    const userDbs: Database[] = Array.from(this.realDatabases.entries()).map(([id, meta]) => ({
      id,
      name: meta.name,
      type: meta.type as any
    }));
    return [...userDbs, ...systemDbs];
  }

  async uploadDatabase(file: File): Promise<Database> {
     const { db, type } = await this.sqliteEngine.createDatabaseFromFile(file);
     const dbId = `user-db-${this.virtualIdCounter++}`;

     this.sqliteEngine.registerDatabase(dbId, db);
     this.realDatabases.set(dbId, { name: file.name, type: 'sqlite' });

     return { id: dbId, name: file.name, type: 'sqlite' };
  }

  async executeQuery(dbId: string, sql: string, queryId: string, browserCredential?: CredentialEntry): Promise<QueryResult> {
      const bridge = (window as any).externalMessage;
      if (browserCredential && bridge?.send) {
          const startTime = performance.now();
          try {
              const payload = {
                  credentialId: browserCredential.id,
                  connectionname: browserCredential.connectionName,
                  sql,
                  params: [],
                  requestId: `q-${Date.now()}`
              };
              const response = await bridge.send(JSON.stringify(payload));

              if (response?.ok === false || response?.error) {
                  throw new Error(response.error || "Execution failed in browser");
              }

              // Use RemoteSchemaService's normalization to ensure result format compatibility
              const normalized = remoteSchemaService.normalize(response);

              return {
                  columns: normalized.columns,
                  rows: normalized.rows,
                  rowCount: normalized.rows.length,
                  executionTimeMs: Math.round(performance.now() - startTime),
                  timestamp: Date.now(),
                  rawJson: response
              };
          } catch (e: any) {
              return {
                  columns: [], rows: [], rowCount: 0,
                  executionTimeMs: Math.round(performance.now() - startTime),
                  timestamp: Date.now(),
                  error: e.message
              };
          }
      }

      if (dbId === 'db-mongo') return this.mongoEngine.executeQuery(dbId, sql);

      if (this.realDatabases.has(dbId)) {
          return this.sqliteEngine.executeQuery(dbId, sql);
      } else {
          return this.mockEngine.executeQuery(dbId, sql);
      }
  }

  async getDatabaseTables(dbId: string, browserCredential?: CredentialEntry): Promise<string[]> {
      const schema = await this.getDatabaseSchema(dbId, browserCredential);
      return schema.tables.map(t => t.name);
  }

  async getDatabaseSchema(dbId: string, browserCredential?: CredentialEntry): Promise<DbSchema> {
      if (browserCredential && (window as any).externalMessage?.send) {
          return remoteSchemaService.getRemoteSchema(browserCredential);
      }

      if (dbId === 'db-mongo') return this.mongoEngine.getSchema(dbId);
      if (this.realDatabases.has(dbId)) {
          return this.sqliteEngine.getSchema(dbId);
      }
      return this.mockEngine.getSchema(dbId);
  }

  async explainQuery(dbId: string, sql: string): Promise<QueryResult> {
      const dbType = this.realDatabases.get(dbId)?.type || 'postgres';
      let explainSql = `EXPLAIN (FORMAT JSON, ANALYZE) ${sql}`;
      if (dbType === 'sqlite') explainSql = `EXPLAIN QUERY PLAN ${sql}`;
      if (dbType === 'mssql') explainSql = `SET STATISTICS XML ON; ${sql}`;

      return this.executeQuery(dbId, explainSql, `explain-${Date.now()}`);
  }
}

export const muulService = new MuulService();
